-- Poems batch 277
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c05a1222-519f-43b8-bf75-cac5d7d6060c','湖州歌九十八首  其七五','汪元量','宋','宋诗','song-poetry','','[]','第六筵開在禁庭，蒸麋燒鹿薦杯行。',32,'全唐诗/poet.song.245000.json','["第六筵開在禁庭，蒸麋燒鹿薦杯行。", "三宮滿飲天顔喜，月下笙歌入舊城。"]'),
('7e386865-ec8b-4093-95da-4c7659fd3e56','湖州歌九十八首  其七六','汪元量','宋','宋诗','song-poetry','','[]','第七筵排極整齊，三宮游處軟輿提。',32,'全唐诗/poet.song.245000.json','["第七筵排極整齊，三宮游處軟輿提。", "杏漿新沃燒熊肉，更進鵪鶉野雉雞。"]'),
('5eec63cd-5594-4be8-ade8-14f170c7c0ae','湖州歌九十八首  其七七','汪元量','宋','宋诗','song-poetry','','[]','第八筵開在北亭，三宮豐燕已恩榮。',32,'全唐诗/poet.song.245000.json','["第八筵開在北亭，三宮豐燕已恩榮。", "諸行百戲都呈藝，樂局伶官叫點名。"]'),
('1d99dc8c-10ff-4694-bba0-95ef1dcfa86f','湖州歌九十八首  其七八','汪元量','宋','宋诗','song-poetry','','[]','第九筵開盡帝妃，三宮端坐受金巵。',32,'全唐诗/poet.song.245000.json','["第九筵開盡帝妃，三宮端坐受金巵。", "須臾殿上都酣醉，拍手高歌舞雁兒。"]'),
('98b73024-62e1-4010-ab66-2d35f8aa76e0','湖州歌九十八首  其七九','汪元量','宋','宋诗','song-poetry','','[]','第十瓊筵敞禁庭，兩廂丞相把壺瓶。',32,'全唐诗/poet.song.245000.json','["第十瓊筵敞禁庭，兩廂丞相把壺瓶。", "君王自勸三宮酒，更送天香近玉屏。"]'),
('d1adc1f5-a967-4ddc-b7e4-64dab712551e','湖州歌九十八首  其八○','汪元量','宋','宋诗','song-poetry','','[]','一人不殺謝乾坤，萬里來來謁帝閽。',32,'全唐诗/poet.song.245000.json','["一人不殺謝乾坤，萬里來來謁帝閽。", "高下受官隨品從，九流藝術亦沾恩。"]'),
('8ea2b6bb-6aa3-4718-b855-afe7acc194c6','湖州歌九十八首  其八一','汪元量','宋','宋诗','song-poetry','','[]','僧道恩榮已受封，上庠儒者亦恩隆。',32,'全唐诗/poet.song.245000.json','["僧道恩榮已受封，上庠儒者亦恩隆。", "福王又拜平原郡，幼主新封瀛國公。"]'),
('6fedd936-2675-481c-a4bc-08c4ce446edb','湖州歌九十八首  其八二','汪元量','宋','宋诗','song-poetry','','[]','金屋粧成物色新，三宮日用御厨珍。',32,'全唐诗/poet.song.245000.json','["金屋粧成物色新，三宮日用御厨珍。", "其餘宮女千餘箇，分嫁幽州老斵輪。"]'),
('a0da4f19-4291-4d34-b651-8a03201f8c78','湖州歌九十八首  其八三','汪元量','宋','宋诗','song-poetry','','[]','每月支糧萬石鈞，日支羊肉六千斤。',32,'全唐诗/poet.song.245000.json','["每月支糧萬石鈞，日支羊肉六千斤。", "御厨請給葡萄酒，別賜天鵝與野麕。"]'),
('73fd1aef-b666-4255-bad0-ec71f13f63d3','湖州歌九十八首  其八四','汪元量','宋','宋诗','song-poetry','','[]','三宮寢室異香飄，貂鼠氈簾錦繡標。',32,'全唐诗/poet.song.245000.json','["三宮寢室異香飄，貂鼠氈簾錦繡標。", "花毯褥裀三萬件，織金鳳被八千條。"]'),
('e4d98d7e-107e-4d2c-84bb-f994a11e9fb1','湖州歌九十八首  其八五','汪元量','宋','宋诗','song-poetry','','[]','客中忽忽又重陽，滿酌葡萄當菊觴。',32,'全唐诗/poet.song.245000.json','["客中忽忽又重陽，滿酌葡萄當菊觴。", "謝后已叨新聖旨，謝家田土免輸糧。"]'),
('b953d57c-56b0-4c43-9b82-b2d5084b21f3','湖州歌九十八首  其八六','汪元量','宋','宋诗','song-poetry','','[]','雪裏天家賜炕羊，兩壺九醖紫霞觴。',32,'全唐诗/poet.song.245000.json','["雪裏天家賜炕羊，兩壺九醖紫霞觴。", "三宮夜給千條燭，更賜高麗黑玉香。"]'),
('c7b47e40-ec18-4138-a390-7331bb9f20cb','湖州歌九十八首  其八七','汪元量','宋','宋诗','song-poetry','','[]','三殿加餐强自寬，內家日日問平安。',32,'全唐诗/poet.song.245000.json','["三殿加餐强自寬，內家日日問平安。", "大元皇后來相探，特賜絲紬二百單。"]'),
('b303d06b-d03d-4839-b094-1b323597ff43','湖州歌九十八首  其八八','汪元量','宋','宋诗','song-poetry','','[]','萬里修途似夢中，天家賜予意無窮。',32,'全唐诗/poet.song.245000.json','["萬里修途似夢中，天家賜予意無窮。", "昭儀別館香雲煖，自把詩書授國公。"]'),
('a8a26b25-cfa0-432f-b284-165a70dc9d36','湖州歌九十八首  其八九','汪元量','宋','宋诗','song-poetry','','[]','萬里羈孤夜憶家，邊城吹角更吹笳。',32,'全唐诗/poet.song.245000.json','["萬里羈孤夜憶家，邊城吹角更吹笳。", "須臾敕使傳言語，今日天庭賞雪花。"]'),
('4f10a2f8-1002-47f7-85a3-bc298760903c','湖州歌九十八首  其九○','汪元量','宋','宋诗','song-poetry','','[]','雪子飛飛塞面寒，地爐石炭共團欒。',32,'全唐诗/poet.song.245000.json','["雪子飛飛塞面寒，地爐石炭共團欒。", "天家賜酒十銀甕，熊掌天鵝三玉盤。"]'),
('664230cf-5cc4-4e06-afd1-3e5f22927a49','湖州歌九十八首  其九一','汪元量','宋','宋诗','song-poetry','','[]','江南郡守列金階，內裏華筵日日排。',32,'全唐诗/poet.song.245000.json','["江南郡守列金階，內裏華筵日日排。", "文武官僚多二品，還鄉盡带虎頭牌。"]'),
('12b3f6be-57b8-4666-8f24-19aa2da7f419','湖州歌九十八首  其九二','汪元量','宋','宋诗','song-poetry','','[]','四川昝帥尚麤豪，萬馬來燕貢一遭。',32,'全唐诗/poet.song.245000.json','["四川昝帥尚麤豪，萬馬來燕貢一遭。", "奏授虎符三百面，內家更賜織金袍。"]'),
('2a580189-c6f8-4e3d-9c6b-e02e79dd8bf9','湖州歌九十八首  其九三','汪元量','宋','宋诗','song-poetry','','[]','九重蕡燭照簾櫳，三殿乘輿去賀冬。',32,'全唐诗/poet.song.245000.json','["九重蕡燭照簾櫳，三殿乘輿去賀冬。", "金面垂慈多喜色，史官書瑞奏年豐。"]'),
('b09407da-6701-4efb-9ced-c84113a3eeef','湖州歌九十八首  其九四','汪元量','宋','宋诗','song-poetry','','[]','曉望燕雲正雪天，閉門氈帳恣高眠。',32,'全唐诗/poet.song.245000.json','["曉望燕雲正雪天，閉門氈帳恣高眠。", "內家遺鈔三千錠，添賜三宮日用錢。"]'),
('6c175bab-f4ed-44c2-9556-2370571fbcb9','湖州歌九十八首  其九五','汪元量','宋','宋诗','song-poetry','','[]','東宮雪裏燕三宮，妃子殷勤把酒鍾。',32,'全唐诗/poet.song.245000.json','["東宮雪裏燕三宮，妃子殷勤把酒鍾。", "百十箜篌彈玉指，兩行珠翠擊金鏞。"]'),
('75c52bd4-ad85-4763-80ad-74dbee14787b','湖州歌九十八首  其九六','汪元量','宋','宋诗','song-poetry','','[]','夜來酒醒四更過，漸覺衾裯冷氣多。',32,'全唐诗/poet.song.245000.json','["夜來酒醒四更過，漸覺衾裯冷氣多。", "踏雪敲門雙敕使，傳言太子送天鵝。"]'),
('9d78066e-80c2-446d-a814-c1d5678bc0de','湖州歌九十八首  其九七','汪元量','宋','宋诗','song-poetry','','[]','兩下金幱障御階，異香縹緲五門開。',32,'全唐诗/poet.song.245000.json','["兩下金幱障御階，異香縹緲五門開。", "都人罷市從容立，迎接南朝駙馬來。"]'),
('064e0242-adee-43cd-a84e-0abb21cc1d78','湖州歌九十八首  其九八','汪元量','宋','宋诗','song-poetry','','[]','杭州萬里到幽州，百咏歌成意未休。',32,'全唐诗/poet.song.245000.json','["杭州萬里到幽州，百咏歌成意未休。", "燕玉偶然通一笑，歌喉宛轉作吳謳。"]'),
('ec844610-f55f-4dc3-8d98-cb15a3f11eae','越州歌二十首  其一','汪元量','宋','宋诗','song-poetry','','[]','淮南西畔草離離，萬檝千艘水上飛。',32,'全唐诗/poet.song.245000.json','["淮南西畔草離離，萬檝千艘水上飛。", "旗幟蔽江金鼓震，伯顔丞相過江時。"]'),
('5042154d-40fb-46a9-8a03-6cc77c23435a','越州歌二十首  其二','汪元量','宋','宋诗','song-poetry','','[]','東南半壁日昏昏，萬騎臨軒趣幼君。',32,'全唐诗/poet.song.245000.json','["東南半壁日昏昏，萬騎臨軒趣幼君。", "三十六宮隨輦去，不堪回首望吳雲。"]'),
('f8f2b1a1-8e56-40f2-8c6c-ef6d3b1e90a8','越州歌二十首  其三','汪元量','宋','宋诗','song-poetry','','[]','一陣西風滿地烟，千軍萬馬浙江邊。',32,'全唐诗/poet.song.245000.json','["一陣西風滿地烟，千軍萬馬浙江邊。", "官司把斷西興渡，要奪漁船作戰船。"]'),
('31178603-66d2-45db-ae3d-705aaa534956','越州歌二十首  其四','汪元量','宋','宋诗','song-poetry','','[]','兩峰雲鎖幾時開，昨夜京城戰鼓哀。',32,'全唐诗/poet.song.245000.json','["兩峰雲鎖幾時開，昨夜京城戰鼓哀。", "漁父生來載歌舞，滿頭白髪見兵來。"]'),
('e7951d50-1ffd-4099-8964-5b7f60cf438f','越州歌二十首  其五','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋風吹雨暗天涯，越鳥巢翻何以家。',32,'全唐诗/poet.song.245000.json','["秋風吹雨暗天涯，越鳥巢翻何以家。", "嶺上萬松都斫盡，西湖新路欲排叉。"]'),
('022cf664-d9fb-4068-8021-27c63b6a46c8','越州歌二十首  其六','汪元量','宋','宋诗','song-poetry','','[]','師相平章誤我朝，千秋萬古恨難銷。',32,'全唐诗/poet.song.245000.json','["師相平章誤我朝，千秋萬古恨難銷。", "蕭牆禍起非今日，不賞軍功在斷橋。"]'),
('ede146cd-97b1-4950-9b5d-40cf0ca16d43','越州歌二十首  其七','汪元量','宋','宋诗','song-poetry','','[]','蒼生慟哭入雲霄，內苑瓊林已作樵。',32,'全唐诗/poet.song.245000.json','["蒼生慟哭入雲霄，內苑瓊林已作樵。", "打斷六更天未曉，禁庭兩桁籸盤燒。"]'),
('481186e3-0a17-4c33-ad12-84d4d1410423','越州歌二十首  其八','汪元量','宋','宋诗','song-poetry','','[]','魯港當年傀儡場，六軍盡笑賈平章。',32,'全唐诗/poet.song.245000.json','["魯港當年傀儡場，六軍盡笑賈平章。", "三聲鑼響三更後，不見人呼大魏王。"]'),
('771954e6-82da-497c-91b1-e8daba5a3851','越州歌二十首  其九','汪元量','宋','宋诗','song-poetry','','[]','脫却黄袍心莫欺，魏王事業止於斯。',32,'全唐诗/poet.song.245000.json','["脫却黄袍心莫欺，魏王事業止於斯。", "孤舟走過揚州去，表奏朝廷乞太師。"]'),
('d8117628-b130-44dc-9661-3ded1937e8ec','越州歌二十首  其一○','汪元量','宋','宋诗','song-poetry','','[]','賈廟巍巍盡敕封，秦齊兩國受恩同。',32,'全唐诗/poet.song.245000.json','["賈廟巍巍盡敕封，秦齊兩國受恩同。", "木棉庵下無依鬼，合策麒麟第一功。"]'),
('f2e1e5d3-5a5f-40c4-b0d1-75dcde44d4cc','越州歌二十首  其一一','汪元量','宋','宋诗','song-poetry','','[]','集芳園裏策奇功，丞相南行面發紅。',32,'全唐诗/poet.song.245000.json','["集芳園裏策奇功，丞相南行面發紅。", "留得紫綿三百曲，風吹雨打併成空。"]'),
('e96facc8-9ea3-4800-ac46-2d7e40b9e93b','越州歌二十首  其一二','汪元量','宋','宋诗','song-poetry','','[]','羣臣上疏納忠言，國害分明在目前。',32,'全唐诗/poet.song.245000.json','["羣臣上疏納忠言，國害分明在目前。", "只論平章行不法，公田之後又私田。"]'),
('d5817f89-7f37-4945-87fc-123fa7ad263a','越州歌二十首  其一三','汪元量','宋','宋诗','song-poetry','','[]','甲子初秋柳宿乖，皇天無雨只空雷。',32,'全唐诗/poet.song.245000.json','["甲子初秋柳宿乖，皇天無雨只空雷。", "正當七月初三夜，帝勸長星酒一杯。"]'),
('11aa15bd-96d0-45a1-ab92-748f2b1c432a','越州歌二十首  其一四','汪元量','宋','宋诗','song-poetry','','[]','絲風毛雨共淒凉，燕子樓空恨恨長。',32,'全唐诗/poet.song.245000.json','["絲風毛雨共淒凉，燕子樓空恨恨長。", "今日客逢新酒熟，夜來春去落花忙。"]'),
('49316fa8-9f81-475a-ae87-edb25906969e','越州歌二十首  其一五','汪元量','宋','宋诗','song-poetry','','[]','月夜湖歌歌正長，船來船去水茫茫。',32,'全唐诗/poet.song.245000.json','["月夜湖歌歌正長，船來船去水茫茫。", "上塘歌了下塘唱，更唱吳王與越王。"]'),
('ffabbbfb-1fd5-46f0-b149-e22d42bdf57a','越州歌二十首  其一六','汪元量','宋','宋诗','song-poetry','','[]','昨夢吳山閬苑開，風吹仙樂下瑶臺。',32,'全唐诗/poet.song.245000.json','["昨夢吳山閬苑開，風吹仙樂下瑶臺。", "翠圍紅陣知多少，半揭珠簾看駕來。"]'),
('8041c657-33e1-410c-a826-f32c79f049a4','越州歌二十首  其一七','汪元量','宋','宋诗','song-poetry','','[]','鼇山燈月照人嬉，宣德門前萬玉姬。',32,'全唐诗/poet.song.245000.json','["鼇山燈月照人嬉，宣德門前萬玉姬。", "記得那年三五夜，快行擎駕倒行歸。"]'),
('a77c6426-2112-4da4-9a16-56d1efc87a5b','越州歌二十首  其一八','汪元量','宋','宋诗','song-poetry','','[]','內湖三月賞新荷，錦纜龍舟緩緩拖。',32,'全唐诗/poet.song.245000.json','["內湖三月賞新荷，錦纜龍舟緩緩拖。", "醉裏君王宣樂部，隔花教唱採蓮歌。"]'),
('bebdb3d9-642c-4f21-b8cb-783718124df7','越州歌二十首  其一九','汪元量','宋','宋诗','song-poetry','','[]','年年宮柳好春光，百囀黄鸝繞建章。',32,'全唐诗/poet.song.245000.json','["年年宮柳好春光，百囀黄鸝繞建章。", "冶杏夭桃紅勝錦，牡丹屏裏燕諸王。"]'),
('e34d61ec-ba8f-4cee-9136-9a5c7028f048','越州歌二十首  其二○','汪元量','宋','宋诗','song-poetry','','[]','昔夢吳山列御筵，三千宮女燭金蓮。',32,'全唐诗/poet.song.245000.json','["昔夢吳山列御筵，三千宮女燭金蓮。", "而今莫說夢中夢，夢裏吳山只自憐。"]'),
('c1900d86-9b57-4743-a963-92f7a62cf36f','賈魏公出師','汪元量','宋','宋诗','song-poetry','','[]','奏罷出師表，翻然辭廟堂。',48,'全唐诗/poet.song.245000.json','["奏罷出師表，翻然辭廟堂。", "千艘空寶玉，萬馬下錢塘。", "□許命真主，欺孤欲假王。", "可能清海岱，宗社再昌唐。"]'),
('6ed1a3f2-5542-4e22-92b9-db00f35d7c74','孫殿帥從魏公出師','汪元量','宋','宋诗','song-poetry','','[]','我宋麒麟閣，公當向上名。',48,'全唐诗/poet.song.245000.json','["我宋麒麟閣，公當向上名。", "出師休背主，誓死莫偷生。", "社稷逢今日，英雄在此行。", "忽爲兒女態，一笑欲傾城。"]'),
('35dc7c89-4b57-4cbe-86a6-e2083553f7b1','魯港敗北','汪元量','宋','宋诗','song-poetry','','[]','夜半槌金鼓，南邊事已休。',48,'全唐诗/poet.song.245000.json','["夜半槌金鼓，南邊事已休。", "三軍坑魯港，一舸走揚州。", "星殞天應泣，江喧地欲流。", "欺孤生異志，回首媿巢由。"]'),
('dd1f7d7f-9c51-4a9a-b325-91583d72fcb2','北師駐皋亭山','汪元量','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江上雨初乾，風入端門陣陣酸。',64,'全唐诗/poet.song.245000.json','["錢塘江上雨初乾，風入端門陣陣酸。", "萬馬亂嘶臨警蹕，三宮垂淚濕鈴鸞。", "童兒空想追徐福，癘鬼終朝滅賀蘭。", "苦議和親休練卒，嬋娟剩遣嫁呼韓。"]'),
('fa16c092-6bcd-4492-a0a2-e119caac8ae8','宋宮人分嫁北匠','汪元量','宋','宋诗','song-poetry','','[]','皎皎千嬋娟，盈盈翠紅圍。',192,'全唐诗/poet.song.245000.json','["皎皎千嬋娟，盈盈翠紅圍。", "輦來路迢遞，梳鬟理征衣。", "復采鴛鴦花，綴之連理枝。", "憂愁忽已失，歡樂當自茲。", "君王不重色，安肯留金閨。", "再令出宮掖，相看淚交垂。", "分配老斵輪，强顔相追隨。", "舊恩棄如土，新寵豈所宜。", "誰謂事當爾，苦樂心自知。", "含情理金徽，煩聲亂朱絲。", "一彈丹鳳離，再彈黄鵠飛。", "已恨聽者少，更傷知音稀。", "吞聲不忍哭，寄曲宣餘悲。", "可憐薄命身，萬里榮華衰。", "江南天一涯，流落將安歸。", "向來承恩地，月落夜烏啼。"]'),
('a3ac33dc-797d-4791-876c-04d7746cde38','答同舍杜德機','汪元量','宋','宋诗','song-poetry','','[]','北風吹我上金臺，忍見蛾眉墮馬嵬。',32,'全唐诗/poet.song.245000.json','["北風吹我上金臺，忍見蛾眉墮馬嵬。", "宴罷蟠桃王母去，江南腸斷賀方回。"]'),
('58b503b3-8c84-4906-993d-381ca64ac869','幽州除夜醉歌','汪元量','宋','宋诗','song-poetry','','[]','燕姬壓酒春宵永，列炬摇光拂紅影。',80,'全唐诗/poet.song.245000.json','["燕姬壓酒春宵永，列炬摇光拂紅影。", "銀鴨香烘雲母屏，綺窗繡閣流芳馨。", "脆管聲含蘭氣嬌，鳳釵拖頸烏雲飄。", "錦瑟無端促絃急，纖蛾斂翠翻成泣。", "雕籠啁哳雞鳴早，一笑紅顔鏡中老。"]'),
('8016a8ef-a83e-4554-8b29-cc609b653e92','除夕同舍集飲','汪元量','宋','宋诗','song-poetry','','[]','萬里陰寒淚欲流，暫時歡笑且忘憂。',64,'全唐诗/poet.song.245000.json','["萬里陰寒淚欲流，暫時歡笑且忘憂。", "已呼赤脚來烹雁，更遣蒼頭爲割牛。", "燕伎女來情不惡，魯男子在話難投。", "却憐半夜朝天去，霜瓦差差十二樓。"]'),
('8137feb3-c6bc-4d40-bf79-6d76e02cdd34','山東飛放','汪元量','宋','宋诗','song-poetry','','[]','天子出獵山之東，臂鷹健卒豪且雄。',32,'全唐诗/poet.song.245000.json','["天子出獵山之東，臂鷹健卒豪且雄。", "我欲從之出雲中，坐看萬馬如游龍。"]'),
('61034955-9836-4bc6-9060-4ec238e1a12c','江陵','汪元量','宋','宋诗','song-poetry','','[]','月到荆江上，輕帆莫遠揚。',48,'全唐诗/poet.song.245000.json','["月到荆江上，輕帆莫遠揚。", "水摇龍影動，風送雁聲長。", "北斗回秋柄，南辰耿夜光。", "徘徊舒一嘯，詩興落瀟湘。"]'),
('e6992449-883b-415f-8b52-425d88efe02a','巴陵','汪元量','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','重到巴陵秋正清，岳陽城下繫孤舲。',64,'全唐诗/poet.song.245000.json','["重到巴陵秋正清，岳陽城下繫孤舲。", "江湖萬里水雲闊，天地一凉河漢明。", "月出洞庭魚婢舞，氣蒸雲夢雁奴腥。", "篙工又鼓瀟湘柁，漁笛漁榔上下鳴。"]'),
('d2c9c2d2-a3f1-430b-81c6-d07f158eaf1a','蜀道','汪元量','宋','宋诗','song-poetry','','[]','蜀道難行高接天，秦關勒馬望西川。',32,'全唐诗/poet.song.245000.json','["蜀道難行高接天，秦關勒馬望西川。", "峨眉崒嵂知何處，劍閣崔巍若箇邊。"]'),
('5cc907b7-c9ca-46f1-ab84-c8a791332958','長沙','汪元量','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭過了浪猶高，河伯欣然止怒濤。',64,'全唐诗/poet.song.245000.json','["洞庭過了浪猶高，河伯欣然止怒濤。", "傍岸買魚仍問米，登樓呼酒更持螯。", "湘汀暮雨幽蘭溼，野渡寒風古樹號。", "詩到巴陵吟不得，屈原千古有離騷。"]'),
('2b9a9967-9be6-4b23-aec4-822e162d4d8e','成都','汪元量','宋','宋诗','song-poetry','','[]','錦城滿目是烟花，處處紅樓賣酒家。',64,'全唐诗/poet.song.245000.json','["錦城滿目是烟花，處處紅樓賣酒家。", "坐看浮雲橫玉壘，行觀流水盪金沙。", "巴童棧道騎高馬，蜀卒城門射老鴉。", "見說近來多盜跖，夜深戰鼓不停撾。"]'),
('60876136-1149-4bad-bd43-4113a7f10cad','聞父老說兵','汪元量','宋','宋诗','song-poetry','','[]','昔聞天兵入西蜀，鞞鼓亂撾裂巖谷。',96,'全唐诗/poet.song.245000.json','["昔聞天兵入西蜀，鞞鼓亂撾裂巖谷。", "金鞍戰馬踏雲梯，日射旌旗紅𫂙𫂙。", "黑霧壓城塵漲天，西方殺氣成愁烟。", "釣魚臺畔古戰場，六軍戰血平三川。", "天寒日落愁無色，將軍一劍萬人敵。", "婦女多在官軍中，兵氣不揚長太息。"]'),
('af12db9f-4d76-4c61-97b6-f94a57ff35f8','昝相公席上','汪元量','宋','宋诗','song-poetry','','[]','燕雲遠使棧雲間，便遣郫筒助客歡。',64,'全唐诗/poet.song.245000.json','["燕雲遠使棧雲間，便遣郫筒助客歡。", "閃閃白魚來丙穴，綿綿紫鶴出巴山。", "神仙縹緲艷金屋，城郭繁華號錦官。", "萬里橋西一回首，黑雲遮斷劍門關。"]'),
('bd585e9b-0efe-411a-aaa1-c9a10263a142','歌妓許冬冬携酒郊外小集','汪元量','宋','宋诗','song-poetry','','[]','益州歌妓許冬冬，客裏相逢似燕鴻。',64,'全唐诗/poet.song.245000.json','["益州歌妓許冬冬，客裏相逢似燕鴻。", "醉擁蜀琴抽白雪，舞迴班扇割西風。", "山炰野饌荒山裏，浪蘂浮花古寺中。", "偶爾留連借餘景，出門一笑夕陽紅。"]'),
('68feade4-069d-4196-bdb9-f74ed29efa46','隆州','汪元量','宋','宋诗','song-poetry','','[]','歇馬隆州借夕凉，壺中薄酒似酸湯。',64,'全唐诗/poet.song.245000.json','["歇馬隆州借夕凉，壺中薄酒似酸湯。", "城濠寨屋偏栽柳，市井人家却種桑。", "官逼稅糧多作孽，民窮田土盡拋荒。", "年來士子多差役，隸籍鹽場與錦坊。"]'),
('fe520dc0-7010-447d-ad8d-855ad3beb2a8','彭州','汪元量','宋','宋诗','song-poetry','','[]','我到彭州酒一觴，遺儒相與話淒凉。',64,'全唐诗/poet.song.245000.json','["我到彭州酒一觴，遺儒相與話淒凉。", "渡江九廟歸塵土，出塞三宮坐雪霜。", "岐路茫茫空望眼，興亡滾滾入愁腸。", "此行歷盡艱難處，明日繁華是錦鄉。"]'),
('0762164e-8bdc-42fb-b8e0-93a2e0cebe2a','彭州歌  其一','汪元量','宋','宋诗','song-poetry','','[]','彭州昔號小成都，城市繁華錦不如。',32,'全唐诗/poet.song.245000.json','["彭州昔號小成都，城市繁華錦不如。", "尚有遺儒頭雪白，見人猶自問詩書。"]'),
('fc301ebb-4d11-4c91-8210-d27d252f22cc','彭州歌  其二','汪元量','宋','宋诗','song-poetry','','[]','彭州又曰牡丹鄉，花月人稱小雒陽。',32,'全唐诗/poet.song.245000.json','["彭州又曰牡丹鄉，花月人稱小雒陽。", "自笑我來逢八月，手攀枯榦舉清觴。"]'),
('44333a72-f56c-49cf-acdc-f4f36a6bc343','漢州','汪元量','宋','宋诗','song-poetry','','[]','馬踏巉巖緩著鞭，漢州城外看青天。',64,'全唐诗/poet.song.245000.json','["馬踏巉巖緩著鞭，漢州城外看青天。", "雲橫疊嶂吞殘日，風捲崇岡起曉烟。", "地拔翠峰森似筍，溪明錦石小如錢。", "官郵睡足出門去，信口語言詩未圓。"]'),
('6c234195-0f13-4f42-b1e1-1f010229eda5','綿州','汪元量','宋','宋诗','song-poetry','','[]','綿州八月秋氣深，芙蓉溪上花陰陰。',64,'全唐诗/poet.song.245000.json','["綿州八月秋氣深，芙蓉溪上花陰陰。", "使君喚船復載酒，書生快意仍長吟。", "擊鼓吹笙歡客飲，脫巾露髪看日沈。", "歸來不知其所往，但見月高松樹林。"]'),
('87ca5bf5-0f79-455c-b413-59109c59a32f','永康軍','汪元量','宋','宋诗','song-poetry','','[]','錦城飛馬過青城，無奈風聲更雨聲。',32,'全唐诗/poet.song.245000.json','["錦城飛馬過青城，無奈風聲更雨聲。", "一夜不眠何似者，籌花賭酒到天明。"]'),
('8d5d81d0-1eee-4458-8c32-37c1c40c6464','萬州','汪元量','宋','宋诗','song-poetry','','[]','槎牙鳥道沒人烟，狼虎交橫馬不前。',32,'全唐诗/poet.song.245000.json','["槎牙鳥道沒人烟，狼虎交橫馬不前。", "回首青山藏白跖，萬州城下草連天。"]'),
('235e3980-2773-4115-96ea-642449b1aace','重慶府','汪元量','宋','宋诗','song-poetry','','[]','鐵作篙師鐵作舟，風撞浪湧可無憂。',64,'全唐诗/poet.song.245000.json','["鐵作篙師鐵作舟，風撞浪湧可無憂。", "林間麋鹿遥相望，峽裏蛟龍橫不休。", "目斷弔橋空悄悄，頭昏伏枕自悠悠。", "錦城秋色追隨盡，好處山川更一游。"]'),
('b1710ab2-c423-407d-9387-c2305ee1c9a3','涪州','汪元量','宋','宋诗','song-poetry','','[]','曉立驗檣烏，時聞鳥獸呼。',48,'全唐诗/poet.song.245000.json','["曉立驗檣烏，時聞鳥獸呼。", "斯須風力健，遮莫水程迂。", "赤岸石稠疊，白鹽山獨孤。", "眼前猶有險，不盡更危途。"]'),
('79c44311-ba7d-47d3-be94-51cd5aff4bc4','瀘州','汪元量','宋','宋诗','song-poetry','','[]','復作瀘州去，輕舟疾復徐。',72,'全唐诗/poet.song.245000.json','["復作瀘州去，輕舟疾復徐。", "峽深藏虎豹，谷暗隠樵漁。", "西望青羌遠，南瞻白帝迂。", "晴嵐侵簟枕，寒露溼衣裾。", "野沼荷將盡，山園荔已疏。", "長官相見後，置酒斫鯨魚。"]'),
('3f33fe54-522d-41b7-a504-746729eb8ab9','榮州','汪元量','宋','宋诗','song-poetry','','[]','醉倚高樓上，裁詩得五言。',48,'全唐诗/poet.song.245000.json','["醉倚高樓上，裁詩得五言。", "蠶叢雲羃羃，鳥道月昏昏。", "妓女吹金管，庖丁洗玉盆。", "客癡渾不寐，府主更開樽。"]'),
('f3c9d64b-a47e-4bc9-b1e7-24a8acc82638','戎州  其一','汪元量','宋','宋诗','song-poetry','','[]','豪士家園爲我開，樹頭樹底錦堆堆。',32,'全唐诗/poet.song.245000.json','["豪士家園爲我開，樹頭樹底錦堆堆。", "書生大嚼真快意，不枉戎州走一迴。"]'),
('955b8f5b-c3f8-49ae-a108-fbfe835defcd','戎州  其二','汪元量','宋','宋诗','song-poetry','','[]','錦荔戎州第一奇，大如雞子壓枝垂。',32,'全唐诗/poet.song.245000.json','["錦荔戎州第一奇，大如雞子壓枝垂。", "金刀剪下三千顆，對客從容把酒巵。"]'),
('12325586-c48e-4e44-b62a-af0b42c4979d','戎州  其三','汪元量','宋','宋诗','song-poetry','','[]','害馬勞人事已灰，長安無復使臣來。',32,'全唐诗/poet.song.245000.json','["害馬勞人事已灰，長安無復使臣來。", "滿園蓊蔚千千樹，盡是楊妃死後栽。"]'),
('a917beac-8b1e-46f9-a470-1c209c7c7cb2','戎州  其四','汪元量','宋','宋诗','song-poetry','','[]','錦樹高枝種萬窠，歲收百斛足生涯。',32,'全唐诗/poet.song.245000.json','["錦樹高枝種萬窠，歲收百斛足生涯。", "八錢買得一斤重，魯直詩中特地誇。"]'),
('25838bc9-6a3d-4c6e-977f-5f12400e4bf2','戎州  其五','汪元量','宋','宋诗','song-poetry','','[]','錦殻中間玉一團，樹高數丈實難攀。',32,'全唐诗/poet.song.245000.json','["錦殻中間玉一團，樹高數丈實難攀。", "瀘戎顆顆甜如蜜，夔梓纍纍味薄酸。"]'),
('da828c1a-8e69-4803-b9c3-b0fce4cdca6b','潼州府','汪元量','宋','宋诗','song-poetry','','[]','潼江待我洗吟眸，如此江山是勝遊。',64,'全唐诗/poet.song.245000.json','["潼江待我洗吟眸，如此江山是勝遊。", "紅袖鬬歌纔拍手，綠鬟對舞盡纏頭。", "箜篌急撚風生座，鼙鼓連撾月上樓。", "一夜不眠雞戒曉，又騎鋪馬過綿州。"]'),
('6d4417f2-82de-4f52-a365-f8f4bd509be4','興元府','汪元量','宋','宋诗','song-poetry','','[]','秋風吹我入興元，下馬荒郵倚竹門。',64,'全唐诗/poet.song.245000.json','["秋風吹我入興元，下馬荒郵倚竹門。", "詩句未成雲渡水，酒杯方舉月臨軒。", "山川寂寞非常態，市井蕭條似破村。", "官吏不仁多酷虐，逃民餓死棄兒孫。"]'),
('2cde8814-5984-4796-89f8-8e5206662300','利州','汪元量','宋','宋诗','song-poetry','','[]','雲棧遥遥馬不前，風吹紅樹带青烟。',64,'全唐诗/poet.song.245000.json','["雲棧遥遥馬不前，風吹紅樹带青烟。", "城因兵破慳歌舞，民爲官差失井田。", "巖谷搜羅追獵戶，江湖刻剝及漁船。", "酒邊父老猶能說，五十年前好四川。"]'),
('6b2fa288-970e-4390-8915-01f97626573c','隆慶府','汪元量','宋','宋诗','song-poetry','','[]','雁山突兀插青天，劍閣西來接劍泉。',32,'全唐诗/poet.song.245000.json','["雁山突兀插青天，劍閣西來接劍泉。", "如此江山快人意，滿船載酒下潼川。"]'),
('e4b8e811-f194-411c-8ed9-dfa37855bd7f','閬州','汪元量','宋','宋诗','song-poetry','','[]','閬州城南海棠溪，客子不可無新詩。',64,'全唐诗/poet.song.245000.json','["閬州城南海棠溪，客子不可無新詩。", "正嫌風攪浪花碎，更被雨衝雲葉垂。", "野鷗出沒底心性，山禽飛舞猶威儀。", "江南或問閬州景，錦屏山水天下奇。"]'),
('350cc097-24a8-43d4-ab8f-1f8f1c271736','鳳州','汪元量','宋','宋诗','song-poetry','','[]','鳳州山館有清輝，古木扶疏散陸離。',96,'全唐诗/poet.song.245000.json','["鳳州山館有清輝，古木扶疏散陸離。", "紅尾錦雞鳴古埭，綠頭花鴨盪幽池。", "荷聲策策秋來後，桂影團團月上時。", "病馬嚙荄思故櫪，驚烏繞樹宿何枝。", "三分割據人如夢，滿目興亡客自癡。", "走筆成詩聊紀實，岷峨風土出蹲鴟。"]'),
('0266d253-5cce-42b9-9aad-816a4bbfbe32','鳳州歌  其一','汪元量','宋','宋诗','song-poetry','','[]','鳳州南去是南岐，大散橫盤勢更危。',32,'全唐诗/poet.song.245000.json','["鳳州南去是南岐，大散橫盤勢更危。", "躍馬紫金河畔路，萬株楊柳撒金絲。"]'),
('254799cb-1115-4c4f-a8a1-16f3983b1d3d','鳳州歌  其二','汪元量','宋','宋诗','song-poetry','','[]','去路迢迢入兩當，三千三百到華陽。',32,'全唐诗/poet.song.245000.json','["去路迢迢入兩當，三千三百到華陽。", "黄花川上黄花驛，千百猿聲斷客腸。"]'),
('b4b20cf0-2e42-4d2a-a7f2-0498e073f55d','和人賀楊僕射致政','汪元量','宋','宋诗','song-poetry','','[]','蓮府公卿拜後塵，手持優詔挂朱輪。',64,'全唐诗/poet.song.245000.json','["蓮府公卿拜後塵，手持優詔挂朱輪。", "從軍幕下三千客，聞禮庭中七十人。", "飾帳麗詞推北巷，畫堂清樂掩南鄰。", "豈同王謝山陰會，空敘流杯醉暮春。"]'),
('11baa67e-7585-4e5c-9fe5-d3d44a14dbd0','初庵傅學士歸田里','汪元量','宋','宋诗','song-poetry','','[]','燕臺同看雪花天，別後音書雁不傳。',64,'全唐诗/poet.song.245000.json','["燕臺同看雪花天，別後音書雁不傳。", "紫閣笑談爲職長，彤闈朝謁在班前。", "揮毫屢掃三千字，把酒時呼十四絃。", "聞已挂冠歸故里，尚方宣賜鈔成船。"]'),
('f400c82e-638c-4ee5-9a14-d317d3415fb6','酬方塘趙待制見贈','汪元量','宋','宋诗','song-poetry','','[]','久謂儒冠誤，窮愁方棄書。',48,'全唐诗/poet.song.245000.json','["久謂儒冠誤，窮愁方棄書。", "十年心不展，萬里意何如。", "司馬歸無屋，馮驩出有車。", "吾曹猶未化，爛醉且穹廬。"]'),
('3abccba8-1449-45e3-aa77-5f494f7a8cbf','酬隠者劉桃岡','汪元量','宋','宋诗','song-poetry','','[]','食既彈長鋏，囊懸少錯刀。',72,'全唐诗/poet.song.245000.json','["食既彈長鋏，囊懸少錯刀。", "功名須汝輩，詩酒且吾曹。", "强項貧而樂，揚眉氣自豪。", "北來魚字密，南去雁書高。", "擬折淵明柳，重尋夢得桃。", "明珠忽委贈，價重九方臯。"]'),
('c282e30f-d29b-48c3-a8bb-51d442a1c12c','答開先老子萬一山','汪元量','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山五老，招我此行。',20,'全唐诗/poet.song.245000.json','["廬山五老，招我此行。", "我琴不鼓，無虧無成。"]'),
('8f00b1ce-4362-42c9-8477-da10b5565802','張平章席上','汪元量','宋','宋诗','song-poetry','','[]','兩鬢蕭蕭不耐秋，興來今日謁公侯。',32,'全唐诗/poet.song.245000.json','["兩鬢蕭蕭不耐秋，興來今日謁公侯。", "舞餘燕玉錦纏頭，又著紅靴踢繡毬。"]'),
('77ac6fbd-d002-42fd-bbe3-ef0b23f0bd6c','題王導像','汪元量','宋','宋诗','song-poetry','','[]','秦淮浪白蔣山青，西望神州草木腥。',32,'全唐诗/poet.song.245000.json','["秦淮浪白蔣山青，西望神州草木腥。", "江左夷吾甘半壁，只緣無淚洒新亭。"]'),
('79e2b7d5-32a0-4208-bab2-408660735fd7','浮丘道人招魂歌  其一','汪元量','宋','宋诗','song-poetry','','[]','有客有客浮丘翁，一生能事今日終。',81,'全唐诗/poet.song.245000.json','["有客有客浮丘翁，一生能事今日終。", "齧氈雪窖身不容，寸心耿耿摩蒼空。", "睢陽臨難氣塞充，大呼南八男兒忠。", "我公就義何從容，名垂竹帛生英雄。", "嗚呼一歌兮歌無窮，魂招不來何所從。"]'),
('3f21d0e6-bc70-40ed-8d99-9d8195629a21','浮丘道人招魂歌  其二','汪元量','宋','宋诗','song-poetry','','[]','有母有母死南國，天氣黯淡殺氣黑。',81,'全唐诗/poet.song.245000.json','["有母有母死南國，天氣黯淡殺氣黑。", "忍埋玉骨崖山側，蓼莪劬勞淚沾臆。", "孤兒以忠報罔極，拔舌剖心命何惜。", "地結萇弘血成碧，九泉見母無言責。", "嗚呼二歌兮歌復憶，魂招不來長嘆息。"]'),
('f32bdbbd-49e5-44f9-8b1f-2955771b9421','浮丘道人招魂歌  其三','汪元量','宋','宋诗','song-poetry','','[]','有弟有弟隔風雪，音信不通雁飛絕。',81,'全唐诗/poet.song.245000.json','["有弟有弟隔風雪，音信不通雁飛絕。", "獨處空廬坐縲絏，短衣凍指不能結。", "天生男兒硬如鐵，白刃飛空肢體裂。", "此時與汝成永訣，汝于何處收兄骨。", "嗚呼三歌兮歌聲咽，魂招不來淚流血。"]'),
('795fd775-5fae-446e-89df-76e5518468f7','浮丘道人招魂歌  其四','汪元量','宋','宋诗','song-poetry','','[]','有妹有妹天一方，良人去後逢此殃。',81,'全唐诗/poet.song.245000.json','["有妹有妹天一方，良人去後逢此殃。", "黄塵暗天道路長，男呻女吟不得將。", "汝母已死埋炎荒，汝兄跣足行雪霜。", "萬里相逢淚滂滂，驚定拭淚還悲傷。", "嗚呼四歌兮歌欲狂，魂招不來歸故鄉。"]'),
('3fdd2343-361b-4130-bad7-e5ba0c21aeeb','浮丘道人招魂歌  其五','汪元量','宋','宋诗','song-poetry','','[]','有妻有妻不得顧，饑走荒山汗如雨。',81,'全唐诗/poet.song.245000.json','["有妻有妻不得顧，饑走荒山汗如雨。", "一朝中道逢狼虎，不肯偷生作人婦。", "左掖虞姬右陵母，一劍捐身剛自許。", "天上地下吾與汝，夫爲忠臣妻烈女。", "嗚呼五歌兮歌聲苦，魂招不來在何所。"]'),
('a4500857-b9c7-44c6-9b82-bd72c37afcbf','浮丘道人招魂歌  其六','汪元量','宋','宋诗','song-poetry','','[]','有子有子衣裳單，皮肉凍死傷其寒。',81,'全唐诗/poet.song.245000.json','["有子有子衣裳單，皮肉凍死傷其寒。", "蓬空煨燼不得安，叫怒索飯饑無餐。", "亂離走竄千里山，荆棘蹲坐膚不完。", "失身被繫淚不乾，父聞此語摧心肝。", "嗚呼六歌兮歌欲殘，魂招不來心鼻酸。"]'),
('c75be58d-6f15-47b2-a007-8f0a56287ff5','浮丘道人招魂歌  其七','汪元量','宋','宋诗','song-poetry','','[]','有女有女清且淑，學母曉粧顔如玉。',81,'全唐诗/poet.song.245000.json','["有女有女清且淑，學母曉粧顔如玉。", "憶昔狼狽走空谷，不得還家收骨肉。", "關河喪亂多殺戮，白日驅人夜燒屋。", "一雙白璧委溝瀆，日暮潜行向天哭。", "嗚呼七歌兮歌不足，魂招不來淚盈掬。"]'),
('486b4cac-be20-4aab-97fc-481bd6339ebb','浮丘道人招魂歌  其八','汪元量','宋','宋诗','song-poetry','','[]','有詩有詩吟嘯集，紙上飛蛇歕香汁。',81,'全唐诗/poet.song.245000.json','["有詩有詩吟嘯集，紙上飛蛇歕香汁。", "杜陵寶唾手親拾，滄海月明老珠泣。", "天地長留國風什，鬼神護呵六丁立。", "我公筆勢人莫及，每一呻吟淚痕溼。", "嗚呼八歌兮歌轉急，魂招不來風習習。"]'),
('31ac22ea-2e03-4482-9bf3-06cb52c23922','浮丘道人招魂歌  其九','汪元量','宋','宋诗','song-poetry','','[]','有官有官位卿相，一代儒宗一敬讓。',81,'全唐诗/poet.song.245000.json','["有官有官位卿相，一代儒宗一敬讓。", "家亡國破身漂蕩，鐵漢生擒今北向。", "忠肝義膽不可狀，要與人間留好樣。", "惜哉斯文天已喪，我作哀章淚悽愴。", "嗚呼九歌兮歌始放，魂招不來默惆悵。"]'),
('442bdb94-8706-46f6-9817-00096adb508d','蘇臺懷古','汪元量','宋','宋诗','song-poetry','','[]','靈巖寺古樹森羅，滿目興亡落逝波。',64,'全唐诗/poet.song.245000.json','["靈巖寺古樹森羅，滿目興亡落逝波。", "越相舟中西子去，楚王宮裏北人過。", "歌臺日暖遊麋鹿，禁苑風高走駱駝。", "却羨老僧無一事，自携瓶錫入烟蘿。"]'),
('43e414f6-e861-4353-8651-244b1e977293','題賜硯','汪元量','宋','宋诗','song-poetry','','[]','斧柯片石伴幽閒，堪與遺民共號頑。',32,'全唐诗/poet.song.245000.json','["斧柯片石伴幽閒，堪與遺民共號頑。", "試憶當時承賜事，墨痕如淚盡成斑。"]'),
('0f16394f-e003-4c76-a580-58bea778366d','月夜擬李陵詩傳  其一','汪元量','宋','宋诗','song-poetry','','[]','清時難再得，離別安可留。',72,'全唐诗/poet.song.245000.json','["清時難再得，離別安可留。", "出門望西北，欲往還綢繆。", "俯視長河奔，方舟激中流。", "驚波一何駭，返顧令人憂。", "天風吹枯桑，日暮寒颼颼。", "何當從此別，送子狐白裘。"]'),
('da957b2f-4e61-4c6e-a176-c66b5dc0e196','月夜擬李陵詩傳  其二','汪元量','宋','宋诗','song-poetry','','[]','嘉會不可再，聚散空彷徨。',60,'全唐诗/poet.song.245000.json','["嘉會不可再，聚散空彷徨。", "臨流歌長吟，送子遊遠方。", "悲風來天末，圓月流景光。", "行人駕言邁，令我結中腸。", "豈無一尊酒，與子發慨慷。"]'),
('1c4da904-10a6-4db8-ba33-6407ed5893fe','月夜擬李陵詩傳  其三','汪元量','宋','宋诗','song-poetry','','[]','河梁日將暮，遊子安所從。',60,'全唐诗/poet.song.245000.json','["河梁日將暮，遊子安所從。", "執手古路側，征裾飄長風。", "行行忽已遠，眇若孤飛鴻。", "人生非松喬，代謝自有終。", "長當崇令名，赤心以爲忠。"]'),
('3edbc1f9-dfe2-4349-b1e2-c67be8b4dc41','柴秋堂越上寄詩就韻柬奚秋崖','汪元量','宋','宋诗','song-poetry','','[]','越王臺上我同游，越女樓中君獨留。',64,'全唐诗/poet.song.245000.json','["越王臺上我同游，越女樓中君獨留。", "燕子日長宜把酒，鯉魚風起莫行舟。", "江山有待偉人出，天地不仁前輩休。", "何處如今覓巢許，欲將心事與渠謀。"]'),
('0ccfce6f-b3b2-4b76-b218-36e1b368ca1e','憶湖上','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我憶西湖斷橋路，雨色晴光自朝暮。',48,'全唐诗/poet.song.245000.json','["我憶西湖斷橋路，雨色晴光自朝暮。", "燕去鴻來今幾度，梅花萬里水雲隔。", "日夜思家歸不得，偶然醉歸文姬側。"]'),
('5cd358bd-3650-4dbb-a6ae-59c53e8728de','賈魏公雪中下湖','汪元量','宋','宋诗','song-poetry','','[]','凍木號風雪滿天，平章猶放下湖船。',32,'全唐诗/poet.song.245000.json','["凍木號風雪滿天，平章猶放下湖船。", "獸爐金帳羔兒美，不念襄陽已六年。"]'),
('8cfa6fc7-fff6-4bb9-8322-cbee42549652','西湖舊夢  其一','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南高峰對北高峰，十里荷花九里松。',32,'全唐诗/poet.song.245000.json','["南高峰對北高峰，十里荷花九里松。", "煙雨樓臺僧占了，西湖風月屬吾儂。"]'),
('4da036cd-7cdc-4404-a1d6-6fbf1039427b','西湖舊夢  其二','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','如此湖山正好嬉，遊人船上醉如泥。',32,'全唐诗/poet.song.245000.json','["如此湖山正好嬉，遊人船上醉如泥。", "黄鶑不入垂楊柳，却立海棠花上啼。"]'),
('4174feea-0402-4192-9288-c8fd5710925e','西湖舊夢  其三','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紅橈綠舫盪清波，露脚斜飛濕芰荷。',32,'全唐诗/poet.song.245000.json','["紅橈綠舫盪清波，露脚斜飛濕芰荷。", "回首湧金門外望，裏河猶自沸笙歌。"]'),
('af3f3dd9-cd7e-44d3-a28e-2d681f65b243','西湖舊夢  其四','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','嵯峨雲髻簇金鈿，血色羅裙濕曉煙。',32,'全唐诗/poet.song.245000.json','["嵯峨雲髻簇金鈿，血色羅裙濕曉煙。", "陌上相逢通一笑，第三橋下是奴船。"]'),
('1ba15542-0005-4346-8f4e-4aa95f5c2315','西湖舊夢  其五','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','溶溶漾漾碧粼粼，船去船來不礙人。',32,'全唐诗/poet.song.245000.json','["溶溶漾漾碧粼粼，船去船來不礙人。", "日午中官傳上旨，內家宣賜玉堂春。"]'),
('3156d6d4-e432-4354-b8a9-c0f9d655f67d','西湖舊夢  其六','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月香水影逋梅白，雨色晴光坡柳青。',32,'全唐诗/poet.song.245000.json','["月香水影逋梅白，雨色晴光坡柳青。", "一箇銷金鍋子裏，舞裙歌扇不曾停。"]'),
('01d057f5-573b-4266-b070-a357e73f76e8','西湖舊夢  其七','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帝城官妓出湖邊，盡作軍裝鬬畫船。',32,'全唐诗/poet.song.245000.json','["帝城官妓出湖邊，盡作軍裝鬬畫船。", "奪得錦標權遺喜，金銀關會賞嬋娟。"]'),
('bb5e6020-570c-4da7-bfe5-32f95edc3d22','西湖舊夢  其八','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','王孫挾彈打鴛鴦，紅藕花前世界凉。',32,'全唐诗/poet.song.245000.json','["王孫挾彈打鴛鴦，紅藕花前世界凉。", "揭起蓬窗弄湖水，潜螭雙眼射金光。"]'),
('61c3f7a4-497f-4ac5-99a7-16e8e446dc70','西湖舊夢  其九','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芙蓉照水桂香飄，車馬紛紛度六橋。',32,'全唐诗/poet.song.245000.json','["芙蓉照水桂香飄，車馬紛紛度六橋。", "錦幔籠船人似玉，隔花相對學吹簫。"]'),
('323a0c4a-7967-4b7e-9612-bfde10f57e3c','西湖舊夢  其一○','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六花飛舞似鵝毛，丞相身穿御賜袍。',32,'全唐诗/poet.song.245000.json','["六花飛舞似鵝毛，丞相身穿御賜袍。", "不念長安有貧者，下湖打鼓飲羊羔。"]'),
('5a108e0d-80ec-4455-947a-19e2c869757b','玉局詩','汪元量','宋','宋诗','song-poetry','','[]','聯騎來登卯酉山，老君玉局護闌干。',32,'全唐诗/poet.song.245000.json','["聯騎來登卯酉山，老君玉局護闌干。", "步虛殿上香雲繞，空翠蕭森北斗寒。"]'),
('1706826b-a224-40b8-b506-0356a97def67','昝相公送錦被','汪元量','宋','宋诗','song-poetry','','[]','蜀都府主迎賓客，贈我蜀錦三百尺。',224,'全唐诗/poet.song.245000.json','["蜀都府主迎賓客，贈我蜀錦三百尺。", "美人䔩䔩弄金梭，鴛鴦機上初成疋。", "繁花亂蘂皆同心，艷枿中含杜鵑血。", "玉妃如霜姑射仙，金刀剪破雲霞纈。", "爲我裁成合歡被，細意密縫無線跡。", "道人把玩色相射，銀海光摇淚珠滴。", "却憶故家初破時，繡龍畫雉如砂石。", "綺窗窈窕花離離，紅粧萬鏡嬌無力。", "百幅錦帆風不動，綠濕紅鮮盪春碧。", "紛華過眼一夢如，蜀錦吳綾復何益。", "白茅安用紅錦包，虎皮難以裹羊質。", "只今卷錦還府主，心地了然無得失。", "銅壺漏斷銀缸滅，崑崙影轉初三月。", "道人坐久聞妙香，紙帳蒲團自清絕。"]'),
('55ffa15d-6047-4af4-913f-ec8b389022c5','社牲','汪元量','宋','宋诗','song-poetry','','[]','年登斂牲錢，日吉視牢筴。',48,'全唐诗/poet.song.245000.json','["年登斂牲錢，日吉視牢筴。", "烹庖香滿村，未覺膰脤窄。", "餕餘裹青蒻，籬落笑言啞。", "咄哉陳孺子，乃有天下責。"]'),
('ff89d23e-fa0a-438b-9467-2840c72e486f','寄李鶴田','汪元量','宋','宋诗','song-poetry','','[]','南泉多載夜光還，健步移梅種玉山。',32,'全唐诗/poet.song.245000.json','["南泉多載夜光還，健步移梅種玉山。", "八十二翁猶矍鑠，苦吟不放此心閑。"]'),
('dc4013ef-e284-482e-a16d-a8ed02ed18a6','寄趙青山同舍  其一','汪元量','宋','宋诗','song-poetry','','[]','六館風流不可尋，形骸土木淚痕深。',32,'全唐诗/poet.song.245000.json','["六館風流不可尋，形骸土木淚痕深。", "有時咄咄空書字，俗子寧知我輩心。"]'),
('9c38d51f-6f66-450d-a05f-4d9e557f2bc9','寄趙青山同舍  其二','汪元量','宋','宋诗','song-poetry','','[]','短褐離披紫鳳圖，非揚非墨亦非儒。',32,'全唐诗/poet.song.245000.json','["短褐離披紫鳳圖，非揚非墨亦非儒。", "獨憐後輩欺前輩，自笑今吾即故吾。"]'),
('64620ec0-7087-4c52-a1d2-d5ca937b93dd','寄趙青山同舍  其三','汪元量','宋','宋诗','song-poetry','','[]','聚嘲叢謗腐儒癡，江海漂零酒一巵。',32,'全唐诗/poet.song.245000.json','["聚嘲叢謗腐儒癡，江海漂零酒一巵。", "閑把至音調綠綺，朗吟新句寫烏絲。"]'),
('1f08476b-979a-4915-9cdf-0357e2b919b9','寄趙青山同舍  其四','汪元量','宋','宋诗','song-poetry','','["\u8861\u5c71"]','謝傅東山喜劫棋，劉生南嶽怕聯詩。',32,'全唐诗/poet.song.245000.json','["謝傅東山喜劫棋，劉生南嶽怕聯詩。", "君侯自有通身膽，用舍行藏且順時。"]'),
('9141b271-c66a-4087-b5f3-a6ebf147ec67','唐律寄呈父鳳山提舉  其一','汪元量','宋','宋诗','song-poetry','','[]','西興渡口亂啼鴉，錦纜牽江目力賒。',64,'全唐诗/poet.song.245000.json','["西興渡口亂啼鴉，錦纜牽江目力賒。", "六館衣冠淪道路，三宮珠玉走風砂。", "山川不盡心難老，歲月憂煎髪漸華。", "行到湘南歸不得，倚門應是望天涯。"]'),
('c2c07e30-8133-4c2c-b671-6eae303f27a4','唐律寄呈父鳳山提舉  其二','汪元量','宋','宋诗','song-poetry','','[]','黄帽催人急放舟，荻花楓葉共颼颼。',64,'全唐诗/poet.song.245000.json','["黄帽催人急放舟，荻花楓葉共颼颼。", "天公作惡雲翻手，河伯爲妖風打頭。", "接翅野鴉圍古堞，斷行孤雁落中州。", "吳山只隔淮山路，江北江南處處愁。"]'),
('0e56b3fd-d00e-4fd9-bb73-4613ea85f8bc','唐律寄呈父鳳山提舉  其三','汪元量','宋','宋诗','song-poetry','','[]','燕山只在亂雲邊，過了黄河便豁然。',64,'全唐诗/poet.song.245000.json','["燕山只在亂雲邊，過了黄河便豁然。", "鼠帽蒙頭車上坐，貂裘擁鼻草間眠。", "秋砧擣落千營月，曉寨炊殘萬竈煙。", "說與奚奴休笑我，詩人要看好山川。"]'),
('708f1297-ac5c-4c1a-9e07-6e306df85bf9','唐律寄呈父鳳山提舉  其四','汪元量','宋','宋诗','song-poetry','','[]','錦帆浩蕩濕龍鸞，樂指三千粉淚寒。',64,'全唐诗/poet.song.245000.json','["錦帆浩蕩濕龍鸞，樂指三千粉淚寒。", "萬里遠行看日近，一人不殺見天寬。", "玉關屢沐軍羅拜，金殿時蒙上問安。", "宴罷御香携滿袖，醉歸環珮月中看。"]'),
('5de71e91-991f-4853-8e17-32fc72be2ce4','唐律寄呈父鳳山提舉  其五','汪元量','宋','宋诗','song-poetry','','[]','昔年去國大蒼黄，同舍諸生半死亡。',64,'全唐诗/poet.song.245000.json','["昔年去國大蒼黄，同舍諸生半死亡。", "春別浙江花似霧，秋行磧地草如霜。", "時沽市酒借餘景，屢宿官郵悲故鄉。", "滿目故人皆厚祿，吾儕添得兩奚囊。"]'),
('d813c28c-9f07-4275-b42a-311f09f73119','唐律寄呈父鳳山提舉  其六','汪元量','宋','宋诗','song-poetry','','[]','抱琴挾策馬蕭蕭，北望燕雲道路遥。',64,'全唐诗/poet.song.245000.json','["抱琴挾策馬蕭蕭，北望燕雲道路遥。", "紫塞曉行聞雁叫，黄河夜渡見魚跳。", "周回四蜀愁雙劍，浩蕩三湘夢六橋。", "踏遍乾坤猶是客，小山叢桂不能招。"]'),
('21f2162e-94a8-4fb1-8141-47755a290bf6','唐律寄呈父鳳山提舉  其七','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夜來夢裏到吾廬，夢破潸然淚似珠。',64,'全唐诗/poet.song.245000.json','["夜來夢裏到吾廬，夢破潸然淚似珠。", "吳女北游簪素柰，湘娥南望泣蒼梧。", "風吹遠浦秋鴻杳，月出空山夜鶴孤。", "忽憶西湖梅與柳，夢隨雲水度西湖。"]'),
('0e467b29-8c62-401d-968b-2bb5d3eb1b42','唐律寄呈父鳳山提舉  其八','汪元量','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽諸峰處處嘉，麻鞋竹杖躡青霞。',64,'全唐诗/poet.song.245000.json','["南嶽諸峰處處嘉，麻鞋竹杖躡青霞。", "山前已見九杈□，洞裏不逢三朵花。", "巖瀑垂垂騰曉蜃，野田渺渺落寒鴉。", "衡陽鼓角風悲咽，游子斯時正憶家。"]'),
('e451271d-252c-404e-848b-d51e902887ce','唐律寄呈父鳳山提舉  其九','汪元量','宋','宋诗','song-poetry','','[]','愁來不可更禁當，望鬼門關斷盡腸。',64,'全唐诗/poet.song.245000.json','["愁來不可更禁當，望鬼門關斷盡腸。", "無處告訴只欲死，有時顛倒忽成狂。", "三湘風雨失舟檝，萬里路岐多雪霜。", "遥憶武林社中友，下湖簫鼓醉紅裝。"]'),
('5710e9e6-12ae-4bb1-b9d3-0a1e3217a7d6','唐律寄呈父鳳山提舉  其一○','汪元量','宋','宋诗','song-poetry','','[]','自笑儒衣世法疏，窮愁何日得伸舒。',64,'全唐诗/poet.song.245000.json','["自笑儒衣世法疏，窮愁何日得伸舒。", "一從挾策來燕地，幾擬陳情乞鑑湖。", "風雨凄凄鴻雁瘦，雪霜凜凜鶺鴒孤。", "湘江樓上無憀甚，不見吳山似畫圖。"]'),
('71252db7-deda-49ec-8d51-bcd4efef4ab3','衡山道中寄平遠趙宣慰','汪元量','宋','宋诗','song-poetry','','["\u8861\u5c71"]','回雁峰前問訊，楚江幾度蘭香。',28,'全唐诗/poet.song.245000.json','["回雁峰前問訊，楚江幾度蘭香。", "望美人兮何許，水雲隔斷瀟湘。"]'),
('dd3e9a1f-738c-4d7a-aa95-11aafb9e9ceb','月夜聽琴','汪元量','宋','宋诗','song-poetry','','[]','如此良夜，秋空月圓。',20,'全唐诗/poet.song.245000.json','["如此良夜，秋空月圓。", "君彈山鬼，我拊水仙。"]'),
('385b0210-9723-4266-9263-2ec9a538ba46','聽徐雪江琴','汪元量','宋','宋诗','song-poetry','','[]','徐卿寒夜彈玉琴，凍雲妬月波澄陰。',128,'全唐诗/poet.song.245000.json','["徐卿寒夜彈玉琴，凍雲妬月波澄陰。", "海上神峰削幽翠，十二樓前玉妃墜。", "湘娥素女相對泣，翠竹蒼梧淚痕濕。", "幽蘭不香蕙花死，千愁萬怨青楓裏。", "風敲葉脫雨如嘯，百鳥喧啾孤鳳叫。", "老龍吐珠赤灑灑，山鬼摇𣟴走堂下。", "徐卿徐卿且停手，呼兒割雞酌春酒。", "曲高調古人不識，側耳西樓咽箏笛。"]'),
('c29f6d9c-c0cf-4aeb-b0c9-dc67f6269f6b','昝舍人錦江泛舟','汪元量','宋','宋诗','song-poetry','','[]','舍人與客放船開，網得鯨魚餉酒杯。',32,'全唐诗/poet.song.245000.json','["舍人與客放船開，網得鯨魚餉酒杯。", "西川錦雀甜如蜜，錄事相分二百枚。"]'),
('81e27d8c-cfc3-4eae-960d-f5a2494dba9e','昝元帥相拉浣花溪泛舟','汪元量','宋','宋诗','song-poetry','','[]','行都元帥千蹄馬，腰佩角弓箭盈把。',96,'全唐诗/poet.song.245000.json','["行都元帥千蹄馬，腰佩角弓箭盈把。", "浣花溪頭具小舟，擊鼓吹簫行酒斝。", "舞腰嬝娜錦纏頭，風吹金縷隨東流。", "公孫弟子背面笑，拔劍一擊蛟龍愁。", "萬里橋西有茅屋，杜子當年來卜築。", "湘江一醉不復歸，四松寂寞擎寒玉。"]'),
('4e9bc317-3cd3-4777-a1f5-ff227871fa20','麻姑仙壇歌','汪元量','宋','宋诗','song-poetry','','[]','麻姑飄飄出煙霧，紅尾鳳飛騎不住。',128,'全唐诗/poet.song.245000.json','["麻姑飄飄出煙霧，紅尾鳳飛騎不住。", "青城山高風露寒，珮環掛著山花樹。", "花霧濛濛香濕衣，一點柔紅瀉香露。", "群仙行酒擘麒麟，玉盌金盤間犀筯。", "瓊璈鐵笛含氤氳，二十三絃語幽素。", "瓊臺醼罷醉不歸，月出崑崙天未曙。", "青衣結束金絲蘂，鶴扇雙行引歸路。", "白雲疊疊水潺潺，神仙窟宅知何處。"]'),
('6da5441e-778b-4f51-8e06-0db8b8e21a85','蠶叢祠','汪元量','宋','宋诗','song-poetry','','[]','西蜀風煙天一方，蠶叢古廟枕斜陽。',32,'全唐诗/poet.song.245000.json','["西蜀風煙天一方，蠶叢古廟枕斜陽。", "茫然開國人天主，彷彿鴻荒盤古王。"]'),
('b8ec8e47-7502-436e-afae-43dab8a256d3','神女祠','汪元量','宋','宋诗','song-poetry','','[]','野廟凄凉向峽中，斷崖無路一從容。',32,'全唐诗/poet.song.245000.json','["野廟凄凉向峽中，斷崖無路一從容。", "楚王神女知何在，雲鎖巫山十二峰。"]'),
('909f5367-5803-4c7c-806c-e5eaf1046dff','湘夫人祠','汪元量','宋','宋诗','song-poetry','','[]','舟維古渡小從容，二女含嚬媚晚風。',64,'全唐诗/poet.song.245000.json','["舟維古渡小從容，二女含嚬媚晚風。", "野廟半間蒙薜荔，湘江兩岸泣芙蓉。", "玉臺有鏡蝌銘古，錦瑟無絃雁柱空。", "行近祠南默惆悵，倚筇江上數青峰。"]'),
('2e04315e-0ebe-49d5-a855-e5b88f8796b9','明皇廟','汪元量','宋','宋诗','song-poetry','','[]','三郎幸蜀大琅璫，夜雨聞鈴欲斷腸。',32,'全唐诗/poet.song.245000.json','["三郎幸蜀大琅璫，夜雨聞鈴欲斷腸。", "遺廟至今香火閙，女巫調笑舞霓裳。"]'),
('a2460d84-cb64-4dba-9e9e-b67e37036abc','錦江蜀先主廟','汪元量','宋','宋诗','song-poetry','','[]','國破人何在，宮名喜尚存。',48,'全唐诗/poet.song.245000.json','["國破人何在，宮名喜尚存。", "雖云蜀先主，猶是漢諸孫。", "吳魏不相下，關張豈少恩。", "崩年在三峽，遺恨滿乾坤。"]'),
('dbfae46a-e060-4425-b45b-5829cdf7cdc9','後主廟','汪元量','宋','宋诗','song-poetry','','[]','漢賊不兩立，英雄恨不平。',48,'全唐诗/poet.song.245000.json','["漢賊不兩立，英雄恨不平。", "孔明勞已死，仲達走還生。", "雙劍鷹鸇急，三秦虎豹橫。", "東南無霸氣，恢復恐難行。"]'),
('135306dc-2712-49a4-8cef-962c7ae7ec47','忠武侯廟','汪元量','宋','宋诗','song-poetry','','[]','夔門春水拍天流，人日傾城踏磧游。',32,'全唐诗/poet.song.245000.json','["夔門春水拍天流，人日傾城踏磧游。", "古廟蟲蛇穿畫壁，竹風溪雨共啾啾。"]'),
('c5c4d310-f40a-40df-bd7e-43778ffa8e46','蜀相廟','汪元量','宋','宋诗','song-poetry','','[]','我謁武侯祠，陰廊草凄凄。',186,'全唐诗/poet.song.245000.json','["我謁武侯祠，陰廊草凄凄。", "當時南陽結廬學龍卧，深山大澤無人知。", "胡爲蜀先主，三顧前致辭。", "欲煩恢復天下計，先生籌策天下奇。", "浩然出山來，凜凜虎豹姿。", "乘時既得人，上曰真吾師。", "已曉關與張，二子不復疑。", "孤有孔明在軍中，如龍有水相因依。", "曆數既有歸，破賊當自茲。", "可憐復漢社稷心未已，當時三峽圖壘空巍巍。", "先生有才過曹丕，中原恢復未可知。", "惜哉軍務勞，一心死無私。", "出師一表如皎日，千古萬古鴻名垂。"]'),
('d7943a11-b686-4e57-9129-367183637024','嘉定府','汪元量','宋','宋诗','song-poetry','','[]','郡樓著眼蜀天寬，分得巴江水一灣。',32,'全唐诗/poet.song.245000.json','["郡樓著眼蜀天寬，分得巴江水一灣。", "大小峨眉相對立，梨花山接海棠山。"]'),
('31f5e92c-6481-4eab-a362-1837daf97aa0','函谷關','汪元量','宋','宋诗','song-poetry','','[]','田文夜半至函關，雞未鳴時去路難。',32,'全唐诗/poet.song.245000.json','["田文夜半至函關，雞未鳴時去路難。", "不是三千珠履客，如何秦地得生還。"]'),
('3f3790bc-c7c7-46c4-9572-e0d6dbca9a16','南嶽道中  其一','汪元量','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽陰陰松道凉，又騎站馬望荆襄。',64,'全唐诗/poet.song.245000.json','["南嶽陰陰松道凉，又騎站馬望荆襄。", "山中老柏滴寒翠，江上危峰撐夕陽。", "昔往不堪經灧澦，此行重得看瀟湘。", "三宮萬里知安否，何日檀欒把壽觴。"]'),
('17efe747-fa17-42e4-9f80-5984e81a62d4','南嶽道中  其二','汪元量','宋','宋诗','song-poetry','','["\u8861\u5c71"]','夜來大醉別衡陽，今日長吟下楚湘。',64,'全唐诗/poet.song.245000.json','["夜來大醉別衡陽，今日長吟下楚湘。", "翠藻青苹魚市井，白蘋紅蓼雁家鄉。", "江雲起處濛濛濕，山雨來時陳陳凉。", "欹枕不禁肝肺熱，汪然流涕惜興亡。"]'),
('2841f5d0-d2fa-41cd-9882-3ef4bb14264e','舊內曲水池','汪元量','宋','宋诗','song-poetry','','[]','錦溝引水入觴池，兩兩金船上下馳。',64,'全唐诗/poet.song.245000.json','["錦溝引水入觴池，兩兩金船上下馳。", "春季夫人扶輦疾，玉堂學士带花遲。", "當時行樂雖然秘，此日遺蹤自可悲。", "回首支郎新棟宇，浮屠千尺白差差。"]'),
('fe608baf-22b8-413e-89f2-d7cc2f70dc7c','幽州城南江鄉園','汪元量','宋','宋诗','song-poetry','','[]','幽州城南花滿溪，秋千摇颺高復低。',48,'全唐诗/poet.song.245000.json','["幽州城南花滿溪，秋千摇颺高復低。", "吹笙擊鼓園之西，金鞍馬踏芳草堤。", "花娘滿眼歌聲齊，今日爛醉歸去兮。"]'),
('03e5bd4e-228b-4d3c-b26b-ed8f671a3fb8','吳山','汪元量','宋','宋诗','song-poetry','','[]','海枯龍去雨淋淋，羯鼓諠譁山禁林。',64,'全唐诗/poet.song.245000.json','["海枯龍去雨淋淋，羯鼓諠譁山禁林。", "虎士墮弢兵力倦，鷄人罷箭漏聲沈。", "鶑摇御柳春猶閙，燕蹴宮花霧轉深。", "腸斷木綿庵裏客，可憐郿塢築黄金。"]'),
('bf064d38-6c6c-45aa-bf52-c94ebd7d5a91','青城山','汪元量','宋','宋诗','song-poetry','','[]','敕使穿雲破濕苔，水邊坐石更行杯。',64,'全唐诗/poet.song.245000.json','["敕使穿雲破濕苔，水邊坐石更行杯。", "翩翩野鶴飛如舞，冉冉巖花笑不來。", "亂木交柯盤聖井，數峰削玉並仙臺。", "平明絕頂窮幽討，更上青城望一回。"]'),
('5fc2fea9-fe82-4d5f-a95d-d31c180f14e8','黄州江下','汪元量','宋','宋诗','song-poetry','','[]','黄州渡口，赤壁磯頭。',20,'全唐诗/poet.song.245000.json','["黄州渡口，赤壁磯頭。", "冷風凄雨，一葉扁舟。"]'),
('f018a9cc-29b1-4424-8dd9-d707058a360e','巴江','汪元量','宋','宋诗','song-poetry','','[]','巴□鼓櫂興悠悠，野鹿銜花出峽頭。',32,'全唐诗/poet.song.245000.json','["巴□鼓櫂興悠悠，野鹿銜花出峽頭。", "網得巨魚堪切膾，携觴重上荔枝樓。"]'),
('24680234-eaa8-4df0-b002-7c92434df048','廬山三疊泉','汪元量','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','唐不過李仙，宋不過蘇子。',24,'全唐诗/poet.song.245000.json','["唐不過李仙，宋不過蘇子。", "此泉來高處，亦復聊爾耳。"]'),
('853c59f0-a5a6-4d29-be9f-79b7b11a05b5','藥市  其一','汪元量','宋','宋诗','song-poetry','','[]','成都五月，家家列藥於市，以爲盛事。',17,'全唐诗/poet.song.245000.json','["成都五月，家家列藥於市，以爲盛事。"]'),
('ba6991d0-6db4-4732-9e51-3a450eb68864','藥市  其二','汪元量','宋','宋诗','song-poetry','','[]','蜀鄉人是大醫王，一道長街盡藥香。',32,'全唐诗/poet.song.245000.json','["蜀鄉人是大醫王，一道長街盡藥香。", "天下蒼生正狼狽，願分良劑救膏肓。"]'),
('dec0f852-6013-4733-8251-720f7d6c6314','蜀主芙蓉城','汪元量','宋','宋诗','song-poetry','','[]','芙蓉城上草萋萋，吊古徘徊日欲西。',32,'全唐诗/poet.song.245000.json','["芙蓉城上草萋萋，吊古徘徊日欲西。", "帝子不來花蘂去，荒宮無主亂鴉啼。"]'),
('cf2a426a-bea4-4816-8ab3-896efe76b7c3','牡丹平','汪元量','宋','宋诗','song-poetry','','[]','長平山上紫雲封，蜀老相傳隠者宮。',32,'全唐诗/poet.song.245000.json','["長平山上紫雲封，蜀老相傳隠者宮。", "高樹蔽天三十里，開花十丈舞春風。"]'),
('7a7ba598-068f-45f5-8afa-e8d0fad3d90d','百花潭','汪元量','宋','宋诗','song-poetry','','[]','萬里揚鞭到益州，旌旗小隊錦江頭。',32,'全唐诗/poet.song.245000.json','["萬里揚鞭到益州，旌旗小隊錦江頭。", "紅船載酒環歌女，摇蕩百花潭水秋。"]'),
('08c9ca91-cbb3-40a7-9522-f757adc1cb38','蠶市','汪元量','宋','宋诗','song-poetry','','[]','成都美女白如霜，結伴携筐去采桑。',32,'全唐诗/poet.song.245000.json','["成都美女白如霜，結伴携筐去采桑。", "一歲蠶苗凡七出，寸絲那得做衣裳。"]'),
('e3637de0-0ff1-499b-8964-1f3845e82e7c','廢苑見牡丹黄色者','汪元量','宋','宋诗','song-poetry','','[]','西園兵後草茫茫，亭北猶存御愛黄。',32,'全唐诗/poet.song.245000.json','["西園兵後草茫茫，亭北猶存御愛黄。", "晴日暖風生百媚，不知作意爲誰香。"]'),
('b8209712-1c91-4fba-ab07-b3b0d86efab9','慈元殿賜牡丹','汪元量','宋','宋诗','song-poetry','','[]','九重羯鼓聲動地，萬年枝上回春意。',64,'全唐诗/poet.song.245000.json','["九重羯鼓聲動地，萬年枝上回春意。", "天遣姮娥散一枝，一枝先到山人家。", "焚香再拜臯國色，雨露沾濡知帝力。", "我願人間春不老，長對此花顔色好。"]'),
('395f3aea-5e18-41f1-ad9f-1833c0661ba7','昌州海棠有香  其一','汪元量','宋','宋诗','song-poetry','','[]','我到昌州看海棠，恰逢時節近重陽。',32,'全唐诗/poet.song.245000.json','["我到昌州看海棠，恰逢時節近重陽。", "人言好種亦難得，只有州衙一樹香。"]'),
('84771c8c-1f92-4f67-be61-01929133755c','昌州海棠有香  其二','汪元量','宋','宋诗','song-poetry','','[]','香霏堂上樹婆娑，不見嫣然亦可嘉。',64,'全唐诗/poet.song.245000.json','["香霏堂上樹婆娑，不見嫣然亦可嘉。", "且向秋風一盃酒，枝頭的的兩三花。", "夜夢花仙索我詩，他山別種世間稀。", "一年四季花如錦，莫把嬌姿比貴妃。"]'),
('3ec1b5b8-42f6-4669-95a4-9b86c44c3058','錦城秋暮海棠','汪元量','宋','宋诗','song-poetry','','[]','錦城海棠妙無比，秋光染出胭脂蘂。',272,'全唐诗/poet.song.245000.json','["錦城海棠妙無比，秋光染出胭脂蘂。", "日照殷紅如血鮮，箭砂粧粒真珠子。", "玉環著酒睡初覺，臉薄粉香淚如洗。", "絳紗穿露水晶圓，笑殺荷花守紅死。", "蜀鄉海棠根本別，有色有香成二美。", "春花開殘秋復花，簸弄東君權不已。", "錦袍公子汗血駒，賓客諠譁間朱紫。", "有酒如池肉如山，銀燭千條照羅綺。", "蕭娘十八青絲髪，手把金鍾歌皓齒。", "神仙艷骨世所無，歌聲直入青雲裏。", "江南倦客慘不樂，鳴笛哀箏亂人耳。", "干戈滿地行路難，屏裏吳山數千里。", "遥憐花國化青蕪，浪蘂浮花敢欣喜。", "草堂無詩花無德，竊號花仙寧不耻。", "春花撩亂亦可憐，秋花爛熳何爲爾。", "花前妙舞曲未終，紅雪紛紛落流水。", "薄命佳人只土塵，拋盃拔劍長歌起。"]'),
('79368e0b-bfee-436b-876d-6104e85fff8e','九月九日賞紅葉  其一','汪元量','宋','宋诗','song-poetry','','[]','天平山木似花開，青女裁成錦綉堆。',32,'全唐诗/poet.song.245000.json','["天平山木似花開，青女裁成錦綉堆。", "暫借秋光作春色，白衣解遣麴生來。"]'),
('514fc0e1-8708-4b23-8e47-e23f744cecb4','九月九日賞紅葉  其二','汪元量','宋','宋诗','song-poetry','','[]','鳳凰山上少人家，紅葉漫山映落霞。',32,'全唐诗/poet.song.245000.json','["鳳凰山上少人家，紅葉漫山映落霞。", "却笑陶潜歸栗里，東籬寂寞對黄花。"]'),
('55552a89-5598-414b-b0c7-61765a1c809d','雲安聞鵑','汪元量','宋','宋诗','song-poetry','','[]','雲安風景愚能說，蒼峽風掀浪如雪。',96,'全唐诗/poet.song.245000.json','["雲安風景愚能說，蒼峽風掀浪如雪。", "杜鵑叫得口流血，染遍山花歸不得。", "臣甫再拜哦新詩，詩成甫也成愁絕。", "都人重是古帝魂，敬重此鳥心不輟。", "不知此鳥知不知，四時叫得巴山裂。", "却憶群姬左右趨，三十六宮醉花月。"]'),
('547834ac-72a9-438a-82dc-d1cf610d0e32','小桃源入三巖觀魚','汪元量','宋','宋诗','song-poetry','','[]','眉州城外小桃源，行入三巖澗水喧。',32,'全唐诗/poet.song.245000.json','["眉州城外小桃源，行入三巖澗水喧。", "人近碧潭纔撫掌，喚魚出洞跳龍門。"]'),
('cd53a919-9102-4e79-a216-ebcda4e78259','永安宮','汪元量','宋','宋诗','song-poetry','','[]','蜀主遺宮有古槐，頹牆古木鳥喈喈。',64,'全唐诗/poet.song.245000.json','["蜀主遺宮有古槐，頹牆古木鳥喈喈。", "金輿罷幸荒金屋，玉仗休班廢玉階。", "三峽浪舂紅日碎，兩崖風振黑雲霾。", "孔明圖壘仍登覽，野寺殘僧拾墮柴。"]'),
('5f441403-2b81-48a7-af94-3d6f2484ed56','眉州借景亭','汪元量','宋','宋诗','song-poetry','','[]','巍亭借景引壺觴，元祐詩人翰墨香。',96,'全唐诗/poet.song.245000.json','["巍亭借景引壺觴，元祐詩人翰墨香。", "蒼峽雷霆龍意氣，碧崖煙雨豹文章。", "隔鄰修竹娟娟靜，夾道枯桑冉冉黄。", "水泛簾櫳簷影倒，風吹城堞角聲長。", "巴童結束歌仍俊，蜀女腰肢舞亦狂。", "千古相望翁季在，眉山草木有輝光。"]'),
('b0669d8b-d3dc-423b-bf7e-f70b11ff3503','夔門','汪元量','宋','宋诗','song-poetry','','[]','赤甲山連白帝山，三巴三峽百牢關。',32,'全唐诗/poet.song.245000.json','["赤甲山連白帝山，三巴三峽百牢關。", "孤舟行客愁無那，十二峰前十二灘。"]'),
('c8abe316-fc89-4aa5-b9be-b6d297a113aa','夔門驛','汪元量','宋','宋诗','song-poetry','','[]','宿酲未解據胡床，亭午披衣望麝香。',64,'全唐诗/poet.song.245000.json','["宿酲未解據胡床，亭午披衣望麝香。", "三峽夜來天似水，百蠻秋後月如霜。", "洲前橘柚垂垂實，石上藤蘿細細長。", "又欲拏舟過灩澦，黄牛白狗接高唐。"]'),
('ef13a494-c16c-4a1a-b340-469a8fe3bc0b','草堂  其一','汪元量','宋','宋诗','song-poetry','','[]','子美西來築此堂，浣花春水共凄凉。',64,'全唐诗/poet.song.245000.json','["子美西來築此堂，浣花春水共凄凉。", "鳴鳩乳燕歸何處，野草閑花護短牆。", "英雄去矣柴門閉，鄰里傷哉竹徑荒。", "安得山缾盛乳酒，送分漁父濯滄浪。"]'),
('3ffa4bde-2644-48b0-b851-ab8f91a74c96','草堂  其二','汪元量','宋','宋诗','song-poetry','','[]','白髪遨遊梓閬間，中原戎馬未平安。',64,'全唐诗/poet.song.245000.json','["白髪遨遊梓閬間，中原戎馬未平安。", "粗飯濁醪常欠缺，老妻稚子半饑寒。", "扁舟出峽風濤壯，短褐行湘天地寬。", "僑寓耒陽牛酒飽，不知曾憶使君灘。"]'),
('4b86e8df-a32d-498d-8a0a-59e7b53cd7d4','劍門','汪元量','宋','宋诗','song-poetry','','[]','劍門崔嵬若相抗，雲棧縈迴千百丈。',64,'全唐诗/poet.song.245000.json','["劍門崔嵬若相抗，雲棧縈迴千百丈。", "石角鉤連皆北向，失勢一落心膽喪。", "側身西望不可傍，猛虎毒蛇相下上。", "安得朱亥袖椎來，爲我碎打雙疊嶂。"]'),
('a3306ffd-2498-4b14-8826-dcad633c754e','琴臺','汪元量','宋','宋诗','song-poetry','','[]','文園多病厭文君，恨入金徽不忍聞。',32,'全唐诗/poet.song.245000.json','["文園多病厭文君，恨入金徽不忍聞。", "寂寞高臺留古跡，來牛去馬自成羣。"]'),
('97c937b1-716e-4458-9323-3b2dffed293e','嚴鄭公故宅','汪元量','宋','宋诗','song-poetry','','[]','蜀山突兀接青天，鄭公故宅城相連。',64,'全唐诗/poet.song.245000.json','["蜀山突兀接青天，鄭公故宅城相連。", "深深古木哀黄鳥，漠漠荒煙哭杜鵑。", "舞罷遺鈿流水外，戰餘折戟落花前。", "將軍好武通文墨，割據操心未必然。"]'),
('94a39427-a1b8-49dd-bbd5-86158acc2bd5','花蕊夫人故宅  其一','汪元量','宋','宋诗','song-poetry','','[]','千古風流一夢中，江山閲盡幾英雄。',32,'全唐诗/poet.song.245000.json','["千古風流一夢中，江山閲盡幾英雄。", "芙蓉城裏家何在，花蘂夫人宅已空。"]'),
('66448c2b-bbbe-4f30-a97f-3a324c77e5bc','花蕊夫人故宅  其二','汪元量','宋','宋诗','song-poetry','','[]','宅前宅後好青山，零落重門半掩關。',32,'全唐诗/poet.song.245000.json','["宅前宅後好青山，零落重門半掩關。", "玉貌久歸天上去，宮詞百首落人間。"]'),
('299946d0-d949-4bcc-a2e2-d43ba715fb16','重訪草堂','汪元量','宋','宋诗','song-poetry','','[]','放櫂花谿去，重來訪草堂。',144,'全唐诗/poet.song.245000.json','["放櫂花谿去，重來訪草堂。", "菰蒲依靜渚，楊柳遶回塘。", "野塹棨高下，山牆竹短長。", "槁梧含古色，瘦菊減清香。", "鼙鼓檛三疊，旌旗列兩行。", "花娘紛舞袖，座客競飛觴。", "醤蘸生葱白，虀澆熟韭黄。", "洪爐催捲餠，匕首割燒羊。", "大笑諸公醉，高談小子狂。", "城關猶未掩，冠蓋已飛揚。", "鳥語青松裏，人行錦樹傍。", "杜陵輕出峽，千古隔瀟湘。"]'),
('acb934b6-139d-446d-b3c9-61c4db37ed94','忠州荔枝樓小憩','汪元量','宋','宋诗','song-poetry','','[]','竟日揚鞭不暫閑，畏途疊疊是青山。',32,'全唐诗/poet.song.245000.json','["竟日揚鞭不暫閑，畏途疊疊是青山。", "西風吹落忠州去，錦繡窠中屋萬間。"]'),
('3fb4eb63-94ba-44de-90bc-eb2dee0957a2','光相寺','汪元量','宋','宋诗','song-poetry','','[]','峨眉縣西四十里，峭壁懸崖削寒翠。',384,'全唐诗/poet.song.245000.json','["峨眉縣西四十里，峭壁懸崖削寒翠。", "崎嶇棧道動摇摇，矮石支撐同贔屭。", "忽窺萬仞黑無底，下有龍淵七十二。", "攀捫步步足難移，大盤小盤八十四。", "行行更入娑羅平，側立長嗟心膽碎。", "洗脚溪頭登土峰，板屋數間光相寺。", "寺中蕭然無個僧，普賢小殿生陰氣。", "天仙橋上光明巖，銀色光中世界異。", "須臾風雨洗天來，兜羅綿雲塞天地。", "虛空現出大圓光，五色暈中瞻大士。", "日暮雲收山寂然，乙夜燈分百千計。", "別有草庵三四僧，花木滿軒頗清致。", "有時雲起自雷巖，兩道金光出巖際。", "有時雲散光獨明，猶見光中回象轡。", "僧云又有清現光，白日無雲光更麗。", "奇花異草吹香風，怪獸珍禽左右至。", "善財童子何許來，五十三參見真諦。", "神通變化無了時，如幻如夢復如戲。", "胡爲狡獪弄精魂，機事機心極無謂。", "儒生持此問山僧，僧曰如是觀如是。", "若言有相更有光，靈化千千誠小技。", "何如無光復無相，湛寂名爲第一義。", "菩薩空中數點頭，收斂圓光無一事。", "雪山萬點白差差，初日照之光毳毳。"]'),
('b5a14812-cfa1-4f0d-a69a-d5cb67cac4cf','峽邊山寺','汪元量','宋','宋诗','song-poetry','','[]','寺近陰崖多霧雨，峽邊靈竇忽風雷。',32,'全唐诗/poet.song.245000.json','["寺近陰崖多霧雨，峽邊靈竇忽風雷。", "松間白足携詩板，石上蒼頭把酒杯。"]'),
('761334ee-9d32-4c3b-9b01-79847a446ce2','居擬蘇武  其一','汪元量','宋','宋诗','song-poetry','','[]','棠棣本同根，芳葩亦相聯。',108,'全唐诗/poet.song.245000.json','["棠棣本同根，芳葩亦相聯。", "誰謂忽遠役，懷抱無由宣。", "况我骨肉親，與子枝葉連。", "昔爲雙飛鳬，今爲孤飛鳶。", "徘徊復彷徨，感激涕泗漣。", "道路阻且遠，四海霏塵煙。", "鶺鴒恐失羣，遶樹何翩翩。", "我有一斗酒，可以同笑言。", "去去從此辭，努力雲中鞭。"]'),
('7dc556d8-0bd2-4ad5-9fe9-842c85562817','居擬蘇武  其二','汪元量','宋','宋诗','song-poetry','','[]','黄鶴一遠舉，千年方始歸。',120,'全唐诗/poet.song.245000.json','["黄鶴一遠舉，千年方始歸。", "衆鳥念其群，哀鳴亦相依。", "彼美雙鴛鴦，一旦生乖離。", "幸有盈尊酒，聊以與子違。", "請歌遠遊吟，慷慨聲以悲。", "清商咽絲竹，激烈愴復悽。", "行人不可留，萬里將何之。", "念子日已遠，會念未有期。", "俛首長歎息，淚下沾我衣。", "安得生羽翰，與子成雙飛。"]'),
('b282d56e-d80a-48f8-998b-21221c0f9b88','居擬蘇武  其三','汪元量','宋','宋诗','song-poetry','','[]','結髪爲新婚，恩愛相匹儔。',96,'全唐诗/poet.song.245000.json','["結髪爲新婚，恩愛相匹儔。", "歡樂殊未已，征夫忽西遊。", "中夜起彷徨，仰視天漢流。", "衆星正縱橫，皓月澄中州。", "明發臨古道，古道何悠悠。", "生死從此辭，握手淚不收。", "勉哉惜芳姿，毋使懷百憂。", "丈夫抱赤心，婦女安可留。"]'),
('072dcf7e-2f89-4cad-a5fd-d0c6d9242581','居擬蘇武  其四','汪元量','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','皎皎雲間月，灼灼我室閭。',108,'全唐诗/poet.song.245000.json','["皎皎雲間月，灼灼我室閭。", "酣歌美長夜，清輝麗高隅。", "征夫許報國，將使萬里途。", "是時吹寒風，晨起驅行車。", "仰視天文乖，俯視長江殊。", "良友惜遠別，執手相踟躕。", "清時不屢好，嘉會難再娛。", "萬里一失所，中道將何如。", "願子著明誓，善保千金軀。"]'),
('60bbde9c-67a8-4ce8-8343-5c97ab999577','竹枝歌  其一','汪元量','宋','宋诗','song-poetry','','[]','快風吹我入三巴，桂櫂蘭橈倚暮花。',32,'全唐诗/poet.song.245000.json','["快風吹我入三巴，桂櫂蘭橈倚暮花。", "一道月明天似水，湘靈鼓瑟下長沙。"]'),
('f65550ec-cc50-435a-bab0-1817be44ec82','竹枝歌  其二','汪元量','宋','宋诗','song-poetry','','[]','賈誼祠前酹酒尊，汨羅江上吊騷魂。',32,'全唐诗/poet.song.245000.json','["賈誼祠前酹酒尊，汨羅江上吊騷魂。", "耒陽更有一抔土，行路人傳是假墳。"]'),
('6c0f16a4-bb5c-4257-82a7-1bbf8f44849c','竹枝歌  其三','汪元量','宋','宋诗','song-poetry','','[]','黄陵廟前楓葉丹，黄陵渡頭煙水寒。',32,'全唐诗/poet.song.245000.json','["黄陵廟前楓葉丹，黄陵渡頭煙水寒。", "美人萬里不相見，月子彎彎只自看。"]'),
('f8fb310a-9cd3-4b8f-b2b6-e5080e978bd7','竹枝歌  其四','汪元量','宋','宋诗','song-poetry','','[]','柘枝舞罷竹枝歌，風燭須臾奈爾何。',32,'全唐诗/poet.song.245000.json','["柘枝舞罷竹枝歌，風燭須臾奈爾何。", "馬玉池中鴻雁密，定王臺上駱駝多。"]'),
('0d404707-73f4-427a-b441-779b6d672a60','竹枝歌  其五','汪元量','宋','宋诗','song-poetry','','[]','落木蕭蕭風怒號，平沙漠漠雁腥臊。',32,'全唐诗/poet.song.245000.json','["落木蕭蕭風怒號，平沙漠漠雁腥臊。", "湘江秋水澄如練，山鬼囂時山月高。"]'),
('522862c0-f5cf-4eca-aa5c-2523378ea17d','竹枝歌  其六','汪元量','宋','宋诗','song-poetry','','[]','湘江日落亂帆飛，不向東歸便北歸。',32,'全唐诗/poet.song.245000.json','["湘江日落亂帆飛，不向東歸便北歸。", "楊柳渡頭村店裏，青裙女子賣烏柙。"]'),
('eef46ef4-48d9-4790-b8ee-ea415718a9ec','竹枝歌  其七','汪元量','宋','宋诗','song-poetry','','[]','湘南湘北蕙花開，樹頭樹底猨亂哀。',32,'全唐诗/poet.song.245000.json','["湘南湘北蕙花開，樹頭樹底猨亂哀。", "雲巢九疑虞帝廟，雨昏三峽楚王臺。"]'),
('70b86dbc-c9ca-45c9-8599-a66235f0d699','竹枝歌  其八','汪元量','宋','宋诗','song-poetry','','[]','白頭漁父白頭妻，網得魚多夜不歸。',32,'全唐诗/poet.song.245000.json','["白頭漁父白頭妻，網得魚多夜不歸。", "生怕渡官搜著稅，巴東轉柁向巴西。"]'),
('083d832d-ad28-4e77-9731-e7b32078bafc','竹枝歌  其九','汪元量','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','弄玉吹簫過洞庭，煙波渺渺接巴陵。',32,'全唐诗/poet.song.245000.json','["弄玉吹簫過洞庭，煙波渺渺接巴陵。", "朗吟仙子來何處，飛上君山玩月明。"]'),
('ba4b0752-0872-4769-8089-69ceae54da32','竹枝歌  其一○','汪元量','宋','宋诗','song-poetry','','[]','天上人間一夢過，春來秋去奈愁何。',32,'全唐诗/poet.song.245000.json','["天上人間一夢過，春來秋去奈愁何。", "銅仙有淚如鉛水，不似湘妃竹上多。"]'),
('00ba2764-16f1-447a-bd71-14079dbc6cac','短歌','汪元量','宋','宋诗','song-poetry','','[]','腰寶劍，背瑶琴，燕雲萬里金門深。',80,'全唐诗/poet.song.245000.json','["腰寶劍，背瑶琴，燕雲萬里金門深。", "斬邪誅佞拱北極，阜財解慍歌南音。", "駕驊騮，御狐貉。", "度關山，望河洛。", "况是東南宇宙窄，桑田變海風濤惡。", "勸君一醉千日醒，世事花開又花落。"]'),
('151893ec-c255-4816-8db4-9e5fd68ae596','送皇甫秀才下荆州','汪元量','宋','宋诗','song-poetry','','[]','西南多勝概，挾策緩周旋。',48,'全唐诗/poet.song.245000.json','["西南多勝概，挾策緩周旋。", "笛弄五溪月，櫂摇三峽天。", "楚江萍似斗，太華藕如船。", "歸橐應無價，人爭秀句傳。"]'),
('3617ed36-7c01-4184-a77d-74dcc60c71ae','送汪水雲','宋宮人','宋','宋诗','song-poetry','','[]','客有黄金共璧懷，如何不肯贖奴回。',32,'全唐诗/poet.song.245000.json','["客有黄金共璧懷，如何不肯贖奴回。", "今朝且盡穹廬酒，後夜相思無此杯。"]'),
('afda8d1b-e197-46c1-aa09-a53558deb3f7','送水雲歸吳','王清惠','宋','宋诗','song-poetry','','[]','朔風獵獵割人面，萬里歸人淚如霰。',32,'全唐诗/poet.song.245000.json','["朔風獵獵割人面，萬里歸人淚如霰。", "江南江北路茫茫，粟酒千鍾爲君勸。"]'),
('e3fd37ce-8ed1-4e2f-813c-7c9261afe63b','李陵臺和水雲韻','王清惠','宋','宋诗','song-poetry','','[]','李陵臺上望，答子五言詩。',48,'全唐诗/poet.song.245000.json','["李陵臺上望，答子五言詩。", "客路八千里，鄉心十二時。", "孟勞欣已稅，區脫未相離。", "忽報江南使，新來貢荔枝。"]'),
('038c7b33-875d-4f41-80a8-c5b61782941c','擣衣詩呈水雲','王清惠','宋','宋诗','song-poetry','','[]','妾命薄如葉，流離萬里行。',24,'全唐诗/poet.song.245000.json','["妾命薄如葉，流離萬里行。", "黄塵燕塞外，愁坐聽衣聲。"]'),
('2fdf6af0-fa16-4642-84bf-461fd6470eed','秋夜寄水月水雲二昆玉','王清惠','宋','宋诗','song-poetry','','[]','萬里倦行役，秋來瘦幾分。',24,'全唐诗/poet.song.245000.json','["萬里倦行役，秋來瘦幾分。", "因看河北月，忽憶海東雲。"]'),
('87089922-ea5a-4874-a7a4-d294957db918','詩一首','王清惠','宋','宋诗','song-poetry','','[]','愁到儂時酒自斟，挑燈看劍淚痕深。',64,'全唐诗/poet.song.245000.json','["愁到儂時酒自斟，挑燈看劍淚痕深。", "黄金台迥少知己，碧玉調高空好音。", "萬葉秋聲孤館夢，一窗寒月故鄉心。", "庭前昨夜梧桐雨，勁氣瀟瀟入短襟。"]'),
('b9d4294c-a6a5-4e50-8bf1-3b92eec86e9e','送水雲歸吳','陳真淑','宋','宋诗','song-poetry','','[]','天山雪子落紛紛，醉擁貂裘坐夜分。',32,'全唐诗/poet.song.245000.json','["天山雪子落紛紛，醉擁貂裘坐夜分。", "明日馬頭南地去，琴邊應是有文君。"]'),
('88cad7fe-0c60-4eb6-a8c9-02b3bb1daded','送水雲歸吳','黄慧真','宋','宋诗','song-poetry','','[]','萬疊燕山冰雪勁，萬里長城風雨橫。',32,'全唐诗/poet.song.245000.json','["萬疊燕山冰雪勁，萬里長城風雨橫。", "君衣雲錦勒花驄，此酒一杯何日更。"]'),
('eac30f64-ab6c-4044-8f85-d4be4a81520e','送水雲歸吳','何鳳儀','宋','宋诗','song-poetry','','[]','十年燕客身如病，一曲剡溪心不競。',32,'全唐诗/poet.song.245000.json','["十年燕客身如病，一曲剡溪心不競。", "憑君寄語愛梅仙，天理現時人事盡。"]'),
('5cd450fb-ec88-4d20-9d7c-7e26766f8a22','送水雲歸吳','周靜真','宋','宋诗','song-poetry','','[]','燕山雪花大如席，馬上吟詩無紙筆。',32,'全唐诗/poet.song.245000.json','["燕山雪花大如席，馬上吟詩無紙筆。", "他時若遇隴頭人，折寄梅枝須一一。"]'),
('2119aa58-c8b1-411f-b0d9-7c516a865b06','送水雲歸吳','葉靜慧','宋','宋诗','song-poetry','','[]','塞上砧聲響似雷，憐君騎馬望南回。',32,'全唐诗/poet.song.245000.json','["塞上砧聲響似雷，憐君騎馬望南回。", "今宵且向穹廬醉，後夜相思無此杯。"]'),
('03c3c539-0ada-45d2-8512-fe2612266d81','送水雲歸吳','孔清真','宋','宋诗','song-poetry','','[]','瘦馬長吟蹇馿吼，坐聽三軍擊刁斗。',32,'全唐诗/poet.song.245000.json','["瘦馬長吟蹇馿吼，坐聽三軍擊刁斗。", "歸人鞍馬不須忙，爲我更釂葡萄酒。"]'),
('379123fb-613f-4fdf-a144-c80ec99102e7','送水雲歸吳','鄭惠真','宋','宋诗','song-poetry','','[]','琵琶撥盡昭君泣，蘆葉吹殘蔡琰啼。',32,'全唐诗/poet.song.245000.json','["琵琶撥盡昭君泣，蘆葉吹殘蔡琰啼。", "歸見林逋煩說似，唐僧三藏入天西。"]'),
('f09d2637-3b9a-48c1-8ccf-f0196732ffc4','送水雲歸吳','方妙靜','宋','宋诗','song-poetry','','[]','萬里秦城風淅淅，一望薊州雲羃羃。',32,'全唐诗/poet.song.245000.json','["萬里秦城風淅淅，一望薊州雲羃羃。", "君今得旨歸故鄉，反鎖衡門勿輕出。"]'),
('07e88cd5-87d6-4df6-97ed-0e3e0e84d668','送水雲歸吳','翁懿淑','宋','宋诗','song-poetry','','["\u534e\u5c71"]','金門夜醉紫霞觴，乞得黄冠還故鄉。',32,'全唐诗/poet.song.245000.json','["金門夜醉紫霞觴，乞得黄冠還故鄉。", "一似陳摶歸華嶽，又如李泌過衡陽。"]'),
('f36c4f31-9ff6-4dd1-a3d3-7fd5998a74e7','送水雲歸吳','章妙懿','宋','宋诗','song-poetry','','[]','一從騎馬逐鈴鑾，過了千山又萬山。',32,'全唐诗/poet.song.245000.json','["一從騎馬逐鈴鑾，過了千山又萬山。", "君已歸裝向南去，不堪腸斷唱陽關。"]'),
('a667ea5e-31fc-4edc-b67e-d4fb88981429','送水雲歸吳','蔣懿順','宋','宋诗','song-poetry','','[]','十年牢落醉穹廬，不用歸榮駟馬車。',32,'全唐诗/poet.song.245000.json','["十年牢落醉穹廬，不用歸榮駟馬車。", "他日儻思人在北，音書還寄雁來無。"]'),
('9040a177-adca-4730-b411-c7a3bd2878cf','送水雲歸吳','林順德','宋','宋诗','song-poetry','','[]','歸舟夜泊西興渡，坐看潮來又潮去。',32,'全唐诗/poet.song.245000.json','["歸舟夜泊西興渡，坐看潮來又潮去。", "江草江花春復春，山青水綠原如故。"]'),
('5c699af8-18e6-45d4-91fe-d85a54be7931','送水雲歸吳','袁正淑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','抱琴歸去海東濱，莫逐成連覓子春。',32,'全唐诗/poet.song.245000.json','["抱琴歸去海東濱，莫逐成連覓子春。", "十里西湖明月在，孤山尋訪種梅人。"]'),
('b34852b1-1a78-4b26-927d-ac697d9bca59','送夫赴襄陽','盧氏','宋','宋诗','song-poetry','','[]','羨君家世舊纓簪，百戰常懷報主心。',64,'全唐诗/poet.song.245000.json','["羨君家世舊纓簪，百戰常懷報主心。", "草檄有才追記室，築臺無路繼淮陰。", "射鵰紫塞秋雲黑，走馬黄河夜雪深。", "白首丹衷知未變，歸來雙肘印黄金。"]'),
('4be418c3-0f06-42f6-bc0e-56ee962adbb3','絕命詞','盧氏','宋','宋诗','song-poetry','','[]','夫爲萇弘血，妾感共姜詩。',24,'全唐诗/poet.song.245000.json','["夫爲萇弘血，妾感共姜詩。", "夫妻同死義，天地一凄其。"]'),
('17376cbf-08bd-44e0-ae21-172362260d65','送西秦張仲實遊大滌洞天','林昉','宋','宋诗','song-poetry','','[]','此時仙興發，九鎖訪名峰。',48,'全唐诗/poet.song.245000.json','["此時仙興發，九鎖訪名峰。", "玉洞晝飛鼠，石池春浴龍。", "異人花外見，道士酒邊逢。", "余欲采芳茗，白雲何所從。"]'),
('b27f727a-be00-4e02-b914-63f7ccca4571','西湖','林昉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小舫撐春花浪香，第三橋底弄晴光。',32,'全唐诗/poet.song.245000.json','["小舫撐春花浪香，第三橋底弄晴光。", "吟邊飛起輕鷗片，十里天風舞綠楊。"]'),
('331d57b2-b8cb-4504-bf49-26f1b0467a7d','蓬門','林昉','宋','宋诗','song-poetry','','[]','新笋綠沿坡，蓬門誰見過。',48,'全唐诗/poet.song.245000.json','["新笋綠沿坡，蓬門誰見過。", "社寒來燕少，晚雨落花多。", "瘦骨詩醫俗，衰容酒借和。", "故園空有夢，客路正風波。"]'),
('10af01db-b175-40b8-ba51-3bc327490b80','病目','林昉','宋','宋诗','song-poetry','','[]','病目兩旬餘，深齋只另居。',48,'全唐诗/poet.song.245000.json','["病目兩旬餘，深齋只另居。", "客知多寄藥，妻勸少看書。", "畏熱燈羞近，貪凉髪屢梳。", "平生心喜菊，因此賸栽鋤。"]'),
('84a51d16-177a-4707-90e4-d6e6ccd9e01a','答王學士','林昉','宋','宋诗','song-poetry','','[]','已著山人屐，那能遠入城。',48,'全唐诗/poet.song.245000.json','["已著山人屐，那能遠入城。", "艱難思變姓，老大畏爭名。", "病葉兼蟲響，閑雲肯雨行。", "長懷陶靖節，出處意分明。"]'),
('f0cbc052-cf5c-4a4f-b904-6b689244592f','答黎教授  其一','林昉','宋','宋诗','song-poetry','','[]','潑甕浮醅新釀熟，得霜寒菊始開齊。',64,'全唐诗/poet.song.245000.json','["潑甕浮醅新釀熟，得霜寒菊始開齊。", "養丹道士顔如玉，愛酒山翁醉似泥。", "不惜蘂從蜂採去，尚餘香有蝶來棲。", "莫嫌學舍宮閑冷，猶得芳樽此共携。"]'),
('e71041c0-8102-48d0-9006-ac99cc3e3375','答黎教授  其二','林昉','宋','宋诗','song-poetry','','[]','共坐欄邊日欲斜，更將金蘂泛流霞。',32,'全唐诗/poet.song.245000.json','["共坐欄邊日欲斜，更將金蘂泛流霞。", "欲知却老延齡藥，百草枯時始見花。"]'),
('4be81f71-14d3-4409-a821-11b088fc8c45','題曾生古劍','林昉','宋','宋诗','song-poetry','','[]','三尺非凡鐵，年深鑄字漫。',48,'全唐诗/poet.song.245000.json','["三尺非凡鐵，年深鑄字漫。", "每尋閑處掛，不敢醉時看。", "紫電光猶濕，蒼蛟血未乾。", "邊秋方用武，莫恨致身難。"]'),
('4a672fc7-8c95-4b85-97d3-e87c8228ddad','夜笛','林昉','宋','宋诗','song-poetry','','[]','夜寒孤笛水邊樓，憶著西風古塞頭。',32,'全唐诗/poet.song.245000.json','["夜寒孤笛水邊樓，憶著西風古塞頭。", "一曲落梅吹得苦，吹人不管聽人愁。"]'),
('f4031ab9-0649-4025-9877-581d5e8d63c1','古冢行','林昉','宋','宋诗','song-poetry','','[]','山前月照青杉樹，下有古人葬時路。',64,'全唐诗/poet.song.245000.json','["山前月照青杉樹，下有古人葬時路。", "古人葬時多子孫，今日子孫無問處。", "花開花謝年復年，新墳漸滿古墳邊。", "猶起高樓與大屋，長爲子孫憂不足。"]'),
('ea9a5359-2c4e-437a-8ff2-e931d9f3dc45','聞子規  其一','林昉','宋','宋诗','song-poetry','','[]','飛到一枝上，須啼三五聲。',24,'全唐诗/poet.song.245000.json','["飛到一枝上，須啼三五聲。", "烟中猶彷彿，月下最分明。"]'),
('cd1974dd-e12f-4f7f-8657-d839b3b430bd','聞子規  其二','林昉','宋','宋诗','song-poetry','','[]','積淚消春色，好花思錦城。',24,'全唐诗/poet.song.245000.json','["積淚消春色，好花思錦城。", "貴人難入耳，祇是惱羈情。"]'),
('881adbe9-ba7a-4fbc-b88e-4c14a0036099','遷居','林昉','宋','宋诗','song-poetry','','[]','破帽老騎馿，霜風落木初。',48,'全唐诗/poet.song.245000.json','["破帽老騎馿，霜風落木初。", "江湖難獨立，貧病又遷居。", "楚客舊留劍，岳僧秋寄書。", "草玄吾不解，空愧子雲廬。"]'),
('a8a4bae5-61eb-4cc4-bb36-8b2c7ace9c3f','題所寓壁','林昉','宋','宋诗','song-poetry','','[]','世路機關險似棋，未逢好著費支持。',64,'全唐诗/poet.song.245000.json','["世路機關險似棋，未逢好著費支持。", "但能不作虧心事，何往非吾得意時。", "草著雨餘青轉耐，髪因閑裏白偏遲。", "一湖水影羣山聚，朝暮相看消幾詩。"]'),
('b859cc3e-638c-4d19-bedc-682d6a9e9e67','古碑','林昉','宋','宋诗','song-poetry','','[]','文殘字磨滅，往事記何人。',48,'全唐诗/poet.song.245000.json','["文殘字磨滅，往事記何人。", "拋在空林下，正當荒墓林。", "夕陽斜見影，古蘚厚生鱗。", "不是逢狂客，誰來與拂塵。"]'),
('2420b8ac-fe6b-4892-97ae-73cebbc66e6c','送秀才歸南海','林昉','宋','宋诗','song-poetry','','[]','歸路番禺遠，蠻鄉島嶼經。',48,'全唐诗/poet.song.245000.json','["歸路番禺遠，蠻鄉島嶼經。", "天黄春有瘴，海黑夜無星。", "北帖船中看，南歌枕上聽。", "遥知到家日，蜩響荔枝青。"]'),
('173e3eb8-9a38-4e26-978f-1a2d82eb0bc3','送人之湘陰謁知己','林昉','宋','宋诗','song-poetry','','[]','一聲歌未斷，江動欲潮生。',48,'全唐诗/poet.song.245000.json','["一聲歌未斷，江動欲潮生。", "是月寒露下，故人湘水行。", "沙雲晴見雁，船火夜聞箏。", "謝令應相喜，先期發吏迎。"]'),
('37e21bf7-b6e9-4be1-b9b5-507f40f7e377','贈汪水雲','李吟山','宋','宋诗','song-poetry','','[]','青雲貴戚玉麟兒，曾逐鑾車入紫闈。',64,'全唐诗/poet.song.245000.json','["青雲貴戚玉麟兒，曾逐鑾車入紫闈。", "王母窗前窺面日，太真膝上畫眉時。", "滄溟水闊龍何在，華表秋深鶴未歸。", "三尺焦桐千古意，黄金誰與鑄鍾期。"]'),
('c0654d34-6e2a-4bb6-8e4e-3ab76b1928d8','題汪水雲詩卷','開先長老','宋','宋诗','song-poetry','','[]','水流雲散海天涯，與子長游亦可嘉。',64,'全唐诗/poet.song.245000.json','["水流雲散海天涯，與子長游亦可嘉。", "歸馬迹漫燕嶠雪，啼鵑血染楚城花。", "乾坤浩蕩空雙眼，南北迢遥事一家。", "三疊琴心誰解意，蓬萊歸路躡青霞。"]'),
('3c39cf98-8b51-44a2-af00-769dcf062a98','題汪水雲詩卷','趙焱','宋','宋诗','song-poetry','','[]','山城拄笏意如何，孤鶴東來態度殊。',64,'全唐诗/poet.song.245000.json','["山城拄笏意如何，孤鶴東來態度殊。", "天上陽春歸閬苑，人間貴客在仙都。", "當年化蝶非真夢，今日騎鯨即故吾。", "莫操錢塘懷古曲，遺黎有淚灑江湖。"]'),
('a3f04231-c3c2-406a-b8b2-7599a63d13bf','送張治中朝京','胡斗南','宋','宋诗','song-poetry','','[]','乾坤人物老，牛斗景星明。',48,'全唐诗/poet.song.245000.json','["乾坤人物老，牛斗景星明。", "鴻翼天風順，馬蹄沙路平。", "松楸還有託，草木亦知名。", "歸日吟千首，江山萬里程。"]'),
('70af1b86-f7fc-44ee-925b-d75332aa7b71','挽文山  其一','胡斗南','宋','宋诗','song-poetry','','[]','裂指秋風感別離，乾坤人物太瑰琦。',64,'全唐诗/poet.song.245000.json','["裂指秋風感別離，乾坤人物太瑰琦。", "生爲孝子忠臣勸，死結皇天后土知。", "萬折江流魚腹石，千年人立首陽碑。", "一門史氏春秋筆，愁絕湖光入畫時。"]'),
('18a8c482-ad5b-43dd-b1cf-e629823b0882','挽文山  其二','胡斗南','宋','宋诗','song-poetry','','[]','金骨神仙玉色人，千霜萬雪見吾真。',64,'全唐诗/poet.song.245000.json','["金骨神仙玉色人，千霜萬雪見吾真。", "聖賢盡節心彌壽，天地爲棺道不貧。", "河漢橫流豪傑淚，風霆怒發鬼神嗔。", "先生出入騎箕尾，長現綱常四大身。"]'),
('e13bf727-b3a6-4a03-a890-4b172dcc40b0','題汪水雲詩卷  其一','胡斗南','宋','宋诗','song-poetry','','[]','一琴一鶴一扁舟，南北東西更九州。',32,'全唐诗/poet.song.245000.json','["一琴一鶴一扁舟，南北東西更九州。", "一曲湖山真得計，半生交結盡清流。"]'),
('04221cb3-773b-48fa-8d23-0d2317a8fc1e','題汪水雲詩卷  其二','胡斗南','宋','宋诗','song-poetry','','[]','翠柳摇摇迓客來，紅梅的的爲公開。',32,'全唐诗/poet.song.245000.json','["翠柳摇摇迓客來，紅梅的的爲公開。", "管寧昔作遼東去，蘇武新從塞北回。"]'),
('f0207a5a-ba2d-4c18-b597-d27da629330b','題汪水雲詩卷  其三','胡斗南','宋','宋诗','song-poetry','','[]','老來無意謁侯門，自愛梅花水月村。',32,'全唐诗/poet.song.245000.json','["老來無意謁侯門，自愛梅花水月村。", "更擬孤山結茅屋，杖藜聊復信乾坤。"]'),
('acd4ba41-a153-406f-b771-26b7232c9488','題汪水雲詩卷  其四','胡斗南','宋','宋诗','song-poetry','','[]','魁笑先生尚可癡，湖山日日有新詩。',32,'全唐诗/poet.song.245000.json','["魁笑先生尚可癡，湖山日日有新詩。", "水光雲影窗三尺，雨抹晴裝畫四時。"]'),
('f6920e55-9fa1-420f-a3ea-98aa991f1cd4','題汪水雲詩卷  其五','胡斗南','宋','宋诗','song-poetry','','["\u897f\u6e56"]','篋裏新詩意不傳，飄蓬白髪地行仙。',32,'全唐诗/poet.song.245000.json','["篋裏新詩意不傳，飄蓬白髪地行仙。", "江南江北都看了，更住西湖一百年。"]'),
('7906e4e5-1162-4415-bf8e-4fced06f2393','題汪水雲詩卷  其六','胡斗南','宋','宋诗','song-poetry','','[]','越舞吳謳別幾春，御船坊下即迷津。',32,'全唐诗/poet.song.245000.json','["越舞吳謳別幾春，御船坊下即迷津。", "年來依舊多游賞，半是南人半北人。"]'),
('26574777-60a0-4c68-b573-32ba37af4395','題汪水雲詩卷  其七','胡斗南','宋','宋诗','song-poetry','','[]','當年出塞幾紅娃，曾共氈房看雪花。',32,'全唐诗/poet.song.245000.json','["當年出塞幾紅娃，曾共氈房看雪花。", "今日湖亭霜月夜，夢中猶聽撚琵琶。"]'),
('92b7b635-3ab0-4b58-a520-002e473dbd51','題汪水雲詩卷  其八','胡斗南','宋','宋诗','song-poetry','','[]','詩家冷淡作生涯，有客相過旋煮茶。',32,'全唐诗/poet.song.245000.json','["詩家冷淡作生涯，有客相過旋煮茶。", "斫去梅花除去柳，繞隄只合種桑麻。"]'),
('df60e1e6-452c-4e25-93c6-2d13b48446c7','題汪水雲詩卷  其九','胡斗南','宋','宋诗','song-poetry','','[]','十里鶑花處處嬌，南新橋過北新橋。',32,'全唐诗/poet.song.245000.json','["十里鶑花處處嬌，南新橋過北新橋。", "船來船去東風裏，何處佳人弄玉蕭。"]'),
('5b553176-7206-462a-a1d4-054dd5d7d6f2','題汪水雲詩卷  其一○','胡斗南','宋','宋诗','song-poetry','','["\u897f\u6e56"]','螺子江頭酒一壺，瑒花香處賦歸歟。',32,'全唐诗/poet.song.245000.json','["螺子江頭酒一壺，瑒花香處賦歸歟。", "西湖他日笙歌裏，還憶山中人姓胡。"]'),
('699078d4-3232-4d01-b4e3-bf1a7696c316','題汪水雲詩卷  其一','劉師復','宋','宋诗','song-poetry','','[]','萬里歸來葺故園，闞湖新結小船軒。',32,'全唐诗/poet.song.245000.json','["萬里歸來葺故園，闞湖新結小船軒。", "雙親八十喜康健，七子侍勞三十孫。"]'),
('532694e9-8aee-4283-9d3e-3f5effa5f155','題汪水雲詩卷  其二','劉師復','宋','宋诗','song-poetry','','[]','別港鶑嬌恰恰啼，蘇公堤過趙公堤。',32,'全唐诗/poet.song.245000.json','["別港鶑嬌恰恰啼，蘇公堤過趙公堤。", "水西雲北春無頼，細柳新蒲綠未齊。"]'),
('d0f50d1f-04ec-4016-ae33-21b17001d380','題汪水雲詩卷  其三','劉師復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天造西湖錦繡堆，柳邊漁父小篷開。',32,'全唐诗/poet.song.245000.json','["天造西湖錦繡堆，柳邊漁父小篷開。", "能言景定年間事，公主鸞簫錦櫂來。"]'),
('49d66b1b-335b-4b30-8d54-3c0f816c392b','題汪水雲詩卷  其四','劉師復','宋','宋诗','song-poetry','','[]','此客清狂似季真，意行湖曲眺青春。',32,'全唐诗/poet.song.245000.json','["此客清狂似季真，意行湖曲眺青春。", "櫓聲往往來來好，山色朝朝暮暮新。"]'),
('7572ec45-b6b1-4b09-ad41-c28346723c70','題汪水雲詩卷  其五','劉師復','宋','宋诗','song-poetry','','[]','杖藜引客入漁家，盡敞蓬窗作供茶。',32,'全唐诗/poet.song.245000.json','["杖藜引客入漁家，盡敞蓬窗作供茶。", "三面闌干詩思闊，湖光千頃浸荷花。"]'),
('6694def5-e3e4-40f6-8387-103eaaf026d8','題汪水雲詩卷  其六','劉師復','宋','宋诗','song-poetry','','[]','當年飛鳥亦難前，今日中堂起燒烟。',32,'全唐诗/poet.song.245000.json','["當年飛鳥亦難前，今日中堂起燒烟。", "丞相不嗔山色好，歌聲穩送裏河船。"]'),
('f58e5af9-3797-43c6-990b-28b31bf61552','題汪水雲詩卷  其七','劉師復','宋','宋诗','song-poetry','','[]','小小船齋闞碧流，水仙招我下湖游。',32,'全唐诗/poet.song.245000.json','["小小船齋闞碧流，水仙招我下湖游。", "簫聲嫋嫋歌聲合，桂子香中十里秋。"]'),
('48295f02-f55c-4c3e-a8b6-89e560578115','題汪水雲詩卷  其八','劉師復','宋','宋诗','song-poetry','','[]','詩翁老去尚兒嬉，撩撥歌鬟笑挽衣。',32,'全唐诗/poet.song.245000.json','["詩翁老去尚兒嬉，撩撥歌鬟笑挽衣。", "草草杯盤隨處飲，西泠橋入斷橋歸。"]'),
('3a39b031-3498-4f08-9cbb-4a9291bdec13','題汪水雲詩卷  其九','劉師復','宋','宋诗','song-poetry','','[]','北去南來無定居，水流雲在意何如。',32,'全唐诗/poet.song.245000.json','["北去南來無定居，水流雲在意何如。", "湖邊倘有西飛雁，只寄詩筒莫寄書。"]'),
('1d198d38-9c39-46b3-8fdc-50c0c3ef995a','題汪水雲詩卷  其一○','劉師復','宋','宋诗','song-poetry','','[]','澗邊爛醉桂花秋，明發携琴不可留。',32,'全唐诗/poet.song.245000.json','["澗邊爛醉桂花秋，明發携琴不可留。", "遥想兩峰湖一曲，畫船何日許同遊。"]'),
('e4c31549-303c-4066-8eb8-0f2c1cf998c4','題汪水雲詩卷  其一一','劉師復','宋','宋诗','song-poetry','','[]','水流雲在意，政不限西東。',48,'全唐诗/poet.song.245000.json','["水流雲在意，政不限西東。", "山澤秋如瘦，江湖道亦窮。", "浙音惟我聽，冀眼獨居空。", "甚惜匆匆別，西風落葉中。"]'),
('eeebf688-6892-44be-acd4-3ccbd104f0cc','題汪水雲詩卷  其一','羅志仁','宋','宋诗','song-poetry','','[]','歌舞兒嬉度歲年，當時先見憶龍川。',32,'全唐诗/poet.song.245000.json','["歌舞兒嬉度歲年，當時先見憶龍川。", "絕憐遺俗依然在，日日百花金勝船。"]'),
('4fe4171f-ea4c-47f5-9d41-8a23a7108eec','題汪水雲詩卷  其二','羅志仁','宋','宋诗','song-poetry','','[]','八盤九曲已荒凉，四聖三賢半在亡。',32,'全唐诗/poet.song.245000.json','["八盤九曲已荒凉，四聖三賢半在亡。", "乍見少年猶眼纈，只緣山色與湖光。"]'),
('9f4ef50d-aec0-4b4a-abf9-2fba0cfcc6b0','題汪水雲詩卷  其三','羅志仁','宋','宋诗','song-poetry','','[]','斜陽葛嶺少人行，一片荒山繫廢興。',32,'全唐诗/poet.song.245000.json','["斜陽葛嶺少人行，一片荒山繫廢興。", "留得臨湖春雨觀，東風摇落木香棚。"]'),
('ffbe718f-4623-439a-baa0-1c7c0c3e19c9','題汪水雲詩卷  其四','羅志仁','宋','宋诗','song-poetry','','[]','靈隠冷泉圖畫開，奇峰西竺遠飛來。',32,'全唐诗/poet.song.245000.json','["靈隠冷泉圖畫開，奇峰西竺遠飛來。", "天然蒼翠都消減，無奈滿山金碧堆。"]'),
('1e3b1b18-410a-4e77-95d2-275b57849053','題汪水雲詩卷  其五','羅志仁','宋','宋诗','song-poetry','','[]','綠幕紅簾沒柁船，船頭日日撲花錢。',32,'全唐诗/poet.song.245000.json','["綠幕紅簾沒柁船，船頭日日撲花錢。", "笙歌水面盈盈去，過眼笙歌正可憐。"]'),
('23da27f4-77e6-491a-bdd8-80c462b0f588','題汪水雲詩卷  其六','羅志仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子西湖只一般，翠雲珠髻恣君看。',32,'全唐诗/poet.song.245000.json','["西子西湖只一般，翠雲珠髻恣君看。", "世間尤物移人處，高鼻虬鬚也被瞞。"]'),
('de503f49-4c67-492d-9acf-ef48daf570a3','題汪水雲詩卷  其七','羅志仁','宋','宋诗','song-poetry','','[]','銷盡黄金是此窩，高人欹枕看晴波。',32,'全唐诗/poet.song.245000.json','["銷盡黄金是此窩，高人欹枕看晴波。", "錢塘門裏九曲寺，得似先生一曲多。"]'),
('16733b89-b6ce-4502-8772-6f324aab92f8','題汪水雲詩卷  其八','羅志仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾住西湖畫幅間，楚鄉久客亦良難。',32,'全唐诗/poet.song.245000.json','["曾住西湖畫幅間，楚鄉久客亦良難。", "先生道眼無分別，浙水江雲一樣看。"]'),
('45b6ed97-94d0-4cd1-ac92-48b58bb5adaa','題汪水雲詩卷  其九','羅志仁','宋','宋诗','song-poetry','','[]','豐樂華樓已劫灰，湧金春色未塵埃。',32,'全唐诗/poet.song.245000.json','["豐樂華樓已劫灰，湧金春色未塵埃。", "道人有道軒窗靜，那處湖光不好來。"]'),
('ec24c5a9-3e20-4906-ae0e-f2f42eaea6fd','題汪水雲詩卷  其一○','羅志仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','楊柳蘇堤欠補栽，誰能瀛嶼種添梅。',32,'全唐诗/poet.song.245000.json','["楊柳蘇堤欠補栽，誰能瀛嶼種添梅。", "去年我與西湖別，健在明年又會來。"]'),
('96133ec3-669b-4bef-938c-8ad67ad442a5','諷留夢炎','羅志仁','宋','宋诗','song-poetry','','[]','齧雪蘇郎受苦辛，庾公老作北朝臣。',32,'全唐诗/poet.song.245000.json','["齧雪蘇郎受苦辛，庾公老作北朝臣。", "當年龍首黄扉者，猶是衡門一樣人。"]'),
('6a772afd-0700-4e05-9407-3e5adaace36a','句','羅志仁','宋','宋诗','song-poetry','','[]','冷吸蟬吭露，清摇鶴背霜。',12,'全唐诗/poet.song.245000.json','["冷吸蟬吭露，清摇鶴背霜。"]'),
('4b63482d-198d-46e6-9e51-48355087563e','題汪水雲詩卷','孫鼎','宋','宋诗','song-poetry','','[]','北遊不羨築臺金，忽解儒冠雪滿簪。',64,'全唐诗/poet.song.245000.json','["北遊不羨築臺金，忽解儒冠雪滿簪。", "短劍空橫無俠氣，破琴欲撫且悲吟。", "啼猿聲墮楚江碧，遊鹿夢迷吳苑深。", "若見麻姑閒問訊，桃花千樹正陰陰。"]'),
('7111d828-6174-401a-8405-667ff2b1e056','題汪水雲詩卷','彭淼','宋','宋诗','song-poetry','','[]','萬里歸來舊布衣，笳聲不斷轉桐絲。',64,'全唐诗/poet.song.245000.json','["萬里歸來舊布衣，笳聲不斷轉桐絲。", "十年秋入肩吾鬢，四海人傳雲叟詩。", "窖裏雪氈魂些短，江南月砌夢歸遲。", "白頭惆悵相逢晚，況是人間落葉時。"]'),
('6dd573ea-5ae0-4051-9c44-fd6e5547ee81','題汪水雲詩卷','蕭豳','宋','宋诗','song-poetry','','[]','孀娥靈藥被誰偷，碧海青天伴夜愁。',64,'全唐诗/poet.song.245000.json','["孀娥靈藥被誰偷，碧海青天伴夜愁。", "歸郭令威空化鶴，度關老子偶乘牛。", "廣陵散在斜陽遠，梁父吟成昨雨收。", "我亦雲間舊鷄犬，與君相對擊茶甌。"]'),
('37b64a7b-f11a-4b0c-ad8f-e5fe18be8600','題汪水雲詩卷','蕭壎','宋','宋诗','song-poetry','','[]','遼鶴歸來世已殊，忽悲身晚及塘蒲。',64,'全唐诗/poet.song.245000.json','["遼鶴歸來世已殊，忽悲身晚及塘蒲。", "乾坤浩浩琴三尺，歲月堂堂酒一壺。", "剡曲祇今書賀監，稽山在昔庾肩吾。", "行吟便是江南史，它日真堪付董狐。"]'),
('f08bec31-900d-41fd-8c1d-dd0ed6880295','題汪水雲詩卷','劉淵','宋','宋诗','song-poetry','','[]','當時興廢事，說著意猶悲。',48,'全唐诗/poet.song.245000.json','["當時興廢事，說著意猶悲。", "自謂水不返，誰知雲解歸。", "十年麋鹿恨，一卷杜鵑詩。", "又入離騷國，清彈霜葉飛。"]'),
('f7c6107a-a488-430d-b939-ee57468c8005','題汪水雲詩卷','劉豐祿','宋','宋诗','song-poetry','','[]','海水奔騰朔風急，巨鰲震動坤軸折。',128,'全唐诗/poet.song.245000.json','["海水奔騰朔風急，巨鰲震動坤軸折。", "茫茫水與雲相連，中有仙人渺獨立。", "槁梧三尺操南音，輕視功名等秋葉。", "調高韻古泣鬼神，氈帳輕彈燕薊月。", "錦囊萬里詩一編，字字丹心瀝青血。", "回首銅仙舊夢寒，撫卷令人雙鬢雪。", "祇今復作瀟湘遊，擬續離騷弔忠魄。", "獨夜何心聞杜鵑，雲暗蒼梧正愁絕。"]'),
('acf6fc78-f8a8-466f-990c-b740d15610b3','題汪水雲詩卷','蕭璩','宋','宋诗','song-poetry','','[]','璧月歌殘鐵騎圍，銀濤風急鷁舟飛。',64,'全唐诗/poet.song.245000.json','["璧月歌殘鐵騎圍，銀濤風急鷁舟飛。", "海山運并隨鰲盡，城郭身今化鶴歸。", "琴怨詩愁春一雨，江南渭北淚雙霏。", "與君厭聽桑田語，一笑遊絲罥落暉。"]'),
('9e408e43-1da8-406e-bcb4-7c67ecb5b33e','題汪水雲詩卷','趙雲','宋','宋诗','song-poetry','','[]','江南江北馬如飛，曾著金門羽客衣。',64,'全唐诗/poet.song.245000.json','["江南江北馬如飛，曾著金門羽客衣。", "李泌暫遊衡嶽去，陳摶已請華山歸。", "風雲萬里氣無敵，雨露兩朝恩有輝。", "偶爾江頭相邂逅，細聽流水十三徽。"]'),
('602ac85b-28f8-41e1-bdd6-5ac81f5cfbe9','題汪水雲詩卷','羅綺','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南越長淮北眺燕，三書上徹九重天。',64,'全唐诗/poet.song.245000.json','["南越長淮北眺燕，三書上徹九重天。", "氈寒馿重幽州雪，劍曉龍吟易水烟。", "齊好無移竽尚在，秦酬有爽璧終全。", "知音向近西湖上，却不當初早理絃。"]'),
('f3a126ec-29bb-46e7-a4b8-ad6ad2027fde','題汪水雲詩卷','張弘道','宋','宋诗','song-poetry','','[]','風檣陣馬不可羈，我亦回首薊北馳。',96,'全唐诗/poet.song.245000.json','["風檣陣馬不可羈，我亦回首薊北馳。", "爲我援琴作商聲，和以長吟商聲悲。", "遼鶴一去不復返，茫茫天海秋雁飛。", "黯然十操發金石，掩卷忍讀胡笳詩。", "相逢把臂不可別，白蘋洲渚菊花時。", "天涯地角聚復散，水雲雲水同襟期。"]'),
('404d2296-48eb-498c-bf91-d0a1fe63749d','題汪水雲詩卷','張時中','宋','宋诗','song-poetry','','[]','吳江潮落曉光微，萬里風沙撲面飛。',64,'全唐诗/poet.song.245000.json','["吳江潮落曉光微，萬里風沙撲面飛。", "帝化海濱精衛怨，仙吟華表令威歸。", "秋空愁斷銅仙遠，夜雨歌沉玉樹非。", "隨意黄冠方外去，雲臺何似首陽薇。"]'),
('726901c7-897c-471f-afb6-39bff153de39','題汪水雲詩卷','尹閴','宋','宋诗','song-poetry','','[]','平生寧用拙，方鑿不圓卿。',48,'全唐诗/poet.song.245000.json','["平生寧用拙，方鑿不圓卿。", "風月少知己，江山多故情。", "北辰終夕仰，西雨幾時晴。", "水與雲無定，君當保令名。"]'),
('3402795b-de55-4b7f-af4e-2f00ca3e4472','題汪水雲詩卷','蕭克翁','宋','宋诗','song-poetry','','[]','舊時綵箋結綺，晚歲銅仙渭城。',28,'全唐诗/poet.song.245000.json','["舊時綵箋結綺，晚歲銅仙渭城。", "三十年來家國，吾琴無虧無成。"]'),
('d3a4d021-a71a-4add-847d-ef5892afaa26','題汪水雲詩卷','祝從龍','宋','宋诗','song-poetry','','[]','竹杖芒鞋短後衣，抱琴何處覓鍾期。',64,'全唐诗/poet.song.245000.json','["竹杖芒鞋短後衣，抱琴何處覓鍾期。", "百年爛醉烏程酒，千首新吟晉宋詩。", "京洛風塵如昨日，湖山水月此何時。", "近來見說人心別，不看南枝看北枝。"]'),
('c2ecd359-be23-407c-a170-02f3719dd262','題汪水雲詩卷','夏天民','宋','宋诗','song-poetry','','[]','仰峰昨夜三尺雪，梅花吟老坐如橛。',130,'全唐诗/poet.song.245000.json','["仰峰昨夜三尺雪，梅花吟老坐如橛。", "道人啄扉來摻別，茗盌冰膠不堪啜。", "袖中枝桐半皴裂，爲予載拊舒鬰結。", "誰裁古調多曲折，拍拍胡笳中音節。", "燕山孤纍心石鐵，神物護持筆生舌。", "杜陵老翁代佛說，長歌自擊唾壺缺。", "萬古劍鋩倒流血，毛髪森森照關月。", "於乎嵇康東市計仍拙，廣陵一散何嘗絕。"]'),
('187e7db5-e426-40d2-81bf-5b05de942974','題汪水雲詩卷','王祖弼','宋','宋诗','song-poetry','','[]','相逢邂逅不相期，又是江湖一段奇。',64,'全唐诗/poet.song.245000.json','["相逢邂逅不相期，又是江湖一段奇。", "我輩恨生南渡後，道人嘯出北征詩。", "百年歲月心難老，萬里江山夢已馳。", "細閲行程更相問，河清久說水漣漪。"]'),
('ad4cac82-44fe-4cee-94e8-18cbbb62333d','題汪水雲詩卷','戴仁傑','宋','宋诗','song-poetry','','[]','水雲應世地行仙，手抱琴書直到燕。',64,'全唐诗/poet.song.245000.json','["水雲應世地行仙，手抱琴書直到燕。", "萬里滄江鷗浩蕩，千年城郭鶴翩躚。", "履霜中野元無怨，齧雪陰山只自憐。", "今日相逢又相別，新詩滿橐不論錢。"]'),
('4b82a365-7cd2-4ff6-b442-f3c6e648f908','題汪水雲詩卷','曾順孫','宋','宋诗','song-poetry','','[]','道人東魯舊儒生，短褐翛然獨自行。',64,'全唐诗/poet.song.245000.json','["道人東魯舊儒生，短褐翛然獨自行。", "禾黍離離悲故國，風沙漠漠度長城。", "琴音不忍移南操，詩卷猶能續北征。", "如此金臺君拂袖，水天雲闊去留輕。"]'),
('5dd91746-4f01-44b0-9a34-6727ce5766f2','題汪水雲詩卷','劉震祖','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','高深妙語坐鬅鬙，花落茶烟夜雨燈。',64,'全唐诗/poet.song.245000.json','["高深妙語坐鬅鬙，花落茶烟夜雨燈。", "俗眼不知鵬化鷃，書癡何害墨成蠅。", "雲泥夢覺空陳迹，桑海吟殘嗅葛藤。", "劍吼洞庭朱頂急，歸來城郭問雲仍。"]'),
('40558d4d-48fe-4eea-b8d6-ae22312963fc','題汪水雲詩卷','秦嗣彭','宋','宋诗','song-poetry','','[]','禾黍興悲兩鬢皤，千年荆棘幾銅駝。',64,'全唐诗/poet.song.245000.json','["禾黍興悲兩鬢皤，千年荆棘幾銅駝。", "義熙處士流風遠，天寶詩人舊恨多。", "雨露又新周草木，煙塵空想漢山河。", "庾郎謾有江南賦，得似先生醉後歌。"]'),
('ae824dfc-2827-4916-aa32-add02d1b1637','題汪水雲詩卷','兜率長老','宋','宋诗','song-poetry','','[]','窮髪歸來脫孟勞，何嗟澹與泊相遭。',64,'全唐诗/poet.song.245000.json','["窮髪歸來脫孟勞，何嗟澹與泊相遭。", "瑶琴摘罷意猶在，石鼎聯成韻更高。", "世事可能書咄咄，人情只合醉陶陶。", "雁門絃斷無人續，輸子詩成奪錦袍。"]'),
('e82120de-e141-40c3-8896-7d9fd8e27f69','題汪水雲詩卷','熊仲允','宋','宋诗','song-poetry','','["\u897f\u6e56"]','輕輕漠漠暮雲低，枯木寒枝宿鳥稀。',64,'全唐诗/poet.song.245000.json','["輕輕漠漠暮雲低，枯木寒枝宿鳥稀。", "古殿荒凉殘日照，孤城寂寞故山圍。", "十年波浪家何在，萬里關河客未歸。", "惆悵西湖湖上路，梅花如舊世相違。"]'),
('2dba3d2e-761f-4547-9f36-6a29c2c0e6ee','題汪水雲詩卷','蕭炎丑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聽說西湖事，分明在目前。',48,'全唐诗/poet.song.245000.json','["聽說西湖事，分明在目前。", "逋梅籠水月，坡柳弄風烟。", "春夢須臾裏，舊遊三十年。", "把君丙子集，讀罷淚潸然。"]'),
('ecbe2025-673d-4598-ae63-8c2be13d3afb','題汪水雲詩卷','黄居仁','宋','宋诗','song-poetry','','[]','馬上琵琶不復琴，龍荒弔古獨遺音。',64,'全唐诗/poet.song.245000.json','["馬上琵琶不復琴，龍荒弔古獨遺音。", "西風金掌吹清淚，落日銅駝折寸心。", "杜子但傷鵑血化，蘇卿豈料雁書沉。", "當時痛哭無人哭，千載江流轉恨深。"]'),
('7455ab33-c95e-45ba-99ba-f4eb480c0a9c','題汪水雲詩卷','永秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','禾黍離離滿故都，君詩讀罷淚傾珠。',64,'全唐诗/poet.song.245000.json','["禾黍離離滿故都，君詩讀罷淚傾珠。", "立朝食祿千官富，爲國忘軀一事無。", "兵革已將臨北闕，笙歌猶自醉西湖。", "黄冠氅服今誰識，前宋遺賢有此儒。"]'),
('6ec23ae7-179a-4ab3-a8fa-e80ad6618b07','題汪水雲詩卷','楊學周','宋','宋诗','song-poetry','','["\u897f\u6e56"]','握手論心不記年，重逢仍似地行仙。',64,'全唐诗/poet.song.245000.json','["握手論心不記年，重逢仍似地行仙。", "琴彈碧玉時三弄，袖有驪珠近百篇。", "嶽麓曉行雲外履，湘潭夜醉月中船。", "它時歸隠西湖畔，能把新詩寄一聯。"]'),
('e1b3be47-5c90-4410-b054-b8a807a603f2','題汪水雲詩卷','蕭灼','宋','宋诗','song-poetry','','[]','朔風卷雨東南昏，銅仙淚灑辭吳門。',144,'全唐诗/poet.song.245000.json','["朔風卷雨東南昏，銅仙淚灑辭吳門。", "間關萬里踏燕月，埃沙撲面愁人魂。", "携琴早晚隨王母，不似瑶池舊歌舞。", "南冠岌岌操南音，此意此心千萬古。", "十年歸來兩鬢霜，袖有詩史繼草堂。", "西遊蒼梧北太華，筆端傳入古錦囊。", "甫也再拜杜鵑血，潁乎冥入冰炭腸。", "一朝訪我茅屋下，朔風易水爲余寫。", "黄金好鑄鍾子期，知君不是黄冠師。"]'),
('dbecbef3-72ee-4d37-aeb8-515c169dbce2','題汪水雲詩卷','覺性','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u6cf0\u5c71"]','細讀燕雲吟，靜聽流水琴。',84,'全唐诗/poet.song.245000.json','["細讀燕雲吟，靜聽流水琴。", "神遊八極高而深，龍溪玉山猶谷響，燕歌吳詠轟雷音。", "人中龍，天外鶴。", "挾泰山，擘華嶽。", "醉吟不管天地窄，堯桀誰能分善惡。", "雲閣麟臺一笑間，招得赤松歸碧落。"]'),
('81c356a7-dc19-4590-a7d3-6d3568815122','題汪水雲詩卷','楊學李','宋','宋诗','song-poetry','','[]','野服意翛然，心無世網牽。',48,'全唐诗/poet.song.245000.json','["野服意翛然，心無世網牽。", "衣冠舊朝士，湖海老詩仙。", "橫槊思公瑾，登樓憶仲宣。", "瀟湘風月好，何日理歸船。"]'),
('706e0975-4c84-4194-974d-23b718ffcb09','初秋夜坐','楊學李','宋','宋诗','song-poetry','','[]','青燈伴微吟，煩暑猶蒸炊。',120,'全唐诗/poet.song.245000.json','["青燈伴微吟，煩暑猶蒸炊。", "風聲如山雷，怒落窗西籬。", "砌蛩泣候莎，老樹鳴高枝。", "桂魄忽嬋娟，夜氣侵凉絺。", "蓴羹豈不懷，未了一載癡。", "依依游子情，堂萱重馳思。", "祇將冰雪心，或可爲母慈。", "清白爲家箴，夫豈世俗知。", "南來秋復秋，賸喜瓜及期。", "娛親已可望，須記思親時。"]'),
('30716571-f5a4-440b-9445-d9f43c941f70','西郊晚步','楊學李','宋','宋诗','song-poetry','','[]','江城五月風雨餘，嶺南地僻少馳驅。',112,'全唐诗/poet.song.245000.json','["江城五月風雨餘，嶺南地僻少馳驅。", "政餘長日無與俱，尋幽步屧城西隅。", "地平山遠迷綠蕪，垂陽深處聞鷓鴣。", "縈紆小徑逅浮圖，松風夾道如笙竽。", "清池冷浸秋水菰，如有露氣侵庭梧。", "桃笙院靜橫竹奴，栩栩清夢游冰壺。", "覺來殘照不可呼，更待好月同歸塗。"]'),
('cf57a7bb-3e9a-4ee1-a19d-8cf707d1323b','望雲樓','楊學李','宋','宋诗','song-poetry','','[]','樓前山色青如鬟，樓高夜映心斗寒。',172,'全唐诗/poet.song.245000.json','["樓前山色青如鬟，樓高夜映心斗寒。", "推窗縱目納吟思，倚檻爽氣生眉端。", "荒烟宿靄迷野甸，古崖怪石橫驚湍。", "城孤下瞰天蘸碧，日永坐聽風鳴鑾。", "登臨獨慨城郭是，把酒一酹還三歎。", "雖未如元龍高卧之百尺，已不減庾公步月之遊觀。", "又何須黄鶴霄漢之浩渺，亦可想岳陽烟水之彌漫。", "巋然獨立賀江許，已矣樓中沸歌舞。", "勝境無詩亦可羞，謾自簷楹庇風雨。", "望雲人遠迹生塵，祇有江流自今古。"]'),
('fb46a2c9-d3df-4150-9cfa-93c97fb69e0d','題汪水雲詩卷','祖惟和','宋','宋诗','song-poetry','','[]','北去南來策蹇馿，偶然過我古玄都。',64,'全唐诗/poet.song.245000.json','["北去南來策蹇馿，偶然過我古玄都。", "雖無千樹桃花賦，却有三秋桂子圖。", "賀老掛冠方賜剡，張翰命駕已歸吳。", "酒邊說盡興亡事，空羨陶朱據五湖。"]'),
('9b04f308-638c-418a-835b-a17f3a25d61f','題汪水雲詩卷','黄圭','宋','宋诗','song-poetry','','[]','十日不得出，坐窗窺古音。',48,'全唐诗/poet.song.245000.json','["十日不得出，坐窗窺古音。", "五言臣武淚，百詠阿雄心。", "對雪遂忘夜，看詩如聽琴。", "年時塵稿在，便擬石頭沉。"]'),
('07b09760-749d-4888-abed-03d2e52f6bca','題汪水雲詩卷','張嵩老','宋','宋诗','song-poetry','','[]','君不見伯牙流水心，不是子期誰知音。',277,'全唐诗/poet.song.245000.json','["君不見伯牙流水心，不是子期誰知音。", "又不見穎師浮雲操，不是昌黎誰品藻。", "伯牙千古穎無人，此心此操誰重陳。", "折揚黄華笑啞啞，寥寥太古風無淳。", "錢唐君別二十載，江南江北情如海。", "吳霜半染鬢邊絲，朗吟浩蕩殊未艾。", "十年尊酒又逢君，行歌流水絃浮雲。", "在自大古，雅澹飄逸思不羣。", "能言名山大川壯麗可怪處，收拾胸中爲一部。", "歸來歷歷寫瑶琴，一種風氣傳千古。", "又言黄河泰華六合之內不勝遊，何如九州之內更九州。", "抱琴飄飄風萬里，曾是天涯海角頭。", "當時此琴落落天西北，土音往往幾人還解得。", "怊悵悲憤恩怨昵昵多少情，盡寄胡笳十八拍。", "會心又見鍾子期，識操又遇韓昌黎。", "眼高已覺空四海，此水此雲不在他人知。"]'),
('3ed81aca-8022-424a-8ee0-619a38f3e804','題汪水雲詩卷','嚴日益','宋','宋诗','song-poetry','','[]','紫皇宮殿紅雲低，春歸天上日欲西。',368,'全唐诗/poet.song.245000.json','["紫皇宮殿紅雲低，春歸天上日欲西。", "瑶池催花撾羯鼓，姚魏天香分雨露。", "沉香亭北雉尾高，詩成先奪雲錦袍。", "縱橫奏賦三千字，文采風流多意氣。", "珮聲楊柳鳳池頭，絲綸五色爛不收。", "巨鰲跳波海門黑，氈雪風砂墮陰域。", "翠華鞭鸞凌紫烟，天寒月照青塚邊。", "黄金不啼玉不泣，桑嶺流沙馬飛急。", "孤臣淚結冰稜稜，兩宮祝髪傳佛燈。", "梵尊說法天龍拜，四大山河金色界。", "風飄仙樂去不迴，香圍粉陣成飛埃。", "南冠楚囚血化碧，恨入胡笳十八拍。", "穹廬帳暖融冷光，猶隨供奉聯鵷行。", "子房忽伴赤松去，華表千年令威語。", "商郊周甸禾黍悲，宮袍卸却披霞衣。", "青藜老仙選詩哭，彷彿東都夢華錄。", "吳霜壓損長眉青，胸蟠耿耿何時平。", "讀書萬卷貧難救，天若知情天亦瘦。", "雲翻雨覆爭奈何，榮枯得失哀恨多。", "相逢莫說夢中夢，琴寄南音時一弄。", "世間未必無子期，至音元不求人知。", "泠然七十二峰下，軒轅鼎邊退三舍。", "流水行雲萬里心，故家喬木春陰陰。"]'),
('48ea4227-344c-4721-aeb2-f1890c63a0ce','題汪水雲詩卷  其一','聶守真','宋','宋诗','song-poetry','','[]','汴隄楊柳摇春風，翠華南幸紫禁空。',192,'全唐诗/poet.song.245000.json','["汴隄楊柳摇春風，翠華南幸紫禁空。", "雕欄玉砌明月冷，羽人規作神仙宮。", "蘇堤楊柳飄晴雪，又見紫鸞催駕發。", "沉香亭北鶑亂啼，金殿又成諸佛剎。", "東南王氣一旦終，乾坤四海今會同。", "興亡成敗自有數，不由人力由天公。", "二龍南翔一龍北，鳳隻鸞孤重鎩翮。", "南龍苦熱北龍寒，鸞鳳欲飛飛不得。", "周原禾黍秋離離，含光草色春萋萋。", "露盤應拆聲動地，金銅仙人空淚垂。", "來今往古知幾代，嬴顛劉蹶浮雲改。", "□平抵掌笑不言，會見桑田變滄海。"]'),
('a7330dd7-ccd2-49a3-b39b-3ba095552513','題汪水雲詩卷  其二','聶守真','宋','宋诗','song-poetry','','[]','三日錢塘海不波，子嬰繫組納山河。',64,'全唐诗/poet.song.245000.json','["三日錢塘海不波，子嬰繫組納山河。", "兵臨魯國猶弦誦，客過殷墟獨嘯歌。", "鐵馬渡江功赫奕，銅人辭漢淚滂沱。", "知章喜得黄冠賜，野水閒雲一釣簑。"]'),
('f77a5042-bb72-4a32-904e-5df65e083ad8','題汪水雲詩卷  其三','聶守真','宋','宋诗','song-poetry','','[]','一曲絲桐奏未休，蕭蕭笳鼓禁宮秋。',64,'全唐诗/poet.song.245000.json','["一曲絲桐奏未休，蕭蕭笳鼓禁宮秋。", "湖山有意風雲變，江水無情日夜流。", "供奉自歌南渡曲，拾遺能賦北征愁。", "仙人一去無消息，滄海桑田空白頭。"]'),
('91434f90-aa64-4078-bd03-af67f944b461','讀水雲丙子集  其一','聶守真','宋','宋诗','song-poetry','','[]','一夕緇塵蔽海東，潮頭無力障西風。',64,'全唐诗/poet.song.245000.json','["一夕緇塵蔽海東，潮頭無力障西風。", "汗沾鐵馬唐陵在，淚灑銅仙漢祚終。", "昨日又聞金盌出，他年誰信瓦棺空。", "中郎未抵支郎慘，地老天荒恨莫窮。"]'),
('74aa6e45-430a-47d7-ae1c-5ddc38e2ff17','讀水雲丙子集  其二','聶守真','宋','宋诗','song-poetry','','[]','宇宙倉皇過一春，鶑花無主亦銷魂。',64,'全唐诗/poet.song.245000.json','["宇宙倉皇過一春，鶑花無主亦銷魂。", "冰霜不入狼頭帽，風雨偏凌犢鼻褌。", "擊楫當年無祖逖，聞雞中夜有劉琨。", "五陵佳氣飄揚盡，誰識龍顔舊子孫。"]'),
('bdfda52c-beb3-4db7-9d21-5711c50c5b63','讀水雲丙子集  其三','聶守真','宋','宋诗','song-poetry','','["\u897f\u6e56"]','別了金臺尺五天，歸來行橐夜光縣。',64,'全唐诗/poet.song.245000.json','["別了金臺尺五天，歸來行橐夜光縣。", "劍橫碧落琴收匣，雲住青山水到淵。", "錫宴屢陪蓬島客，唱酬休憶蕊宮仙。", "故家只在西湖上，好在晴光雨色邊。"]'),
('7d707b73-712e-40b2-b2d7-ee523746220d','詔赦至感而有詩','聶守真','宋','宋诗','song-poetry','','[]','乾坤殺氣正沉沉，又聽燕臺降德音。',64,'全唐诗/poet.song.245000.json','["乾坤殺氣正沉沉，又聽燕臺降德音。", "萬口盡傳新詔好，累朝誰念舊恩深。", "分茅裂土將軍志，問舍求田父老心。", "麗正立班猶昨日，小臣無語淚霑襟。"]'),
('7d4f55c3-6a70-4730-8708-cd56dc43f674','哀被擄婦','聶守真','宋','宋诗','song-poetry','','[]','當年結髪在深閨，豈料人生有別離。',32,'全唐诗/poet.song.245000.json','["當年結髪在深閨，豈料人生有別離。", "到底不知因色誤，馬前猶自買臙脂。"]'),
('58f284ee-d7a3-4829-9796-7a47bcf167c6','咏胡婦','聶守真','宋','宋诗','song-poetry','','[]','雙柳垂鬟別樣梳，醉來馬上倩人扶。',32,'全唐诗/poet.song.245000.json','["雙柳垂鬟別樣梳，醉來馬上倩人扶。", "江南有眼何曾見，爭捲珠簾看固姑。"]'),
('90f87bc8-9fce-4933-b797-c859cc17768e','送稅官仇副使詩十首  其一','熊禾','宋','宋诗','song-poetry','','[]','儒道未易行，俛首爲祿仕。',24,'全唐诗/poet.song.245000.json','["儒道未易行，俛首爲祿仕。", "仕而不得祿，卓哉見廉吏。"]'),
('1daf7c80-a610-44b5-9cc6-fee3b2b55ab1','送稅官仇副使詩十首  其二','熊禾','宋','宋诗','song-poetry','','[]','關征足自潤，人謂惡能廉。',24,'全唐诗/poet.song.245000.json','["關征足自潤，人謂惡能廉。", "吾獨知彥脩，一葉亦不霑。"]'),
('1b70a4d0-18d7-4b7a-8d74-c5f6e6f7e93f','送稅官仇副使詩十首  其三','熊禾','宋','宋诗','song-poetry','','[]','莆城如斗大，征額鉅萬積。',24,'全唐诗/poet.song.245000.json','["莆城如斗大，征額鉅萬積。", "逭責猶未能，餘潤安可得。"]'),
('df05fbdd-e36f-42e0-b05a-75c6d583c327','送稅官仇副使詩十首  其四','熊禾','宋','宋诗','song-poetry','','[]','市廛有寬征，僚吏無間言。',24,'全唐诗/poet.song.245000.json','["市廛有寬征，僚吏無間言。", "弊例亦麾却，益知彥脩賢。"]'),
('ae568eee-db99-4ad0-af2a-53a8534e2a36','送稅官仇副使詩十首  其五','熊禾','宋','宋诗','song-poetry','','[]','課餘自哦詩，詩罷還教子。',24,'全唐诗/poet.song.245000.json','["課餘自哦詩，詩罷還教子。", "時時視橐餘，質鬻市薪米。"]'),
('f4a85da9-0734-4413-a96d-48cb1c8581fb','送稅官仇副使詩十首  其六','熊禾','宋','宋诗','song-poetry','','[]','世無半山叟，嘆息屏間詩。',24,'全唐诗/poet.song.245000.json','["世無半山叟，嘆息屏間詩。", "曾參尚投杼，知己何敢期。"]'),
('d86025ae-a6f4-460e-aea2-d59f3f0c3957','送稅官仇副使詩十首  其七','熊禾','宋','宋诗','song-poetry','','[]','古來抱關人，玩世可無悶。',24,'全唐诗/poet.song.245000.json','["古來抱關人，玩世可無悶。", "內省既不愆，得仁又何怨。"]'),
('b93688fa-888d-4976-aee3-37e5b1f3b387','送稅官仇副使詩十首  其八','熊禾','宋','宋诗','song-poetry','','[]','正直男子身，自有神與謀。',24,'全唐诗/poet.song.245000.json','["正直男子身，自有神與謀。", "世治天理現，何必事禱求。"]'),
('5dbaeeed-0043-4c26-b74a-84ac36967722','送稅官仇副使詩十首  其九','熊禾','宋','宋诗','song-poetry','','[]','彥脩但自脩，逆境堪進德。',24,'全唐诗/poet.song.245000.json','["彥脩但自脩，逆境堪進德。", "知我自有天，純固在學力。"]'),
('851e2165-a91d-441a-a1bd-a4f0cf047ff2','送稅官仇副使詩十首  其一○','熊禾','宋','宋诗','song-poetry','','[]','世事良可見，浩蕩書生心。',24,'全唐诗/poet.song.245000.json','["世事良可見，浩蕩書生心。", "先民亦會計，儒道終當行。"]'),
('a964fa32-edac-4325-b099-0f7cbc8ffa1b','上嚴廉訪十首  其一','熊禾','宋','宋诗','song-poetry','','[]','七閩天南陬，實惟文明方。',48,'全唐诗/poet.song.245000.json','["七閩天南陬，實惟文明方。", "風氣一以開，文治何其昌。", "我思常公化，迪我真無疆。", "開端固匪易，再造伊誰當。"]'),
('beb4390d-af0c-47c2-ba09-70909d217774','上嚴廉訪十首  其二','熊禾','宋','宋诗','song-poetry','','[]','大哉伊洛傳，正統接洙泗。',48,'全唐诗/poet.song.245000.json','["大哉伊洛傳，正統接洙泗。", "一源肇南來，九曲清日泚。", "百年尚無有，千載那可俟。", "崇臺勵風化，此是第一義。"]'),
('0ccf724e-4143-41e3-b088-31b56a302603','上嚴廉訪十首  其三','熊禾','宋','宋诗','song-poetry','','[]','四海文公書，行世日杲杲。',48,'全唐诗/poet.song.245000.json','["四海文公書，行世日杲杲。", "晚年制作心，三禮重探討。", "質文貴時宜，消長關世道。", "烱然百聖心，來哲當有考。"]'),
('28149239-3337-4fec-a451-7b9e59007dfe','上嚴廉訪十首  其四','熊禾','宋','宋诗','song-poetry','','[]','因思傳記學，本欲釋經義。',48,'全唐诗/poet.song.245000.json','["因思傳記學，本欲釋經義。", "春秋列三家，儀禮亦存二。", "荆舒彼何人，繁碎妄譏毀。", "煌煌姬孔書，坐此竟廢棄。"]'),
('2a73adc2-2897-423f-a6cf-5de25683776c','上嚴廉訪十首  其五','熊禾','宋','宋诗','song-poetry','','[]','春秋得忠臣，炎紹猶有述。',48,'全唐诗/poet.song.245000.json','["春秋得忠臣，炎紹猶有述。", "至今十七篇，末學或不識。", "乾淳有大儒，奏請非不力。", "一時欠良遇，志士重嗟惜。"]'),
('c56b64d1-0cee-4666-8178-ca547e93855f','上嚴廉訪十首  其六','熊禾','宋','宋诗','song-poetry','','[]','古人重民教，禮樂用爲急。',48,'全唐诗/poet.song.245000.json','["古人重民教，禮樂用爲急。", "虞書有三官，周典猶二職。", "太學領奉常，西都有餘責。", "兩生既不來，何參又無術。"]'),
('ee600abe-bd15-4316-87c6-bc413d829a17','上嚴廉訪十首  其七','熊禾','宋','宋诗','song-poetry','','[]','漢興歷數世，茲事竟未遑。',48,'全唐诗/poet.song.245000.json','["漢興歷數世，茲事竟未遑。", "一絕不復續，千載重慨慷。", "房魏輔貞觀，汗瀋空流漿。", "開寶襲唐陋，儀儼負義方。"]'),
('b50fadf0-21cc-4062-a021-5c5544c008e9','上嚴廉訪十首  其八','熊禾','宋','宋诗','song-poetry','','[]','煌煌五星聚，瑞世啟文治。',48,'全唐诗/poet.song.245000.json','["煌煌五星聚，瑞世啟文治。", "明道十事奏，橫渠一方議。", "有志不得行，曲學竟持世。", "六經亡其一，此責竟誰諉。"]'),
('9d6836af-374d-4f05-acce-aa2f65731ac9','上嚴廉訪十首  其九','熊禾','宋','宋诗','song-poetry','','[]','南方尚秉禮，文風未云衰。',48,'全唐诗/poet.song.245000.json','["南方尚秉禮，文風未云衰。", "釋奠古雅樂，鄉飲舊漢儀。", "表章在正學，舍魯將安之。", "願言假良遇，制作逢昌時。"]'),
('9066c29e-80a0-47ea-84fa-f3b968edd1e0','上嚴廉訪十首  其一○','熊禾','宋','宋诗','song-poetry','','[]','斯文迓續交，天意豈無擬。',48,'全唐诗/poet.song.245000.json','["斯文迓續交，天意豈無擬。", "猗歟恪齋翁，雅意敦典禮。", "推行大經綸，宣風自茲始。", "百世常公祠，罔俾獨專美。"]'),
('bace0edf-e2c1-432b-bc65-57a37bf200a2','贈王典史五首  其一','熊禾','宋','宋诗','song-poetry','','[]','百里古君侯，一邑天下積。',48,'全唐诗/poet.song.245000.json','["百里古君侯，一邑天下積。", "掾曹擬六官，典領幾相職。", "民親教彌數，職要事應劇。", "慎哉勿辭卑，儒術隨所益。"]'),
('ef57fb40-9835-4307-94ce-464000e8dd1c','贈王典史五首  其二','熊禾','宋','宋诗','song-poetry','','[]','愚嘗聞之師，六官欠經制。',48,'全唐诗/poet.song.245000.json','["愚嘗聞之師，六官欠經制。", "戶禮與刑兵，上法天時四。", "丞曹象陰陽，右左各分治。", "斯言擴前聞，大小豈殊致。"]'),
('8dc2309f-c48c-4f93-874b-e4d77bcd9436','贈王典史五首  其三','熊禾','宋','宋诗','song-poetry','','[]','自從大道裂，教法日益殊。',48,'全唐诗/poet.song.245000.json','["自從大道裂，教法日益殊。", "文學與政事，往往成兩途。", "簿書吏應俗，佔畢儒誠迂。", "二者不相能，世道良可吁。"]'),
('dd9bb506-baab-469f-a4e7-8c19ddc14169','贈王典史五首  其四','熊禾','宋','宋诗','song-poetry','','[]','每愛湖學規，明經必治事。',48,'全唐诗/poet.song.245000.json','["每愛湖學規，明經必治事。", "待賓與吏師，伊川有成議。", "皇極欠統一，體用非有二。", "早學無專科，已仕竟何試。"]'),
('1b214897-8b65-4d2b-81ae-840bcdd9ae30','贈王典史五首  其五','熊禾','宋','宋诗','song-poetry','','[]','我愛熙然翁，識暢度亦夷。',48,'全唐诗/poet.song.245000.json','["我愛熙然翁，識暢度亦夷。", "飾政必以儒，公餘只吟詩。", "利欲膠盆中，三嘆斯人希。", "安得公伯輩，萬宇陽春熙。"]'),
('e7fa059c-86a4-4f05-8965-a22dac539293','寄趙菊東山長三首  其一','熊禾','宋','宋诗','song-poetry','','[]','男兒貴神交，何必見顔色。',48,'全唐诗/poet.song.245000.json','["男兒貴神交，何必見顔色。", "大江有佳士，夢寐不可得。", "忽來幔亭間，片雲不相識。", "娟娟已在眼，猶此一水隔。"]'),
('dfb7ab3e-3903-49b8-a50b-6db362ebb22d','寄趙菊東山長三首  其二','熊禾','宋','宋诗','song-poetry','','[]','澹然幽貞姿，乃是夕英菊。',48,'全唐诗/poet.song.245000.json','["澹然幽貞姿，乃是夕英菊。", "托根九秋抄，霜露凄已肅。", "我疑靈均伴，只有淵明獨。", "采采黄金花，豈意杜陵曲。"]'),
('08498a50-4333-4b08-bbf2-566a4d56bdc6','寄趙菊東山長三首  其三','熊禾','宋','宋诗','song-poetry','','[]','胡爲此不采，却采泮水芹。',48,'全唐诗/poet.song.245000.json','["胡爲此不采，却采泮水芹。", "聖人望魯念，彼黍車轔轔。", "餘澤孟孫氏，管商何足論。", "新畬有陳根，猶是豐芑春。"]'),
('1a19cc75-9fc9-4740-8529-82fc9d5e4cb0','三山先賢祠落成八首  其一','熊禾','宋','宋诗','song-poetry','','[]','填宿久旅奎，一朝開文治。',48,'全唐诗/poet.song.245000.json','["填宿久旅奎，一朝開文治。", "行歌閩水春，芹藻見新意。", "林亭鬰環合，祠宮敞宏麗。", "欲賡泮宮頌，且作鄉校議。"]'),
('1fb56af8-fbaa-4daf-b260-f9c3c8e76e07','三山先賢祠落成八首  其二','熊禾','宋','宋诗','song-poetry','','[]','平地忽突兀，敏手何神哉。',48,'全唐诗/poet.song.245000.json','["平地忽突兀，敏手何神哉。", "藹然色笑中，見此通濟才。", "入門知我心，三歲猶初來。", "祀典關百世，所貴重討裁。"]'),
('8c5a43e5-2cfe-4ba6-9159-858902c455bc','三山先賢祠落成八首  其三','熊禾','宋','宋诗','song-poetry','','[]','道原出於一，秩祀安有二。',48,'全唐诗/poet.song.245000.json','["道原出於一，秩祀安有二。", "作俑唐開元，損益端有俟。", "楊馬彼何人，周程列其次。", "論議輕一時，典祀誤來世。"]'),
('5f17ca5c-807d-43ee-a53c-8ea1457f2db9','三山先賢祠落成八首  其四','熊禾','宋','宋诗','song-poetry','','[]','共惟無極翁，混元再開闢。',48,'全唐诗/poet.song.245000.json','["共惟無極翁，混元再開闢。", "關洛與考亭，杲杲行世日。", "惟此五大賢，人極頼以立。", "謂宜昭明薦，千古爲令式。"]'),
('da273a18-2dad-4c9f-8805-43a7a4e7c3c3','三山先賢祠落成八首  其五','熊禾','宋','宋诗','song-poetry','','[]','武夷九曲水，流出三神山。',48,'全唐诗/poet.song.245000.json','["武夷九曲水，流出三神山。", "考亭得勉齋，壁立孔門顔。", "信齋繼其志，經禮頼以完。", "六經復其一，百世功不刊。"]'),
('dbed09e4-1036-43e9-b0ea-0a2231c113a1','三山先賢祠落成八首  其六','熊禾','宋','宋诗','song-poetry','','[]','憶昔文治初，觀風有常公。',48,'全唐诗/poet.song.245000.json','["憶昔文治初，觀風有常公。", "維時得歐陽，名籍上國通。", "當年主賓美，至今藹餘風。", "新祠薦泉菊，還宜列同宮。"]'),
('a1ba4f5a-661f-4439-bd2e-8158528c7453','三山先賢祠落成八首  其七','熊禾','宋','宋诗','song-poetry','','[]','州牧風化遺，鄉賢典刑舊。',48,'全唐诗/poet.song.245000.json','["州牧風化遺，鄉賢典刑舊。", "年代較後先，人品類賢否。", "公議豈有情，祀典固非苟。", "道義思無疆，功言期不朽。"]'),
('347b209e-6cf1-4b97-9f72-ad9b4e6fc9ac','三山先賢祠落成八首  其八','熊禾','宋','宋诗','song-poetry','','[]','偉哉雲溪翁，興學功百世。',48,'全唐诗/poet.song.245000.json','["偉哉雲溪翁，興學功百世。", "豈求奐輪美，作事見典制。", "迂生吐狂愚，萬一裨末議。", "他時勒堅珉，洋洋可無愧。"]'),
('6827b867-90ba-4f19-9686-ebc892f2a165','贈朱仁甫','熊禾','宋','宋诗','song-poetry','','[]','吾宗賢叔父，窮壤一全人。',48,'全唐诗/poet.song.245000.json','["吾宗賢叔父，窮壤一全人。", "欲義終取義，求仁果得仁。", "夜常形夢寐，晝亦想精神。", "寄語賢孫子，天知我一真。"]'),
('7be436af-8504-4a25-ba94-db67a46924d8','荒城步月','熊禾','宋','宋诗','song-poetry','','[]','出門喜清曠，興盡喚歸船。',48,'全唐诗/poet.song.245000.json','["出門喜清曠，興盡喚歸船。", "携手共明月，知心惟老天。", "暮潮生遠浦，秋色滿平田。", "落落男兒事，相逢豈偶然。"]'),
('1e6b08cf-99b1-4971-a076-2abd66d48157','泊舟野望','熊禾','宋','宋诗','song-poetry','','[]','樹色連雲色，春歸物更妍。',48,'全唐诗/poet.song.245000.json','["樹色連雲色，春歸物更妍。", "落紅飄近岸，新綠漲平川。", "野鸛窺漁笱，沙鷗避客船。", "斜陽江上立，搔首意茫然。"]'),
('48f1f691-8389-4aff-b716-e27f12ac5132','登昇真岩','熊禾','宋','宋诗','song-poetry','','[]','仙宮鬰岧嶢，仰望如升天。',48,'全唐诗/poet.song.245000.json','["仙宮鬰岧嶢，仰望如升天。", "人生無羽翰，凡骨難神仙。", "行險非所願，攀高已無緣。", "且安平易道，聊以返自然。"]'),
('b2b6e64f-2143-4c07-9010-d8056134f2d1','蒙泉','熊禾','宋','宋诗','song-poetry','','[]','天池有佳水，雲氣護深山。',48,'全唐诗/poet.song.245000.json','["天池有佳水，雲氣護深山。", "我愛泓澄好，人嫌澤潤慳。", "暗空鳴滴滴，高壁瀉潺潺。", "漸近塵泥涴，何時復此還。"]'),
('496de290-4e82-4187-b4b4-7be3af5c1820','贈筆生','熊禾','宋','宋诗','song-poetry','','[]','東坡詠鼠鬚，山谷歌猩猩。',60,'全唐诗/poet.song.245000.json','["東坡詠鼠鬚，山谷歌猩猩。", "微物豈足道，斯文頗關情。", "片言斧鉞凜，一字華衮榮。", "化工運方寸，亦自芒端生。", "寄語管城子，所托甚非輕。"]'),
('e54b2a0a-0354-405f-9c0b-8b60becf48fe','贈琢硯','熊禾','宋','宋诗','song-poetry','','[]','我聞銅雀瓦，只覆嬌屋姝。',84,'全唐诗/poet.song.245000.json','["我聞銅雀瓦，只覆嬌屋姝。", "又聞端溪石，只近貪泉夫。", "胡爲得貴重，置我几案隅。", "尚恐習氣膩，解使簡冊污。", "我有一寸鐵，秉心與之俱。", "永矢磨不磷，千載明區區。", "彼哉瓦與石，飄擲付太虛。"]'),
('dfdacd5e-6cd3-4637-86e3-ca00dd3c2061','題山雲海月樓','熊禾','宋','宋诗','song-poetry','','[]','壺山一片雲，滄海一輪月。',96,'全唐诗/poet.song.245000.json','["壺山一片雲，滄海一輪月。", "仁人典刑靜，志士胸次闊。", "我來登斯樓，撫景亦奇絕。", "一天任舒卷，萬古看出沒。", "吟情俯八極，酒興小溟渤。", "雲來地脈動，雲去悄無迹。", "月出天光生，月落萬山黑。", "歸來一夢覺，東窗又明發。"]'),
('90bc920f-75ef-41e1-8436-15f3838244ea','聞崇安縣學立碑','熊禾','宋','宋诗','song-poetry','','[]','出山未踰月，輒復入山去。',192,'全唐诗/poet.song.245000.json','["出山未踰月，輒復入山去。", "平生武夷志，茲遊適真遇。", "誅茅倘可遂，豈但山水趣。", "扶摇欣夙心，躊躇動長慮。", "恭惟文公學，倡道匪虛語。", "向微剖析功，斯人遂聾瞽。", "齋居一原嘆，此嘆無人悟。", "晚年制作心，門人未輕許。", "真實浸泬寥，枝葉謾誇詡。", "漂淪未百年，剽竊立門戶。", "吾黨固有愆，斯道自今古。", "扶偏須忠臣，邪說可無距。", "同志此來游，興言激余素。", "禮樂愧河汾，興唐竟誰予。", "大隠堂前水，滔滔自東注。", "回薄萬古心，無言對天柱。"]'),
('18b2aa85-df26-4944-937a-00475b6c4be3','寄張廉訪','熊禾','宋','宋诗','song-poetry','','[]','七閩古要荒，是爲越南徼。',288,'全唐诗/poet.song.245000.json','["七閩古要荒，是爲越南徼。", "秦漢列職方，居民亦稀少。", "文風漸褰開，李唐盛稱表。", "問之何因爾，風氣有先兆。", "桓桓觀察公，切切廑告詔。", "至今章掖流，詩書被餘照。", "伊洛道既南，考亭重繼紹。", "譬之中天日，萬古垂炳耀。", "豈但行中原，衣被彌嶺嶠。", "云胡一氣遷，變化有難料。", "百年詩書地，末俗事攘矯。", "豈是殷民頑，此亦關感召。", "天下本無事，庸人自爲擾。", "庸人亦何傷，貪人禍非小。", "小貪人易知，大貪一何巧。", "豺狼不堪問，狐鼠何足道。", "哀哀清漳民，仁者宜一吊。", "何年彗旄頭，燐火猶有爝。", "十家九空荒，落日曛野燒。", "邇來痛甫定，生意漸原草。", "三年兩徵兵，行人亦傷悼。", "閩地本磽瘠，山海相带繞。", "兩耕不供餐，儉歲即有莩。", "獨藉煮海餘，易以供歲調。"]'),
('81c549f6-062e-4307-b740-4ce3a41b6cb4','題林氏藥圃','熊禾','宋','宋诗','song-poetry','','[]','採藥來，神山在何許。',286,'全唐诗/poet.song.245000.json','["採藥來，神山在何許。", "忽聞瀛海頭，居然一玄圃。", "天風吹輕帆，至人展良晤。", "圃中藥千本，歷歷皆手樹。", "我生抱奇疢，歲久不得愈。", "三年蓄艾心，有此一朝聚。", "惠我方匕劑，翛然脫沈痼。", "吾觀此圃中，來遊亦無數。", "夫豈獨我私，一一隨所取。", "同游二三友，牽連亦遭遇。", "餐此霞屑餘，騰身即飛翥。", "人生各有累，那得免患苦。", "至人略形骸，一視等胞與。", "過之或忘情，我獨刻肺腑。", "世人持狹見，一膜便爾汝。", "比鄰立藩牆，邊幅生齟齬。", "老矣多閲人，知君用心處。", "斯人匪斯今，意度一何溥。", "我嘗讀西銘，一初混中處。", "茫茫大化運，上下四方宇。", "當作一圃觀，何物不儲貯。", "豈但百草性，曾入農氏譜。", "奇葩與異石，海陸細分部。", "金膏丹空青，亦不憚遠阻。"]'),
('a7daac25-8950-4984-8025-bcb21dfe0dbd','上致用院李同知論海舶','熊禾','宋','宋诗','song-poetry','','[]','易經致民用，肇自羲農先。',288,'全唐诗/poet.song.245000.json','["易經致民用，肇自羲農先。", "耒耜既生聚，市易還懋遷。", "公私不交病，本末無倒懸。", "古人致主術，稱物靡有偏。", "厥初禹作貢，不但中邦田。", "四海自錫貢，不憚來遠邊。", "碣石來冀右，海岱青徐連。", "東南並淮揚，亦自江海沿。", "夫豈寶遠物，有道歸陶甄。", "成周制國用，半在周官編。", "虞衡與商賈，胡不末利捐。", "艱難開國心，什一猶欲蠲。", "裒益固有道，公功格皇天。", "後儒不知學，說理多虛玄。", "生財昧大道，民命日益朘。", "管商一作俑，蠹弊貽千年。", "漁鹽尚抑末，奈何誘開阡。", "懷清一以築，煢獨堪哀憐。", "封君擅半賦，公私重熬煎。", "寒機凍女手，汗粒赬農肩。", "織衣不上體，舂粟不下咽。", "傷哉力田家，欲說涕淚漣。", "何如棄之去，逐末利百千。", "矧此賈舶人，入海如登仙。"]'),
('e0daf09a-b0ca-4ef4-aabd-984c7d39d3d6','春雨','熊禾','宋','宋诗','song-poetry','','[]','春來一月雨，米斗錢三千。',132,'全唐诗/poet.song.245000.json','["春來一月雨，米斗錢三千。", "江空盡絕市，竈冷厨無烟。", "我從莆城來，四望良凄然。", "濱海皆食淡，邏卒相尋挻。", "纍纍起夫役，庶局供熬煎。", "玉食寧幾何，千百俱並緣。", "祇今二月節，何暇及種田。", "使臣詢民瘼，當務固有先。", "近倉有陳粟，庶解朝夕懸。", "州縣價一平，鄉閭自然寬。", "欲言事何限，何當息民肩。"]'),
('c6c47487-b8c5-4357-bdfc-e723409c6fc7','茶荔謠','熊禾','宋','宋诗','song-poetry','','[]','陽春播一氣，著處成芳菲。',288,'全唐诗/poet.song.245000.json','["陽春播一氣，著處成芳菲。", "閩地本荒落，山川亦何奇。", "嬴劉始爲郡，望秩暨武夷。", "通仕良鮮少，貢入還稀微。", "晚唐得常公，文化今有遺。", "國初歸職方，况復兵革稀。", "聖化溥涵育，生生浩無涯。", "昭陵銳圖治，四夷息鞭笞。", "峨峨四諫官，日晏猶彤墀。", "君謨起南服，感知無不爲。", "芹曝猶欲獻，茶貢詎非宜。", "草木貴多識，荔譜何傷而。", "豈意成濫觴，歲獻妨耕犁。", "當年東坡老，作詩嘆荔枝。", "詩語似成讖，采茶武夷溪。", "民力固甚憊，卉木且具腓。", "士人作是事，興言痛心脾。", "閩溪何澍湃，閩山何嶔𡼭。", "彼一草木秀，不憚勤航梯。", "昌黎感二鳥，世道矧益漓。", "我思全盛際，賢書連馹馳。", "公卿項背望，仄席須謀惟。", "十家九詩書，三年下芝泥。", "宣靖名節著，炎紹勳業資。"]'),
('aac932d3-387f-48ba-9bf8-bd2bc60f43d7','探梅','熊禾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我歸及初夏，正值梅黄時。',288,'全唐诗/poet.song.245000.json','["我歸及初夏，正值梅黄時。", "曾得二三友，共賦梅仁詩。", "當時梅樹下，捋實攀條枝。", "顧此廊廟物，棄之或塗泥。", "豈不盤實供，酸澀終見遺。", "古來遇不遇，物理亦可推。", "凉風八九月，葉盡條枝痿。", "精華雖內腴，知者良亦希。", "而况腔殻中，認此一性微。", "古今詠梅者，此趣誰得知。", "仁者天地心，生生無窮期。", "維此生之性，物物皆有之。", "安得似此梅，獨秉純陽姿。", "一枝一太極，靜動常相隨。", "却於坤復間，微微見端倪。", "凝陰不翕固，陽德無繇施。", "所以探梅人，用意常在茲。", "清霜十月旦，吟邊發新題。", "梅亦顧我笑，笑我世俗爲。", "無華亦無實，此境正自奇。", "半年不我問，覿面當何辭。", "見花始知樹，識趣毋乃卑。", "我今對梅語，此道何足疑。", "自守固爾分，求知豈其宜。"]'),
('c8b3c75e-deab-4578-b80a-e4a166ffe4d2','詠菊','熊禾','宋','宋诗','song-poetry','','[]','廬峰幾千仞，中有雲一龕。',252,'全唐诗/poet.song.245000.json','["廬峰幾千仞，中有雲一龕。", "幽幽遯世人，誅茅結爲庵。", "我嘗造其間，追尋極幽探。", "山中滿蘭蕙，谷口羅松杉。", "更有藥圃畦，種菊杞與甘。", "療疾還延年，未數菊水潭。", "百年未云久，澗草空毿毿。", "我居北澗北，子住南澗南。", "偶然比鄰並，妙處誰能參。", "古來種菊人，祗言晉陶潜。", "當年移南村，北地何所躭。", "亦曰素心人，可與共晤談。", "云何舍之去，我懷殊未諳。", "八表方停雲，處處迷征驂。", "何如且歸來，理此荒徑三。", "歲晚永爲伴，青松冠前岩。", "唐人愛牡丹，末俗亦易酣。", "保此霜下傑，毋令澗懷慚。", "萬古晉徵士，可使頑夫廉。", "題作柴桑人，綱目書法嚴。", "我欲質巾几，白雲滿虛簷。"]'),
('519c1dc3-4b2b-4e55-85db-e0d66e0cf4bd','遊武夷山','熊禾','宋','宋诗','song-poetry','','[]','我來武夷山，遠意起千古。',288,'全唐诗/poet.song.245000.json','["我來武夷山，遠意起千古。", "嘗疑混沌開，疏鑿未經禹。", "峽山猶古梁，洪濤莽回互。", "行舟留大壑，營巢餘斷樹。", "垠崖波濤痕，隠隠皆可臯。", "陶然上古民，要服固深阻。", "秦威何桓桓，薄海猶廣土。", "六合皆湧沸，一枝豈寧處。", "嘗言十三君，隠隠避秦侶。", "一日厭塵寰，泠然遂高舉。", "上山娛賓雲，下山滿豺虎。", "神仙何渺茫，虹橋想虛語。", "桃源亦其類，好事自誇詡。", "風氣日已開，蛇斷出真主。", "遂令閩山陬，盡入職方宇。", "漢志名始彰，祠堂用魚脯。", "流傳世代久，琳宮粲衣羽。", "至今此名山，號爲神仙府。", "恭惟我遯翁，辭闢厥功溥。", "于焉卜精廬，溪山九曲五。", "圖書盡在是，斯地儼鄒魯。", "我以負笈生，來茲有年數。", "自慚仁智心，未臯高深趣。", "斯游亦何意，會心覬真遇。"]'),
('f6b12982-ae29-4a6a-b728-a06129a6ecef','古風壽九十','熊禾','宋','宋诗','song-poetry','','[]','百年九十多，百里九十半。',168,'全唐诗/poet.song.245000.json','["百年九十多，百里九十半。", "我持千歲樽，祝公椿松算。", "憶昔釣璜叟，桓桓鷹揚旦。", "是時年未百，一出戡禍亂。", "丹書佐太平，樹立更明煥。", "又思淇澳翁，盛德爲世冠。", "懿戒亦何年，耄境若童草。", "前公十年期，丹扆隆簡眷。", "太公出爲將，遠業俟時奮。", "後公更五年，進德當不倦。", "武公入爲相，蒼生副深願。", "昭代儒老成，碩望孚衆觀。", "百年未爲多，名節千載看。", "后皇啟昌運，萬一效裨贊。"]'),
('e740db95-7b7b-4ebd-9b08-df327e53881b','與程縣尹','熊禾','宋','宋诗','song-poetry','','[]','我思程伯子，試令晉城邑。',276,'全唐诗/poet.song.245000.json','["我思程伯子，試令晉城邑。", "豈弟父母人，一念誠懇惻。", "存心民必濟，正己吏自格。", "雖然一邑小，允矣天下式。", "槃槃古東陽，亶爲禮義國。", "弦歌視曲阜，豈惟文公澤。", "尚想興學功，百年未陳迹。", "古來號難治，此語諒非必。", "人懷學道心，功化亦俄刻。", "重惟伊洛傳，道南此其脈。", "家傳餘政譜，師授存學則。", "此邦有美俗，文獻猶可及。", "接畛皆儒黌，興起易爲力。", "當今尚文化，鄉校首扶植。", "非無善政人，教化豈遑急。", "明公下車來，聲譽已洋溢。", "三年田里間，公來始休息。", "簡靜公優爲，不擾知政績。", "山人重期望，亹亹慎無斁。", "四海文公邦，正學自茲出。", "政教豈殊途，飾吏貴儒術。", "善化必因俗，吾世俱有責。", "到手事必爲，莫讓功第一。"]'),
('37dec5bb-91b9-4a80-9706-f41d6c2c0027','贈陳教諭','熊禾','宋','宋诗','song-poetry','','[]','每惟斯道南，七閩小鄒魯。',216,'全唐诗/poet.song.245000.json','["每惟斯道南，七閩小鄒魯。", "考亭四書學，日月行萬古。", "我生亦何幸，私淑欣有遇。", "南來証文獻，令人動遐慮。", "斯文欠統一，正學真一縷。", "莆陽禮義國，斂袵殷黼冔。", "緬思東湖集，復齋接前緒。", "至今耆俊多，淵源此其祖。", "德閎有聞孫，邂逅快披臯。", "儒先教化地，師傳盛稱譽。", "教成畀鄰邦，祖訓有遺矩。", "豈但美彼芹，更思甘棠樹。", "一邑召可行，盡分皆有補。", "十室有忠信，矧此萬家聚。", "派近源可尋，我來重瞻遡。", "當年絃誦聲，溪水自東注。", "典刑前輩人，溪山正堪數。", "安得杖屨陪，安溪溪頭路。"]'),
('f10a1a0a-dec7-4aff-b009-e9fe808f9bc5','送胡雙湖歸新安','熊禾','宋','宋诗','song-poetry','','[]','城南講太極，寒泉參近思。',288,'全唐诗/poet.song.245000.json','["城南講太極，寒泉參近思。", "古人學道志，千里焉得辭。", "𡼭嶔入閩錄，泱漭遊湘詩。", "共惟紫陽翁，跬步懷親慈。", "親在望雲想，親去廬墓悲。", "往迹尚歷歷，流風詎應衰。", "紫陽有學子，綽綽醇儒姿。", "手携圖象編，來扣文公祠。", "爲我再月留，著意窺精微。", "理象本一原，體用非殊岐。", "精爽諒有迪，渙然契深期。", "末流學易偏，此語慎勿疑。", "今晨出別語，愴然敘心知。", "家君授余學，感子爲發揮。", "母塋有雙湖，築室吾將依。", "願子識一語，晨昏奉無違。", "聞君陳大義，臨分重含悽。", "顧惟雙湖象，在易已具垂。", "八卦各具體，惟水獨兩之。", "兩間水爲月，聖賢常取斯。", "坎水與兌澤，行止固有時。", "說從止處得，險與行相隨。", "居原麗澤占，講習相涵滋。", "行觀游水至，德行宜常持。"]'),
('12b7cb76-a276-4513-b59c-4a8d6f8ff84a','玉融陳心我諸友蕭寺讀書','熊禾','宋','宋诗','song-poetry','','[]','偶成汗漫遊，邂逅得良際。',288,'全唐诗/poet.song.245000.json','["偶成汗漫遊，邂逅得良際。", "畏途日如湯，且作旬日憩。", "居然二三友，讀書此蕭寺。", "古人固有之，豈意見吾世。", "人生各有營，壯歲多穢氣。", "紛紛陌上兒，倥傯名與利。", "借曰未有知，蚩蚩事遊戲。", "妖艷東家桃，醲鮮西鄰醉。", "北山鬬雙陸，南園賞新荔。", "誰能空山中，作此窮活計。", "滿架儒先書，學成欲何濟。", "真如嚼餘甘，泊然味無味。", "是中有何好，吃吃不小置。", "拱手對我言，此亦各有志。", "童蒙本無知，未省學何事。", "珍重希賢人，爲我重指示。", "蔗境初未佳，漸久乃有嗜。", "况茲得摳承，詎敢萌厭棄。", "我聞重欣然，疑慮亦隨繼。", "言之豈云艱，守此諒非易。", "勇銳亦易能，堅苦方可畏。", "河汾有禮樂，興邦定房魏。", "燕山有義方，儀儼真世瑞。", "斯人未云多，斯道今豈墜。"]'),
('f3d1071b-72c3-4e57-b03f-c73608a81721','題東坡詩集後','熊禾','宋','宋诗','song-poetry','','[]','東坡真天人，再拜當斂袵。',240,'全唐诗/poet.song.245000.json','["東坡真天人，再拜當斂袵。", "千古岷峨英，浩氣發耿耿。", "用世固磊落，作詩更雄騁。", "熙寧化宜更，當國惜已甚。", "胡爲叫怒呶，使我毛髪懔。", "九天忠臣心，欲發不暇忍。", "雪堂何從容，人事得盡屏。", "江山拓胸次，風月動佳興。", "我觀此時詩，下語已清永。", "晚喫惠州飯，晨夕對蔬笋。", "和陶數十篇，習氣脫略盡。", "岷江幾百阻，到海渺萬頃。", "公詩蓋三變，每變輒近正。", "少年縱橫習，豈意造此境。", "偶於玄寂中，佳處得深省。", "學道便爲真，此語吾敢信。", "文固氣所充，要在以理勝。", "洋洋大雅音，千載嘆寥泯。", "言詩抑小技，所入宜重慎。", "我詩難示人，特此聊自警。"]'),
('caeb7ed5-1f3c-4982-94b4-2559e50418be','三綱嘆','熊禾','宋','宋诗','song-poetry','','[]','三綱首夫婦，大義天地侔。',288,'全唐诗/poet.song.245000.json','["三綱首夫婦，大義天地侔。", "世人不見理，人欲滔天流。", "卦象利牝馬，詩歌美關鳩。", "一陰與一陽，物物有匹逑。", "引手戒援溺，發言愧中冓。", "人道豈獸禽，今乃不爾猶。", "明明白晝攫，豈復人間羞。", "邇來六合混，不限風馬牛。", "燕姬與越女，妙舞還清謳。", "倍蓰與什百，但欲稱所求。", "一星欲火炎，燄燄焚林丘。", "大則相棄捐，小亦生懲尤。", "六如與五耦，傾覆卒未休。", "衽席有陷阱，談笑皆戈矛。", "天性自此夷，同氣或爲仇。", "讒言間黑白，骨肉成深仇。", "每恨共世子，天分太甚柔。", "事明易爲决，何至經瀆溝。", "不如挺之兒，處變才俱優。", "孝子成父美，豈是相嫉仇。", "家人繼之睽，二女志不投。", "一家祇三親，恩義本相繆。", "乾綱一以解，渙散更莫收。", "升堂道既絕，徒重薰養憂。"]'),
('41923318-c95e-4cad-a8bc-60b450dea465','陰字亭','熊禾','宋','宋诗','song-poetry','','[]','湧翠豈蘭亭，唐峰非山陰。',120,'全唐诗/poet.song.245000.json','["湧翠豈蘭亭，唐峰非山陰。", "一渠疏曲水，四野成茂林。", "對此坐歎息，超然起遐心。", "當年諸王集，幽情暢登臨。", "虛曠非遠識，絕勝名利襟。", "近代翁李遊，至理窮高深。", "云何夸毗子，清談且駸駸。", "抗志有近遠，撫事無古今。", "此日復何日，有酒始酌斟。", "援琴不敢發，誰歟爲知音。"]'),
('8fde1134-22c6-4a23-be43-3810d67983b8','觀釣','熊禾','宋','宋诗','song-poetry','','[]','暫停窗間詩，觀此池上釣。',72,'全唐诗/poet.song.245000.json','["暫停窗間詩，觀此池上釣。", "魚尾何沉沉，竹竿何嫋嫋。", "一絲波面動，摇曳出深沼。", "校人畜我時，活我良謂厚。", "作鱠終當供，設餌誠不料。", "何當兩相忘，萬里游浩渺。"]'),
('f376a848-b5fe-4e2b-9bb8-3ff81b659b10','上張廉訪  其一','熊禾','宋','宋诗','song-poetry','','[]','荒山十室九無人，行道三年兩調兵。',32,'全唐诗/poet.song.245000.json','["荒山十室九無人，行道三年兩調兵。", "聞得老貪今授首，老夫買犢要春耕。"]'),
('1ed2982d-2500-47d7-b4a6-3778f082e140','上張廉訪  其二','熊禾','宋','宋诗','song-poetry','','[]','書生久嘆三綱絕，天道那無一髪存。',32,'全唐诗/poet.song.245000.json','["書生久嘆三綱絕，天道那無一髪存。", "東海不須更憂旱，邇來一婦已無冤。"]'),
('a5a77ca5-d0fa-42ff-a153-41b7d6d5538f','上張廉訪  其三','熊禾','宋','宋诗','song-poetry','','[]','道傍竹馬綵旌旗，頌德歌辭紀政碑。',32,'全唐诗/poet.song.245000.json','["道傍竹馬綵旌旗，頌德歌辭紀政碑。", "使者郊原問民瘼，也應采到老夫詩。"]'),
('54fc940b-feb9-48a0-96b2-62e763d6ece2','平江舟中不寐','熊禾','宋','宋诗','song-poetry','','[]','遠水蕭蕭荻葦風，月明雲外叫孤鴻。',32,'全唐诗/poet.song.245000.json','["遠水蕭蕭荻葦風，月明雲外叫孤鴻。", "丹楓擁被疏蓬底，夢斷山深野寺鍾。"]'),
('9a53d68e-4105-4745-ae10-c73e97c0729d','江邊客舍','熊禾','宋','宋诗','song-poetry','','[]','輕寒無頼入征裘，野水閑雲總是愁。',32,'全唐诗/poet.song.245000.json','["輕寒無頼入征裘，野水閑雲總是愁。", "極目遠山橫靄外，數聲鳴櫓過蘋洲。"]'),
('45f52c44-b259-4d16-a07c-00c5c55c15ac','客舍雨','熊禾','宋','宋诗','song-poetry','','[]','青煙著雨傍樓橫，輾轉虛窗夢不成。',32,'全唐诗/poet.song.245000.json','["青煙著雨傍樓橫，輾轉虛窗夢不成。", "客裏清愁無可奈，卧聽簷溜瀉秋聲。"]'),
('cffd0e57-9297-4618-9aba-6b219a577dc8','乙酉端午聯句','熊禾','宋','宋诗','song-poetry','','[]','離騷讀罷意沈沈，痛飲狂歌作楚吟。',32,'全唐诗/poet.song.245000.json','["離騷讀罷意沈沈，痛飲狂歌作楚吟。", "魚腹有靈應瞑目，後來猶自有孫心。"]'),
('3d2cf78f-82df-40a4-bfcd-8f68f724dba6','遊南園次傍花隨柳句','熊禾','宋','宋诗','song-poetry','','[]','憂世心衰且樂天，不妨飛詠此雲川。',32,'全唐诗/poet.song.245000.json','["憂世心衰且樂天，不妨飛詠此雲川。", "天高地下有千載，物換人非無百年。"]'),
('8eea57e9-4840-4798-b0b5-f07a74237aa6','又','熊禾','宋','宋诗','song-poetry','','[]','柳綠花紅別一天，新來人物舊山川。',32,'全唐诗/poet.song.245000.json','["柳綠花紅別一天，新來人物舊山川。", "若爲喚起堯夫夢，再整三千六百年。"]'),
('b92d84f2-4ab6-457e-a731-83da8c3aa136','詠盆梅','熊禾','宋','宋诗','song-poetry','','[]','一聲羌笛晚風斜，再問花期便覺賒。',32,'全唐诗/poet.song.245000.json','["一聲羌笛晚風斜，再問花期便覺賒。", "茵幌泥沙可隨分，莫將春意殢殘花。"]'),
('d03bb4be-9032-4851-b042-0485afa2a18d','送洛陽靳都事','熊禾','宋','宋诗','song-poetry','','[]','銅駝巷陌棘風凉，尚記東都舊帝鄉。',64,'全唐诗/poet.song.245000.json','["銅駝巷陌棘風凉，尚記東都舊帝鄉。", "甲馬營空雲氣遠，杜鵑聲老洛園荒。", "天開地闢人才出，風起雲飛汗竹香。", "倘得行窩容我老，春風借地種姚黄。"]'),
('aa7327b9-c78f-479b-92cb-83c0c45f7720','別福清諸友','熊禾','宋','宋诗','song-poetry','','[]','自從堯曆數昌辰，已是三千六百春。',64,'全唐诗/poet.song.245000.json','["自從堯曆數昌辰，已是三千六百春。", "渺渺文明知幾聚，悠悠蓋壤定何人。", "斯文一縷千鈞日，我輩三綱五典身。", "日邁月征各珍重，幾多疏缺待彌綸。"]'),
('821f09fa-586a-423b-8e1c-4b2c69f1ef3d','聞讀書有感','熊禾','宋','宋诗','song-poetry','','[]','萬疊青山鎖暮陰，倚欄凝竚意深深。',64,'全唐诗/poet.song.245000.json','["萬疊青山鎖暮陰，倚欄凝竚意深深。", "趁時士女忺秦服，學語兒童解楚吟。", "當日繁華逐流水，何年拱把秀穹林。", "遼東俎豆銅川筮，認取斯人萬古心。"]'),
('24e32c7b-50b3-438d-857e-b02121c7e2b7','勉無咎  其一','熊禾','宋','宋诗','song-poetry','','[]','萬古綱常六尺軀，可嗤杜老悔爲儒。',64,'全唐诗/poet.song.245000.json','["萬古綱常六尺軀，可嗤杜老悔爲儒。", "林間已聽鳩呼婦，竹外行看鳳引雛。", "倘有牛眠先卜兆，豈無盤谷早營菟。", "世間忙處應多錯，儘把韋弦玩座隅。"]'),
('e7c1f070-ed35-4b09-8bc0-dc8d8b46602e','勉無咎  其二','熊禾','宋','宋诗','song-poetry','','[]','喚作三才祇此軀，乾坤一日可無儒。',64,'全唐诗/poet.song.245000.json','["喚作三才祇此軀，乾坤一日可無儒。", "稍餘禮義存餘脈，亟把詩書教小雛。", "黑窣窣時魚是魯，聲嗚嗚處虎爲菟。", "祇今時節當如此，可笑迂生獨向隅。"]'),
('3f17a724-d3d2-4333-bf2a-fed6271cefa0','經理武夷書院','熊禾','宋','宋诗','song-poetry','','[]','大隠東南第幾峰，我思論學武夷翁。',64,'全唐诗/poet.song.245000.json','["大隠東南第幾峰，我思論學武夷翁。", "春秋時義今如昨，文獻風流已不同。", "陽欲復時宜靜俟，道當窮處有時通。", "先生若有觀梅約，好把篇詩和渚宮。"]'),
('c0004895-dd66-43c0-a968-bbe4f16bcf26','經理建陽縣學','熊禾','宋','宋诗','song-poetry','','[]','當年衛道大賢功，人士今知有學宮。',64,'全唐诗/poet.song.245000.json','["當年衛道大賢功，人士今知有學宮。", "自嘆升堂慚董子，豈無笑列議韓公。", "儒風濟濟衣冠舊，世事茫茫塵網中。", "我已結茅溪五曲，飛鴻尚許遡天風。"]'),
('a71449f5-0533-48c7-9132-a80351c91b12','越州道中','熊禾','宋','宋诗','song-poetry','','[]','野田秋溜正潺潺，新翠喬林繞舍環。',64,'全唐诗/poet.song.245000.json','["野田秋溜正潺潺，新翠喬林繞舍環。", "淡日凝煙橫別浦，斜風吹雨過前山。", "柴扉初放牛羊出，漁艇方携蟹蛤還。", "自笑平生愛遊覽，天教長在水雲間。"]'),
('08f56b38-98c9-40ad-b681-4dbb3038ced6','客裏書事','熊禾','宋','宋诗','song-poetry','','[]','西風凉信入虛簷，絺綌微單已戒嚴。',64,'全唐诗/poet.song.245000.json','["西風凉信入虛簷，絺綌微單已戒嚴。", "鄉夢不隨秋夜永，客愁偏向雨聲添。", "清高鳴雁低雲海，漂泊流螢傍竹簾。", "搔首寒燈樓舍悄，行藏自曉不須占。"]'),
('1f9eb6b6-4ccd-4b76-9941-d3da41895acd','奉懷明仲舊鄰舍','熊禾','宋','宋诗','song-poetry','','[]','久客爲鄰憶杖藜，情親端與弟兄齊。',64,'全唐诗/poet.song.245000.json','["久客爲鄰憶杖藜，情親端與弟兄齊。", "一生磨螘團團走，百事枰棋著著低。", "武定波寒看落月，石頭秋晚弔荒蹊。", "茅簷作計能成否，破壁何堪草滿畦。"]'),
('e50424db-4e6b-4ec5-bd86-3dece95c0845','蕪湖過繁昌旅舍蕭然偶書','熊禾','宋','宋诗','song-poetry','','[]','竹窗漸白卷寒衾，上巳纔過節物深。',64,'全唐诗/poet.song.245000.json','["竹窗漸白卷寒衾，上巳纔過節物深。", "野杏出籬明望眼，蔞蒿滿地藹愁心。", "已知賦分多行役，焉用詩鳴得賞音。", "春在江山無限好，緩驅羸馬度煙林。"]'),
('ed90bca7-d426-4495-9583-660e76a7a394','乙巳元日鰲峰書院會拜五十五人','熊禾','宋','宋诗','song-poetry','','[]','曉日曈曈一歲初，鄉閭盛會說吾廬。',64,'全唐诗/poet.song.245000.json','["曉日曈曈一歲初，鄉閭盛會說吾廬。", "運當堯歷三千六，數協羲圖五十餘。", "脩竹歲寒欣得友，野花春色且携書。", "大篇聽取艱貞訓，萬古天心定不虛。"]'),
('979aca25-5e78-4390-a400-60fafa747ad7','入武夷山二首  其一','熊禾','宋','宋诗','song-poetry','','[]','一見識君多道氣，再陪杖屨此躋攀。',64,'全唐诗/poet.song.245000.json','["一見識君多道氣，再陪杖屨此躋攀。", "高山流水知公志，明月清風共我閑。", "落落半生心未泯，寥寥千載事相關。", "出山一步塵埃滿，便好賫糧莫出山。"]'),
('afe48003-c5e8-4fde-8b38-9ea1b4a8ccb5','入武夷山二首  其二','熊禾','宋','宋诗','song-poetry','','[]','試問山中亦何好，見山便自喜居山。',64,'全唐诗/poet.song.245000.json','["試問山中亦何好，見山便自喜居山。", "不堪造物半生役，枉使男兒百歲閑。", "天柱沈冥陰雨外，幔亭縹渺彩雲間。", "蒼生辛苦何終極，控鶴仙人去不還。"]'),
('9bff7c5e-2afd-433a-a34e-5a520462c72c','索茶','熊禾','宋','宋诗','song-poetry','','[]','兩帙詩課早已了，三杯酒債亦可休。',64,'全唐诗/poet.song.245000.json','["兩帙詩課早已了，三杯酒債亦可休。", "我去問君去無去，君留任我留不留。", "門前雨深泥滑滑，道人四壁風颼颼。", "且留看詩可罷酒，請燒香鼎調茶甌。"]'),
('e7446434-61b6-47ba-8327-caa866f9e1dc','上劉治中','熊禾','宋','宋诗','song-poetry','','[]','弱水流西河水東，瞻烏爰止誰雌雄，天地方閉何時通。',104,'全唐诗/poet.song.245000.json','["弱水流西河水東，瞻烏爰止誰雌雄，天地方閉何時通。", "顛倒溷室成仙宮，我羨仙人在高空，絕粒輕舉乘天風。", "豢養不及真神龍，人生剪羽樊籠中，名尤利怨方相攻。", "忽聞海上蓬萊翁，却來幔亭跨長虹。", "願留徜徉群仙峰，塵寰渺渺知何窮。"]'),
('f0834ff4-6801-49b9-9ebc-6c460cda4712','擣衣曲','熊禾','宋','宋诗','song-poetry','','[]','北望悠悠音信少，空房念遠心常早。',96,'全唐诗/poet.song.245000.json','["北望悠悠音信少，空房念遠心常早。", "流螢煜煜夜稍清，寒雁嗈嗈寒已到。", "細絲清水練方新，在椸半濕日中明。", "隔籬翁媼寐不熟，月落尚聞砧杵聲。", "將軍錦帳環歌舞，百戰尚遲歸寸土。", "老農肩米肉成瘡，思婦裁衣淚如雨。"]'),
('f5bdc03c-cbe7-4b39-9273-6a12a5efa0ae','贈朱仁甫','熊禾','宋','宋诗','song-poetry','','[]','九州四海文公書，千秋萬古文公祠。',240,'全唐诗/poet.song.245000.json','["九州四海文公書，千秋萬古文公祠。", "文公之祠何所始，考亭雲谷與武夷。", "建安城中一畝地，桓桓寢廣世守之。", "時人擬作曲阜宅，表章何代壞者誰。", "魯餘宮室已壯麗，廣地何必取此爲。", "鮒池藏書抱祭器，間關之際亦可悲。", "斯人今代不復見，爲公故宅三歔欷。", "玄孫適此相邂逅，劇談往事無休期。", "別來已是二十載，城府之事了不知。", "但聞祠堂舊基址，勢家亭館今巍巍。", "東邊自是子住處，一枝不許鳥鵲棲。", "成都閟宮思丞相，通泉書室記□□。", "斯文所係豈止此，經從此地空漣洏。", "百年公論會有定，文公之後人見知。", "子行定有我同志，爲我問訊出此詩。"]'),
('fe4557e1-ad8a-4c66-8b39-e436723e73a9','春光歎','熊禾','宋','宋诗','song-poetry','','[]','平生不喜桃李春，懶隨年少爭芳新。',192,'全唐诗/poet.song.245000.json','["平生不喜桃李春，懶隨年少爭芳新。", "堂前酌我金叵羅，春衫密縫恣其仁。", "出郊相逢好朋伴，贈我殽羞薦歌管。", "等閑對客難爲勸，强作春妍趁遊衍。", "人言洛陽富春光，我來看花如醉狂。", "蚩堤欲决值連雨，著鞭跨馬空自忙。", "天津一聲來杜宇，東君冉冉歸何處。", "春會有歸歸太早，忍見紅荒在塵土。", "歸來山中自閉門，落花片片餘空山。", "今春只向風雨過，傷春懷抱將誰言。", "武陵風景四時好，扁舟徑問桃源叟。", "春來春去總不知，賞心一付尋芳友。"]'),
('0319a4d4-6cee-4967-84f0-858e24952e15','觀洛行','熊禾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','我生海南萬山間，出門岡隴相迴環。',384,'全唐诗/poet.song.245000.json','["我生海南萬山間，出門岡隴相迴環。", "平田更無十里闊，何處知有天地寬。", "男兒墮地六合志，抱此一寸常悁悁。", "早年曾作天府客，長歌東出穆陵關。", "關頭仰天坐嘆息，百年事業如彈丸。", "乾坤只限衣带水，何繇萬里窺中原。", "只今文軌一朝混，地不改辟時易然。", "斯須洛京見嵩華，咫尺孔林登泰山。", "聖賢往迹正在此，譬若木水有本原。", "北方學道古所貴，當年楚産皆其偏。", "從來一氣有旺歇，况及人事多移遷。", "程門立雪道南後，幸此一脈猶綿延。", "武夷考亭今洙泗，文公之學行八埏。", "當時亦號小洛陽，游胡劉蔡居相聯。", "風流不減程邵馬，至今故老人能言。", "起來高目視八荒，斯文一縷千鈞懸。", "人心不啻溺焚急，茫茫大柄伊誰顓。", "但得人讀周孔書，不患古道今無傳。", "圖書龍馬事闊遠，滎河溫洛仍當年。", "疇分三三卦八八，舉目法象非虛玄。", "大哉伊亳一德書，此極翼翼甸幅員。", "太平六典深識此，下方餘意公惓惓。", "不惟周官列三百，更將儀禮陳三千。", "成周致治絕千古，空餘軌則留殘編。"]'),
('a3fc29b2-7d01-4167-b3ee-28dc50470362','贈周善長省親','熊禾','宋','宋诗','song-poetry','','[]','客路三千親七十，行道無情亦沾臆。',288,'全唐诗/poet.song.245000.json','["客路三千親七十，行道無情亦沾臆。", "阿娘七十更加四，阿翁七十更加八。", "人生至樂那有是，君獨胡爲此役役。", "五鼎珍羞不見多，一盂菽水堪爲悅。", "八方渺渺夕陽西，與君早决歸來策。", "高曾規矩父弓冶，君家正印斯文脈。", "我生喜讀平園文，到老更看梅谷集。", "此翁豈弟真可人，直把文章事游劇。", "慶兒二首望不淺，城山佳讖真端的。", "相邊佳作漸家數，慎真不覺譽兒癖。", "更想高陽壽內辭，曾是修行嚥梅實。", "二老隨宜也自歡，終欠斑衣兒在側。", "須知團聚第一樂，此外蠅知總無益。", "名驥墜地千里心，丹鳳沖霄九秋翼。", "蕭曹事業已千千，當年豈要從刀筆。", "丈夫未遇固脫略，時人孰測調元術。", "平園相譜當相傳，撫卷臨風三嘆息。", "勗哉勗哉後之人，百世詩書尚餘澤。"]'),
('b05c5997-5b1f-4169-b995-0db19e215565','湧翠亭梅花','熊禾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','來者爲新去爲陳，陰陽如代各還春。',256,'全唐诗/poet.song.245000.json','["來者爲新去爲陳，陰陽如代各還春。", "花開花謝亦常理，對花不必尤花神。", "平生性耆不在花，兩年頗與梅相親。", "何人種梅繞此屋，一見使我心清冷。", "老樹槎牙溪側徑，枯枝倒掛池邊亭。", "花開主人不復賞，我來却作花主人。", "此花不必相香色，凜凜大節何崢嶸。", "北海雪深臣皓首，霜寒中野兒悲吟。", "荷蓧老人留植杖，滄浪孺子來濯纓。", "神人妃子固有態，此花不是兒女情。", "托根山谷居歲晚，自分不及芳春辰。", "春前臘後挺高潔，留與桃李爭妍新。", "春寒桃李猶未開，莫隨羌管輕飄零。", "先生自是絕俗士，西湖東閤當齊名。", "巡簷索笑興不淺，金樽檀板隨紅塵。", "斯言近戲君勿訝，南山松柏終年青。"]'),
('66343add-9549-43a1-ae9c-de0249647e7e','贈醫士詹翠峰','熊禾','宋','宋诗','song-poetry','','[]','我觀卦氣先天圖，更參歧伯答問書。',272,'全唐诗/poet.song.245000.json','["我觀卦氣先天圖，更參歧伯答問書。", "雖然三墳不可得，此即造化陰陽樞。", "超然便可會大道，學不至此應非儒。", "醫亦其中一事耳，造妙直與神明俱。", "後人自是識根淺，九流既裂家法殊。", "儒家道家已爲二，醫術下視史與巫。", "蒼生百萬命安寄，天地生物意亦辜。", "日來運氣頗自別，顛倒溫凉與寒熱。", "衆工庸技漫嘗試，須藉良醫爲宣節。", "翠峰直是英傑士，家世箕裘素儒業。", "辭章小技我易工，要參大道融明徹。", "太上好生無別事，且向醫方究施設。", "垂簾市肆心自閑，左右圖書恣怡悅。", "便是羲皇以上人，豈但當年佗扁訣。", "今茲出手才小試，邦人感恩已凜烈。", "長歌爲作儒醫行，德君之深望君切。", "古稱良相即良醫，大化煩君更調燮。"]'),
('575ba3f9-197d-4602-b56d-7579292b1b85','贈外科醫者','熊禾','宋','宋诗','song-poetry','','[]','男兒踏地志四方，出門大路行康莊。',96,'全唐诗/poet.song.245000.json','["男兒踏地志四方，出門大路行康莊。", "况爲馹使期令速，千里萬里瞬息將。", "云胡邂逅遭一跌，頗覺平陸成羊腸。", "古云一蹶得一便，又云三折醫之良。", "幸逢瞑眩得早瘳，莫若視地足勿傷。", "生全天地父母恩，一舉足兮慎勿忘。"]'),
('0b1fa675-6788-458d-8a1e-9212fc61a3d4','與徐同知','熊禾','宋','宋诗','song-poetry','','[]','武夷山中舊學子，汗漫偶作觀海遊。',396,'全唐诗/poet.song.245000.json','["武夷山中舊學子，汗漫偶作觀海遊。", "此觀此遊亦何有，炎氛瘴雨爛不收。", "蓬萊絕島固難望，何處大澤并高丘。", "獨聞東南倚天聳石壁，上有一輪照耀之明月，下有一道演迤之清流。", "此流不求清，此月不求明。", "衆星冥濛日轂遠拍天，煙浪渺渺令人愁。", "因思八極間，品彙豈不稠。", "后皇生物至今日，茫茫大化無停輈。", "群陰剝盡碩果在，新畬再闢陳根留。", "我輩等是豐芑春，盛德何止數世謀。", "男兒生世有不朽，百年易邁千載悠。", "造物生材諒非偶，陽春有脚先南州。", "八郡春已滿，忍使四海赤子寒颼颼。", "一時澤物亦易足，旱須霖雨川須舟。", "書生却顧動遐想，願爲來世蒼生憂。", "斯文迓續正此時，安得古綆千尋脩。", "莘郊匹夫樂堯道，朝鮮逋播敘禹疇。", "兩生不來至今尚綿蕝，房魏背汗豈但唐人羞。", "禮頹樂壞二千載，欲觀周道當何繇。", "我聞伊洛道南後，武夷雲谷今魯鄒。", "孔堂金石未盡泯，淹中斷簡猶堪搜。", "獨抱遺經守迂拙，歲月兀兀春復秋。", "蚊蝱負山力謾苦，精衛填海志未休。", "書生迂拙公所知，此來見公亦何求。"]'),
('dbe713e3-8d24-4879-9a68-4acf45a1bc1b','別永福諸友','熊禾','宋','宋诗','song-poetry','','[]','高哉永陽山，清哉永陽水。',388,'全唐诗/poet.song.245000.json','["高哉永陽山，清哉永陽水。", "不須問芝嶺，不須尋桃源，桃源芝嶺近在永陽裏。", "此山朝朝暮暮有爽氣，此水一點不受汙泥滓。", "黼冕峨峨盡周獻，弦誦洋洋尚周禮。", "員顱方趾天地間，靖獻此心固何爾。", "梅坡先生真絕俗，夜月清標照寒水。", "年移物換耳不聞，不撓不汙直如矢。", "留遠先生心更苦，風雪漫漫燕萬里。", "腴田好爵某不顧，携手河梁得魚泚。", "暘彼諸老皆典刑，三嘆此邦皆俗媺。", "嗟哉世之人，醉中偷生夢中死。", "高岡千仞亦陵遲，狂衆一啜滔滔是。", "如此衣冠古人物，直入畫圖播青史。", "更有一事興我聞，後生尚及見典刑。", "兵戈生長三十載，豪傑豈必文王興。", "邇來童冠入小學，能文何啻百許人。", "雖然文章亦未授，山深最喜習氣淳。", "萬方颯颯聲一概，此地未著裘馬塵。", "甘能受和白受來，豈有質實無其文。", "古云變魯可至道，百年正學亦失真。", "尼山一何高，泗洙一何深。", "聖門登臨別是一般起，處處山水滿我仁智心。", "悠悠清泉滌我慮，飄飄長風吹我襟。", "認取當年詠歸意，與我同賦暮春吟。"]'),
('95f1d8d3-6686-4fbe-967a-5930e784b6d9','七夕遇雨訪石堂先生  其一','熊禾','宋','宋诗','song-poetry','','[]','今宵無月燭，鬃瓢瀉銀河。',36,'全唐诗/poet.song.245000.json','["今宵無月燭，鬃瓢瀉銀河。", "誰言滂沱淚，恨此離別多。", "爾會亦云數，吾感亦如何。"]'),
('737a8bab-7c85-4f87-8c99-38b46ed2da43','七夕遇雨訪石堂先生  其二','熊禾','宋','宋诗','song-poetry','','[]','冀亳與歧山，一際五百年。',36,'全唐诗/poet.song.245000.json','["冀亳與歧山，一際五百年。", "洙泗豈無集，未遇時運偏。", "世降道愈悠，擊壤呼堯天。"]'),
('1a4c6093-5fce-4591-adda-421b32accd98','七夕遇雨訪石堂先生  其三','熊禾','宋','宋诗','song-poetry','','[]','東都亦論道，忽夢金光身。',36,'全唐诗/poet.song.245000.json','["東都亦論道，忽夢金光身。", "太和豈無治，髽髪終殊倫。", "夜半一炷香，命世胡邅屯。"]'),
('1b8f049a-7e8a-4588-a89f-5653840642f2','七夕遇雨訪石堂先生  其四','熊禾','宋','宋诗','song-poetry','','[]','混之再開闢，喚覺千載迷。',36,'全唐诗/poet.song.245000.json','["混之再開闢，喚覺千載迷。", "龍門空寶匣，明月照玉溪。", "五緯集未久，又報填旅奎。"]'),
('053582c5-0c9c-48ec-a889-76833ca5d6c0','七夕遇雨訪石堂先生  其五','熊禾','宋','宋诗','song-poetry','','[]','高高不可問，神光終朦朧。',36,'全唐诗/poet.song.245000.json','["高高不可問，神光終朦朧。", "雲錦不成報，謾爾欺盲聾。", "柱維久傾折，會有補煉功。"]'),
('619f298d-328c-4795-ac65-988927ff0da7','賦游高逸軒懷藍遠洞','熊禾','宋','宋诗','song-poetry','','[]','世情弱卑近，子獨志高遠。',288,'全唐诗/poet.song.245000.json','["世情弱卑近，子獨志高遠。", "中庭敞明軒，大字書鉅扁。", "軒前山百丈，山下水千澗。", "摩空屹蒼蒼，赴壑來滾滾。", "神明萬宇澄，清曠百慮遠。", "恭惟孔孟翁，古聖一關鍵。", "勿云仰之高，萬象不吾隠。", "勿云道之遠，千里在發軔。", "卓爾固難知，博約端可勉。", "一貫未易悟，忠恕力可踐。", "云胡千載間，架漏安蹇淺。", "下者志富貴，妾婦視儀衍。", "次者志功名，童子羞管晏。", "知子質直資，勿憚厪考問。", "五夫小洛陽，猶當有文獻。", "當年胡與劉，水泉得源本。", "及門紫陽人，斯道益弘闡。", "四海褰孤風，百世想遐韻。", "未登泰華高，丘阜即層巘。", "未涉海滄遠，沼沚亦深沔。", "志高猶恐卑，志遠猶恐邇。", "周公思三王，伊尹樂堯舜。", "宣尼萬世師，道在兼祖憲。", "志大心欲小，勗子宜重慎。"]'),
('2a581243-5fe5-4da8-a6fa-e5ce630782fe','石壁泉','熊禾','宋','宋诗','song-poetry','','[]','一滴流漿石骨穿，于今一掬掃炎氛。',32,'全唐诗/poet.song.245000.json','["一滴流漿石骨穿，于今一掬掃炎氛。", "鶴仙業已成陳跡，瀑布聲中隠劍痕。"]'),
('26e2c22e-c86c-4329-8e60-d354a13e5436','咏武夷懷朱晦翁','熊禾','宋','宋诗','song-poetry','','[]','五月凉巾陟翠微，竹根香露濕人衣。',64,'全唐诗/poet.song.245000.json','["五月凉巾陟翠微，竹根香露濕人衣。", "雲行老樹青猿過，雪落長溪白鷺飛。", "仙徑好花愁急雨，洞亭芳草怨斜暉。", "我來只欲平林去，細叩先生玉版扉。"]'),
('9e1575ba-ea03-4cd4-a60a-a1ed343b6b1a','赫曦臺四景 薄暮明霞','熊禾','宋','宋诗','song-poetry','','[]','赫曦薄暮真奇絕，初到殘陽復西沒。',64,'全唐诗/poet.song.245000.json','["赫曦薄暮真奇絕，初到殘陽復西沒。", "仙霞山外何處山，五彩雲霞互明滅。", "須臾群陰解剝盡，雨脚如麻漸開豁。", "冥冥勃勃不可留，空有殘霞半天赤。"]'),
('d411064d-e5ad-4d0a-bf5e-7d0a7ce53ca4','赫曦臺四景 中宵皓月','熊禾','宋','宋诗','song-poetry','','[]','赫曦日夕真奇絕，最好中秋看明月。',64,'全唐诗/poet.song.245000.json','["赫曦日夕真奇絕，最好中秋看明月。", "竦身飛上第一峰，不覺清寒近天闕。", "初離海角猶朦朧，行到天心轉光潔。", "今宵端正照山河，長笛一聲愁欲裂。"]'),
('ff490eec-abd0-48c7-b3a8-8c28885e38b2','赫曦臺四景 中夜白雲','熊禾','宋','宋诗','song-poetry','','[]','赫曦中夜真奇絕，起視茫茫大瀛渤。',64,'全唐诗/poet.song.245000.json','["赫曦中夜真奇絕，起視茫茫大瀛渤。", "風濤雪浪無際涯，絕岸時看孤島出。", "洪爐巨甑如蒸炊，囿形宇宙非金石。", "直凌倒景窺三光，俯見塵寰如超越。"]'),
('990e9a83-5c88-48ce-8d2e-6b5b421dc5ba','赫曦臺四景 鷄鳴出日','熊禾','宋','宋诗','song-poetry','','[]','赫曦清晝真奇絕，遠望海門觀出日。',64,'全唐诗/poet.song.245000.json','["赫曦清晝真奇絕，遠望海門觀出日。", "金戈鐵騎走千峰，閃閃萬旗張天赤。", "神龍飛上使人驚，爍眼祥光成五色。", "扶桑欲出升何難，認取真情凝太極。"]'),
('fe1d43b2-3ee1-4f66-9c34-3c6e37aa5238','山中  其一','于石','宋','宋诗','song-poetry','','[]','我家萬山中，日日采樵去。',48,'全唐诗/poet.song.245000.json','["我家萬山中，日日采樵去。", "捫蘿上層巔，苔滑不留履。", "落日負樵歸，雲深失歸路。", "誰家犬吠聲，聲在雲深處。"]'),
('02c8aeb5-7b13-47ff-bdcf-ed6adb5b6a45','山中  其二','于石','宋','宋诗','song-poetry','','[]','偶因抱甕出，夜汲澗底泉。',48,'全唐诗/poet.song.245000.json','["偶因抱甕出，夜汲澗底泉。", "蕩摇水中月，水定光復圓。", "問水水不語，問月月不言。", "倚樹一長嘯，萬壑松風寒。"]'),
('d0914ae6-5099-4e40-b45d-a2d5da7b7293','擬古','于石','宋','宋诗','song-poetry','','[]','君心如柳枝，春盡絮狂飛。',48,'全唐诗/poet.song.245000.json','["君心如柳枝，春盡絮狂飛。", "妾心如古木，不受春風吹。", "古木寧槁死，可伐不可移。", "風絮飛不已，飄零將安歸。"]'),
('8b19410c-399b-4aea-896f-89f0cf5d13e4','晚步','于石','宋','宋诗','song-poetry','','[]','徑狹不容車，溪淺不容釣。',48,'全唐诗/poet.song.245000.json','["徑狹不容車，溪淺不容釣。", "平蕪淡雲烟，獨鳥下殘照。", "見山孑無言，倚樹忽長嘯。", "徘徊澹忘歸，空林明遠燒。"]'),
('40f1117e-a7ff-4796-8a0c-eb38cf4df96d','有客','于石','宋','宋诗','song-poetry','','[]','有客叩我門，動色談公侯。',60,'全唐诗/poet.song.245000.json','["有客叩我門，動色談公侯。", "權門熱於火，富貴可力求。", "我性不諧俗，素拙生計謀。", "苟求未必得，徒爲君子羞。", "拂衣起謝客，夷然卧林丘。"]'),
('dda6dfad-7d24-43f0-ac8e-e993fa9dba16','和淵明詩','于石','宋','宋诗','song-poetry','','[]','林屋本深寂，而多禽鳥喧。',60,'全唐诗/poet.song.245000.json','["林屋本深寂，而多禽鳥喧。", "一靜制群動，何必更幽偏。", "西風掃脫葉，見此林杪山。", "朝看孤雲出，暮看孤雲還。", "雲飛亦何心，相對兩忘言。"]'),
('dcf56ecc-e55f-4ec6-a36e-7463914d6e90','宿棲真院分韵得獨字','于石','宋','宋诗','song-poetry','','[]','空翠冷滴衣，石蘚滑吾足。',60,'全唐诗/poet.song.245000.json','["空翠冷滴衣，石蘚滑吾足。", "偶隨白雲去，栖此林下屋。", "樓影挂斜陽，鐘聲出深竹。", "山僧老面壁，誰與伴幽獨。", "分我雲半間，欹枕聽飛瀑。"]'),
('f6a43b89-ab8b-4fe9-b8e5-6e1645e36422','寄意','于石','宋','宋诗','song-poetry','','[]','妾家有明鏡，百鍊方能成。',84,'全唐诗/poet.song.245000.json','["妾家有明鏡，百鍊方能成。", "寶匣玉爲臺，持以奉良人。", "自恃妾貌妍，懶拂鏡上塵。", "妾貌未及衰，妾鏡先已昏。", "貌衰不再少，鏡昏能再明。", "爲君一磨拭，烱烱光如新。", "徒能照妾貌，安能照妾心。"]'),
('b5c0ff56-c83a-41ba-917a-d049afabcb3b','述懷','于石','宋','宋诗','song-poetry','','[]','孔明卧隆中，世事若不聞。',72,'全唐诗/poet.song.245000.json','["孔明卧隆中，世事若不聞。", "草廬兩三策，大義固已明。", "陶潜晉處士，束带恥屈身。", "浩然歸去來，把酒惟長吟。", "潜魚遊深淵，好鳥鳴高林。", "是以古君子，出處各有心。"]'),
('f3fb6584-c413-4aa4-a7d5-07d393a8fac0','庭前有松樹','于石','宋','宋诗','song-poetry','','[]','庭前有松樹，百尺盤虬龍。',72,'全唐诗/poet.song.245000.json','["庭前有松樹，百尺盤虬龍。", "材大不適用，偃蹇霜雪中。", "五陵年少兒，種花不種松。", "寄言傲霜雪，何似媚春風。", "松有千歲根，花無十日紅。", "衆人逐時好，君子惟固窮。"]'),
('5d18bb46-7622-4f5d-a693-3831bb37f051','探梅分韻得香字','于石','宋','宋诗','song-poetry','','[]','絕壁兩屨雲，荒村半橋霜。',72,'全唐诗/poet.song.245000.json','["絕壁兩屨雲，荒村半橋霜。", "孤往欲何之，林下幽徑長。", "寒梅在何許，臨風幾徜徉。", "誰家斷籬外，一枝寄林塘。", "水靜不摇影，竹深難護香。", "無言獨倚樹，山空月荒凉。"]'),
('3ff98908-0640-4abb-80bc-ccbb5c948daf','所懷寄何寺簿','于石','宋','宋诗','song-poetry','','[]','斜日明遠樹，落葉走空階。',60,'全唐诗/poet.song.245000.json','["斜日明遠樹，落葉走空階。", "閉門寂無事，心澹境自佳。", "美人期不來，此樂誰與偕。", "豈無南飛雁，可以寄所懷。", "所懷不可寄，孤雲渺天涯。"]'),
('3dc72e1d-1a97-4965-aa70-ff14adaa52ce','蟬','于石','宋','宋诗','song-poetry','','[]','斜陽掛庭樹，有蟬鳴樹顛。',72,'全唐诗/poet.song.245000.json','["斜陽掛庭樹，有蟬鳴樹顛。", "無端聒人耳，驚我閑窗眠。", "吾觀動物中，至清莫如蟬。", "翩然蛻污濁，飽餐風露寒。", "此外一無求，何苦浪喧喧。", "口給祇屢憎，不如且忘言。"]'),
('32e4c836-0063-4377-ab4b-ac0cc11f1f6c','擬古','于石','宋','宋诗','song-poetry','','[]','東籬有佳菊，埋沒野草傍。',84,'全唐诗/poet.song.245000.json','["東籬有佳菊，埋沒野草傍。", "草蔓日以滋，菊苗日以荒。", "生意幾欲息，菊短草何長。", "深秋嚴霜下，百草不復芳。", "采采東籬花，澹然發幽香。", "萬物各有時，盛衰固其常。", "榮華不足恃，窮困果何傷。"]'),
('a3937231-8b30-41d3-9c7d-bd982183ffc3','送趙宰之上虞  其一','于石','宋','宋诗','song-poetry','','[]','百里子男邦，職任非不厚。',96,'全唐诗/poet.song.245000.json','["百里子男邦，職任非不厚。", "治民如牧羊，擾之則驚走。", "睠茲上虞邑，江海環左右。", "蕭蕭北風寒，怒濤聲撼吼。", "元亮已賦歸，世事付盃酒。", "宗子古維城，此行應不苟。", "繭絲與保障，二者孰先後。", "勉旃重勉旃，毋袖經綸手。"]'),
('b81d95c4-8f56-4bd7-bc18-f4f4d20b4134','送趙宰之上虞  其二','于石','宋','宋诗','song-poetry','','[]','吾聞句踐國，昔有鴟夷子。',96,'全唐诗/poet.song.245000.json','["吾聞句踐國，昔有鴟夷子。", "沼吳收雋功，扁舟五湖裏。", "又聞越東山，安石真奇士。", "一局別墅棋，失笑屐折齒。", "緬懷百世風，可以肅頑鄙。", "峨峨禹穴山，滔滔浙江水。", "山川今猶昔，寧無安與蠡。", "爲我謝二公，幸爲蒼生起。"]'),
('0f171d25-80b4-4460-a109-247d2724d92c','感興  其一','于石','宋','宋诗','song-poetry','','[]','愚公欲移山，精衛欲填海。',96,'全唐诗/poet.song.245000.json','["愚公欲移山，精衛欲填海。", "嗟乎智力窮，山海元不改。", "春秋更戰國，仁義日荒怠。", "近趨管晏功，遠受儀秦詒。", "楊墨騁邪說，申韓禍無罪。", "孔孟生其間，迂闊誰復採。", "羣囂競紛紜，智力幾百倍。", "山崩海可竭，吾道固長在。"]'),
('9cb9a23c-35e1-4edb-80df-61ada81c1ddc','感興  其二','于石','宋','宋诗','song-poetry','','[]','游魚聞餌香，寧悟鈎入口。',96,'全唐诗/poet.song.245000.json','["游魚聞餌香，寧悟鈎入口。", "不忍一朝饑，竟落漁人手。", "捕雉必以媒，相呼欣得偶。", "失身羅網中，乃爲媒所誘。", "嗟哉二物微，智不料其後。", "飛潜一失所，雖悔復何咎。", "矧爲物之靈，而不慎所守。", "饑渴能害心，交游多賣友。"]'),
('70114601-8811-40ec-b84a-3ad89626d395','次韻秉國種菊','于石','宋','宋诗','song-poetry','','[]','淵明令彭澤，自謂歸來好。',108,'全唐诗/poet.song.245000.json','["淵明令彭澤，自謂歸來好。", "外物一無累，剛被菊花惱。", "東籬興悠然，一醉舒懷抱。", "陶沒已千載，愛菊人何少。", "誰能輕富貴，高蹈一世表。", "種菊學淵明，此意何矯矯。", "栽培春雨中，不待秋風老。", "南山無古今，世事何時了。", "先生笑不言，杜門方却掃。"]'),
('e100e424-3390-4350-b232-b09d10c61454','贈張君玉','于石','宋','宋诗','song-poetry','','[]','閉門十日雨，蕭然抱孤琴。',96,'全唐诗/poet.song.245000.json','["閉門十日雨，蕭然抱孤琴。", "之子從何來，踏雨叩我門。", "對床話達曉，山窗耿青燈。", "挽衣不可留，何以贈子行。", "問子此何時，瞇目凄黄塵。", "四海非不寬，可語今幾人。", "瀟瀟風雨中，奔走欲何營。", "願子重自愛，堂有白髪親。"]'),
('8f599a5a-30a9-4926-9432-160a3a7d242a','八月十四夜對月','于石','宋','宋诗','song-poetry','','[]','好風從西來，浮雲忽中披。',108,'全唐诗/poet.song.245000.json','["好風從西來，浮雲忽中披。", "片月耿層空，清氣入詩脾。", "皎皎萬里光，誰言一分虧。", "虧者盈之漸，乘除迭相推。", "既圓終復缺，何如未圓時。", "過滿易招損，極盛必有衰。", "人事無不然，一笑姑置之。", "願我尊有酒，何喜亦何悲。", "頹然就一醉，月落吾不知。"]'),
('8183fe70-cfe4-44c5-a966-af6cc9ce8e0e','山中何所有','于石','宋','宋诗','song-poetry','','[]','山中何所有，古松與清泉。',96,'全唐诗/poet.song.245000.json','["山中何所有，古松與清泉。", "一泓涵素月，千尺摇蒼烟。", "我生乏世用，樂此山林閑。", "臨流或倚樹，物我兩悠然。", "慎勿作梁棟，斧斤斵其天。", "慎勿入江海，洶湧生波瀾。", "流蕩易忘返，正直難自全。", "我欲叩其理，水去松無言。"]'),
('d5a8a146-f6fb-4310-8e30-2b18e32d7f88','感興  其一','于石','宋','宋诗','song-poetry','','[]','吳起爲魯將，殺妻殊不仁。',84,'全唐诗/poet.song.245000.json','["吳起爲魯將，殺妻殊不仁。", "樂羊伐中山，食子太無情。", "功名苟爲重，骨肉無乃輕。", "以此謀富貴，何如甘賤貧。", "沛豐三尺劍，抵掌收楚秦。", "未央玉巵壽，以功驕父兄。", "惜哉一杯酒，終愧一杯羹。"]'),
('fcf1c081-ce21-4ddd-a3e8-de69b9886f2d','感興  其二','于石','宋','宋诗','song-poetry','','[]','晉人殺鳴犢，孔子不渡河。',60,'全唐诗/poet.song.245000.json','["晉人殺鳴犢，孔子不渡河。", "河之水洋洋，臨流一長歌。", "豈無舟與楫，所懼蛟與鼉。", "蛟鼉任險怪，不度如我何。", "黄鵠一遠舉，奚憂嬰網羅。"]'),
('84c98d0c-9dfd-4420-976b-4a4c6a348f93','感興  其三','于石','宋','宋诗','song-poetry','','[]','衛人將授甲，鶴有乘軒寵。',48,'全唐诗/poet.song.245000.json','["衛人將授甲，鶴有乘軒寵。", "愛人不如禽，士固不爲用。", "唐人競朝梁，怒殺孫供奉。", "獸猶知有君，人胡不愧悚。"]'),
('042b6d14-ddc2-43cf-b133-7e29798651cd','感興  其四','于石','宋','宋诗','song-poetry','','[]','鷹犬飽粱肉，饑人厭粥糜。',72,'全唐诗/poet.song.245000.json','["鷹犬飽粱肉，饑人厭粥糜。", "牆屋被文繡，民有號寒兒。", "禽獸食人食，土木衣人衣。", "俗偷或過侈，民窮易爲非。", "君子固有守，豈若世所爲。", "富貴苟可得，貧賤終莫移。"]'),
('27844d3a-e872-467e-86ea-9c3279e861b6','感興  其五','于石','宋','宋诗','song-poetry','','[]','羣棲平沙雁，有警奴輒鳴。',84,'全唐诗/poet.song.245000.json','["羣棲平沙雁，有警奴輒鳴。", "鳴多謂奴妄，哀嗷墮弓矰。", "甡甡中林鹿，以媒誘其羣。", "相呼入網罟，鹿死媒獨生。", "骨肉不相信，效忠况他人。", "輕言託心腹，賣友終不仁。", "君子能審友，四海皆弟兄。"]'),
('9befc2f1-ed9c-45a7-9a7d-e7809f70a416','有所思','于石','宋','宋诗','song-poetry','','[]','君在南山南，水闊雲漫漫。',108,'全唐诗/poet.song.245000.json','["君在南山南，水闊雲漫漫。", "我在北山北，木落天地寬。", "所思不可見，孤峰碧巑岏。", "片雲遥相望，脈脈一水間。", "水流渺何許，撫松獨盤桓。", "人生有離合，把酒欲問天。", "何以寄所思，取琴倚風彈。", "一彈不成調，再彈誰與言。", "抱琴耿無寐，月落空山寒。"]'),
('c92463e7-c549-4f5e-bc4d-9534ca0e4731','杜少陵贈衛八處士韻別秉國','于石','宋','宋诗','song-poetry','','[]','昔君坐談詩，古音振宮商。',144,'全唐诗/poet.song.245000.json','["昔君坐談詩，古音振宮商。", "昔我起舞劍，三尺星斗光。", "我劍何慷慨，君詩何老蒼。", "感此一笑嘆，徒成九迴腸。", "久別忽想見，歲月驚惶惶。", "豈無平生友，對面險太行。", "知心今幾人，况復天一方。", "安得飛霞佩，共挹天瓢漿。", "道義有真樂，何必甘膏粱。", "臨行勸我酒，我飲不盡觴。", "一飲情易闌，再飲情更長。", "斜陽重回首，烟水空蒼茫。"]'),
('964b94c7-20fa-4605-bbbb-5ad0eddade4c','示衢子','于石','宋','宋诗','song-poetry','','[]','我學三十年，巧不能勝拙。',144,'全唐诗/poet.song.245000.json','["我學三十年，巧不能勝拙。", "汝年今弱冠，慎勿虛歲月。", "何必千里師，而後可受業。", "何必萬卷書，而後稱博洽。", "讀書貴有用，豈徒資筆舌。", "立身一弗謹，萬事皆瓦裂。", "蔬肉同一飽，自可甘薇蕨。", "布帛同一煖，何必輕裋褐。", "貧賤士之常，紛華安足悅。", "晴窗明几硯，夜燈耿風雪。", "汝今其勉旃，經史須涉獵。", "顧我何足學，當學古賢哲。"]'),
('427e49e9-2cd7-416f-8c78-5fa7d8ba97e5','戊子元夕大雪','于石','宋','宋诗','song-poetry','','[]','去年逢元夕，交光燈與月。',96,'全唐诗/poet.song.245000.json','["去年逢元夕，交光燈與月。", "今年逢元夕，交光燈與雪。", "有月已甚奇，一雪更奇絕。", "燦爛星斗光，晃耀瓊瑶闕。", "紛紛競兒嬉，笙歌聲不歇。", "年來獨衰懶，頗亦厭喧雜。", "呼兒早閉門，擁爐燒落葉。", "雪月兩不知，孤燈任明滅。"]'),
('b56af7d0-c4fc-4833-b8ed-56d93674f9d3','次張嘉父閑居','于石','宋','宋诗','song-poetry','','[]','有詩可以吟，何必擬李陵。',144,'全唐诗/poet.song.245000.json','["有詩可以吟，何必擬李陵。", "有酒可以酌，何必慕伯倫。", "自吟復自酌，一笑睨白雲。", "卷舒見吾道，聚散亦世情。", "老我一茅屋，蕭蕭山下村。", "種瓜有餘地，吾亦安吾貧。", "興來即杖屨，孤往無與朋。", "晨出未啟戶，暮歸或扣門。", "翛然脫塵鞅，無懷與大庭。", "所以軒冕貴，不移丘壑心。", "此意誰獨識，千載一淵明。", "淵明不復作，視此壁上琴。"]'),
('920caa8c-20ef-48b3-a4f6-be655a41b008','伯勞','于石','宋','宋诗','song-poetry','','[]','嗚呼有生初，蠢蠢不知幾。',144,'全唐诗/poet.song.245000.json','["嗚呼有生初，蠢蠢不知幾。", "血氣均有欲，擾擾靡窮已。", "伯益烈山澤，庭氏挾弓矢。", "驅除或未盡，遺類復紛靡。", "豈惟梟鳥惡，亦有伯勞氏。", "瑣瑣至微物，凶悖乃如此。", "不思天壤間，萬物雖異類。", "子之於父母，恩愛均一理。", "卵翼哺爾成，胡爲遽忘義。", "昔聞烏反哺，羔羊能跪乳。", "蜂蟻識君臣，豺狼知父子。", "寄語當世人，爲此勿爲彼。"]'),
('848bbc8e-f308-4369-b236-73c67cd8742c','鵲鴉行','于石','宋','宋诗','song-poetry','','[]','世以鵲爲吉，人多喜其鳴。',168,'全唐诗/poet.song.245000.json','["世以鵲爲吉，人多喜其鳴。", "世以鴉爲凶，鳴多人輒嗔。", "吉凶一以定，嗔喜此焉分。", "相彼新羅鷂，于何分愛憎。", "群鴉競喧集，有耳若不聞。", "一鵲不相容，搏擊以爲能。", "不知鵲可喜，甘與鴉爲羣。", "妒善復黨惡，鷙悍徒不仁。", "石顯怙權寵，望之不容身。", "林甫擅柄用，何有乎九齡。", "寧爲望之辱，不作石顯榮。", "寧爲九齡死，不作林甫生。", "邪正苟倒置，是非竟難陳。", "人事無不然，何獨此微禽。"]'),
('bca3be1e-83ba-4266-9cbd-8d2e80045079','故家有喬木','于石','宋','宋诗','song-poetry','','[]','故家有喬木，衆鳥巢其枝。',168,'全唐诗/poet.song.245000.json','["故家有喬木，衆鳥巢其枝。", "紛然各卵育，自啄還自飛。", "誰歟恣殘忍，緣木登其危。", "毀室取爾子，殺戮輕如嬉。", "漂摇風雨中，巢破不復支。", "破者尚可完，死者終無歸。", "自謂翔後集，今乃失所依。", "胡不舍之去，遠擇高林栖。", "主人不我愛，舍此復何之。", "哀哀鳴向天，路遠天不知。", "吾聞重太息，事莫大於斯。", "弱肉强之食，擾擾今何時。", "人生且未保，爾死誰復悲。", "寄言民父母，赤子方流離。"]'),
('621895fd-9d87-4b16-b274-4c87ec6b5c84','鄰叟言','于石','宋','宋诗','song-poetry','','[]','客行歸故鄉，依依一鄰叟。',180,'全唐诗/poet.song.245000.json','["客行歸故鄉，依依一鄰叟。", "把酒向我言，重嘆生不偶。", "大男年二十，前年方娶婦。", "府帖點鄉兵，井邑備攻守。", "萬騎聲撼天，戰骨今欲朽。", "小男年十三，嬌癡猶戀母。", "所恃惟此兒，未忍輒笞毆。", "垂白力耕耘，一飯僅充口。", "東鄰數十家，兵火十無九。", "西鄰破茅屋，蕭然一無有。", "悍吏猛索租，摧剝及鷄狗。", "嗟子行四方，頗亦聞此否。", "偶述鄰里情，勿訝言語醜。", "老婦洗瓦盆，呼兒進畦韭。", "願子姑暫留，爲我進盃酒。"]'),
('32dbf1ac-0198-4a3e-a487-e65b4d9df6e3','母子別','于石','宋','宋诗','song-poetry','','[]','客遊嚴陵道，中路哭者誰。',192,'全唐诗/poet.song.245000.json','["客遊嚴陵道，中路哭者誰。", "哀哀母子別，云是夫棄妻。", "百年結歡愛，一旦生別離。", "妾去何足憐，憐此乳下兒。", "哌哌未能語，棄去良可悲。", "兒啼苦戀母，母聞轉悲凄。", "欲語別離苦，孩提爾何知。", "徒能撫汝頂，相顧空淚垂。", "夫婦義已絕，母子恩亦虧。", "爾饑誰與哺，爾寒誰與衣。", "明年爾學行，誰與相提携。", "人言無母憐，有父尚可依。", "爾父忍棄我，棄汝將如遺。", "去去兩相失，相見未有期。", "娟娟秀眉目，夢寐或見之。", "夜靜澗聲咽，猶似聞兒啼。"]'),
('a0cd8482-398e-4479-9e40-86d2509ed47d','丁亥冬大雪','于石','宋','宋诗','song-poetry','','[]','頑雲撥不開，陰風挾嚴威。',204,'全唐诗/poet.song.245000.json','["頑雲撥不開，陰風挾嚴威。", "大雪止復作，細民已噓嚱。", "人言豐年瑞，可樂胡反悲。", "頻年豈無雪，雪少寒不知。", "誰爲禦寒計，茅屋曝晴曦。", "今年雪大作，始信貧無衣。", "地爐燎濕薪，僵坐縮如龜。", "年豐固可樂，一飽遠莫期。", "但憂今日寒，未慮明年饑。", "豈知紈絝子，重裘擁柔肌。", "綉閣藹春風，金帳環蛾眉。", "惟恨雪不多，低唱飲羔兒。", "且盡一己歡，寧爲爾民思。", "爾民毋自苦，會有年豐時。", "雞豚燕同社，玉粒香浮炊。", "一飽有餘樂，八珍亦奚爲。", "寄語紈絝子，此意知不知。"]'),
('5a994e89-ef1a-4caf-9c01-a29a403817fd','路傍女','于石','宋','宋诗','song-poetry','','[]','路傍誰家女，躊躇不能去。',204,'全唐诗/poet.song.245000.json','["路傍誰家女，躊躇不能去。", "自言妾小時，家本樵川住。", "十五嫁良人，長年秉機杼。", "辛勤奉舅姑，足不越庭戶。", "去年秋棗紅，邊人健如虎。", "移家入深林，自謂百無慮。", "空山鳴劍戟，失色駭相顧。", "星散各偷生，不幸適相遇。", "妾身如風花，飄零委塵土。", "妾命如蜉蝣，焉能保朝暮。", "一死恨不蚤，空爲年少誤。", "去去忽相失，零落在中路。", "妾有乳下兒，咿啞方學語。", "四海尚干戈，安知爾生死。", "回首望天涯，家山在何處。", "妾命負所天，顧影惟自憐。", "自憐輕失節，天下何獨妾。"]'),
('e39525b5-9f2e-4b82-992f-10c643bc0a7e','七月七日','于石','宋','宋诗','song-poetry','','[]','西風掃殘暑，微月澹新秋。',252,'全唐诗/poet.song.245000.json','["西風掃殘暑，微月澹新秋。", "相傳織女星，今夕嫁牽牛。", "翩翩聯鵲橋，亭亭擁龍輈。", "多少乞巧人，笑語穿針縷。", "吾嘗夜觀象，細與推其由。", "惟有五緯星，順逆有去留。", "經星二十八，歷歷如綴旒。", "萬古儼不動，分列十二州。", "其餘衆常星，爛然滿空浮。", "休咎必有證，君德修不修。", "胡獨牛與女，不與衆星侔。", "乃知塵世人，配偶相綢繆。", "少陵號詩史，萬象窮冥搜。", "亦云年年渡，秋期何用愁。", "彼哉柳河東，抱拙不自謀。", "旁趨事曲折，竊效兒女求。", "誰與倡邪說，誕謾不復收。", "淫褻轉相襲，寖使其辭浮。", "仙槎倘可乘，我欲凌空遊。", "再拜二星靈，一洗千古羞。", "天高不可問，河漢空西流。"]'),
('2bd6c35d-8866-4188-8f4d-aaee0f38b607','訪葉靈淵','于石','宋','宋诗','song-poetry','','[]','細路如蛇盤，山根復山巔。',228,'全唐诗/poet.song.245000.json','["細路如蛇盤，山根復山巔。", "振衣上千仞，頓覺天地寬。", "四山朗開豁，斜陽淡平川。", "溪淺不可舟，橋斷衣可搴。", "依依桑柘村，翳翳井里烟。", "老翁古柳樞，扶杖白垂肩。", "問途入深巷，蒲柳隠敗垣。", "忽得幽人居，一室靜且安。", "中有插架書，外有負郭田。", "種秫可釀酒，枕書時醉眠。", "自言居家好，笑我行路難。", "欲分清溪尾，著我屋數椽。", "踏月兩相過，亦足陶情歡。", "子雖愛我厚，我亦愧子言。", "天涯倦遊客，豈不懷故山。", "抱薪煮白石，岸巾曝晴簷。", "興來或杖履，松陰弄潺湲。", "如此豈不樂，胡爲復盤桓。", "泠然御風去，月暮孤雲寒。"]'),
('56d98173-7ff0-448d-ae49-ca192706074d','次韻呂芳卿春游','于石','宋','宋诗','song-poetry','','[]','春光美於酒，我得醉其淳。',120,'全唐诗/poet.song.245000.json','["春光美於酒，我得醉其淳。", "春情浩於海，我得涉其濱。", "人生貴適意，何須苦悲顰。", "軒軒遠游志，恨不窮入垠。", "流連慮忘返，豈徒玩芳新。", "遊子多愒日，志士惟競辰。", "二者孰得失，誰能究其因。", "俯仰天壤間，何輕用此身。", "驕惰由放逸，美好出艱辛。", "此日何足惜，我思古之人。"]'),
('968217c7-dee6-474c-abf0-8ae78c2d710a','呼兒','于石','宋','宋诗','song-poetry','','[]','澗深飛瀑寒，雲破斷崖碧。',48,'全唐诗/poet.song.245000.json','["澗深飛瀑寒，雲破斷崖碧。", "呼兒入深林，掃此松下石。", "澹然忘世故，一枕聊自適。", "夢斷山月高，孤猨嘯青壁。"]'),
('c4eac156-1898-4528-9ea2-65807ed21e62','鄰叟招飲','于石','宋','宋诗','song-poetry','','[]','燈火隔籬落，呼兒掩柴門。',228,'全唐诗/poet.song.245000.json','["燈火隔籬落，呼兒掩柴門。", "鄰叟挽我衣，笑指老瓦盆。", "酒盡意未已，語雜情更真。", "嗟嗟行路難，勸我歸與鄰。", "團圞一家樂，亦足娛其親。", "低頭愧叟言，未語面輒頳。", "父昔教我書，意在爲榮親。", "十歲始知學，二十能爲文。", "三十將遠遊，海波忽揚塵。", "年今幾半百，親老安可云。", "歲時一盃酒，父子祖與孫。", "客多在家少，暫聚還復分。", "曾不如爾樂，歡然力耕耘。", "父醉兒解扶，翁歸嫗相迎。", "十日九在家，笑語藹生春。", "我無田可歸，豈無山可耕。", "我無秫可釀，豈無泉可烹。", "幸及親未衰，菽水或可營。", "無愧鄰叟言，乃不愧予心。"]'),
('f5976134-8432-4170-b5d0-3daf2289a98c','我從山中遊','于石','宋','宋诗','song-poetry','','[]','我從山中遊，歸來林壑暝。',48,'全唐诗/poet.song.245000.json','["我從山中遊，歸來林壑暝。", "澗水凍不流，月出四山靜。", "柴扉不敢敲，恐驚孤鶴醒。", "徘徊踏明月，倚杖看松影。"]'),
('7a1986ae-29f6-4ef8-8d2a-a5db3be63ef8','次韻鄭德彝擬古集句','于石','宋','宋诗','song-poetry','','[]','明月照高樓，永夜不闔扉。',96,'全唐诗/poet.song.245000.json','["明月照高樓，永夜不闔扉。", "盈盈樓上女，耿耿如相依。", "歲月忽已晚，草木變芬菲。", "扳條折其榮，風流付枕幃。", "蹇修時不存，悠悠誰與歸。", "仰視浮雲馳，俯見月在衣。", "置書懷袖中，有約吾敢違。", "願寄雙飛燕，爲我西北飛。"]'),
('aad4fb80-a185-4a95-8592-f9b57c8542da','次韻子益秋懷集句','于石','宋','宋诗','song-poetry','','[]','春草秋更綠，能得幾時好。',72,'全唐诗/poet.song.245000.json','["春草秋更綠，能得幾時好。", "人生非金石，坐愁紅顔老。", "振衣千仞岡，木落雁飛早。", "無營地轉幽，遂動自紛擾。", "時哉不我與，全身以爲寶。", "不是傲當時，用拙存吾道。"]'),
('5db474c4-4e86-4de6-b418-12379027c87c','次韻劉和德賦淵明','于石','宋','宋诗','song-poetry','','[]','士之生斯世，身窮志彌篤。',120,'全唐诗/poet.song.245000.json','["士之生斯世，身窮志彌篤。", "不惟氣浩然，亦是敦薄俗。", "淵明晉高士，志豈在微祿。", "不以進爲榮，不以退爲辱。", "雲出鳥倦還，吾亦從吾欲。", "南山豈無豆，東籬亦有菊。", "日與田父遊，氣象和而肅。", "一枕北窗風，紅塵任奔逐。", "起視天壤間，四海空兩目。", "但願樽有酒，寧顧瓶無粟。"]'),
('a6fcb67d-66fa-4929-bf0c-f8abd188b701','再遊石壁寺','于石','宋','宋诗','song-poetry','','[]','曾爲石壁遊，更借僧房宿。',156,'全唐诗/poet.song.245000.json','["曾爲石壁遊，更借僧房宿。", "樓閣倚林腰，溪山醒塵目。", "敲門尋舊僧，清響應林谷。", "老僧不厭客，分我雲半屋。", "禪月豈後身，尚餘詩滿腹。", "疑我亦荀鶴，再與賦漢牧。", "汲井晝煮茶，洗鉢夜分粥。", "山空人語寂，邀我入深竹。", "獨抱無絃琴，不唱浮生曲。", "月樹影參差，風鳴聲斷續。", "翛然出塵表，身世轉幽獨。", "明朝出山去，無言笑相矚。", "江上石牛眠，秋草爲誰綠。"]'),
('41fced81-e24b-4fa0-91b6-77656da10271','小石塘源','于石','宋','宋诗','song-poetry','','[]','萬山鬰回合，羣木尤老蒼。',288,'全唐诗/poet.song.245000.json','["萬山鬰回合，羣木尤老蒼。", "細路百盤折，崎嶇陟羊腸。", "凉陰覆峭壁，縈迴澗流長。", "綠蘿下百尺，笑挹清泉香。", "甘寒試一潄，齒頰凝冰霜。", "拂石坐未去，樵叟來我傍。", "云此澗中水，其源來浦陽。", "浦陽婺屬邑，亦我父母邦。", "欲我飲此水，而不忘故鄉。", "叟言起予意，振衣欲飛揚。", "便將隨水源，徑度千仞岡。", "叟前挽我衣，遲留且勿忙。", "吾家隔前坡，林居愧荒凉。", "寒醅旋可壓，爲子炊黄粱。", "微徑行犖确，柴門隠松篁。", "推戶拂塵席，延我入中堂。", "呼兒出長揖，闊步何蹡踉。", "問我從何來，驚顧走欲僵。", "屢呼不復出，自起致茶湯。", "坐不分賓主，高談到羲皇。", "炊烟淡茅屋，勸我飲盡觴。", "葫蘆爛鵝鴨，盤飣羅芥薑。", "一飽共酣寢，此樂殊未央。", "攝衣起謝叟，聽我歌慨慷。"]'),
('0c10323b-1b73-41d7-8e55-8923ef7a0c4c','紫薇翁歌','于石','宋','宋诗','song-poetry','','[]','一掬之泉，可湘可沿。',79,'全唐诗/poet.song.245000.json','["一掬之泉，可湘可沿。", "一拳之石，可潄可眠。", "其動也以天。", "萬壑之風，不琴而絃。", "兩山之雲，不爐而烟。", "其靜也以天。", "前鐘後鼎，左瓢右簞。", "何榮何辱，孰愚孰賢，先生笑而不言。"]'),
('ae100ff2-5cae-443e-89d9-05686dc4227e','野田黄雀行','于石','宋','宋诗','song-poetry','','[]','鳴不擇上林，栖不依華屋。',69,'全唐诗/poet.song.245000.json','["鳴不擇上林，栖不依華屋。", "雄飛各呼雌，翩翩自相逐。", "渴飲野田水，饑啄野田粟。", "一飲一啄能幾何，慎勿遠飛投網羅。", "君不見金籠老鸚鵡，向人空作閑言語。"]'),
('2920aa26-40bf-47d9-84ae-3a3a88129a60','美人一章寄徐秉國','于石','宋','宋诗','song-poetry','','[]','有美人兮天一方，弭絳節兮擷瓊芳。',112,'全唐诗/poet.song.245000.json','["有美人兮天一方，弭絳節兮擷瓊芳。", "瑶環瑜珥鏘琳琅，修竹蕭蕭翠袖長。", "芝宮芙館椒爲堂，青瑣窗戶白玉床。", "一笑滿酌天瓢漿，簸弄驪龍明月光。", "欲往從之路茫茫，愛而不見空彷徨。", "安得騎麟鞭鳳凰，飛霞翩翩高頡頏。", "白雲縹緲遥相望，憑誰寄取雙瓊璫。"]'),
('8b5a7f0f-f956-4a3b-ad97-d78d3c7848e8','贈星命松坡','于石','宋','宋诗','song-poetry','','[]','昌黎之生月南斗，牛奮其角箕張口。',128,'全唐诗/poet.song.245000.json','["昌黎之生月南斗，牛奮其角箕張口。", "坡翁宿直斗牛箕，自謂文似昌黎叟。", "顧予命亦坐磨蝎，碌碌浪隨二公後。", "文章學問愧前修，有口但知能飲酒。", "松坡磊落湖海人，爲我掉舌談星辰。", "蛟龍蟠屈終變化，君子憂道寧憂貧。", "夜半狂吟踏破甕，結柳爲車窮莫送。", "掀髯一笑問松坡，文如二子今何用。"]'),
('1a9d6946-9820-4976-838d-234c8f43acc1','浪吟','于石','宋','宋诗','song-poetry','','[]','十載驅馳翰墨場，翩翩霞佩高頡頏。',160,'全唐诗/poet.song.245000.json','["十載驅馳翰墨場，翩翩霞佩高頡頏。", "賦窺賈馬搜班揚，詩崇晉漢卑齊梁。", "斯文未喪道未亡，欲尋墜緒何茫茫。", "蕭騷裋褐凄風霜，匣中蛟龍吼干將。", "男兒有志行四方，安用把筆工文章。", "掀髯長嘯俛大荒，殘烟落日塵沙黄。", "紛紛蟻穴爭侯王，邯鄲一夢炊黄粱。", "斷鶴續鳬誰短長，世間萬事俱亡羊。", "何如長歌歸故鄉，古松流水遶石床。", "濁酒一壺琴一張，卧聽孺子歌滄浪。"]'),
('857327c9-6b41-47cd-a035-b58174b441e6','贈王法官','于石','宋','宋诗','song-poetry','','[]','石作人言豕人立，或嘯其梁闞其室。',152,'全唐诗/poet.song.245000.json','["石作人言豕人立，或嘯其梁闞其室。", "道人叱咤鞭雷公，馭風騎氣行虛空。", "赤手縛鬼如縛虎，畫地爲牢通鬼語。", "登壇攝將如有神，問其姓字皆忠臣。", "生不求生以害仁，死猶赫赫濯厥靈。", "百鬼啖盡何足恤，吾獨因之三太息。", "關雲長，張睢陽，凜然大節死不屈，至今日月猶爭光。", "荆州一失不復得，江淮保障誰之力。", "欲爲漢唐開太平，老天胡不留斯人。"]'),
('e57b457a-346a-4e66-a841-33b3c703f48f','續金銅仙人辭漢歌','于石','宋','宋诗','song-poetry','','[]','漢皇銳意求神仙，神仙之效何茫然。',240,'全唐诗/poet.song.245000.json','["漢皇銳意求神仙，神仙之效何茫然。", "蓬萊弱水不可到，且立宮中承露盤。", "饑餐玉屑不堪飽，誰謂有方能却老。", "人生修短數在天，多慾未必能延年。", "秋風吹老茂陵樹，年年空滴金莖露。", "建章宮闕隨烟塵，塊然屹立惟銅人。", "宮官西來果何意，一朝辭漢將歸魏。", "吁嗟銅人如有知，口不能言惟淚垂。", "自從曹氏盜神器，父子相傳已三世。", "漢宮故物無一存，汝獨猶能感舊恩。", "凄然照影臨渭水，一折銅人扶不起。", "寧爲棄物委道傍，不忍漂泊離故鄉。", "迢迢東望洛城路，回首長安愁日暮。", "長安繁華非昔時，洛陽寥落誰復悲。", "漢魏興亡何日了，長見銅人卧秋草。"]'),
('2b863594-3c5d-465d-8a63-3004933e3dc7','次韻徐覺風鈴','于石','宋','宋诗','song-poetry','','[]','鏘然非金亦非玉，壹片宮商紛其觸。',183,'全唐诗/poet.song.245000.json','["鏘然非金亦非玉，壹片宮商紛其觸。", "歘如環轡玲瓏摇佩旌，鏗如鳴球拍琴九奏簫韶聲。", "凄如孤鴻叫群嘹唳穿雲去，清如幽泉滴瀝飄落斷崖處。", "餘音欲斷還復鳴，咄咄胡牀靜中據。", "乃知簷鈴適與風相會，鏘鏘錚錚可聽不可佩。", "我憐其輕脆不足恃，戛則成音擊則碎。", "嗟哉無情之物能感人，浮華言語自古多誤身。", "喧然聲名滿天地，好聲過耳俱成塵。", "物情萬變伏還起，人生幾何安足恃。", "何如物我兩忘言，雲在青山水在月。"]'),
('01a3f343-a3f7-4c7d-9887-076f71383467','薄薄酒','于石','宋','宋诗','song-poetry','','[]','薄薄酒，可盡歡。',178,'全唐诗/poet.song.245000.json','["薄薄酒，可盡歡。", "粗粗布，可御寒。", "醜婦不與人爭妍。", "西園公卿百萬錢，何如江湖散人秋風一釣船。", "萬騎出塞銘燕然，何如馿背長吟灞橋風雪天。", "張燈夜宴，不如濯足早眠。", "高談雄辯，不如靜坐忘言。", "八珍犀筯，不如一飽苜蓿盤。", "高車駟馬，不如杖屨行花邊。", "一身自適心乃安，人生誰能滿百年。", "富貴蟻穴一夢覺，利名蝸角兩觸蠻。", "得之何榮失何辱，萬物飄忽風中烟。", "不如眼前一杯酒，憑高舒嘯天地寬。"]'),
('ccfb3c61-52fd-45af-9562-fff8306f87eb','答吳子真','于石','宋','宋诗','song-poetry','','[]','子居金華山之東，我居金華山之西。',140,'全唐诗/poet.song.245000.json','["子居金華山之東，我居金華山之西。", "東西相望二百里，半面未識心相知。", "扳條採榮遠莫致，夢中往往或見之。", "子持一卷易，我携一篇詩。", "此詩此易世不識，與子共作千年期。", "前乎千載事已矣，後乎千載誰是非。", "握手論心語未了，松風萬壑寒生衣。", "山深夢斷不可覓，落花耿耿寒梅枝。", "起視金華萬山頂，惟有白雲來去飛。"]'),
('fde6c308-7bbc-43fe-a7c3-9db584b7f40c','偶成','于石','宋','宋诗','song-poetry','','[]','長劍不入英雄手，勁氣摩空拂牛斗。',148,'全唐诗/poet.song.245000.json','["長劍不入英雄手，勁氣摩空拂牛斗。", "埋光鏟采今幾年，匣中忽作蛟龍吼。", "古琴不入時人耳，斷絃掛壁塵埃久。", "桐尾半作爨下焦，高山流水今安有。", "自笑長不滿七尺，役役徒爲牛馬走。", "學劍學琴兩無用，肯以窮困移所守。", "孔顔非厄，盜跖非壽。", "西子非妍，無鹽非醜。", "一時榮辱閑過眼，千古是非空掛口。", "何如長歌歸去來，萬事無心一杯酒。"]'),
('dabdf022-3710-4e09-a82f-921347db54d5','答諸公遊山作','于石','宋','宋诗','song-poetry','','[]','金華山巔一揮手，俯視塵寰仰星斗。',161,'全唐诗/poet.song.245000.json','["金華山巔一揮手，俯視塵寰仰星斗。", "閑雲滿地白鶴飛，積雪暗天蒼兕吼。", "北山周回七百里，名著洞天非不久。", "世人未識山中樂，問我山中何所有。", "舊傳叱石化羊眠，亦有耕田驅鹿走。", "大士浴缾今尚在，孝標書堂誰與守。", "翩然東訪赤松子，何須辟穀能延壽。", "出門一笑天地寬，齪齪徒爲兒女醜。", "君不見東坡遊赤壁，東望武昌西夏口。", "江山風月兩依然，誰能與客携魚酒。"]'),
('e8f52171-1209-4f1f-a62f-a0fd60376163','答諸友','于石','宋','宋诗','song-poetry','','[]','之子詞場無敵手，騎麟翳鳳集北斗。',152,'全唐诗/poet.song.245000.json','["之子詞場無敵手，騎麟翳鳳集北斗。", "藉藉人間月旦評，滔滔筆下風濤吼。", "方摶扶摇九萬里，可速則速久則久。", "文章何止擬相如，政事亦堪脩冉有。", "回首落日烟塵昏，滿眼風寒沙石走。", "老天應未喪斯文，君子固宜知所守。", "刀以銛而缺，硯以鈍而壽。", "名高多謗毀，女妒無妍醜。", "乃知明哲可保身，安用嚅唲浪開口。", "悠然一笑對南山，壁上有琴樽有酒。"]'),
('2773434f-dd5f-40a9-b384-17def1b35a57','夜燒松明火次韻黄養正','于石','宋','宋诗','song-poetry','','[]','銀爐熾炭麒麟紅，銷金帳煖熏籠烘。',230,'全唐诗/poet.song.245000.json','["銀爐熾炭麒麟紅，銷金帳煖熏籠烘。", "爨下有蠟可代薪，笑我夜寒癡坐然枯松。", "貧富貴賤何不公，安能排雲叫呼天九重。", "空憐爾松生抱有用材，不遇匠石梁棟施帡幪。", "盤根錯節屹立凍不死，凜凜勁氣猶足排嚴冬。", "顛崖峭壁人跡絕，閑雲流水相冥濛。", "胡爲明不能保身，丁丁斧斤山其童。", "鶉衣百結縮如蝟，地爐擁膝便可閑從容。", "當年榷油幸不嚴汝禁，餘用尚及斯民窮。", "陽和無聲入骨髓，不知夜雪沒屋霜橫空。", "但見濛濛香霧靄四壁，紅煇紫焰明窗櫳。", "禦寒何必裘蒙茸，盎然一室回春風。", "何當散作一天煖，坐令四海盡在春風中。"]'),
('e210e56c-268c-4861-babd-9a3cbd4f0996','祈雨','于石','宋','宋诗','song-poetry','','[]','六月不雨至七月，草木脆乾石欲裂。',112,'全唐诗/poet.song.245000.json','["六月不雨至七月，草木脆乾石欲裂。", "方士畫符如畫鴉，呵叱風伯鞭雷車。", "九天雲垂海水立，驕陽化爲雨三日。", "萬口競誇方士靈，彼亦自謂吾符神。", "誰知水旱皆天數，貪天之功天所惡。", "吾心修德可弭災，大抵雨從心上來。", "桑林自責天乃雨，豈在區區用方士。"]'),
('2acdfd39-864b-40f5-9376-b1808e5a149e','次韻趙九翁','于石','宋','宋诗','song-poetry','','[]','風雪騎馿窮鄭五，良史武陵忝厥祖。',320,'全唐诗/poet.song.245000.json','["風雪騎馿窮鄭五，良史武陵忝厥祖。", "文章千古推賀白，餘子碌碌何足數。", "西風客路一相逢，笑睨平蕪共懷古。", "神遊千載渺襟期，不學時妝競媚嫵。", "翩然一鶚迅秋空，縱橫健筆凌鸚鵡。", "愧我栖栖一釣翁，胯下寧甘少年侮。", "兩鬢風霜颯短褐，把酒長歌話愁苦。", "君留不住我亦歸，楓林葉落津頭鼓。", "劍光錯落耿青燈，夜半聞鷄與君舞。", "幾回欲寄別後書，雁飛不過衡陽浦。", "樹陰黯黯江東雲，柳色依依渭城雨。", "人生相會不可期，去住真如萍散聚。", "我在金華北山北，茅屋三間雲一塢。", "君在濲江西港西，種秫有田瓜有圃。", "我不能往君不來，凄凄風雨誰爲主。", "何當共作子長遊，南浮沅湘北齊魯。", "不然赤壁弔東坡，高攀栖鶻登虯虎。", "放浪形骸期汗漫，霽月一襟春萬宇。", "逍遥容與澹忘歸，弭節江臯采芳杜。", "狂吟曾點舞雩風，一笑渠儂行凉踽。"]'),
('22045326-0eab-452a-a133-f12a1b5412a1','梁父吟','于石','宋','宋诗','song-poetry','','[]','建安天下如潰瓜，一榻之外非吾家。',160,'全唐诗/poet.song.245000.json','["建安天下如潰瓜，一榻之外非吾家。", "黄屋飄颻定何許，龍爲魚兮鼠爲虎。", "老瞞持力敢欺天，朵頤漢鼎方垂涎。", "紫髯將軍一攘臂，控荆引越三千里。", "慷慨山東大耳兒，南飛烏鵲棲無枝。", "草廬一語君臣契，目中久已無吳魏。", "堂堂大義凜不磨，靈關劍閣爭嵯峨。", "昨夜西南一星落，六尺之孤竟誰托。", "渭水旌旗歸故都，江上空存八陣圖。", "抱膝長歌出師表，古柏蒼蒼爲誰老。"]'),
('1b7d2b6b-6081-4adc-8323-e0f359e79313','姑惡','于石','宋','宋诗','song-poetry','','[]','村南村北麥花老，姑惡聲聲啼不了。',50,'全唐诗/poet.song.245000.json','["村南村北麥花老，姑惡聲聲啼不了。", "有姑不養反怨姑，至今爲爾傷風教。", "噫，君雖不仁臣當忠，父雖不慈子當孝。"]'),
('484a2f27-4c0a-45c7-9542-ccc4d3dc8c12','贈姚星士','于石','宋','宋诗','song-poetry','','[]','姚生年來如我貧，瀾翻口舌談星辰。',114,'全唐诗/poet.song.245000.json','["姚生年來如我貧，瀾翻口舌談星辰。", "凄風落日低黄塵，客路相逢眼爲青。", "草鞋生翼杖生鱗，一笑索我詩贈行。", "我詩何足爲重輕，歷象妙處須推尋。", "相國之生孕昴精，客星動摇歸富春。", "天不祚漢星墜營，泰階或坼中台星。", "大抵人事關天文，試算天下英雄今幾人。"]'),
('bea6d3c1-1d92-4788-b52f-64f4d65e92f6','己卯寒食','于石','宋','宋诗','song-poetry','','[]','今年客路逢寒食，村落無烟春寂寂。',80,'全唐诗/poet.song.245000.json','["今年客路逢寒食，村落無烟春寂寂。", "荒塚纍纍人不識，芳草凄凄吐花碧。", "麥飯一盂酒一滴，哀哀兒女春衫濕。", "我過其傍因太息，有墳可酹何須泣。", "干戈滿地邊雲黑，路傍多少征人骨。"]'),
('3aa6feb9-1aad-41bc-bf8e-2147d70b6af7','追和東坡次蔡郎中遊湖韻','于石','宋','宋诗','song-poetry','','[]','昔年著脚窮深幽，藕花十里烟波秋。',89,'全唐诗/poet.song.245000.json','["昔年著脚窮深幽，藕花十里烟波秋。", "騎馿踏月楊柳市，買舟聽雨菰蒲洲。", "酒樓倚天沸歌管，繁華轉眼如雲浮。", "山川悠悠尚如昨，歲月匆匆不可留。", "君不見錢唐江上潮，早潮生兮晚潮落，滔滔東去何時休。"]'),
('15ca9f7b-3b47-48a9-adaf-9280aa837eff','西湖荷花有感','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我昔扁舟泛湖去，四望荷花浩無數。',192,'全唐诗/poet.song.245000.json','["我昔扁舟泛湖去，四望荷花浩無數。", "誰家畫舫倚紅妝，笑聲逈入花深處。", "笙歌凄咽水雲寒，花色似嫌脂粉污。", "夜深人靜月明中，方識荷花有真趣。", "水天倒浸碧琉璃，凈質芳姿澹相顧。", "亭亭翠蓋擁羣仙，輕風微顫凌波步。", "酒暈潮紅淺渥唇，膚如凝脂腰束素。", "一捻香骨薄裁冰，半破芳心嬌泣露。", "湖光花氣滿衣襟，月落波寒浸香霧。", "恍然人在蕊珠宮，便欲移家臨水住。", "回首落日低黄塵，十年不到湖山路。", "花開花落幾秋風，湖上青山自如故。"]'),
('63c553c6-2258-4323-b4d3-ae4a1a1cc4a9','琴寥歌','于石','宋','宋诗','song-poetry','','[]','壁乎琴兮不彈，心乎道兮忘言。',54,'全唐诗/poet.song.245000.json','["壁乎琴兮不彈，心乎道兮忘言。", "操履霜兮猗蘭，忠與孝兮兩全。", "松風兮澗泉，琴無絃兮有絃。", "青霞兮柯仙，道不傳兮有傳。"]'),
('7f8956f6-2dab-4e15-be31-c572eda914f7','有虎行','于石','宋','宋诗','song-poetry','','[]','有虎有虎山之巔，怒目炯炯當晝眠。',188,'全唐诗/poet.song.245000.json','["有虎有虎山之巔，怒目炯炯當晝眠。", "百獸畏伏不敢前，憑林一吼秋風寒。", "昨日鄰家婦，哀哀哭其子，叩頭叫天天不語。", "或曰梟食母、犬吠主，含沙射影毒欲死。", "封豕長蛇肆侵侮，如此紛紛何獨虎。", "虎哉虎哉爾何知，磨牙摇尾爭奔馳。", "妖狐猶將假爾威，豈知彊者易弱盛必衰。", "北平將軍怒欲飛，彎弓遠掛扶桑枝。", "嗟爾有力何由施，吾見食汝肉而寢汝皮。", "倚劍睨天三太息，弱肉彊食今何時。", "麒麟騶虞亦物耳，嗚呼吾不得而一見之。"]'),
('7db36b60-2ad9-48cd-b82c-416da09b78f8','張德裕盤谷隠居','于石','宋','宋诗','song-poetry','','[]','盤谷四面環青山，晴嵐暖翠浮雲烟。',208,'全唐诗/poet.song.245000.json','["盤谷四面環青山，晴嵐暖翠浮雲烟。", "盤谷之阻多幽泉，湛然深碧蛟螭蟠。", "中有華屋貯神仙，猿鳥不驚犬不喧。", "竹侵行逕松礙簷，人疑無路堪攀緣。", "忽聞讀書聲琅然，始信別是壺中天。", "翩然振屐登其巔，仰林俯壑天地寬。", "桑麻盡處開平川，千帆來往無時閑。", "旁有一葉漁翁船，出沒紅蓼黄蘆邊。", "呼之來泊岩下灣，就船買魚歸烹鮮。", "煮茗有泉秫有田，問之世事笑不言。", "家藏黄石書一編，安用李愿歸來篇。", "我欲前峰卜數椽，幅巾杖屨行其間。", "目送歸鴻揮五絃，閑窗靜聽松風眠。"]'),
('2895dc62-8cfe-4653-889c-e4e5336e3804','田家婦','于石','宋','宋诗','song-poetry','','[]','村南村北麥欲枯，桑麻陰陰滿路隅。',96,'全唐诗/poet.song.245000.json','["村南村北麥欲枯，桑麻陰陰滿路隅。", "炊黍田頭行餉夫，餠爐未熟兒呱呱。", "鴨頭長襪短布襦，平生未識鉛與朱。", "彈箏不用如羅敷，懷金不願逢秋胡。", "眼前富貴何足娛，一身飽煖自有餘。", "茅簷笑語寒燈孤，夜舂曉織奉舅姑。"]'),
('2d058ed3-3e45-4e8a-83ba-55676995c9ca','對雪','于石','宋','宋诗','song-poetry','','[]','頑雲怙勢吞燭龍，一夜老盡江上峰。',164,'全唐诗/poet.song.245000.json','["頑雲怙勢吞燭龍，一夜老盡江上峰。", "驂鸞駕鶴下瑶闕，羽衣森列飛行空。", "玉虯夭矯振鱗甲，獵獵怒戰誰爭鋒。", "銀河剪刻紛弄巧，姑射縹緲來無蹤。", "半開半落花繞樹，無根無蒂絮因風。", "造物幻出不可測，萬變歸我一慨中。", "重裘何富，負薪何窮。", "烹茶何儉，飲羔何豐。", "天意茫茫無問處，人事悠悠定何許。", "豐年固知雪可喜，貧民不以雪爲瑞。", "安得見晛消凝陰，寒崖草木皆生春。"]'),
('9b8a3c89-ba40-45f4-8935-98b0f194d625','同韻傚歐蘇體','于石','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','草廬抱膝方卧龍，獰飈撼戶雲埋峰。',179,'全唐诗/poet.song.245000.json','["草廬抱膝方卧龍，獰飈撼戶雲埋峰。", "凍鵲依依飛墮地，饑鷹側翅低盤空。", "豈知水官夜鏖戰，鞭虯笞鳳驅前鋒。", "茫茫萬里混一色，遠近高下俱迷蹤。", "松標特立凜生氣，竹腰不折凌高風。", "長江一派清不泯，浩浩獨行天地中。", "小民祁寒易咨怨，君子守道惟固窮。", "有雪無雪兩不問，仁耕義耨無歉豐。", "君不見閉門無人僵卧處，任渠門外深丈許。", "窮則當與凡民異，達則當爲國之瑞。", "何當燮理司化鈞，坐令寒谷回陽春。"]'),
('1188f812-43b4-4324-9db7-ae86923e0dea','山居  其一','于石','宋','宋诗','song-poetry','','[]','結屋萬山頂，柴扉晝懶開。',48,'全唐诗/poet.song.245000.json','["結屋萬山頂，柴扉晝懶開。", "搗茶驚鶴醒，拋果引猿來。", "笋短和泥掘，松高倚石栽。", "有時尋勝去，多趁暮鐘回。"]'),
('ed1faa40-5e6c-48db-8aaa-a27946192921','山居  其二','于石','宋','宋诗','song-poetry','','[]','不談當世事，榮辱兩無聞。',48,'全唐诗/poet.song.245000.json','["不談當世事，榮辱兩無聞。", "詩思半山月，生涯一塢雲。", "硯乾分瀑潤，香斷借蘭熏。", "有客時相過，呼兒採澗芹。"]'),
('e311971a-3592-4ce4-9b38-884f5a1e8a3b','春遊集句','于石','宋','宋诗','song-poetry','','[]','興來無遠近，吾得及春遊。',48,'全唐诗/poet.song.245000.json','["興來無遠近，吾得及春遊。", "江月誰人影，山光落釣舟。", "樹交花兩色，石橫水分流。", "天外猿啼處，數峰生暮愁。"]'),
('87208b96-435a-4ddf-9698-00fa96111e3d','雪竹','于石','宋','宋诗','song-poetry','','[]','君子亭亭操，剛强能自持。',48,'全唐诗/poet.song.245000.json','["君子亭亭操，剛强能自持。", "夷齊餓欲死，巡遠守方危。", "大節不可屈，真心終莫移。", "人心與物理，每向歲寒枝。"]'),
('057637f6-876a-4999-b1e5-4f3c502ae7a3','吾家  其一','于石','宋','宋诗','song-poetry','','[]','松陰六七里，茅屋兩三家。',48,'全唐诗/poet.song.245000.json','["松陰六七里，茅屋兩三家。", "坡煖四時笋，溪寒五月花。", "泉聲挾風雨，雲氣走龍蛇。", "誰謂謀生拙，門前數畝瓜。"]'),
('63889c84-582c-489a-b102-0d69aadf4f85','吾家  其二','于石','宋','宋诗','song-poetry','','[]','明月成三友，青山結四鄰。',48,'全唐诗/poet.song.245000.json','["明月成三友，青山結四鄰。", "家貧猿執爨，林靜鳥司晨。", "好竹能醫俗，幽花不媚人。", "盤餐何所有，春韭與秋蓴。"]'),
('c913769b-9ff5-436f-bf58-2bc1e8cb9462','雪','于石','宋','宋诗','song-poetry','','[]','天地混一色，樓高試捲簾。',48,'全唐诗/poet.song.245000.json','["天地混一色，樓高試捲簾。", "青山新面目，老樹換鬚髯。", "夜皎月千里，晴暄雨四簷。", "豈無寒餒者，僵卧在窮閻。"]'),
('f0301a92-6a1a-4c85-855f-ce2199df15e2','抱膝吟','于石','宋','宋诗','song-poetry','','[]','治亂古來有，英雄今豈無。',48,'全唐诗/poet.song.245000.json','["治亂古來有，英雄今豈無。", "人情雲聚散，世態草榮枯。", "事定見天理，時艱識丈夫。", "山川渺何許，烟雨暗平蕪。"]'),
('28448004-d278-4570-8e44-436e1945412b','伊昔  其一','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','伊昔西湖柳，清陰滿畫樓。',48,'全唐诗/poet.song.245000.json','["伊昔西湖柳，清陰滿畫樓。", "午凉欺舞扇，晚雨繫漁舟。", "春盡花無主，風寒葉自秋。", "六橋今在否，空惜舊時遊。"]'),
('7e2a406a-c0d1-4a71-9672-1b9c9fefb23c','伊昔  其二','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','伊昔西湖上，孤山幾樹梅。',48,'全唐诗/poet.song.245000.json','["伊昔西湖上，孤山幾樹梅。", "斷籬深院落，流水舊亭臺。", "明月無今古，春風自去來。", "逋仙不復作，消瘦爲誰開。"]'),
('b1db87d7-e092-4481-93b8-958031c1a83b','伊昔  其三','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','伊昔西湖裏，娉婷十里蓮。',48,'全唐诗/poet.song.245000.json','["伊昔西湖裏，娉婷十里蓮。", "香凝花上露，影落鏡中天。", "枕簟水亭雨，笙歌月夜船。", "雙鴛不解事，常傍翠陰眠。"]'),
('cf0e0bd5-79b1-453c-a3d8-002af97e1b4c','伊昔  其四','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','伊昔西湖外，清陰九里松。',48,'全唐诗/poet.song.245000.json','["伊昔西湖外，清陰九里松。", "天低深雨露，風怒走蛟龍。", "林靄通樵徑，山雲隔寺鐘。", "何時一行樂，重到北高峰。"]'),
('dfd724a4-f63f-4cf3-99f6-1bfda24b2629','水亭小集','于石','宋','宋诗','song-poetry','','[]','亭俯一泓碧，倚欄思濯纓。',48,'全唐诗/poet.song.245000.json','["亭俯一泓碧，倚欄思濯纓。", "游魚驚扇影，幽鳥避歌聲。", "雲斷遠山出，林疏落日明。", "竹風如有意，爲我掃棋枰。"]'),
('d1aed295-4b2c-4ce7-9193-5835b9441c40','得家書','于石','宋','宋诗','song-poetry','','[]','久客秋又晚，思家夢屢驚。',48,'全唐诗/poet.song.245000.json','["久客秋又晚，思家夢屢驚。", "空階聞葉落，隔樹見燈明。", "親老貧常健，兒癡學未成。", "凄凉今夜月，照我故鄉情。"]'),
('e7df0db0-943e-4908-b720-bc403fce72aa','次韻趙德輿','于石','宋','宋诗','song-poetry','','[]','人生渺如寄，天地一蘧廬。',48,'全唐诗/poet.song.245000.json','["人生渺如寄，天地一蘧廬。", "無酒喜留客，有錢多買書。", "敲冰時煮茗，踏雨晚挑蔬。", "抱道空憂世，年今四十餘。"]'),
('21ce73ea-987e-41bc-bec2-8ac7b470ff3c','次韻芳卿一室','于石','宋','宋诗','song-poetry','','[]','一室志天下，何須山更深。',48,'全唐诗/poet.song.245000.json','["一室志天下，何須山更深。", "英雄四海眼，道義百年心。", "蕉鹿夢中夢，松風吟處吟。", "幽泉鳴絕壁，不作世間音。"]'),
('e949a0ec-868d-41b0-80a2-a5f68e8cf728','次韻潘天英自感','于石','宋','宋诗','song-poetry','','[]','處士柴桑屋，將軍細柳營。',48,'全唐诗/poet.song.245000.json','["處士柴桑屋，將軍細柳營。", "窮通觀世變，離合見人情。", "花不求春艷，器當思晚成。", "窩中足安樂，何必傳無名。"]'),
('33f4629d-21b0-4bf5-b637-f758935acd09','次韻邵僉判幽居','于石','宋','宋诗','song-poetry','','[]','閉門久不出，摩挲鬢欲翁。',48,'全唐诗/poet.song.245000.json','["閉門久不出，摩挲鬢欲翁。", "有盃問明月，無扇障西風。", "神駿老嘶櫪，紙鳶高入空。", "天應憐我懶，瓜圃自泉通。"]'),
('3dc0beaf-7613-4fe8-bd8b-004cf0080685','次韻徐月卿秋興','于石','宋','宋诗','song-poetry','','[]','西風渺何許，安處即家鄉。',48,'全唐诗/poet.song.245000.json','["西風渺何許，安處即家鄉。", "社舞鄰呼飲，時思禮薦嘗。", "孤燈茅屋雨，落葉石橋霜。", "鷄黍當年約，誰能繼范張。"]'),
('7c40e6e3-6cea-49e5-b4e1-9669d6ceb862','次韻天民有年','于石','宋','宋诗','song-poetry','','[]','四海同一稔，茆簷藹富穰。',48,'全唐诗/poet.song.245000.json','["四海同一稔，茆簷藹富穰。", "鄰燈曉炊暖，溪雨晚舂香。", "有客歌良耜，何人餓首陽。", "三時足勤苦，真樂在冬藏。"]'),
('f5cba8aa-57a8-4b44-95a9-2a1ceead3561','再和潘天英韻','于石','宋','宋诗','song-poetry','','[]','人生一傳舍，於世懶蠅營。',48,'全唐诗/poet.song.245000.json','["人生一傳舍，於世懶蠅營。", "千古月知己，四時花有情。", "吟懷今鄭綮，家學昔玄成。", "自適眼前樂，何須身後名。"]'),
('8a7d45ad-eb25-4bf2-acd8-16039ed0e6ee','寒梅','于石','宋','宋诗','song-poetry','','[]','閉門一卷易，風定縷香凝。',48,'全唐诗/poet.song.245000.json','["閉門一卷易，風定縷香凝。", "落葉空階雨，殘梅閣硯冰。", "鳥啼深夜語，犬吠隔籬燈。", "不作紅塵夢，寒窗幾曲肱。"]'),
('bcaa1615-a307-42dd-9f9d-cacd7db80deb','林下','于石','宋','宋诗','song-poetry','','[]','結屋萬松頂，悄無人往還。',48,'全唐诗/poet.song.245000.json','["結屋萬松頂，悄無人往還。", "飲猿摇澗月，飛鷺點秋山。", "竹靜風相撓，水流雲自閑。", "翛然忘物我，禽語兩相關。"]'),
('929b47c1-9edf-4192-b1b2-16b03ca3b05a','次韻鄭德彝即事','于石','宋','宋诗','song-poetry','','[]','瓢空飯落埃，陋巷一顔回。',48,'全唐诗/poet.song.245000.json','["瓢空飯落埃，陋巷一顔回。", "月坐人醉醒，風眠戶闔開。", "搜奇屐穿雪，習懶硯生苔。", "舊菊今存否，長歌歸去來。"]'),
('2ade1aeb-3a14-48e9-80a8-c5fda2f88f1b','春興','于石','宋','宋诗','song-poetry','','[]','春來無處不繁華，豈獨公侯富貴家。',64,'全唐诗/poet.song.245000.json','["春來無處不繁華，豈獨公侯富貴家。", "青鏡照眉池上柳，碧紗映目霧中花。", "貧誰知己燕相識，閑不求官蜂自衙。", "惟有東風無厚薄，年年芳草滿天涯。"]'),
('06877f89-e902-48c0-a12f-790c5e54ac7f','春晚','于石','宋','宋诗','song-poetry','','[]','夕陽門巷靜無塵，茶竈烟凝碧樹陰。',64,'全唐诗/poet.song.245000.json','["夕陽門巷靜無塵，茶竈烟凝碧樹陰。", "千尺遊絲縈遠思，一聲幽鳥伴孤吟。", "落紅庭院春多少，新綠池塘水淺深。", "每向靜中觀物態，榮枯過眼不關心。"]'),
('29d31f9e-388b-47be-9105-f56e11a6da3a','過北山何先生故宅','于石','宋','宋诗','song-poetry','','[]','青雲不在金華巔，白雲孤起金華岑。',64,'全唐诗/poet.song.245000.json','["青雲不在金華巔，白雲孤起金華岑。", "百世相傳勉齋學，四書誰識晦翁心。", "水流盤澗自深淺，月照北山無古今。", "人問故廬何處是，門前松桂蔚成林。"]'),
('944eaa96-7735-44ba-943d-9134842d7cee','鹿田','于石','宋','宋诗','song-poetry','','[]','鹿田逈在翠微巔，乘興來尋半日閑。',64,'全唐诗/poet.song.245000.json','["鹿田逈在翠微巔，乘興來尋半日閑。", "徑入古松行落葉，目隨飛鳥破寒烟。", "鐘聲不隔東西寺，屐齒何辭上下山。", "一見老僧如舊識，相留煮茗試巖泉。"]'),
('5b24db27-e572-44bc-a68d-fc4e33943b80','赤松宮','于石','宋','宋诗','song-poetry','','[]','幾人學道得成仙，兄弟俱仙世所難。',64,'全唐诗/poet.song.245000.json','["幾人學道得成仙，兄弟俱仙世所難。", "白石不隨秋草爛，赤松長鎖暮雲寒。", "月涵古井一泓碧，雲護空山半粒丹。", "我欲乘風蛻凡骨，願隨鷄犬事劉安。"]'),
('f0500d07-1905-48e2-ae74-9889fe59220f','棲真院','于石','宋','宋诗','song-poetry','','[]','空翠凝寒不受埃，斷崖千尺擁崔嵬。',64,'全唐诗/poet.song.245000.json','["空翠凝寒不受埃，斷崖千尺擁崔嵬。", "老僧倚樹驚猿去，童子掃階知客來。", "石徑晴因松露濕，茶烟遠趁竹風回。", "禪家也辦吟邊料，不種閑花只種梅。"]'),
('3b3ff77b-b721-414a-9f85-157ed4ec6ba6','半山亭','于石','宋','宋诗','song-poetry','','[]','萬疊嵐光冷滴衣，清泉白石鎖烟扉。',64,'全唐诗/poet.song.245000.json','["萬疊嵐光冷滴衣，清泉白石鎖烟扉。", "半山落日樵相語，一逕寒松僧獨歸。", "葉墮誤驚幽鳥去，林空不礙斷雲飛。", "層崖峭壁疑無路，忽有鐘聲出翠微。"]'),
('175bbbcc-6c4e-45fa-8f8c-bf7e956169a5','歸興','于石','宋','宋诗','song-poetry','','[]','歸歟高枕寄林泉，安用悲歌行路難。',64,'全唐诗/poet.song.245000.json','["歸歟高枕寄林泉，安用悲歌行路難。", "君子患無真氣節，世人空笑舊衣冠。", "雪深處士梅花屋，月冷先生苜蓿盤。", "誰謂家貧無一物，牀頭三尺劍光寒。"]'),
('b738a410-80e8-451c-8186-8d51924a9436','自笑','于石','宋','宋诗','song-poetry','','[]','歸來更讀十年書，自笑今吾即故吾。',64,'全唐诗/poet.song.245000.json','["歸來更讀十年書，自笑今吾即故吾。", "栗里溪山晉處士，桐江風月漢狂奴。", "種梅添得詩多少，愛菊何拘酒有無。", "隨分生涯聊爾耳，門前應免吏催租。"]'),
('67132bc4-0b16-45bd-a9e9-1e746a0684b7','春事','于石','宋','宋诗','song-poetry','','[]','白了江梅柳又青，遊絲千尺網紅塵。',64,'全唐诗/poet.song.245000.json','["白了江梅柳又青，遊絲千尺網紅塵。", "鵓鳩夫婦孤村雨，杜宇君臣故國春。", "客裏易添芳草思，樽前誰是去年人。", "桃花源上空流水，安得漁郎一問津。"]'),
('3903fae4-0e4d-426f-816b-2be8c97f56c6','題石壁寺','于石','宋','宋诗','song-poetry','','[]','石壁名山多勝遊，背環古木面清流。',64,'全唐诗/poet.song.245000.json','["石壁名山多勝遊，背環古木面清流。", "一池空對旃檀塔，雙港中分芳草洲。", "豹隠安知興廢事，牛眠不礙往來舟。", "海棠菡萏今何在，風月人間幾度秋。"]'),
('b985f537-a927-4a42-a6b1-828ede028224','雪','于石','宋','宋诗','song-poetry','','[]','誰歟變幻舊乾坤，剪水仙人手段新。',64,'全唐诗/poet.song.245000.json','["誰歟變幻舊乾坤，剪水仙人手段新。", "銀屋萬家成驟富，青山半點不藏春。", "西園太尉方交賀，北海中郎豈願臣。", "把酒孤吟元不俗，何須夜訪剡溪人。"]'),
('92878c6d-a566-4e12-a0d3-189d975af5e0','清明次韻趙登','于石','宋','宋诗','song-poetry','','[]','九十春光半晦明，東郊携手趁新晴。',64,'全唐诗/poet.song.245000.json','["九十春光半晦明，東郊携手趁新晴。", "飄零風絮如行客，冷煖厨烟見世情。", "宿雨鞦韆花有淚，斜陽古塚草無名。", "勸君且盡樽前興，柳上一聲何處鶑。"]'),
('cd48ab6d-8b74-464e-9746-f8cb6f002acf','九日次韻王壽翁','于石','宋','宋诗','song-poetry','','[]','半生飲菊試仙方，安用狂歌賦玉堂。',64,'全唐诗/poet.song.245000.json','["半生飲菊試仙方，安用狂歌賦玉堂。", "烏帽任教今日落，紫萸不改舊年香。", "人生還有幾重九，世事都歸一醉鄉。", "千古淵明呼不醒，天涯風雨暗潯陽。"]'),
('3609d6da-d131-41da-b850-4392f5a724a4','秉國池亭','于石','宋','宋诗','song-poetry','','[]','曲曲闌干面面櫺，紅塵飛不到斯亭。',64,'全唐诗/poet.song.245000.json','["曲曲闌干面面櫺，紅塵飛不到斯亭。", "避人幽鳥入深竹，戀釣游魚弄翠萍。", "天闊倒涵秋水碧，牆低不礙遠山青。", "翛然獨占閑中趣，一枕荷風午睡醒。"]'),
('4b2e8335-a914-4ea7-8345-39924a31bc3d','江山送客次韻','于石','宋','宋诗','song-poetry','','[]','依依柳色黯江亭，酒味離愁孰重輕。',64,'全唐诗/poet.song.245000.json','["依依柳色黯江亭，酒味離愁孰重輕。", "携手忍看分手處，別時爭似見時情。", "百年離合悲歡事，一笑東西南北程。", "芳草斜陽渺無際，何當重問白鷗盟。"]'),
('52ce407b-80c4-4d89-a185-25b430e00604','端午次韻和徐改之  其一','于石','宋','宋诗','song-poetry','','[]','榴花灼爍露初乾，乍試香羅怯曉寒。',64,'全唐诗/poet.song.245000.json','["榴花灼爍露初乾，乍試香羅怯曉寒。", "自古獨醒多見忌，與君一醉笑相看。", "無邪安用艾懸戶，徇俗聊將黍飣盤。", "千載沉湘呼不起，至今遺恨楚江干。"]'),
('c91f7548-a87d-40a8-a1ce-fdbb29c71ae4','端午次韻和徐改之  其二','于石','宋','宋诗','song-poetry','','[]','濤頭洒淚眼難乾，魚腹沉冤骨未寒。',64,'全唐诗/poet.song.245000.json','["濤頭洒淚眼難乾，魚腹沉冤骨未寒。", "楚些一章招莫返，曹碑八字好難看。", "水流不盡湘江恨，俗奠空陳蘋藻盤。", "我亦逢時增感慨，凜然忠孝孰能干。"]'),
('a0659c18-fae3-45c6-8907-2b3f4ddba215','分蜂','于石','宋','宋诗','song-poetry','','[]','羣蜂割據作生涯，戶牖新開蜜釀花。',64,'全唐诗/poet.song.245000.json','["羣蜂割據作生涯，戶牖新開蜜釀花。", "漢世侯王自分國，秦民父子各當家。", "尊卑兩盡君臣義，朝夕爭趨南北衙。", "因感途人本兄弟，無知微物亦何嗟。"]'),
('e0ba9d2b-ebc0-4b89-b8dc-0d4dc6d3f914','瀟江亭','于石','宋','宋诗','song-poetry','','[]','背依古塔面層峰，曲曲闌干峻倚空。',64,'全唐诗/poet.song.245000.json','["背依古塔面層峰，曲曲闌干峻倚空。", "萬屋參差江色外，片帆出沒樹陰中。", "五更鐘鼓半山月，兩岸漁樵一笛風。", "極目子陵臺下路，滔滔惟有水流東。"]'),
('cf0065df-7c80-4db7-9588-b445a2a717ce','孤雁','于石','宋','宋诗','song-poetry','','[]','流落天涯偶失羣，何心飲啄到江城。',64,'全唐诗/poet.song.245000.json','["流落天涯偶失羣，何心飲啄到江城。", "一身去就分南北，四海飄零孰弟兄。", "無伴月明惟顧影，欲鳴風慘不成聲。", "明年回首關山路，依舊團圞骨肉情。"]'),
('f739ddc6-36e8-48cd-8c15-87e36ecaa30e','雪中梅','于石','宋','宋诗','song-poetry','','[]','蕊珠宮闕傍冰壺，森列羣仙下藐姑。',64,'全唐诗/poet.song.245000.json','["蕊珠宮闕傍冰壺，森列羣仙下藐姑。", "玉骨輕勻鉛粉面，霜紈薄襯素羅襦。", "兩般誰識花開謝，一色中分香有無。", "底事陽春藏不得，凝陰消盡轉清癯。"]'),
('f67cdac3-ae17-4e34-a248-28324e0a9505','送友人之武林','于石','宋','宋诗','song-poetry','','[]','錢唐江上一帆風，爲我重尋舊日蹤。',64,'全唐诗/poet.song.245000.json','["錢唐江上一帆風，爲我重尋舊日蹤。", "十里湖山空戰艦，千年宮闕咽僧鐘。", "潮生潮落東西浙，雲去雲來南北峰。", "往事茫茫何處問，殘烟衰草泣寒蛩。"]'),
('9f451204-a4a7-443d-9d64-72bcbb7c32d6','清明次韻周君會  其一','于石','宋','宋诗','song-poetry','','[]','可惜韶光過眼明，一分流水二分塵。',64,'全唐诗/poet.song.245000.json','["可惜韶光過眼明，一分流水二分塵。", "杜鵑聲感客中客，蝴蝶夢飛身外身。", "一滴清明寒食酒，萬家紅杏綠楊春。", "鬬鷄走狗非吾事，新火書燈誰共親。"]'),
('f580a7d5-a476-4374-8f23-709631cf4e0b','清明次韻周君會  其二','于石','宋','宋诗','song-poetry','','[]','墓祭非經古未聞，年來拜掃隘車塵。',64,'全唐诗/poet.song.245000.json','["墓祭非經古未聞，年來拜掃隘車塵。", "誰憐原上千年塚，且醉樽前百歲身。", "榆火欲燃行客晚，梨花不減故園春。", "石泉澆醒浮生夢，耿耿孤懷孰與親。"]'),
('e146d3ce-0956-48f7-9162-c9764b53f619','次韻秉國初夏','于石','宋','宋诗','song-poetry','','[]','團扇初分月桂芳，單衣乍試雪羅香。',64,'全唐诗/poet.song.245000.json','["團扇初分月桂芳，單衣乍試雪羅香。", "新荷祇似世情薄，飛絮不如歸興忙。", "梅潤圖書晨雨暝，棋聲庭院午風凉。", "日來竹報平安否，試向平泉問贊皇。"]'),
('ecb9372d-d7f3-4cc1-99f0-ffeb0f975619','白沙昭利廟','于石','宋','宋诗','song-poetry','','[]','百戰收功老故山，寒溪怒湧白沙泉。',64,'全唐诗/poet.song.245000.json','["百戰收功老故山，寒溪怒湧白沙泉。", "雲臺不與四七將，廟食何傳千萬年。", "香冷誰能燃漢火，水流空自溉吳田。", "愚民不識前朝事，浪說神能駕鐵船。"]'),
('448531b4-5a40-45b0-aac2-45f374868106','九日同黄宏公遊古城山','于石','宋','宋诗','song-poetry','','[]','信步攀躋感舊遊，寒烟衰草思悠悠。',64,'全唐诗/poet.song.245000.json','["信步攀躋感舊遊，寒烟衰草思悠悠。", "西風白髪空驚老，晚節黄花獨耐秋。", "宇宙幾人歡喜飲，江山一片古今愁。", "淵明三逕今猶在，自笑不如歸去休。"]'),
('4fad0898-7495-4c08-a4eb-ba8553d3e7f9','次二子韻','于石','宋','宋诗','song-poetry','','[]','松邊庭戶竹邊窗，歸卧故山雲半牀。',64,'全唐诗/poet.song.245000.json','["松邊庭戶竹邊窗，歸卧故山雲半牀。", "蕙帳夜寒眠鶴醒，芸籤日煖蠹魚香。", "讀書喜汝眼如月，涉世嗟予鬢欲霜。", "莫道文章真小技，今人當與古爭長。"]'),
('4e6046da-6e51-4944-a5fc-48c905d8a1fe','凈居院','于石','宋','宋诗','song-poetry','','[]','峰迴澗曲路縈紆，萬壑中藏一畫圖。',64,'全唐诗/poet.song.245000.json','["峰迴澗曲路縈紆，萬壑中藏一畫圖。", "雪墮枯枝龍解甲，藤纏怪石虎生鬚。", "滿樓山色自濃淡，隔竹泉聲半有無。", "紙帳蒲團清思足，更添梅種兩三株。"]'),
('f539720f-77c3-445b-b81b-2848e28506d0','次韻吳子益','于石','宋','宋诗','song-poetry','','[]','四野杳無車馬喧，竹陰籬落半開門。',64,'全唐诗/poet.song.245000.json','["四野杳無車馬喧，竹陰籬落半開門。", "牛歸落葉逕邊逕，犬吠斜陽村外村。", "老樹不摇波弄影，扁舟已去岸留痕。", "悠然樂意相關處，坐對青山兩不言。"]'),
('3d3580f8-4bf0-4aaa-9d57-12837824c3ca','春懷次韻','于石','宋','宋诗','song-poetry','','[]','弄晴天氣半昏明，春思不如詩思新。',64,'全唐诗/poet.song.245000.json','["弄晴天氣半昏明，春思不如詩思新。", "芳草斜陽王謝燕，落花流水晉秦人。", "百年臺榭幾杯酒，一片笙歌九陌塵。", "可笑遊蜂貪釀蜜，引渠兒輩口生津。"]'),
('183a8ac4-b6e2-4c53-9b6c-3ce5b22f492e','七月七日','于石','宋','宋诗','song-poetry','','[]','玉宇無塵淡月輝，誰傳織女夜停機。',64,'全唐诗/poet.song.245000.json','["玉宇無塵淡月輝，誰傳織女夜停機。", "阮分南北任貧富，河度東西果是非。", "捫腹有書安用晒，揆心無巧不須祈。", "逢時且共樽前樂，一笑淋漓酒滿衣。"]'),
('0ed8a5b7-620b-4bb8-a930-f4af67d4f29d','自述','于石','宋','宋诗','song-poetry','','[]','大兒不學小兒癡，四十頭顱已可知。',64,'全唐诗/poet.song.245000.json','["大兒不學小兒癡，四十頭顱已可知。", "道勝自然貧亦樂，氣充不與貌俱衰。", "三杯徐邈聖賢酒，一卷淵明甲子詩。", "滿眼世情從厚薄，此心當與古人期。"]'),
('cab65906-8aae-4d51-834c-b5cd491aaab8','秋思  其一','于石','宋','宋诗','song-poetry','','[]','遠水遥天起斷鴻，秋光冷淡客情濃。',64,'全唐诗/poet.song.245000.json','["遠水遥天起斷鴻，秋光冷淡客情濃。", "一川疏雨平沙牧，半樹斜陽隔塢舂。", "落葉輕於流俗態，寒花羞作少年容。", "憑高不礙乾坤眼，興入晴嵐第幾重。"]'),
('712562e4-0dfa-473b-8251-35e448553f90','秋思  其二','于石','宋','宋诗','song-poetry','','[]','草堂何必倣盧鴻，水色蒼茫山色濃。',64,'全唐诗/poet.song.245000.json','["草堂何必倣盧鴻，水色蒼茫山色濃。", "待月軒窗留客話，隔籬燈火起鄰舂。", "蟲鳴終夕如相語，燕去知時不苟容。", "一片吟情渺何許，西風吹入亂雲重。"]'),
('839380e4-1481-44f3-a68d-42094f8e71c3','夜坐讀書有感','于石','宋','宋诗','song-poetry','','[]','四山月落正昏濛，留得書燈到曉紅。',64,'全唐诗/poet.song.245000.json','["四山月落正昏濛，留得書燈到曉紅。", "千古是非昭簡冊，百年興廢老英雄。", "人因厭亂方思治，道本無窮豈有通。", "植立綱常垂萬世，至今周孔不言功。"]'),
('f64d66ce-3723-4d19-95f6-9e921ef553c5','次韻徐廷珪偶成','于石','宋','宋诗','song-poetry','','[]','德行誰能冠四科，將興將廢道云何。',64,'全唐诗/poet.song.245000.json','["德行誰能冠四科，將興將廢道云何。", "百年詩酒晉元亮，萬世功名漢伏波。", "高枕林泉閑夢少，出門風雨落花多。", "人生轉眼榮枯易，未必金章勝綠蓑。"]'),
('720c5464-6a83-4ad5-a7c9-6384f60c0788','讀史  其一','于石','宋','宋诗','song-poetry','','[]','厥初開闢浩難名，帝降而王緒可尋。',64,'全唐诗/poet.song.245000.json','["厥初開闢浩難名，帝降而王緒可尋。", "百代相因三代禮，七絃何似五絃琴。", "時逢否泰有消長，道在乾坤無古今。", "所以孟軻生戰國，欲承三聖正人心。"]'),
('d39f2b4c-4690-4969-83d2-e3f10d5aa362','讀史  其二','于石','宋','宋诗','song-poetry','','[]','世以燔經咎李斯，斯文興喪豈關渠。',64,'全唐诗/poet.song.245000.json','["世以燔經咎李斯，斯文興喪豈關渠。", "楚人未烈咸陽火，秦府猶存博士書。", "吾道不隨灰燼冷，殘烟空鎖帝王居。", "獨嗟先入收圖籍，刀筆區區計亦疏。"]'),
('16d93780-4db6-4cbb-8f26-0554650844cb','讀史  其三','于石','宋','宋诗','song-poetry','','[]','秦亡四海角羣雄，三尺胡然起沛豐。',64,'全唐诗/poet.song.245000.json','["秦亡四海角羣雄，三尺胡然起沛豐。", "首錄酇侯忘紀信，不誅項伯戮丁公。", "親而寡助寧非叛，國爾忘身始是忠。", "賞罰於斯庸未當，終然擊柱或爭功。"]'),
('fc474d96-52ea-47b6-9667-4864dc474b4d','讀史  其四','于石','宋','宋诗','song-poetry','','[]','漢楚興亡事已休，至今堪嘆亦堪羞。',64,'全唐诗/poet.song.245000.json','["漢楚興亡事已休，至今堪嘆亦堪羞。", "鄭君不肯更名籍，項伯胡爲賜姓劉。", "寡助固知親亦叛，孤忠忍以主爲讎。", "人臣貴在明大義，勿爲身謀爲國謀。"]'),
('ebb794c8-c653-4bb3-95ef-715df668416e','讀史  其五','于石','宋','宋诗','song-poetry','','[]','今來古往一封疆，虎鬬龍爭幾帝王。',64,'全唐诗/poet.song.245000.json','["今來古往一封疆，虎鬬龍爭幾帝王。", "百二山河秦地險，八千子弟楚天亡。", "朝廷有道自多助，仁義行師豈恃强。", "往事廢興何處問，寒烟衰草滿斜陽。"]'),
('b00519ae-c895-4517-8ad5-92a514f2ea97','讀史  其六','于石','宋','宋诗','song-poetry','','[]','莫言世事祇如棋，千載是非人共知。',64,'全唐诗/poet.song.245000.json','["莫言世事祇如棋，千載是非人共知。", "吾道廢興時否泰，人才進退國安危。", "詩書未火秦猶在，黨錮無鉤漢亦衰。", "覆轍相尋多不悟，撫編太息此何時。"]'),
('ef8633c4-013d-436f-8d62-31b60b89c51d','讀史  其七','于石','宋','宋诗','song-poetry','','[]','志士匡君貴善謀，古來直筆有春秋。',64,'全唐诗/poet.song.245000.json','["志士匡君貴善謀，古來直筆有春秋。", "孔明扶漢何吞蜀，仁傑興唐乃死周。", "成敗由人天不管，功名遺恨水空流。", "柬之未相姜維將，二子寧無身後憂。"]'),
('b2143318-7beb-4e06-99a9-e534b5c3d207','壬辰春雪','于石','宋','宋诗','song-poetry','','[]','和氣胚胎斡化鈞，胡然積雪擁柴門。',64,'全唐诗/poet.song.245000.json','["和氣胚胎斡化鈞，胡然積雪擁柴門。", "花梢凍壓春無力，山骨晴銷曉有痕。", "陽壯誰令陰作梗，寒驕猶勒暖歸根。", "昌黎浪說豐年瑞，爲瑞爲災未易言。"]'),
('0edd9730-444c-4c33-96ac-2787dc3ee418','西湖','于石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖勝概甲東南，滿眼繁華今幾年。',64,'全唐诗/poet.song.245000.json','["西湖勝概甲東南，滿眼繁華今幾年。", "鐘鼓相聞南北寺，笙歌不斷往來船。", "山圍花柳春風地，水浸樓臺夜月天。", "士女只知遊賞樂，誰能軫念及三邊。"]'),
('9a71d4c4-4901-4a25-8565-aeef99aa7ac5','次韻蘇巨卿','于石','宋','宋诗','song-poetry','','[]','誰叩柴門寄我詩，迎門稚子候予歸。',64,'全唐诗/poet.song.245000.json','["誰叩柴門寄我詩，迎門稚子候予歸。", "青山喚醒十年夢，明月空懷千里思。", "今晉古秦天地隔，范雎張祿姓名非。", "人生百歲發相見，世事悠悠未可知。"]'),
('b39eae74-9815-4683-a4e8-0ddca539218e','三洞','于石','宋','宋诗','song-poetry','','[]','群峭摩天不染埃，凝嵐滴翠鬰崔嵬。',64,'全唐诗/poet.song.245000.json','["群峭摩天不染埃，凝嵐滴翠鬰崔嵬。", "簾垂飛瀑無人捲，舟引遊仙出洞來。", "一竅中誰開混沌，三山外亦有蓬萊。", "捫蘿更問朝真路，夾逕松陰覆綠苔。"]'),
('0e13cd68-c94e-4d69-a011-a008bd8a57b9','次韻徐則正山居','于石','宋','宋诗','song-poetry','','[]','松間花外有虛亭，花自向陽松自陰。',64,'全唐诗/poet.song.245000.json','["松間花外有虛亭，花自向陽松自陰。", "水濁不污明月色，人閑方見白雲心。", "棋邊冷眼安危著，筆底放懷長短吟。", "世忌獨醒還惡醉，淺斟莫使酒杯深。"]'),
('44da2a40-41ef-4090-bf54-116b32ac69b6','月夜納凉','于石','宋','宋诗','song-poetry','','[]','天地空無半點塵，翛然池館浸虛明。',64,'全唐诗/poet.song.245000.json','["天地空無半點塵，翛然池館浸虛明。", "幾更今古月常在，一片襟懷水共清。", "風定波摇晴樹影，魚翻露瀉翠荷聲。", "炎凉圓缺須臾事，我獨於斯感世情。"]'),
('e2b887be-6ba9-43da-b7eb-9cd78767a427','次韻徐永之秋興','于石','宋','宋诗','song-poetry','','[]','誰謂四時秋最愁，胡床談咏晉風流。',64,'全唐诗/poet.song.245000.json','["誰謂四時秋最愁，胡床談咏晉風流。", "山川長在英雄老，草木無邊天地秋。", "驚眼一行漁唱晚，斜陽萬里客凭樓。", "茫茫遠水涵空碧，興入蘆花第幾洲。"]'),
('959228ae-4462-422b-9262-84e215aabc26','次韻君會感思','于石','宋','宋诗','song-poetry','','[]','滿眼山川感舊遊，依然野水自橫舟。',64,'全唐诗/poet.song.245000.json','["滿眼山川感舊遊，依然野水自橫舟。", "一樽長照古今月，兩鬢不禁天地秋。", "有屋有田清潁尾，自蒲自柳曲江頭。", "虛名不落人間世，一逕松風穩跨牛。"]'),
('fc45e1fb-ef34-409d-9164-8b15c868f315','次韻徐深之','于石','宋','宋诗','song-poetry','','[]','文章何必擬卿雲，筆硯無功錢有神。',64,'全唐诗/poet.song.245000.json','["文章何必擬卿雲，筆硯無功錢有神。", "明月能招山入戶，幽花不與世爭春。", "百年亭館幾興廢，十載交遊半故新。", "過眼榮華何足較，青門試問種瓜人。"]'),
('162ef4d6-9c9f-4d5b-91ba-33ce01d12275','次韻宏父初夏','于石','宋','宋诗','song-poetry','','[]','留得三分春意和，荼䕷猶可入吟哦。',64,'全唐诗/poet.song.245000.json','["留得三分春意和，荼䕷猶可入吟哦。", "人情疏密庭前竹，吾道卷舒池上荷。", "結友豈無今管鮑，論詩奚必古陰何。", "梅霖驟漲江天闊，還有長竿可釣麽。"]'),
('487c6451-a9cf-432f-89d5-dc0bfc3b21b3','邵氏園亭','于石','宋','宋诗','song-poetry','','[]','曲曲亭臺日月春，人間榮辱兩無聞。',64,'全唐诗/poet.song.245000.json','["曲曲亭臺日月春，人間榮辱兩無聞。", "梅邊讀易分明月，松下敲棋碎白雲。", "東里先生新釀酒，北山逋客舊移文。", "家傳應得青門趣，手種園瓜手自耘。"]'),
('ae35547f-d015-4bf3-8e78-5f0197c69203','次韻何寺簿閑詠','于石','宋','宋诗','song-poetry','','[]','居喜山深人不知，凝嵐空翠淡含輝。',64,'全唐诗/poet.song.245000.json','["居喜山深人不知，凝嵐空翠淡含輝。", "隔林樵語驚猿去，倚石松枝礙鶴飛。", "留客眠雲聽澗瀑，呼兒踏月掃苔磯。", "冥心靜坐勿輕出，門外藤蘿露濕衣。"]'),
('2754271a-dd0b-42a8-a7a4-68964a3aca7b','水亭夜坐','于石','宋','宋诗','song-poetry','','[]','水光涵月浸虛窗，醉倚欄干午夜凉。',64,'全唐诗/poet.song.245000.json','["水光涵月浸虛窗，醉倚欄干午夜凉。", "蛙一兩聲隔籬落，螢三四點過池塘。", "風摇松影蛟龍活，露瀉荷盤翡翠香。", "俯仰不知天地闊，悠然長嘯據胡床。"]'),
('fad870f8-360f-499b-bba5-cf89a4542e32','次韻楊恂夜興','于石','宋','宋诗','song-poetry','','[]','漫漫夜氣萬山深，風露高寒天宇清。',64,'全唐诗/poet.song.245000.json','["漫漫夜氣萬山深，風露高寒天宇清。", "簷月窺人驚白髪，爐烟凝坐悟黄庭。", "挑燈看劍心猶壯，欹枕聽泉眼獨醒。", "毀譽不公隨好惡，試觀陸羽煮茶經。"]'),
('abcc083e-99f9-4669-aad2-34834816334f','徐子觀生輓詩','于石','宋','宋诗','song-poetry','','[]','一片清虛太極心，浮雲流水世情輕。',64,'全唐诗/poet.song.245000.json','["一片清虛太極心，浮雲流水世情輕。", "有生已作無生計，未死先求不死名。", "墓必預銘唐杜牧，詩能自輓晉淵明。", "巋然貌不隨年老，留與斯文主夏盟。"]'),
('a6014282-2b81-45f1-93de-628c436c45f4','次韻趙子玉書懷','于石','宋','宋诗','song-poetry','','[]','鶉結爲衣鷸作冠，采芝何處問商顔。',64,'全唐诗/poet.song.245000.json','["鶉結爲衣鷸作冠，采芝何處問商顔。", "興亡眼欲窺千古，俯仰心無愧兩間。", "客路西風新白髪，野花啼鳥舊青山。", "日高濃睡平川屋，安用鷄鳴度遠關。"]'),
('2e5448d0-cc1a-493f-85ad-7662f2e3041c','次韻中秋對月','于石','宋','宋诗','song-poetry','','[]','冰壺碾破一輪秋，杯吸長鯨筆挽牛。',64,'全唐诗/poet.song.245000.json','["冰壺碾破一輪秋，杯吸長鯨筆挽牛。", "大地山河明色界，九天宮闕耀瓊樓。", "香浮蟾桂今猶古，曲按霓裳樂易愁。", "四海清光無不照，何須天柱一峰遊。"]'),
('4c480f26-be28-44f7-9830-793eda86c482','次韻君會初冬','于石','宋','宋诗','song-poetry','','[]','一年好景橘黄時，驟冷惟應瘦骨知。',64,'全唐诗/poet.song.245000.json','["一年好景橘黄時，驟冷惟應瘦骨知。", "吠犬頻繁墮霜葉，棲鴉不定戰風枝。", "爐何必試手可熱，文未能成鬢欲絲。", "春逼寒梅三兩點，蹇馿江路試尋詩。"]'),
('074dc923-04a6-4f53-b241-ed5c1d325163','雜興四首  其一','于石','宋','宋诗','song-poetry','','[]','屋上青山屋下雲，清泉爲鏡石爲屏。',32,'全唐诗/poet.song.245000.json','["屋上青山屋下雲，清泉爲鏡石爲屏。", "客來問我謀生計，一卷家傳相鶴經。"]'),
('b7380905-6cdb-49a8-8931-673223ba4617','雜興四首  其二','于石','宋','宋诗','song-poetry','','[]','偶種階前竹數根，引風招月伴清樽。',32,'全唐诗/poet.song.245000.json','["偶種階前竹數根，引風招月伴清樽。", "春來爲愛臨階竹，今日翻嫌竹礙門。"]'),
('5a48f4af-4e4c-4d78-8843-504ba1e87300','雜興四首  其三','于石','宋','宋诗','song-poetry','','[]','采藥歸來竹徑凉，滿身草露濕衣香。',32,'全唐诗/poet.song.245000.json','["采藥歸來竹徑凉，滿身草露濕衣香。", "怕驚幽鳥穿林去，不掃松花卧石床。"]'),
('9e8fddab-a984-424e-8751-4a90c891d31f','雜興四首  其四','于石','宋','宋诗','song-poetry','','[]','四圍綠樹岩藏屋，一枕清風竹滿軒。',32,'全唐诗/poet.song.245000.json','["四圍綠樹岩藏屋，一枕清風竹滿軒。", "醉裏不知山雨過，醒來惟怪瀑聲喧。"]'),
('43d39fe4-adbc-41d1-aef4-d306c3921843','釣臺','于石','宋','宋诗','song-poetry','','[]','傲睨羣雄百戰來，獨全高節老蒿萊。',32,'全唐诗/poet.song.245000.json','["傲睨羣雄百戰來，獨全高節老蒿萊。", "三公不任雲臺將，物色何須及釣臺。"]'),
('cbe7f10d-d132-4331-a98c-d6ae022ea753','孤山','于石','宋','宋诗','song-poetry','','[]','老梅半樹倚枯槎，路入湖心第幾家。',32,'全唐诗/poet.song.245000.json','["老梅半樹倚枯槎，路入湖心第幾家。", "水月荒凉誰復問，遊人多只看荷花。"]'),
('0efbaeb8-de55-4e66-86aa-4817e13d27db','八詠樓','于石','宋','宋诗','song-poetry','','[]','八詠詩傳千古名，蹇馿何在井空澄。',32,'全唐诗/poet.song.245000.json','["八詠詩傳千古名，蹇馿何在井空澄。", "凄凉樓外雙溪月，曾照齊梁幾廢興。"]'),
('761e3a48-6641-49a7-afb2-cae145c688e7','小三洞  其一','于石','宋','宋诗','song-poetry','','[]','四山迴合響幽泉，古木蒼藤路屈盤。',32,'全唐诗/poet.song.245000.json','["四山迴合響幽泉，古木蒼藤路屈盤。", "一局殘棋雙鶴去，石屏空倚白雲寒。"]'),
('d773ba9d-aa4f-4d0b-8b64-1996c8345af8','小三洞  其二','于石','宋','宋诗','song-poetry','','[]','洞門相對是吾家，朝看烟雲暮看霞。',32,'全唐诗/poet.song.245000.json','["洞門相對是吾家，朝看烟雲暮看霞。", "鐵笛一聲山石裂，老松驚落半巖花。"]'),
('bb4634fa-d297-4da2-bb97-5def10d888d7','小三洞  其三','于石','宋','宋诗','song-poetry','','[]','斷崖怒湧四時雪，虛壁寒凝六月霜。',32,'全唐诗/poet.song.245000.json','["斷崖怒湧四時雪，虛壁寒凝六月霜。", "倚樹老僧閑洗鉢，碧桃花落澗泉香。"]'),
('1779aa89-843c-460a-b65a-ba166f6470c8','兜率寺','于石','宋','宋诗','song-poetry','','[]','錢唐一劍倚霜寒，萬水千山蜀道難。',32,'全唐诗/poet.song.245000.json','["錢唐一劍倚霜寒，萬水千山蜀道難。", "瓶鉢生涯何處在，秋風松子落詩壇。"]'),
('90297e00-eb20-4669-b375-6f31a3487514','西岩寺','于石','宋','宋诗','song-poetry','','[]','丹崖翠壁數千尺，絕頂僧房三四間。',32,'全唐诗/poet.song.245000.json','["丹崖翠壁數千尺，絕頂僧房三四間。", "老樹倚岩岩倚屋，白雲飛去又飛還。"]'),
('66c8a7e1-befc-4a27-a7d6-97847634a096','紫薇岩','于石','宋','宋诗','song-poetry','','[]','靈岩舊是先生宅，拈筆新題郡守名。',32,'全唐诗/poet.song.245000.json','["靈岩舊是先生宅，拈筆新題郡守名。", "月落空山人語寂，澗泉猶作讀書聲。"]'),
('4afe6796-9fe8-47a6-95fe-7ef5d035f96a','小反嶺','于石','宋','宋诗','song-poetry','','[]','泉本至清誰曰盜，溪雖可染却名愚。',32,'全唐诗/poet.song.245000.json','["泉本至清誰曰盜，溪雖可染却名愚。", "一夫作難隨傾覆，千古青山獨受污。"]'),
('6f5e25a4-3beb-4b76-9cbf-08a1d4ece81f','凈居院遇雪','于石','宋','宋诗','song-poetry','','[]','夢回寒月吐層崖，湯響松風聽煮茶。',32,'全唐诗/poet.song.245000.json','["夢回寒月吐層崖，湯響松風聽煮茶。", "倚樹恐驚殘雪墮，起來不敢嗅梅花。"]'),
('77587bd8-4add-4764-aa93-5554a4590913','次韻趙羽翁秋江雜興  其一','于石','宋','宋诗','song-poetry','','[]','翩翩水鳥自沉浮，紅蓼黄蘆兩岸秋。',32,'全唐诗/poet.song.245000.json','["翩翩水鳥自沉浮，紅蓼黄蘆兩岸秋。", "隔水人家一犬吠，斜陽籬落有漁舟。"]'),
('be6b6f29-0f79-4521-8b3e-9458eb9689cc','次韻趙羽翁秋江雜興  其二','于石','宋','宋诗','song-poetry','','[]','雁落蘆花洲外洲，半川斜日獨凭樓。',32,'全唐诗/poet.song.245000.json','["雁落蘆花洲外洲，半川斜日獨凭樓。", "笛聲何處雁驚起，點破清江一片秋。"]'),
('2e803d5e-4955-4d90-b072-ab7b6cf6a119','次韻杜若川春日雜興集句  其一','于石','宋','宋诗','song-poetry','','[]','行約青帘共一樽，牧童遥指杏花村。',32,'全唐诗/poet.song.245000.json','["行約青帘共一樽，牧童遥指杏花村。", "如今只有花含笑，悍吏催租夜打門。"]'),
('9e740cc2-3687-4a84-930a-7178148bac9d','次韻杜若川春日雜興集句  其二','于石','宋','宋诗','song-poetry','','[]','九陌凈無車馬塵，不須移檻損天真。',32,'全唐诗/poet.song.245000.json','["九陌凈無車馬塵，不須移檻損天真。", "凡花俗草敗人意，悵望烟雲縹渺人。"]'),
('8c574a66-d1cc-4662-ba10-571794f342b0','丁丑歲旦','于石','宋','宋诗','song-poetry','','[]','不寫桃符換舊詩，辛盤竹爆付兒嬉。',32,'全唐诗/poet.song.245000.json','["不寫桃符換舊詩，辛盤竹爆付兒嬉。", "山深未見新年歷，只記梅花春早遲。"]'),
('c4bcc2f0-189d-4ff3-9cc8-68365b9f7b94','晚眺','于石','宋','宋诗','song-poetry','','[]','漁歌樵語隔溪村，沙上牛歸小徑分。',32,'全唐诗/poet.song.245000.json','["漁歌樵語隔溪村，沙上牛歸小徑分。", "烟樹參差片帆落，半川斜日九峰雲。"]'),
('5fe2d538-97f5-4490-a2d9-0b89cd4ddf12','旅夜','于石','宋','宋诗','song-poetry','','[]','擁爐兀兀坐成睡，夢到家山人不知。',32,'全唐诗/poet.song.245000.json','["擁爐兀兀坐成睡，夢到家山人不知。", "半夜酒醒還是客，一庭黄葉雨來時。"]'),
('55b4e688-d111-41b0-95b3-9e81dbd137a3','旅中遣懷','于石','宋','宋诗','song-poetry','','[]','片雲相望浙東西，回首家山路欲迷。',32,'全唐诗/poet.song.245000.json','["片雲相望浙東西，回首家山路欲迷。", "昨夜桐江江上夢，倒隨流水上雙溪。"]'),
('b29b237b-c9bb-42ee-a478-5b4698e67f82','次韻趙德輿山家','于石','宋','宋诗','song-poetry','','[]','茅簷日暖卧寒林，過午老翁鼾睡聲。',32,'全唐诗/poet.song.245000.json','["茅簷日暖卧寒林，過午老翁鼾睡聲。", "擾擾紅塵山下路，曉霜殘月有人行。"]'),
('a48f3684-526e-42f8-bafc-7602c0f0a18b','寄題千秋觀','于石','宋','宋诗','song-poetry','','[]','崢嶸金碧千秋觀，誰記當年賀監家。',32,'全唐诗/poet.song.245000.json','["崢嶸金碧千秋觀，誰記當年賀監家。", "湖水亦隨人世改，秋光一半失荷花。"]'),
('d3b82c5a-d701-4c51-a14b-cb52b1d59b87','早梅','于石','宋','宋诗','song-poetry','','[]','一氣獨先天地春，兩三花占十分清。',32,'全唐诗/poet.song.245000.json','["一氣獨先天地春，兩三花占十分清。", "冰霜不隔陽和力，半點機緘妙化生。"]'),
('0ccb2a58-1d3d-43cd-a39a-62c1eaf8a65b','白杜鵑花','于石','宋','宋诗','song-poetry','','[]','蜀帝魂銷恨不窮，野花開落倚東風。',32,'全唐诗/poet.song.245000.json','["蜀帝魂銷恨不窮，野花開落倚東風。", "吻乾無復枝頭血，幾度啼來染不紅。"]'),
('921a0faf-cd25-485b-9725-1d4af601d3ec','始皇','于石','宋','宋诗','song-poetry','','[]','萬世綱常具六經，天應未遽喪斯文。',32,'全唐诗/poet.song.245000.json','["萬世綱常具六經，天應未遽喪斯文。", "焚書欲滅先王道，道在人心不可焚。"]'),
('092c94d4-471d-41f5-85ce-85b275055ca6','高帝','于石','宋','宋诗','song-poetry','','[]','呂氏强梁劉氏危，宮中枕卧復誰知。',32,'全唐诗/poet.song.245000.json','["呂氏强梁劉氏危，宮中枕卧復誰知。", "釀成外戚中官禍，興漢已開亡漢基。"]'),
('f7eec53a-5ec3-47c9-bcfe-a24c48a28d44','子房','于石','宋','宋诗','song-poetry','','[]','韓亡誓欲報秦仇，秦滅還興伐楚謀。',32,'全唐诗/poet.song.245000.json','["韓亡誓欲報秦仇，秦滅還興伐楚謀。", "一念爲韓非爲漢，無功何必願封留。"]'),
('669e4327-f68b-436c-8d66-1a969e448e61','許劭','于石','宋','宋诗','song-poetry','','[]','四海同推月旦評，是非公論至今存。',32,'全唐诗/poet.song.245000.json','["四海同推月旦評，是非公論至今存。", "老瞞敢肆奸雄志，未必不因公一言。"]'),
('201602b4-2915-42bc-bfcd-1b6126fb4ba1','禰衡','于石','宋','宋诗','song-poetry','','[]','懷中漫刺欲何之，四海交游只兩兒。',32,'全唐诗/poet.song.245000.json','["懷中漫刺欲何之，四海交游只兩兒。", "不死曹瞞死黄祖，殺身何補漢興衰。"]'),
('c0cd471d-73c4-473e-83be-f241490b2813','孔明','于石','宋','宋诗','song-poetry','','[]','居荆不肯吞劉表，入蜀胡爲詐取璋。',32,'全唐诗/poet.song.245000.json','["居荆不肯吞劉表，入蜀胡爲詐取璋。", "二子孰非劉氏後，豈惟玄德可興王。"]'),
('7a885f03-a9f5-42e0-9e92-0c095ea18148','曹操','于石','宋','宋诗','song-poetry','','[]','心非禪代荀文若，目識奸雄許子將。',32,'全唐诗/poet.song.245000.json','["心非禪代荀文若，目識奸雄許子將。", "身苟未亡終篡漢，不知何德比文王。"]'),
('a77d3a83-a73b-4ace-abf4-b378f2b586d4','柳子厚','于石','宋','宋诗','song-poetry','','[]','早綴朝班附叔文，晚隨兒女拜雙星。',32,'全唐诗/poet.song.245000.json','["早綴朝班附叔文，晚隨兒女拜雙星。", "半生巧宦翻成拙，何用區區更乞靈。"]'),
('367dbb5c-a63f-4521-9966-3a76886a006d','讀明妃引','于石','宋','宋诗','song-poetry','','[]','周求莘女終亡紂，越獻西施竟滅吳。',32,'全唐诗/poet.song.245000.json','["周求莘女終亡紂，越獻西施竟滅吳。", "馬上琵琶徒自恨，不思强漢弱匈奴。"]'),
('73d85d7f-52e5-48b0-9035-a876f0a9d4c5','次韻鑑中八詠  其一','于石','宋','宋诗','song-poetry','','[]','青山削芙蓉，上有浮雲生。',48,'全唐诗/poet.song.245000.json','["青山削芙蓉，上有浮雲生。", "窈窕俯長流，逶迤带重城。", "朝光散霞彩，暮色涵空青。", "鴟夷去不回，遺爾千古名。"]'),
('6238d628-4e64-4f99-9721-3ff1a3eed28f','次韻鑑中八詠  其二','于石','宋','宋诗','song-poetry','','[]','蓬萊失左股，負以垂天翼。',48,'全唐诗/poet.song.245000.json','["蓬萊失左股，負以垂天翼。", "中有仙人居，珠宮燦瑶席。", "凝雲不飛去，化作輪囷石。", "彈琴坐石上，長憶三山客。"]'),
('e427a3c1-a500-48d9-aca6-44f197fb5c28','次韻鑑中八詠  其三','于石','宋','宋诗','song-poetry','','[]','會稽山水國，崇山幽事多。',48,'全唐诗/poet.song.245000.json','["會稽山水國，崇山幽事多。", "當時觴詠處，春淨花顔酡。", "磊落黄金罍，玲瓏白玉珂。", "行樂須及時，美人在丘阿。"]'),
('6426911f-c922-4eb6-a958-a252c1dbca1b','次韻鑑中八詠  其四','于石','宋','宋诗','song-poetry','','[]','梅山如積翠，的皪手堪捧。',48,'全唐诗/poet.song.245000.json','["梅山如積翠，的皪手堪捧。", "遥遥仙人尉，盤盤故時隴。", "丹泉清可鑑，石乳甘於湩。", "行將解塵纓，于焉滔高踵。"]'),
('b6edb6b0-26d4-4b64-b6ab-2eb08f905e73','次韻鑑中八詠  其五','于石','宋','宋诗','song-poetry','','[]','我愛鑑湖水，明如照膽銅。',48,'全唐诗/poet.song.245000.json','["我愛鑑湖水，明如照膽銅。", "澄清若有待，渾濁那能蒙。", "當時賀知章，富貴如苓通。", "豈無一畝地，來築仙人宮。"]'),
('b6abba6a-824c-45fb-8631-67c91e942258','次韻鑑中八詠  其六','于石','宋','宋诗','song-poetry','','[]','驅車曉行邁，行行出郊郭。',48,'全唐诗/poet.song.245000.json','["驅車曉行邁，行行出郊郭。", "斷岡屹崇墉，虛籟殷靈壑。", "雨深瑶草長，風定松花落。", "西山有爽氣，逍遥倚晴閣。"]'),
('cbe9d15e-8309-4d4e-b4e6-cc0e1fed5c22','次韻鑑中八詠  其七','于石','宋','宋诗','song-poetry','','[]','樓居本高明，况在松竹閒。',48,'全唐诗/poet.song.245000.json','["樓居本高明，况在松竹閒。", "溪流深幾尺，新雨過前山。", "浮雲多變態，好鳥亦閒關。", "偃蹇樓中人，對酒還開顔。"]'),
('ac3f4153-ac50-4784-89e8-5d61092720d9','次韻鑑中八詠  其八','于石','宋','宋诗','song-poetry','','[]','視心如蓮花，淨明涵十虛。',48,'全唐诗/poet.song.245000.json','["視心如蓮花，淨明涵十虛。", "出泥本無垢，露體皆真如。", "大千入一息，宴坐忘百須。", "陶公雖飲酒，時能到林廬。"]'),
('32a824fc-f055-4047-beae-c84e20ec578d','弔古行','于石','宋','宋诗','song-poetry','','[]','蒼梧之南湘水頭，烟波逐客增離憂。',96,'全唐诗/poet.song.245000.json','["蒼梧之南湘水頭，烟波逐客增離憂。", "重瞳孤墳閟白日，雙娥貞佩摇清秋。", "江空夜聞鬼對泣，泣罷仍爲鼓瑶瑟。", "瑟聲漸杳江聲長，丹楓墜影天霜白。", "臨江被髪招帝魂，拔劍欲斷東流奔。", "東流無窮帝不返，嗚呼薄俗無由敦。"]'),
('b38d334a-c604-43aa-a802-03fa4f473480','釣臺','于石','宋','宋诗','song-poetry','','[]','拋却羊裘入漢庭，偶然偃卧兩忘形。',32,'全唐诗/poet.song.245000.json','["拋却羊裘入漢庭，偶然偃卧兩忘形。", "先生無處可伸足，太史何煩奏客星。"]'),
('aed29730-ad11-4048-80d8-f81af1c4fab9','晨入東寺閲藏行香','仇遠','宋','宋诗','song-poetry','','[]','明星未高，繁霜已肅。',100,'全唐诗/poet.song.245000.json','["明星未高，繁霜已肅。", "娟娟落月，猶挂茅屋。", "我馬遑遑，我車僕僕。", "晨入緇林，坐閲梵牘。", "字奇義奧，了不可讀。", "空元無象，奚事耳目。", "簡書期程，軒冕桎梏。", "顧影自哂，未能免俗。", "名教真樂，言語穀粟。", "何時式微，知足不辱。"]'),
('758a3533-5663-4415-b85d-b638dd836970','養雁','仇遠','宋','宋诗','song-poetry','','[]','雝雝陽鳥，其居朔方。',80,'全唐诗/poet.song.245000.json','["雝雝陽鳥，其居朔方。", "朅來江南，雪霜備嘗。", "意不耐暑，慮爾早亡。", "乃安水土，羽毛無傷。", "仰羨鵷雛，俯趨鶩行。", "負影隻立，何如還鄉。", "秋風日高，稻粱已黄。", "且謀一飽，勿思翱翔。"]'),
('11853e59-77fa-4a95-a62d-08dec57bd0e6','野飲','仇遠','宋','宋诗','song-poetry','','[]','土岡之西，竹樹之下。',60,'全唐诗/poet.song.245000.json','["土岡之西，竹樹之下。", "板屋三間，娛此隠者。", "塒有肥鷄，廄有羸馬。", "豈無佳菊，采不盈把。", "且漉我酒，放浪林野。", "莫不飲食，知味者寡。"]'),
('b9d82e90-fe34-48f6-8fb1-5bc37207d7f4','題徐壽畫牛','仇遠','宋','宋诗','song-poetry','','[]','此大武者，二十八蹄。',40,'全唐诗/poet.song.245000.json','["此大武者，二十八蹄。", "茂樹之下，豐草萋萋。", "牧童且嬉，夕陽未西。", "何如桃林，歸去來兮。"]'),
('804d4488-75b6-46d0-9285-02799776b1c7','送高仲山通州教授','仇遠','宋','宋诗','song-poetry','','[]','通川得通儒，善類蒙善教。',144,'全唐诗/poet.song.245000.json','["通川得通儒，善類蒙善教。", "如此老成人，真足重學校。", "我昔客朱方，曾窺管中豹。", "言容既篤厚，文字入玄奧。", "交游二十年，夷險同一操。", "閒居虎林麓，倚窗聊寄傲。", "忽承北斗敕，勇鼓來淮櫂。", "華髪映青袍，輕帆愜黄帽。", "天晴宜征途，芹藻春色到。", "臯比坐可暖，三載勤訓導。", "惜哉龜手藥，至老方取效。", "載酒游五山，何由共吟嘯。"]'),
('dccfd53f-b8e0-4c41-8c51-3c0874474077','送楊志行赴徽州教授','仇遠','宋','宋诗','song-poetry','','[]','峨峨紫陽山，翼翼素王宮。',168,'全唐诗/poet.song.245000.json','["峨峨紫陽山，翼翼素王宮。", "中藏朱子書，頗有鄒魯風。", "在昔三十年，我嘗遊其中。", "一溪練带如，環以千翠峰。", "朝嵐與夕霏，四景日不同。", "惜哉屐齒折，我舟遽云東。", "子今振木鐸，出爲斯文宗。", "諸生列館下，待問如撞鐘。", "明經別同異，析理開愚蒙。", "獨坐三鱣堂，教思傳無窮。", "庠序足真樂，詩書有近功。", "行當自此升，豈曰難爲容。", "平生韓孟交，雲龍阻相從。", "願言壽道體，有書附鱗鴻。"]'),
('664e7318-a831-4f76-a5a8-436fcb3eca68','下壽','仇遠','宋','宋诗','song-poetry','','[]','六十本下壽，皤然成禿翁。',84,'全唐诗/poet.song.245000.json','["六十本下壽，皤然成禿翁。", "繫舟貞女瀨，竊祿素王宮。", "暮隨太守車，朝迓御史驄。", "我馬劣難騎，却與無馬同。", "老病厭徒步，足力亦易窮。", "將以馬易牛，歸耕田園中。", "聖人有遺訓，吾不如老農。"]'),
('f3baa68b-ec12-4290-aec7-2695255e4709','小園梅已綠陰忽見一花甚香','仇遠','宋','宋诗','song-poetry','','[]','此枝綠陰繁，枝上子如豆。',72,'全唐诗/poet.song.245000.json','["此枝綠陰繁，枝上子如豆。", "一花褎然見，香襞苔蘚透。", "雖同梨雲夢，亦出桃李右。", "矜驕若自惜，終覺老而瘦。", "昔占百花先，今處百花後。", "春風少年場，尤當敬耆舊。"]'),
('dbf4a64e-0641-4e27-8367-73a6f567f5c6','答陳宗道見寄  其一','仇遠','宋','宋诗','song-poetry','','[]','蹇予山澤臞，飄飄一鷗似。',72,'全唐诗/poet.song.245000.json','["蹇予山澤臞，飄飄一鷗似。", "天風忽假便，飲此金瀨水。", "朝隨章句儒，暮逐副墨子。", "肯嘆飯不足，可戀惟酒美。", "賦芧亦聊復，久矣忘喜怒。", "尾寧曳塗中，人生行樂耳。"]'),
('7a621ada-2851-4164-8610-05c5a385e80d','答陳宗道見寄  其二','仇遠','宋','宋诗','song-poetry','','[]','懷人耿不寐，一夕三四起。',72,'全唐诗/poet.song.245000.json','["懷人耿不寐，一夕三四起。", "江東暮雲合，渺渺隔秋水。", "遺我詩兩章，意古音粹美。", "敢謂義熙餘，及見黄初體。", "君閒恥食粟，我出慚爲米。", "流品敻不同，黄河貫清濟。"]'),
('a3e954f6-195e-4897-89a2-718600617e8d','存耕吟寄姜景星','仇遠','宋','宋诗','song-poetry','','[]','吾不學老農，種此方寸田。',108,'全唐诗/poet.song.245000.json','["吾不學老農，種此方寸田。", "善雨日培壅，安得荒旱年。", "詩書菑且畬，芟藴毋蔓延。", "種固有厚薄，穫豈無後先。", "先疇畎畝在，後世兒孫傳。", "何憂換八百，奚止取十千。", "却笑多牛翁，轉瞬無炊煙。", "我獨遺以安，本固實自堅。", "耘業待歲晚，韓公嘗勉旃。"]'),
('579fdf77-6c49-43a9-b2f1-809e9453cb14','插梅','仇遠','宋','宋诗','song-poetry','','[]','偶得數枝梅，插向陶瓶裏。',48,'全唐诗/poet.song.245000.json','["偶得數枝梅，插向陶瓶裏。", "置之曲密房，注以清冷水。", "肌膚若冰雪，寒極粟不起。", "歲晏且聞香，春深看結子。"]'),
('3eaacfa3-d88b-4cde-b653-f79b46a7f596','示沈道人','仇遠','宋','宋诗','song-poetry','','[]','有涯本無涯，後覺即先覺。',48,'全唐诗/poet.song.245000.json','["有涯本無涯，後覺即先覺。", "名利念既輕，生死路不錯。", "棋枰幾勝負，只看末一著。", "寄語耽酒人，飲時自斟酌。"]'),
('32654ee1-4f8e-4a59-97dd-e9aaff94c8bc','懷白石社尊師道堅','仇遠','宋','宋诗','song-poetry','','[]','我思南山陽，谷神何緜緜。',48,'全唐诗/poet.song.245000.json','["我思南山陽，谷神何緜緜。", "松下笑相別，惚恍忘歲年。", "寄我猶龍經，文字入幽玄。", "終期白石頂，擊竹歌遊仙。"]'),
('248ab178-0b9d-4eca-a324-2e722b5585b0','和子野見寄十二辰體','仇遠','宋','宋诗','song-poetry','','[]','良工鼠鬚筆，戢戢囊穎露。',144,'全唐诗/poet.song.245000.json','["良工鼠鬚筆，戢戢囊穎露。", "抄詩節經史，汗牛車載路。", "信知文中虎，一代人不數。", "細聲笑蚯蠅，妙趣忘魚兔。", "東野龍無雲，胡爲乎泥中。", "蟠屈如睡虵，虛此雲夢胸。", "且騎款段馬，野服隨田翁。", "相羊山澤間，真樂樵牧同。", "開林斬猴杙，種花續春意。", "他年處雞窠，偃蹇增老氣。", "錦鯨卷不宜，貂狗續亦易。", "老硯磨豬肝，翰墨作遊戲。"]'),
('e52ac3a1-e10a-43a3-be77-7e0f512b921b','和卞仲祥','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吾友卞南仲，別我何匆匆。',96,'全唐诗/poet.song.245000.json','["吾友卞南仲，別我何匆匆。", "家有六男兒，乃與不死同。", "阿祥更穎出，亹亹有父風。", "翰墨既瀟灑，文字猶研窮。", "西園蓋常飛，北海樽屢空。", "霜寒瀨水淺，蛟龍若爲容。", "我將歸西湖，春風入脩筇。", "期子梅花下，一酹孤山翁。"]'),
('1e0ee959-a7c5-4a3b-b435-8cfa14c84fe6','和張仲實見寄  其一','仇遠','宋','宋诗','song-poetry','','[]','天地有義氣，五行秋在金。',60,'全唐诗/poet.song.245000.json','["天地有義氣，五行秋在金。", "風吹庭前樹，亦作清商音。", "游子初離羣，百感集一襟。", "諒予老冉冉，無復謠善淫。", "吾方用吾悟，安計他人心。"]'),
('e54e6899-0582-4c0a-9bb1-4a9965799a55','和張仲實見寄  其二','仇遠','宋','宋诗','song-poetry','','[]','古交色不變，百鍊如精金。',60,'全唐诗/poet.song.245000.json','["古交色不變，百鍊如精金。", "一別又三月，書札乖嗣音。", "相望隔一水，離憂盈中襟。", "秋陽不能驕，秋雨不能淫。", "會面不可期，月明千里心。"]'),
('34b2faea-2b9b-4033-9b71-1ef0dbfff82a','和蔣全愚韻','仇遠','宋','宋诗','song-poetry','','[]','金壇有耆英，學博聲名早。',216,'全唐诗/poet.song.245000.json','["金壇有耆英，學博聲名早。", "搜奇薄莊騷，稽古極羲昊。", "君甚似樂天，稅冕居履道。", "息遊鬻駱馬，尚友敬胡杲。", "我生六十年，獨欠識此老。", "來遊溧陽學，文物委秋草。", "黄沙瞇人目，忽見石皓皓。", "君壇高難陟，我壘虛易擣。", "新詩十八韻，韻韻俱壓倒。", "交情託以宣，一字一大好。", "自慚溝中斷，未足被華藻。", "但令小兒輩，藏弆以爲寶。", "相望衣带水，波弱限蓬島。", "玉石資盪磨，鐘鼓宜擊考。", "何由即會面，疑義共探討。", "豈無問字酒，可以濡吻燥。", "昔爲堅多節，今爲科上槁。", "窮達等醉醒，何庸寬懷抱。"]'),
('174a34e4-533f-491f-89b9-6500346dbe06','和金沙蔣文海韻  其一','仇遠','宋','宋诗','song-poetry','','[]','干祿非良圖，好遯實素抱。',60,'全唐诗/poet.song.245000.json','["干祿非良圖，好遯實素抱。", "昔爲駕壑松，今作出山草。", "茫茫海嶽隔，冉冉齒髪老。", "淵明書甲子，拾遺歷天寶。", "迷塗諒未遠，貴在知幾早。"]'),
('00e1a6b2-efc4-4ffa-b1fa-63d9e985edc8','和金沙蔣文海韻  其二','仇遠','宋','宋诗','song-poetry','','[]','我聞茅峰下，曾有卧龍人。',60,'全唐诗/poet.song.245000.json','["我聞茅峰下，曾有卧龍人。", "風雲未承運，淵潜聊自珍。", "世無卞和氏，誰辨玉與珉。", "緇塵化衣裳，我獨潔其身。", "攬鏡忽自笑，奈此白髪新。"]'),
('78a598da-dff2-4dc2-84db-a9403b287627','和金沙蔣文海韻  其三','仇遠','宋','宋诗','song-poetry','','[]','海翁古徵士，接武諸公後。',60,'全唐诗/poet.song.245000.json','["海翁古徵士，接武諸公後。", "聞名三十年，傾蓋即如舊。", "示我伐木章，無能出其右。", "籊籊秋竹竿，坐睨蒲質朽。", "試問五兩綸，何如一杯酒。"]'),
('8aaf15ef-57aa-42b1-b936-95cdeb160cde','和金沙蔣文海韻  其四','仇遠','宋','宋诗','song-poetry','','[]','昔我客朱方，曾識三數公。',72,'全唐诗/poet.song.245000.json','["昔我客朱方，曾識三數公。", "獨欠之句曲，徧走山西東。", "向來劉與王，疇能繼高風。", "今我來金淵，尸祝素王宮。", "閲人晨星稀，見子夕照紅。", "何當分鄰燭，竹徑相與通。"]'),
('2637714c-f37c-4664-94a2-017615e219fc','乙巳歲三月爲溧陽校官上府經烏剎橋和陶淵明韻','仇遠','宋','宋诗','song-poetry','','[]','一日不見山，胸次塵土積。',96,'全唐诗/poet.song.245000.json','["一日不見山，胸次塵土積。", "老來志益壯，清遊等疇昔。", "鍾山草堂古，每恨身微翮。", "况是佳麗地，牛馬風不隔。", "遑遑問征路，冉冉供吏役。", "淵明田可秫，肯爲五斗易。", "石橋跨淮水，岐路由此析。", "俗駕何時回，爲爾謝松菊。"]'),
('ea2c5d3f-5356-4721-a0a5-59ce6d360396','爲金陵宗人賦雲谷詩','仇遠','宋','宋诗','song-poetry','','[]','英英天上雲，洞洞天下谷。',96,'全唐诗/poet.song.245000.json','["英英天上雲，洞洞天下谷。", "皎皎谷中人，精神皎如玉。", "卷舒一何心，怡悅亦自足。", "朝采孕丹砂，夕氣被林麓。", "豈無茯苓芝，隨春入鋤斸。", "自是長生苗，根本元不俗。", "三千年桃花，八千歲椿木。", "不如採藥歸，枕石伴雲宿。"]'),
('7b166b19-04f7-4e74-8d39-0de2faea95a5','西廟古檜和卞南仲韻','仇遠','宋','宋诗','song-poetry','','[]','奇木有古意，愛古人亦奇。',144,'全唐诗/poet.song.245000.json','["奇木有古意，愛古人亦奇。", "嘉禾老君觀，毗陵烈帝祠。", "二檜棟梁物，俱逐劫火移。", "朅來溧城西，見此鐵石姿。", "靈貍肯薦骨，死豹仍留皮。", "拏空有爪龍，踞地無角螭。", "三株兩失葉，簷溜傷南枝。", "僵立萬雪霜，坐更幾鄰儀。", "我將護赤欄，甃以蒼石墀。", "深根直不朽，雅操堅自持。", "棟梁與薪槱，待用各有時。", "罔俾孤山樹，專美坡仙詩。"]'),
('68930142-3bd3-4704-b319-c3b4cb4fa848','學舍自吟','仇遠','宋','宋诗','song-poetry','','[]','金淵文學掾，旅食經歲年。',96,'全唐诗/poet.song.245000.json','["金淵文學掾，旅食經歲年。", "石田薄有收，儘足裨俸錢。", "絲毫了無補，教養愧前賢。", "竹添講堂後，柳栽泮水邊。", "匏花粲籬落，藻带舞漪漣。", "土龍欲致雨，何能起雲煙。", "革带孔漸移，老癯非學仙。", "木居士何者，求福真徒然。"]'),
('97b6a2ef-a9bc-45c4-8575-73b84c892ec7','送虞師憲赴延平書院山長','仇遠','宋','宋诗','song-poetry','','[]','我師文靖公，一傳子朱子。',156,'全唐诗/poet.song.245000.json','["我師文靖公，一傳子朱子。", "佩服中庸書，靜中識根柢。", "秋月湛冰壺，瑩徹無瑕滓。", "延平建精舍，盛德宜世祀。", "君往坐臯比，文行成粹美。", "秋風送書船，南上二千里。", "訝君來何暮，衿佩爭倒屣。", "鳴道鐸方振，問字酒已俟。", "九京如可作，文靖公亦喜。", "予友有黄功，昔分教於此。", "頗知文風盛，十室九儒士。", "是行若登仙，劍氣炯青紫。", "只恐席未溫，思歸慕園綺。"]'),
('940e701e-33fc-43d5-a839-1c6ee2000594','題西梵一翁雙清軒','仇遠','宋','宋诗','song-poetry','','[]','上人碧雲房，苔地不盈丈。',72,'全唐诗/poet.song.245000.json','["上人碧雲房，苔地不盈丈。", "古石六七株，修竹覆其上。", "石兄既奇秀，竹君亦高尚。", "歲晚永相依，屹不染塵坱。", "方參香嚴師，曾識牛丞相。", "解鞍時一息，吾其得閒放。"]'),
('e1c3a9f5-384e-415c-b1b5-541f074ddd84','山泉爲惠君疇賦','仇遠','宋','宋诗','song-poetry','','[]','空青穿秋旻，瘦白噴夏雪。',96,'全唐诗/poet.song.245000.json','["空青穿秋旻，瘦白噴夏雪。", "若非林下士，誰識此高潔。", "山中非無雲，蒼狗隨變滅。", "山中非無月，陰晴易圓缺。", "不如泉混混，萬斛常不竭。", "洗耳塵即清，釀酒香愈冽。", "一醉三十年，至味過麴糵。", "翁意不在茲，勿爲醒者說。"]'),
('bee15586-9598-458a-b556-757a538bd536','梅夢','仇遠','宋','宋诗','song-poetry','','[]','緗梅眩晨霞，素梅迷暮雪。',48,'全唐诗/poet.song.245000.json','["緗梅眩晨霞，素梅迷暮雪。", "一翁著花間，冰霜殊皎潔。", "蜂蝶猶未知，香味老逾烈。", "夢中識歸塗，踏遍孤山月。"]'),
('8ce45ea7-9c2c-4f98-b2ac-f7de257165aa','續夢','仇遠','宋','宋诗','song-poetry','','[]','一夢續一夢，夢短寒夜長。',96,'全唐诗/poet.song.245000.json','["一夢續一夢，夢短寒夜長。", "顛倒無首尾，哀樂迷存亡。", "枕上忽自笑，歷歷見未嘗。", "至人本無夢，有夢其何傷。", "魚旐農夫喜，熊羆男子祥。", "吾年過不惑，夢覺久已忘。", "未來尚曖昧，既往恐思量。", "不知邯鄲道，幾番熟黄粱。"]'),
('a1b7c798-f917-4c05-b9b6-2cd1e3812333','柰花似海棠林檎但葉小異','仇遠','宋','宋诗','song-poetry','','[]','東風擅紅紫，顔色分重輕。',108,'全唐诗/poet.song.245000.json','["東風擅紅紫，顔色分重輕。", "愛此柰子花，嬌艷何盈盈。", "未開足標致，紫綿燦垂纓。", "開繁臙脂褪，徐娘老而貞。", "俗稱爲海紅，結實葉底頳。", "來禽難爲弟，海棠難爲兄。", "我評此三花，同出而異名。", "一枝插銅壺，坐翫心目明。", "安得劍南樵，素縑爲寫生。"]'),
('802de804-e6f1-4f5f-a868-1b565bd62041','題仲賓竹石','仇遠','宋','宋诗','song-poetry','','[]','淇園綠猗猗，昌谷黑離離。',48,'全唐诗/poet.song.245000.json','["淇園綠猗猗，昌谷黑離離。", "謫仙硯池底，茁此兩三枝。", "輔以小崢嶸，標度尤崛奇。", "願堅歲寒心，勿爲風雪欺。"]'),
('71204a33-aa8b-4e27-861e-6b161fb6914f','暢師同玉上人遊茅阜  其一','仇遠','宋','宋诗','song-poetry','','[]','朝辭二竺寺，暮宿三茅峰。',48,'全唐诗/poet.song.245000.json','["朝辭二竺寺，暮宿三茅峰。", "紅樹落一葉，白雲深幾重。", "遠遊喜無雨，清興尤宜冬。", "遥知天壇上，會與仙人逢。"]'),
('1d2a790b-61c2-42cc-af74-8d3d892a4069','暢師同玉上人遊茅阜  其二','仇遠','宋','宋诗','song-poetry','','[]','上人家海上，喜從名山遊。',48,'全唐诗/poet.song.245000.json','["上人家海上，喜從名山遊。", "昔聞三茅君，隠在千峰頭。", "霜寒草木瘦，歲晚泉石幽。", "不見梁丘伯，使我心悠悠。"]'),
('19b7de3e-0b57-45b5-b701-bce33ec8d17b','夜醉','仇遠','宋','宋诗','song-poetry','','[]','山翁醉如泥，夜半方醒然。',48,'全唐诗/poet.song.245000.json','["山翁醉如泥，夜半方醒然。", "既莫省宇宙，况復知歲年。", "閒愁置度外，大道在目前。", "日飲豈不佳，第恐無酒錢。"]'),
('87ff1631-a9d7-4d65-86fc-35a009f9d346','題西山真先生像','仇遠','宋','宋诗','song-poetry','','[]','何年霜月子，寫此西山真。',48,'全唐诗/poet.song.245000.json','["何年霜月子，寫此西山真。", "峨冠褐寬博，詩書發精神。", "可以寘巖壑，可以登麒麟。", "斯人不可作，令我思乾淳。"]'),
('a1628aa4-db00-4463-abc7-9a9739d1d8d5','客來驚睡','仇遠','宋','宋诗','song-poetry','','[]','長晝清和時，惟有睡鄉美。',48,'全唐诗/poet.song.245000.json','["長晝清和時，惟有睡鄉美。", "宰予邊孝先，毋乃今我是。", "門外有客來，推枕矍然起。", "請啜一盃茶，萬事且不理。"]'),
('1a14179b-0705-4e50-ba72-332528c3cbf5','次韻蕭饒州見寄  其一','仇遠','宋','宋诗','song-poetry','','[]','至人本天游，上古惟野處。',132,'全唐诗/poet.song.245000.json','["至人本天游，上古惟野處。", "如何種菊者，亦勝封千戶。", "萬鍾且唾去，况復問阿堵。", "先生東陵侯，成敗久目睹。", "幾程上金臺，一節綰銅虎。", "肯從赤松遊，餐芝擘麟脯。", "溫故窮丹鉛，投閒棄圭組。", "自是橫江鯨，終然辭網罟。", "獨醒笑衆醉，此舉冠千古。", "二疏三高後，欲數指難僂。", "毋煩北山移，猿鶴當起舞。"]'),
('735834f4-1503-4a9b-a8f4-805a290b3fa9','次韻蕭饒州見寄  其二','仇遠','宋','宋诗','song-poetry','','[]','昔寓南國居，日與蕘牧處。',132,'全唐诗/poet.song.245000.json','["昔寓南國居，日與蕘牧處。", "今營西郭居，官梅映窗戶。", "硯山如可博，尺度先畫堵。", "此計當勇决，結構須快臯。", "伐藤斷長蛇，卧石凜伏虎。", "山厨富笋蕨，客至當脩脯。", "野芳散紅紫，粲粲五雜組。", "放懷山水窟，脫迹名利罟。", "平泉綠野堂，盛事追往古。", "願學樵夫拜，相從丈人僂。", "應笑趨炎人，奴顔八風舞。"]'),
('b67e65c9-d36e-45e1-aa82-df16c9551a3a','過岳公故居','仇遠','宋','宋诗','song-poetry','','[]','赤脚踏層冰，素蟾浴清水。',48,'全唐诗/poet.song.245000.json','["赤脚踏層冰，素蟾浴清水。", "可憐偷桃兒，竟以寒餓死。", "木瓢掛空壁，蠹冊堆破几。", "有子如矮奴，踉蹌入城市。"]'),
('0a4bd01b-da6e-44b9-876e-06ce624052ca','剪白鬚','仇遠','宋','宋诗','song-poetry','','[]','臨鏡忽自哂，公然白紛如。',84,'全唐诗/poet.song.245000.json','["臨鏡忽自哂，公然白紛如。", "稚女眼最明，爲我剪白鬚。", "髟髟如素絲，不堪紉破襦。", "參差茁秋草，蔓衍不可除。", "明知我已老，既白難再烏。", "無肉令人癯，眼昏妨讀書。", "顔駟燭之武，吾非斯人徒。"]'),
('a6b6d268-0f62-440c-b86f-b083313441b5','寄史貴質','仇遠','宋','宋诗','song-poetry','','[]','淳祐六十翁，生遇時節好。',120,'全唐诗/poet.song.245000.json','["淳祐六十翁，生遇時節好。", "朝遊漁樵社，晚入詩酒保。", "不爲名利縛，剛被花月惱。", "時發少年狂，未省身已老。", "强歌無餘懽，聞者笑絕倒。", "齒髪漸凋疎，形容頓枯槁。", "平生千金軀，豈不自愛寶。", "幸然本根在，收斂尚及早。", "何必大藥資，尪羸多壽考。", "也無政事堂，也無沙門島。"]'),
('9b79d696-580e-45fd-b5d0-ea53e19acb46','錢儒珍家賞桂','仇遠','宋','宋诗','song-poetry','','[]','客至當飲酒，醉此金粟堆。',72,'全唐诗/poet.song.245000.json','["客至當飲酒，醉此金粟堆。", "秋風何時到，叢樹參差開。", "馨香逆人鼻，蓓蕾藏聖胎。", "攀枝折其榮，落穗浮酒杯。", "後夜有佳月，弄影須徘徊。", "紅袖歌未終，畫角毋庸催。"]'),
('221aa527-c139-4432-8910-72f39d2c5942','凉風','仇遠','宋','宋诗','song-poetry','','[]','凉風撼庭竹，起舞如翠蛟。',48,'全唐诗/poet.song.245000.json','["凉風撼庭竹，起舞如翠蛟。", "亂葉打窗來，卷盡破屋茅。", "飛雲行太空，萬竅爭怒號。", "煩暑一掃凈，解我心鬰陶。"]'),
('64f6a56e-a1fd-4970-9954-9416678d9c75','夜半見月','仇遠','宋','宋诗','song-poetry','','[]','中夜月初上，照我東床明。',72,'全唐诗/poet.song.245000.json','["中夜月初上，照我東床明。", "我心本無事，展轉寐不成。", "仰觀烏鵲飛，俯聽蛩螀鳴。", "念適從何來，衣食非素營。", "三年然後歸，兒女各長成。", "婚嫁願早畢，吾其師向平。"]'),
('04d394ec-4a7d-4d77-8840-dbd4f6cda0ab','與楊志行郭斗南馬德潤屠存博呂公弼僧義慶游鍾山以峰多巧障日江遠欲浮天分韻予得浮字','仇遠','宋','宋诗','song-poetry','','[]','昔讀寶公傳，今作鍾阜遊。',60,'全唐诗/poet.song.245000.json','["昔讀寶公傳，今作鍾阜遊。", "緩行萬松間，直上千峰頭。", "古塔表木末，寒泉貯巖幽。", "遥觀江流奔，始知此生浮。", "甚愛雪竹庵，逸駕吾將休。"]'),
('d883b04e-847f-4a63-9a9e-1e89c765dae4','試涪翁題鄭佽硯','仇遠','宋','宋诗','song-poetry','','[]','我有古鏡硯，肌理細密勻。',84,'全唐诗/poet.song.245000.json','["我有古鏡硯，肌理細密勻。", "沄沄散角痕，巨口細魚鱗。", "涪翁銘其背，文字極雅馴。", "鄭佽彥相者，不知何如人。", "回首數百載，想見元豐春。", "晴窗試磨洗，墨舊兔穎新。", "携歸供行齋，侑此金石身。"]'),
('cb87a67d-3856-43ec-a389-01387677725b','蟋蟀','仇遠','宋','宋诗','song-poetry','','[]','蟋蟀一何多，曉夜鳴不已。',72,'全唐诗/poet.song.245000.json','["蟋蟀一何多，曉夜鳴不已。", "居然聲相應，各爲氣所使。", "零露聊飽蟬，落葉才庇螘。", "秋風滿庭砌，安能久居此。", "愁聲不欲聽，我聽差可喜。", "平生勝負心，一笑付童子。"]'),
('536a693c-b58b-4669-b18e-853989833f11','郊行集句','仇遠','宋','宋诗','song-poetry','','[]','今日我重九，無錢對菊花。',108,'全唐诗/poet.song.245000.json','["今日我重九，無錢對菊花。", "昨夜雨鳴渠，既雨晴亦佳。", "出郭望西郊，山林迹未賒。", "顧憂斯人饑，僵仆亂如麻。", "淵明胡不歸，吾居已及瓜。", "豈無一尊酒，誰敢負年華。", "聊爲山水行，玩奇石路斜。", "門生與兒子，邀我至田家。", "留連向暮歸，爛醉是生涯。"]'),
('c65edf22-0517-4a58-bbf4-6e10c2c34e2f','種菊','仇遠','宋','宋诗','song-poetry','','[]','鄰舍送我菊，惜無盆盎栽。',72,'全唐诗/poet.song.245000.json','["鄰舍送我菊，惜無盆盎栽。", "分種東籬下，倚窗日裴回。", "初看蓓蕾青，黄蘂參差開。", "霜後苦無花，老眼生塵埃。", "得此少自慰，可以薦一盃。", "更用數日晴，南枝須有梅。"]'),
('01df8b9b-fb9d-4cd1-886d-3b4a707dab1f','菊軒吟爲劉君章作','仇遠','宋','宋诗','song-poetry','','[]','大江秋風高，紅葉紛滿地。',96,'全唐诗/poet.song.245000.json','["大江秋風高，紅葉紛滿地。", "采采黄金華，專此秋富貴。", "主翁庭宇靜，霜日自清媚。", "豈不懷淵明，異榻同夢寐。", "春融桃李門，一粲開落易。", "願言堅晚節，香淡有真意。", "平生觀物心，飲水知秋味。", "敢問楚人醒，何如晉人醉。"]'),
('01a5ca54-f8d3-4c1c-a6c0-eee185e6c0e1','通甫弟歸里詩','仇遠','宋','宋诗','song-poetry','','[]','霜重江水縮，艤舟江之湄。',48,'全唐诗/poet.song.245000.json','["霜重江水縮，艤舟江之湄。", "子今戒行色，予亦數歸期。", "已迫葵丘戍，何求買山資。", "酌別苦無酒，秉粟供妻兒。"]'),
('1878ecce-8447-4cbc-8c73-764a6adddc26','風雨不出','仇遠','宋','宋诗','song-poetry','','[]','儒官少公事，閒坐如家居。',108,'全唐诗/poet.song.245000.json','["儒官少公事，閒坐如家居。", "閉戶聽風雨，重讀架上書。", "豈無借書瓻，小酌勿用沽。", "豈無苜蓿盤，園丁送嘉蔬。", "溪童把釣竿，時得徑寸魚。", "采薇拾橡栗，視此已有餘。", "懷哉天地恩，不棄無用儒。", "舍此將何之，狂士多迷途。", "終不如歸田，一蓑溪上鋤。"]'),
('4645b02e-2be8-413b-b9b6-c7668564ddbf','漫興','仇遠','宋','宋诗','song-poetry','','[]','馿鳴有何好，晉人多愛之。',108,'全唐诗/poet.song.245000.json','["馿鳴有何好，晉人多愛之。", "胡不大堤上，隔花聽馬嘶。", "胡不茅屋下，带月聽荒雞。", "我疑古之狂，矯世本尚奇。", "蠟屐柳下鍛，結髦劍首吹。", "端是味無味，以待知者知。", "滿腔浩然氣，抑鬰無所施。", "引頸一長鳴，萬里風雲悲。", "敢問駟與驄，立仗夫何爲。"]'),
('a4b1b32b-4c22-4659-9625-8ef8f2945822','九日鄰翁招飲','仇遠','宋','宋诗','song-poetry','','[]','佳節喜新霽，作意登南山。',132,'全唐诗/poet.song.245000.json','["佳節喜新霽，作意登南山。", "茲山雖不高，亦足供躋攀。", "平明放舟出，日暮騎馬還。", "行止不自由，寸步千里艱。", "北鄰朱公子，言笑破旅顔。", "相與一樽空，徒得半日閒。", "人生各憔悴，仕路復間關。", "六十始平頭，甲子須循環。", "粲粲黄金花，才見秋一斑。", "忍以髪膚脆，犯此風霜頑。", "何如歸去來，期我巖壑間。"]'),
('5bb1c93f-82e8-48b5-ba22-aad5501b8b59','戒飲','仇遠','宋','宋诗','song-poetry','','[]','腹無貯酒腸，小飲輒大醉。',72,'全唐诗/poet.song.245000.json','["腹無貯酒腸，小飲輒大醉。", "醉餘嗽即作，痰唾連涕泗。", "酒亦有何好，上策當自治。", "無錢賒不來，不飲特易事。", "何如飯疏食，飽矣曲肱睡。", "莫笑我獨醒，中有至樂地。"]'),
('dc4f0fe2-bc35-4a28-9dd3-e2250580bc11','飲少','仇遠','宋','宋诗','song-poetry','','[]','此中無他腸，飲少乃輒醉。',48,'全唐诗/poet.song.245000.json','["此中無他腸，飲少乃輒醉。", "眼眩力不支，便欲投床睡。", "頓空名利心，願棄人間事。", "淵明千載上，當復知我意。"]'),
('ff75df1b-04bd-4046-b1a9-32cc49e2cc5e','有懷龔子敬子中','仇遠','宋','宋诗','song-poetry','','[]','兩龔昔所慕，二難今是似。',48,'全唐诗/poet.song.245000.json','["兩龔昔所慕，二難今是似。", "簞瓢魯儒生，衣冠楚君子。", "相期歲月永，不爲弓旌起。", "極目暮雲平，修筠悵予倚。"]'),
('4398a374-bfe2-4ef6-8e73-9691eccb9e83','和子野  其一','仇遠','宋','宋诗','song-poetry','','[]','少年挾英氣，聞雞慕劉祖。',48,'全唐诗/poet.song.245000.json','["少年挾英氣，聞雞慕劉祖。", "老來卧蝸牛，風雨懶出戶。", "酒空薪炭盡，景况詎堪臯。", "自嘆衫袖短，豈曰不善舞。"]'),
('ea61f104-e67c-48c5-bbf3-552c36c9ef5d','和子野  其二','仇遠','宋','宋诗','song-poetry','','[]','此日始生日，避喧作溪行。',84,'全唐诗/poet.song.245000.json','["此日始生日，避喧作溪行。", "出門阻風雪，僕瘁馬亦驚。", "歸卧春一窗，隔窗聽雪聲。", "擁衾守藥鼎，客至慵出迎。", "顔色日已老，何由得青精。", "未能歌雪兒，聊復呼麴生。", "夢中遊西園，一壺梅下傾。"]'),
('fe6bdcf6-a2c6-4437-ad94-08378591c634','報恩寺權公方丈','仇遠','宋','宋诗','song-poetry','','[]','金淵多寶地，此地殊幽深。',48,'全唐诗/poet.song.245000.json','["金淵多寶地，此地殊幽深。", "一錫得安穩，豈必棲山林。", "臨池照佛面，見竹空人心。", "江楓千百年，時作海潮音。"]'),
('d92ed65d-89ec-4a30-b6db-a6b8ea67d754','昔康節先生題安樂窩詩中云樂見善人樂聞善事樂道善言樂行善意此即吾友朱仲明樂善齋之意也繫之以詩','仇遠','宋','宋诗','song-poetry','','[]','人生有至樂，主善以爲師。',84,'全唐诗/poet.song.245000.json','["人生有至樂，主善以爲師。", "善端本固有，樂處亦自知。", "我思舜之徒，雞鳴日孳孳。", "簞瓢在陋巷，顔氏其庶幾。", "之子芝蘭室，書傳爲箴規。", "量力行好事，固窮無妄爲。", "何似安樂窩，受用堯夫詩。"]'),
('db8d0434-c4da-4f9d-ae7b-5fc51eee7d0e','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其一','仇遠','宋','宋诗','song-poetry','','[]','自我來溧陽，四見木葉秋。',96,'全唐诗/poet.song.245000.json','["自我來溧陽，四見木葉秋。", "泮宮久敝漏，量力完且修。", "幸然土木備，及此工役休。", "巍巍大成殿，勢與鄒魯侔。", "聖賢日云邁，可以遺象求。", "捫心了無怍，一掃築舍謀。", "咫尺三茅山，乃獨欠此游。", "且須歸去來，速爲營菟裘。"]'),
('9b688c8c-6194-490f-bb28-99bf6dc7b4e8','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其二','仇遠','宋','宋诗','song-poetry','','[]','迢迢渰水上，有亭曰寒光。',84,'全唐诗/poet.song.245000.json','["迢迢渰水上，有亭曰寒光。", "水天散鷗鷺，四望山蒼蒼。", "向來于湖翁，詩詞題屋枋。", "幾思一遨遊，歲月飛羽忙。", "聞有白龍寺，石塔標鐵梁。", "老僧頗能吟，年來曾遊方。", "須乘未歸前，秋晴呼野航。"]'),
('5d447939-c00e-45cb-8728-e8c3975a802d','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其三','仇遠','宋','宋诗','song-poetry','','[]','我非章句儒，亦非漁樵徒。',84,'全唐诗/poet.song.245000.json','["我非章句儒，亦非漁樵徒。", "少年逞麤豪，提筆賦兩都。", "老尚著儒冠，却悔識之無。", "既難棲山林，又倦遊江湖。", "一官僅供口，康濟不在吾。", "秋風方戒寒，正道日荒蕪。", "行矣且歸耘，寸田聊自娛。"]'),
('6196aef8-02b9-4de7-85b7-cb7c4a9cc309','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其四','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江海寄孤篷，飄飄一鷗似。',96,'全唐诗/poet.song.245000.json','["江海寄孤篷，飄飄一鷗似。", "汲汲謀稻粱，欲去行且止。", "淵明真達者，解印如脫屣。", "五斗何足云，可但折腰恥。", "我嘗慕其人，出仕亦漫爾。", "客行入歲晏，田稼逢水毀。", "逝者既如斯，吾屬可去矣。", "肯負白鷗盟，西湖釣秋水。"]'),
('c2de6c5a-1613-4b57-8e7b-6cf2d0a2f1c7','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其五','仇遠','宋','宋诗','song-poetry','','[]','早從方外遊，志不在婚宦。',120,'全唐诗/poet.song.245000.json','["早從方外遊，志不在婚宦。", "采薇陟西山，采藻涉南澗。", "拄杖僅過眉，短衣不掩骭。", "一爲火宅累，漸覺有憂患。", "難任臣朔饑，俯就博士慢。", "大勝國子師，三年腹藜莧。", "棲遲行路難，堅忍爲客慣。", "昔爲泛泛鳬，今爲嗷嗷雁。", "幸免箠楚慮，官事粗易辦。", "曷不歸孤山，梅花臘前綻。"]'),
('9cda6928-7c3a-4552-a6e1-54542fe8aded','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其六','仇遠','宋','宋诗','song-poetry','','[]','秋空不肯明，風雨滿荒城。',96,'全唐诗/poet.song.245000.json','["秋空不肯明，風雨滿荒城。", "田父遮我說，重九最喜晴。", "此日晴色好，大田足西成。", "一冬暖如春，絮炭價亦輕。", "我雖將去官，於人獨無情。", "去年冶城叟，采菊餐其英。", "今茲隔存歿，使我心怔營。", "出門悵誰語，巵酒當自傾。"]'),
('6deb0c92-6b35-4371-b2ed-7a2fce045265','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其七','仇遠','宋','宋诗','song-poetry','','[]','威鳳巢深林，神龍潜巨壑。',96,'全唐诗/poet.song.245000.json','["威鳳巢深林，神龍潜巨壑。", "泥塗困螻蟻，城市防彈𥐊。", "小草不自貴，已鑄出山錯。", "豈知甘苦淡，有味俱不惡。", "霜降水澤枯，歲晚木葉落。", "榮枯識寒暑，是非悟今昨。", "不見粘壁蝸，甘以退爲樂。", "二休行且三，可但耐辱莫。"]'),
('d3ebef2e-27d6-40b9-85c3-7781e68a6bb8','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其八','仇遠','宋','宋诗','song-poetry','','[]','去郭十五里，翼然屏風山。',96,'全唐诗/poet.song.245000.json','["去郭十五里，翼然屏風山。", "上有看經院，創始昇元間。", "山潤易生雲，竹嫩未作斑。", "登高佛閣小，四面青回環。", "空門事彌多，永日僧不閒。", "歸徑路委蛇，班荆履孱顔。", "信美難久留，道遠足力慳。", "遥知故山月，問我何時還。"]'),
('ed50a417-52dd-4710-94a7-83cbb90b27a1','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其九','仇遠','宋','宋诗','song-poetry','','[]','喬木足秋聲，紅葉表秋色。',108,'全唐诗/poet.song.245000.json','["喬木足秋聲，紅葉表秋色。", "因之念湖山，恨不生羽翼。", "形留神已馳，游倦交漸息。", "西鄰夜砧發，東鄰曉機織。", "我亦有敝廬，松菊暗荆棘。", "北山百年墓，苔竹手所植。", "今長尺若干，霜雪頗自力。", "西風龍蛇蟄，暗雨山林黑。", "東望會言歸，免我長相憶。"]'),
('bd53e7aa-5386-4d36-b8ad-1f6260af3bb3','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其一○','仇遠','宋','宋诗','song-poetry','','[]','七十古所希，我今六十餘。',132,'全唐诗/poet.song.245000.json','["七十古所希，我今六十餘。", "干時本無策，謀生術尤疏。", "就食泮水宮，學圃乏薪蔬。", "凜凜座無氈，踽踽出無馿。", "厭厭尊無酒，呥呥食無魚。", "官居古云冷，已矣當歸歟。", "緬懷二女子，夫家住桐廬。", "三年千里別，曠久不得書。", "日者遣一力，還家問何如。", "江濱桐君山，土肥藥堪鋤。", "山根有閒地，或容房客居。"]'),
('d5f6448a-a537-438b-9c63-6c602411f4ed','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其一一','仇遠','宋','宋诗','song-poetry','','[]','未仕每願仕，既仕復思歸。',120,'全唐诗/poet.song.245000.json','["未仕每願仕，既仕復思歸。", "了知歸來是，宜悟求仕非。", "干祿本爲貧，元非慕輕肥。", "已昧好爲戒，復貽素餐譏。", "時艱士失業，十家九寒饑。", "豈無禹稷思，力薄願乃違。", "吾門可羅雀，載酒人來稀。", "下考劣已書，歸心疾如飛。", "眷言長途馬，老矣思脫鞿。", "晝短歌意長，式微兮式微。"]'),
('7459f8f4-4021-4767-bfc5-4b523a9cd995','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其一二','仇遠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','人寄天地間，官爵寄所寄。',96,'全唐诗/poet.song.245000.json','["人寄天地間，官爵寄所寄。", "所寄本儻來，得喪亦常事。", "何哉淺丈夫，以此芥胸次。", "達人視爲輕，譬彼摴蒲戲。", "役滿須過更，代者乃未至。", "故鄉隔太湖，一舸歸甚易。", "秋高山骨露，始見松竹翠。", "依依古梅村，是中有深意。"]'),
('0adf48cc-0621-4fdd-841d-31e7e7b50433','予久客思歸以秋光都似宦情薄山色不如歸意濃爲韻言志約金溧諸友共賦寄錢唐親舊  其一三','仇遠','宋','宋诗','song-poetry','','[]','游子悲凜秋，秋盡行當冬。',96,'全唐诗/poet.song.245000.json','["游子悲凜秋，秋盡行當冬。", "雨露變霜雪，寒色日以濃。", "豈無紫綺裘，綻裂誰與縫。", "不如早還家，山林專素封。", "掃松棲霞嶺，結茆慧日峰。", "山南與山北，春風入修筇。", "時止可以止，道隆從而隆。", "抱膝且長吟，吾其師卧龍。"]'),
('cd875a96-1e08-4366-ad73-dd4d49b19a0d','盆梅','仇遠','宋','宋诗','song-poetry','','[]','有客送苔梅，來自馬塍裏。',84,'全唐诗/poet.song.245000.json','["有客送苔梅，來自馬塍裏。", "斜枝巧盤折，的皪數十蘂。", "意欲媚春風，寧免少屈己。", "獨憐鐵石腸，竟作柔繞指。", "他鄉忽一見，少慰空谷喜。", "何當解其縛，條直有妙理。", "幸不入俗眼，入俗梅亦恥。"]'),
('b4dfd2c8-0a72-447a-9b0a-fae52a3a98ea','居遊行寄費廷玉','仇遠','宋','宋诗','song-poetry','','[]','繁華錢塘郡，佳麗金陵州。',180,'全唐诗/poet.song.245000.json','["繁華錢塘郡，佳麗金陵州。", "吾生抑何修，兩地得居遊。", "杭也數年別，昇也幾月留。", "鍾山草堂靈，林壑殊清幽。", "開窗眺龍灣，大江日東流。", "鳳皇非故臺，不見白鷺洲。", "冶城塚纍纍，青溪波悠悠。", "長干塔尚在，瓦棺閣已休。", "雨花峙巖顛，錦石爛不收。", "層樓天下無，結構如龍舟。", "六朝王氣歇，故籞成荒丘。", "至今秦淮上，尚聞商女謳。", "山水如此佳，見有此客不。", "懷古復思鄉，日落川雲浮。", "惜無老樊川，酒酣吟杜秋。"]'),
('51c8b73b-f823-4963-a60c-59a1c5ad432b','雪','仇遠','宋','宋诗','song-poetry','','[]','忽驚小窗白，開戶雪如此。',96,'全唐诗/poet.song.245000.json','["忽驚小窗白，開戶雪如此。", "去年臘前無，一白從此始。", "霏霏甚可愛，落落勢未已。", "炯炯眼界明，沾沾田畯喜。", "靜聞野厖吠，立見蟄蝻死。", "鼓腹飽可期，勿畏寒墮指。", "窮檐絕煙火，閉糴三日矣。", "開倉糶官糧，太守如父子。"]'),
('2341b73a-f394-4375-af8e-e01d029f2ec2','立春','仇遠','宋','宋诗','song-poetry','','[]','山城歷日到每遲，新春殘臘俱不知。',64,'全唐诗/poet.song.245000.json','["山城歷日到每遲，新春殘臘俱不知。", "若非一鞭醒寒夢，梅柳爭春無了時。", "牛刀小試東風手，目中全牛果何有。", "勾芒舁歸古廟中，官吏升堂酌春酒。"]'),
('9ba16e49-aac8-432c-b00a-84b2d108c357','竹素山房小飲南徐唐正方善歌吳伶以長簫和之客以鳳凰臺上憶吹簫分韻予得臺字','仇遠','宋','宋诗','song-poetry','','[]','少時聞簫白玉臺，一曲未終丹鳳來。',172,'全唐诗/poet.song.245000.json','["少時聞簫白玉臺，一曲未終丹鳳來。", "金瀨空明秋水淺，妙音久不聞蓬萊。", "吳下老伶燕中回，能以北腔歌落梅。", "紅塵箏笛耳一洗，便覺箜篌憤抑琵琶哀。", "朱方臞仙古音律，宮長羽短隨剪裁。", "小春梅柳參差開，肯待羯鼓花奴催。", "我輩鍾情忘爾汝，濁醪妙理惟醱醅。", "晚風吹寒夕陽下，有酒不飲令人咍。", "今人青眼映山水，古人白骨生莓苔，不如相聚常銜盃。", "嗚呼五公七相安在哉，不如相聚常銜盃。"]'),
('77594010-ce5e-47e8-b757-fb1155a39c03','北園賞梅','仇遠','宋','宋诗','song-poetry','','[]','梅花先受東君知，一晴開遍南北枝。',64,'全唐诗/poet.song.245000.json','["梅花先受東君知，一晴開遍南北枝。", "吳姬持盃勸客醉，已恨賞花三日遲。", "主人惜花不惜酒，自摘一枝春在手。", "大開笑口問東風，金谷幾人曾白首。"]'),
('1b30cb3d-dd95-4577-9580-7d1814ec27e7','題王師尹所藏三峽圖','仇遠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山石橋天下奇，奔湍赴壑潜馮夷。',80,'全唐诗/poet.song.245000.json','["廬山石橋天下奇，奔湍赴壑潜馮夷。", "倚闌俯瞰毛髪竦，品題曾讀坡仙詩。", "畫師筆斡造化窟，豈必夜半夸娥移。", "蜀天茫茫千萬里，彷彿猿聲亦如此。", "何當譜入朱絲絃，水底魚龍應洗耳。"]'),
('f5f21c79-2b05-4bd5-80e5-e93aa9dc58ec','題季路負米圖','仇遠','宋','宋诗','song-poetry','','[]','高堂有親今老矣，孝子晨昏奉甘旨。',64,'全唐诗/poet.song.245000.json','["高堂有親今老矣，孝子晨昏奉甘旨。", "傷哉貧也敢辭勞，百里迢迢親負米。", "後來列鼎坐重裀，積粟萬鍾不逮親。", "古言周急不繼富，爲母請粟非無人。"]'),
('edf9486c-a4af-4b61-a530-3ef999c7cb2c','題范譓卿愛山吟境圖','仇遠','宋','宋诗','song-poetry','','[]','前山排闥如虬奔，後山擁壁如虎蹲。',96,'全唐诗/poet.song.245000.json','["前山排闥如虬奔，後山擁壁如虎蹲。", "三間茅屋白雲裏，一羣野鹿青松根。", "世上好山誰不喜，紗帽可能長隠几。", "詩人見石猶下拜，况是孤高有如此。", "終南捷徑從渠行，少室素價元非輕。", "呼童下山汲清泠，我欲洗耳聽猿聲。"]'),
('d5dced1c-400e-4854-8a7c-e9b7b68f3dc3','送存博教授回虎林','仇遠','宋','宋诗','song-poetry','','[]','雙鶴翩翩溧水陽，紅塵不染素衣裳。',64,'全唐诗/poet.song.245000.json','["雙鶴翩翩溧水陽，紅塵不染素衣裳。", "一歸華表飲風露，一住滄洲謀稻粱。", "湖海波濤多起伏，爭食那能效雞鶩。", "戛然長唳楚天寬，有日相從逐鴻鵠。"]'),
('131dbc5f-bd60-48d1-8314-f2dc70ebc442','草蟲圖','仇遠','宋','宋诗','song-poetry','','[]','昨夜南山雷雨霽，蟄室初開百蟲起。',208,'全唐诗/poet.song.245000.json','["昨夜南山雷雨霽，蟄室初開百蟲起。", "草夭菜秀蒲柳長，生意森然隨氣使。", "陰陽變態足纖巧，分得餘妍歸畫史。", "野蜂採蜜花房裏，官蛙瞠目莎池底。", "紛紛蚱蜢肆跳梁，款款蜻蜓齊點水。", "天牛穴桑奚其天，鬼蝶迷花聿如鬼。", "血國三千亦有蚊，黍馬十萬寧非蟻。", "蝎虎那能捋虎鬚，蝸牛誰堪執牛耳。", "蜣蜋轉丸誠小巧，螳螂搏輪非勇士。", "鳴蟬嘶熱蟋蟀吟，一片繁聲愁客子。", "春風郊野豈不樂，籬落秋風又如此。", "坡仙舊詠只八物，若見此圖心更喜。", "我摩老眼爲題詩，晴日一窗蠅撲紙。"]'),
('bedf74fd-be7d-4ec9-9823-54a7b1f1a6bc','元夜嘆','仇遠','宋','宋诗','song-poetry','','[]','虎林城中正月半，十萬人家燈燦爛。',180,'全唐诗/poet.song.245000.json','["虎林城中正月半，十萬人家燈燦爛。", "溧陽風景方放燈，通宵不禁人遊翫。", "大雪深寒萬木僵，家家冷坐無薪炭。", "典錢買竹又買燈，糠油結凍點燈暗。", "豪民張燈喚歌舞，鼓笛喧轟夜忘旦。", "忽聞買絲造海船，府檄專令豪戶辦。", "倉皇且救火燃眉，縱有華燈何暇看。", "老夫掩關擁爐坐，一盞青燈置書案。", "良辰樂事悵難并，頃刻歡聲作愁嘆。", "蘇公買燈狀，陳子題燈詩。", "癡兒騃女知不知，月明月暗反覆手，且願麥熟休王師。"]'),
('d614e0be-81bf-4101-ae29-cdc6b6df8b2e','雪後祈晴','仇遠','宋','宋诗','song-poetry','','[]','閏正月過二月來，溧陽溪頭花亂開。',128,'全唐诗/poet.song.245000.json','["閏正月過二月來，溧陽溪頭花亂開。", "濃雲急雨洊雷電，不待羯鼓花奴催。", "江南天氣全然別，昨夜清寒今日熱。", "東風忽轉西北風，吹作霏霏一天雪。", "艷桃穠李睡海棠，顔色頓減仍減香。", "燕鶑羞澀未出谷，惟見野水生渾黄。", "晝夜交流已登岸，丘麥畦蔬根浸爛。", "州官憂水復憂民，明日祈晴泰清觀。"]'),
('48bc3512-1842-451e-98b4-a42f7b1739ac','送劉鍊師歸','仇遠','宋','宋诗','song-poetry','','[]','雲中雞犬隨淮南，手攀桂樹歌小山。',192,'全唐诗/poet.song.245000.json','["雲中雞犬隨淮南，手攀桂樹歌小山。", "鴻寶秘書在玉枕，有高尚者還童顔。", "卯金家世學仙子，半生遊山磨屐齒。", "懶耕白雲種瑶草，南去持竿釣湘水。", "天風環珮滄江東，鄱雲溧雨分鄰封。", "浮丘洪崖未之見，擁腫鞅掌常相從。", "拂衣浩然有歸志，湘濱已卜誅茅地。", "寸田尺宅可治生，騎鶴纏腰非易事。", "不如且向金蓮遊，濯足萬里黄河流。", "上界神仙足官府，山中宰相輕公侯。", "人生得意無南北，蠅利蝸名等雞肋。", "道人一粲據槁梧，世間萬事槐安國。"]'),
('faf3dcf9-de68-4c0a-af24-a42d0a55ddf1','寒食遊陳園','仇遠','宋','宋诗','song-poetry','','[]','梨花李花白鬬白，桃花杏花紅映紅。',192,'全唐诗/poet.song.245000.json','["梨花李花白鬬白，桃花杏花紅映紅。", "疏籬曲徑錦步障，間以巨竹青玲瓏。", "獨木爲橋人不渡，柴扉欲鎖春風住。", "豈知野禽浪蜂蝶，時復銜花過牆去。", "春波漲綠春日晴，柳下扣門嵇喜迎。", "池邊亭上少盤礴，坐牀指點呼麴生。", "冷官况逢寒食節，客味凄凉那可說。", "殘盃冷炙何處無，樂意生香聊自悅。", "清明天氣晴更佳，山林川谷多鶑花。", "後庭遺曲少人唱，踏歌椎鼓爭喧嘩。", "笑折一枝花入手，樹猶如此人能久。", "六朝舊事付東流，醉翁之意不在酒。"]'),
('43cce7c8-94c6-41ae-bed2-00fca9ddf805','月琴吟贈程禹仲','仇遠','宋','宋诗','song-poetry','','[]','我月太古色，我琴太古音。',72,'全唐诗/poet.song.245000.json','["我月太古色，我琴太古音。", "色見音聲求，焉能知我心。", "月到茅亭夜亭午，據梧坐看胎仙舞。", "本無圓缺無虧盈，心迹雙清遊太古。", "笑渠空向廣寒遊，記得霓裳羽衣譜。"]'),
('4f5ac99b-727a-4b09-8004-534833b88578','應平叔送牡丹','仇遠','宋','宋诗','song-poetry','','[]','草玄亭前老侯芭，贈我鞓紅三朵花。',96,'全唐诗/poet.song.245000.json','["草玄亭前老侯芭，贈我鞓紅三朵花。", "一春風雨傷麥麻，天香何事來山家。", "且勸花王一盃酒，更祝花王千萬壽。", "洛陽名苑今在否，未必開花大如斗。", "有花可賞不負春，紅紫轉眼俱成塵。", "酣歌誰識李翰林，酒樓柳絮愁殺人。"]'),
('ccfa44b5-d1f2-4f7c-8558-71f4adbdf0bd','德興葉志道字士心葬母于銀山丹井之上作丹泉吟','仇遠','宋','宋诗','song-poetry','','[]','葛公學仙丹有泉，葉公藏母丹泉邊。',128,'全唐诗/poet.song.245000.json','["葛公學仙丹有泉，葉公藏母丹泉邊。", "泉流㶁㶁亂石底，丹光炯炯長松巔。", "陟彼屺兮瞻望母，麻衣土枕常廬墓。", "難將寸草報春暉，祇覺焄蒿泣秋露。", "男兒眼中非無淚，有淚徹泉無厚地。", "泉聲如咽淚如丹，何待洩融歌大隧。", "幽花淡月耿墓門，不招仙魄招母魂。", "子規一聲蒼石裂，白雲渺渺山昏昏。"]'),
('681ba6a3-394c-4db4-b870-64ec4f494223','題沈子和德沖畫龍','仇遠','宋','宋诗','song-poetry','','[]','紅霞飛盡玄雲同，深山大澤生春風。',96,'全唐诗/poet.song.245000.json','["紅霞飛盡玄雲同，深山大澤生春風。", "震雷一聲蟄戶啟，老龍夭矯生蒼穹。", "憶曾艤舟垂虹外，舟子傳呼黑龍掛。", "須臾急雨暗吳淞，昔見真龍今見畫。", "江南久旱草木空，湖水陡落如秋冬。", "蒼生望霓心顒顒，阿香喚起隆中龍。"]'),
('659e2c4a-67c9-474b-af6d-11f7b7b762e1','送春寄友','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老翁欲作送春詩，借問春去將何之。',96,'全唐诗/poet.song.245000.json','["老翁欲作送春詩，借問春去將何之。", "連朝醉不省人事，昨夜春歸更不知。", "客裝欲趁春歸去，家在西湖綠陰處。", "青青竹筍白白魚，也勝客中常茹素。", "杜鵑吻血啼未乾，髪白易黑留春難。", "冶城翁定有新語，楝花風急生餘寒。"]'),
('5c6547dc-4255-4896-8d90-e580cdb56930','贈溧水楊老','仇遠','宋','宋诗','song-poetry','','[]','浙間筆工麻粟多，精藝惟數馮應科。',130,'全唐诗/poet.song.245000.json','["浙間筆工麻粟多，精藝惟數馮應科。", "吳昇姚愷已難得，陸震楊鼎肩相摩。", "我遊金淵飯不足，破硯生苔塵滿目。", "毛錐自笑不中書，白髪紛紛老而禿。", "中山博士子墨卿，貽書薦至楊茂林。", "里儒大半習刀筆，耳聞竽瑟誰知音。", "善刀而藏歸勿出，博士校書行有日。", "定當致汝數百枚，東坡有云北方無此筆。"]'),
('cd9cdf64-cfe9-42d4-9a1e-e212d78f1be3','贈筆工沈秀榮','仇遠','宋','宋诗','song-poetry','','[]','吾家歙石鋒芒出，不但挫墨亦挫筆。',128,'全唐诗/poet.song.245000.json','["吾家歙石鋒芒出，不但挫墨亦挫筆。", "老懶作事苦不多，一筆纔供兩三日。", "近知沈子藝希有，洗擇圓齊易入手。", "不論兔穎與羊毛，染墨試之能耐久。", "禮樂三千成昨夢，禿筆何止十八甕。", "長槍大劍正當時，毛錐子者直安用。", "金淵萬家籍百儒，學書用筆人豈無。", "管城欲重連城價，請携椽筆遊江湖。"]'),
('ff88b449-0af7-434d-adf9-e546c97d19a1','醉醒吟','仇遠','宋','宋诗','song-poetry','','[]','衆人皆醉我獨醒，衆人皆醒我獨醉。',161,'全唐诗/poet.song.245000.json','["衆人皆醉我獨醒，衆人皆醒我獨醉。", "先生何苦與世違，醒醉之中有深意。", "或云酒是腐腸藥，沉湎淫泆無不至。", "或云酒是忘憂物，醉鄉別有一天地。", "左拍五柳先生肩，右把三閭大夫臂。", "醉時元自惺惺著，醒來亦自齁齁睡。", "獨醒獨醉豈多得，衆醉衆醒堪一喟。", "醉者自醉醒自醒，卿法吾情各行志。", "溧江美酒差可戀，說醉論醒姑且置。", "公不見昔人有云，且食蛤蜊那知許事。"]'),
('f0b73419-d6df-4c8d-8100-4d01ace611ea','謝秋澗沈君瑞爲予寫真','仇遠','宋','宋诗','song-poetry','','[]','山村道人今老矣，徒有虛名落人耳。',96,'全唐诗/poet.song.245000.json','["山村道人今老矣，徒有虛名落人耳。", "夢中誰記版築夫，畫像雖多終不似。", "偶來招隠九鎖山，隠侯試筆開生顔。", "鬚眉口鼻宛相肖，只今置之泉石間。", "聞君尤工畫山水，萬壑千林生筆底。", "可能更掃隠居圖，布襪青鞋侶樵子。"]'),
('a0d82d60-fea4-4ff4-9379-a27ea11e53bd','夏雨嘆','仇遠','宋','宋诗','song-poetry','','[]','六月溧陽三日雨，山田喜足低田苦。',192,'全唐诗/poet.song.245000.json','["六月溧陽三日雨，山田喜足低田苦。", "學中亦有北鈴圩，低處水深三尺許。", "秧苗浸倒根已浮，再種何由能入土。", "老夫寓居西郭外，厭聽村村蹋車鼓。", "唇焦面黑嗟農夫，此生悔不業樵漁。", "有山可采水可釣，免得曉夜憂耕鋤。", "去年一熟才了逋，今年再熟力始舒。", "豈期不待稻花白，併隨荇藻歸江湖。", "溧陽近與丹陽接，不雨由來三數月。", "河流淺澀田乾枯，練湖放水通舟楫。", "人間既是寒暑同，天上何爲雨暘別。", "願移此雨慰彼心，還我朱明作炎熱。"]'),
('062a194d-cfa4-4213-8157-1e4d01a119a6','州廳設醮即事','仇遠','宋','宋诗','song-poetry','','[]','去歲今朝六月六，暮雨傾盆風拔木。',208,'全唐诗/poet.song.245000.json','["去歲今朝六月六，暮雨傾盆風拔木。", "今歲公宇醮祈晴，晝日當空生暑溽。", "羽士宣詞官吏拜，燈燭熒煌香馥郁。", "須臾黑雲西北來，如蓋如輪覆廳屋。", "電驅霹靂掣金蛇，簷溜奔騰瀉銀竹。", "幃屏掀開旛幢飛，卷盡香灰吹滅燭。", "天威震怒莫敢喘，謝罪怔營虞褻瀆。", "少焉雨止凉颼颼，天氣如秋失中伏。", "四郊大田多黍苗，一片瀟湘接湖洑。", "村夫中庭涕泗下，歸聞野老吞聲哭。", "只恐戢戢生魚頭，何止廣文飯不足。", "天心仁愛子勿憂，府公移文行振粟。", "古言大雨不爲災，雲雨須臾手翻覆。"]'),
('6621c611-3932-4169-8d9d-1c97885abd2b','荆溪橋','仇遠','宋','宋诗','song-poetry','','[]','荆溪滔滔向東注，長橋束之川后怒。',96,'全唐诗/poet.song.245000.json','["荆溪滔滔向東注，長橋束之川后怒。", "英風颯爽白晝昏，此是孝侯斬蛟處。", "客船逆上帆下檣，何如懸水泝呂梁。", "百篙攢石雙櫓健，進退咫尺千丈强。", "我來偶值凍雨作，且近孝侯祠下泊。", "平生忠孝侯所知，世途更似風波惡。"]'),
('98269e4a-2c1e-43b3-af54-67f6dcb1ea51','七月丙辰迎土山龍王入郛','仇遠','宋','宋诗','song-poetry','','[]','秋陽皜皜人皆苦，安得清風掃殘暑。',98,'全唐诗/poet.song.245000.json','["秋陽皜皜人皆苦，安得清風掃殘暑。", "河流欲斷泉脈乾，一望高田變焦土。", "洮湖白龍迎入城，行道燒香入亭午。", "青天已響阿香車，平地未見商羊舞。", "昔時曾說雨催詩，今朝還要詩催雨。", "願龍速降神力澍甘霖，萬落千村熟禾黍。"]'),
('a7c5bc49-a71f-44ba-a6df-6be7516bd292','諭馬','仇遠','宋','宋诗','song-poetry','','[]','山公有馬不肯騎，東西徒步足力疲。',64,'全唐诗/poet.song.245000.json','["山公有馬不肯騎，東西徒步足力疲。", "吾兒有力駕馭之，兀兀馳驟那敢嘶。", "爾馬亦似欺我老，乘駟乘驄非不好。", "老翁自愛下澤車，放爾春郊飽青草。"]'),
('1501905d-a44b-4cc8-9f5e-a1c9e592c81e','秋雨','仇遠','宋','宋诗','song-poetry','','[]','杜陵昔日歌秋風，卷去屋上茅三重。',146,'全唐诗/poet.song.245000.json','["杜陵昔日歌秋風，卷去屋上茅三重。", "村翁今夜嘆秋雨，衝倒簷前牆數堵。", "瓦傾棟撓直見天，寒侵素被不得眠。", "相如家徒四壁立，我比相如尤可憐。", "錢唐近報融風起，瓦礫塵埃半城市。", "霜餐露宿人遑遑，衣食難謀况居止。", "呼童向曉收篁蘆，補籬織箔聊枝梧。", "雨飄有限行且止，秋陽餘暖留桑榆。", "嗚呼居得一日且一日，丈夫安能事一室。"]'),
('898ceaf9-11ff-4dd0-b9f6-371c8b74a44a','寄南仲','仇遠','宋','宋诗','song-poetry','','[]','坡翁昔年五十二，翰林侍讀爲學士。',242,'全唐诗/poet.song.245000.json','["坡翁昔年五十二，翰林侍讀爲學士。", "溪翁年德與坡同，官職胡爲未相似。", "我道閒人勝貴人，儻來軒冕溪雲比。", "翁今田園瀨水上，頗勝求田陽羨里。", "翁今有弟夜雨對床樂，頗勝卯君懷遠驛中有感秋風起。", "有時筆床茶竈泛洮湖，柳外梅邊從徙倚。", "詩筒經卷靜工夫，光景流連一彈指。", "不論衆醉與獨醒，不問此非并彼是。", "客來不必及時事，有酒且斟無即止。", "從今笑傲五百年，銅狄銅駞皆敝屣。", "小山老桂敷秋香，下弦月照西風凉。", "今夕如此好風月，胡不招邀坡翁霞佩同頡頏。", "翁今放舟何所適，新詩漫表長相憶。", "舟中不可久留兮，盍早歸來共賦碧雲餐白石。"]'),
('32b3c74d-f6af-41d2-97c3-088235b66884','留飲篠塢承隠君山莊','仇遠','宋','宋诗','song-poetry','','[]','夾山崢嶸相對起，貫以盈盈衣带水。',96,'全唐诗/poet.song.245000.json','["夾山崢嶸相對起，貫以盈盈衣带水。", "白雲深塢碧篠合，華屋盤紆蒼樹裏。", "二三隠者古衣冠，魚酒招邀極歡喜。", "維舟岸曲信宿留，惜別依依行復止。", "東南風順帆上桅，一轉瞬間行十里。", "人生交契無故新，他日停雲從此始。"]'),
('a4dd60ed-b8db-4a7f-9125-781716f68a59','菊','仇遠','宋','宋诗','song-poetry','','[]','楚澤秋高衆芳歇，眼中見此霜下傑。',64,'全唐诗/poet.song.245000.json','["楚澤秋高衆芳歇，眼中見此霜下傑。", "南窗粲粲八九株，淡白深黄顔色別。", "自笑背時難獨立，恰是重陽過一月。", "丁寧女子莫摘殘，留伴梅花傲冰雪。"]'),
('4d09d760-88bc-4d84-8478-d3913caa4c3f','和李致遠秀才','仇遠','宋','宋诗','song-poetry','','[]','平生志氣隘九州，直欲濯足萬里流。',320,'全唐诗/poet.song.245000.json','["平生志氣隘九州，直欲濯足萬里流。", "詎期功名坐蹭蹬，不意歲月成繆悠。", "防閑擬鑄鐵門限，牽挽忽作金瀨遊。", "栖巢未穩烏鵲月，歸夢已熟鱸魚秋。", "連宵風雨正僵卧，何時臨壑容奇搜。", "可人喜接一日雅，此地判作三年留。", "說詩解字屢握手，感時懷古頻搔頭。", "吳郡才子止丘沈，梁園舊賦餘枚鄒。", "天上仙應無懵者，眼中客復有此不。", "家聲久識南北阮，筆力眇視大小歐。", "我方得友頗慶快，子亦固窮忘怨尤。", "蹄涔乃使鯨鯢伏，拳石難與嵩岱侔。", "紛紛嗜好異齊瑟，磊磊肝膽呈吳鈎。", "有才未遇政何損，知爾不薦終當羞。", "往事欲談遽易了，濁酒既傾焉得愁。", "平乘樓上王夷甫，下澤車中馬少游。", "須笑即今仕宦人，嚅唲言貌如伶優。", "若爲田園足以活，與爾水火無相求。", "一瓢陋巷誓不出，孤雲野鶴心自由。", "斯文將興天未喪，游子纍纍徒隠憂。"]'),
('4d2448ed-f5e2-4cdd-9337-932bde6cccb1','九日客中','仇遠','宋','宋诗','song-poetry','','[]','菊糕萸蟹年年有，未信今年此地無。',104,'全唐诗/poet.song.245000.json','["菊糕萸蟹年年有，未信今年此地無。", "一瓻新釀正三白，幸是杖頭錢可沽。", "客况凄凉宦情薄，釜欲生魚門羅雀。", "未能早賦歸田園，白酒黄雞差自樂。", "戶曹司馬村校書，相呼徑詣黄公壚。", "滿頭插菊把茱萸，强歌强舞醉相扶，何必更畫豳風圖。"]'),
('ba6093a6-1443-47d9-b087-22dea0623f51','壽星相','仇遠','宋','宋诗','song-poetry','','[]','西方長庚今我是，東郡短人豈兄弟。',64,'全唐诗/poet.song.245000.json','["西方長庚今我是，東郡短人豈兄弟。", "修眉班首頂如鬀，蹡蹡衣裳猶楚製。", "翩然來遊太平世，市上小兒驚且睨。", "身外不須童鶴贅，一粲人間八千歲。"]'),
('022d8e38-310c-4c41-8b97-95fb4a764a11','曉雪','仇遠','宋','宋诗','song-poetry','','[]','昏昏慘慘窗映月，索索颯颯風吹葉。',64,'全唐诗/poet.song.245000.json','["昏昏慘慘窗映月，索索颯颯風吹葉。", "青童開門忽驚笑，昨夜庭心一寸雪。", "東方日出雪漸融，簷花滴滴皆春風。", "山村布被正酣卧，愁殺門前賣炭翁。"]'),
('bc5fb4c3-9b46-4ac9-ae2a-dede662ce986','雨雪閉關子野公明仲祥載酒遠慰晚以詩見寄和答  其一','仇遠','宋','宋诗','song-poetry','','[]','溧陽三日雪平地，城市十家九家閉。',64,'全唐诗/poet.song.245000.json','["溧陽三日雪平地，城市十家九家閉。", "官舍無氈冷徹骨，省事正宜尋老計。", "小人自不知紀年，我久忘吾豈忘世。", "出門無礙將何之，已拚食貧了三歲。"]'),
('461ea9c3-51f2-48ca-bb3a-e142efb0ac49','雨雪閉關子野公明仲祥載酒遠慰晚以詩見寄和答  其二','仇遠','宋','宋诗','song-poetry','','[]','深雪沒履寒徹緜，誰子扣門四詩仙。',64,'全唐诗/poet.song.245000.json','["深雪沒履寒徹緜，誰子扣門四詩仙。", "袖中黄絹虀臼辭，塗抹既醉鳬鷖篇。", "我非不納學泄柳，政爾欲眠如孝先。", "忘形爾汝子勿怪，坦率從來六十年。"]'),
('02a9d9b7-5b2a-4dc6-9bc5-aa2f6ba65a2f','丁未元日','仇遠','宋','宋诗','song-poetry','','[]','花甲喜循環，風霜變老顔。',48,'全唐诗/poet.song.245000.json','["花甲喜循環，風霜變老顔。", "閒身留泮水，歸夢滿湖山。", "雪凍蝗應避，春暄雁欲還。", "桃符隨手寫，禍福不相關。"]'),
('10830165-beed-4bd6-aa49-e19279ba5142','窗外梅方開','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淡月江南樹，香奇影亦奇。',48,'全唐诗/poet.song.245000.json','["淡月江南樹，香奇影亦奇。", "春前十二月，雪後兩三枝。", "冷蘂疏堪數，孤根穩不移。", "西湖老仙宅，清夢夜何其。"]'),
('fa736dc8-9af1-4875-90cd-128d31a2a895','正月二十四日送廉使出郊  其一','仇遠','宋','宋诗','song-poetry','','[]','閒騎羸馬出，遠餞繡衣行。',48,'全唐诗/poet.song.245000.json','["閒騎羸馬出，遠餞繡衣行。", "愛此川原迥，欣然風日晴。", "隔籬梅半落，斷隴麥初生。", "每恨微官縛，茅山負夙盟。"]'),
('96eb8821-4784-4125-a513-111fd79c658b','正月二十四日送廉使出郊  其二','仇遠','宋','宋诗','song-poetry','','[]','野店當官道，村醪喚客留。',48,'全唐诗/poet.song.245000.json','["野店當官道，村醪喚客留。", "偶因乘早出，故作探春遊。", "芳意林梢靜，晴光水面浮。", "人言有龍洞，近在石山頭。"]'),
('bee7eeac-ce86-498e-9f64-18c9cef6db98','聞楊大受凌吉叟吳次山諸友訃音有感二首  其一','仇遠','宋','宋诗','song-poetry','','[]','落落霜餘樹，疏疏曉後星。',48,'全唐诗/poet.song.245000.json','["落落霜餘樹，疏疏曉後星。", "經年才契闊，故友半凋零。", "有夢懷風采，何人作墓銘。", "老孤無限淚，空望浙山青。"]'),
('e4cc60c8-3a84-42e4-ab22-4e0a76755543','聞楊大受凌吉叟吳次山諸友訃音有感二首  其二','仇遠','宋','宋诗','song-poetry','','[]','少長皆吾友，相期滿百齡。',48,'全唐诗/poet.song.245000.json','["少長皆吾友，相期滿百齡。", "生分青白眼，死隔短長亭。", "蕉本身爲幻，藤床夢是醒。", "中山醇酒在，且醉學劉伶。"]'),
('6f994555-ec43-4bf2-aadd-4e55511da07b','孫康侯北歸','仇遠','宋','宋诗','song-poetry','','[]','淮海十年別，北歸今幾時。',48,'全唐诗/poet.song.245000.json','["淮海十年別，北歸今幾時。", "鏡中無舊髪，囊底有新詩。", "每恨爲官縛，翻令見面遲。", "清都遊歷事，還許俗人知。"]'),
('9af2acae-5965-4240-86fe-66b377b4a7ee','夢得墨四片一差短戲呈廷玉','仇遠','宋','宋诗','song-poetry','','[]','昔賢曾夢筆，夢墨定何如。',48,'全唐诗/poet.song.245000.json','["昔賢曾夢筆，夢墨定何如。", "應使山中隠，重研世上書。", "磨人驚老大，飲汁笑空疏。", "長短無庸較，三螺已有餘。"]'),
('f6959404-24f6-4903-9fb3-1303786fafc4','四月十六夜月蝕','仇遠','宋','宋诗','song-poetry','','[]','盛服拜清夜，中庭朝太陰。',48,'全唐诗/poet.song.245000.json','["盛服拜清夜，中庭朝太陰。", "凡來仰天者，俱有愛君心。", "目斷山河影，耳聞鐘磬音。", "還光俄頃易，涕泗漫沾襟。"]'),
('920477c2-bb3b-4e76-9a70-996a2a64074d','送田道士歸茅阜','仇遠','宋','宋诗','song-poetry','','[]','我愛孟東野，君師田子方。',48,'全唐诗/poet.song.245000.json','["我愛孟東野，君師田子方。", "放舟游瀨水，飛舄返華陽。", "有酒須同酌，真情不可忘。", "仙源橋下徑，何日共徜徉。"]'),
('f2e22edc-fa2b-4c7c-aef6-d8d5f23bfa0c','廉公子家藏元石名武夷春雨','仇遠','宋','宋诗','song-poetry','','[]','至寶忽橫道，峰巒高復低。',48,'全唐诗/poet.song.245000.json','["至寶忽橫道，峰巒高復低。", "數尖靈壁石，一曲武夷溪。", "黛色春浮玉，黄流雨曳泥。", "遥知千載下，名與峴山齊。"]'),
('d3937b71-c2d9-4997-97f5-7fbbc6823651','醉聞杜宇','仇遠','宋','宋诗','song-poetry','','[]','家家酒似池，日日醉如泥。',48,'全唐诗/poet.song.245000.json','["家家酒似池，日日醉如泥。", "海燕聊爲客，杜鵑何苦啼。", "狂那知帽落，歸不爲花迷。", "信筆成詩句，苔牋小草題。"]'),
('5f864774-f271-478a-9a43-1b486841780f','移床詩','仇遠','宋','宋诗','song-poetry','','[]','莞簟輕輕卷，藤床故故移。',48,'全唐诗/poet.song.245000.json','["莞簟輕輕卷，藤床故故移。", "暑塵無避處，客舍有凉時。", "開帳迎風易，鈎簾看雨宜。", "綠陰更清絕，舊竹長新枝。"]'),
('9b09f187-f3ec-41f7-992b-2194de032aa3','長晝','仇遠','宋','宋诗','song-poetry','','[]','閒官少公出，長日足高眠。',48,'全唐诗/poet.song.245000.json','["閒官少公出，長日足高眠。", "律己惟三尺，埋頭又兩年。", "雖無乞米帖，安得買山錢。", "莫聽閒唇舌，行藏任老天。"]'),
('3ee94867-029c-4671-aa70-aeb49342fa7d','處暑後風雨','仇遠','宋','宋诗','song-poetry','','[]','疾風驅急雨，殘暑掃除空。',48,'全唐诗/poet.song.245000.json','["疾風驅急雨，殘暑掃除空。", "因識炎凉態，都來頃刻中。", "紙窗嫌有隙，紈扇笑無功。", "兒讀秋聲賦，令人憶醉翁。"]'),
('54655f1c-f5ed-4982-8958-82e4caf51de8','閒步','仇遠','宋','宋诗','song-poetry','','[]','村逕桑麻合，扶筇信所之。',48,'全唐诗/poet.song.245000.json','["村逕桑麻合，扶筇信所之。", "綠陰晴冉冉，白日步遲遲。", "野繭粘高樹，山雌入破籬。", "豈無款段馬，常是小兒騎。"]'),
('95acfca8-81d3-4b45-b3c4-bf60d787f031','鼓角','仇遠','宋','宋诗','song-poetry','','[]','五更相次曉，一曲有餘清。',48,'全唐诗/poet.song.245000.json','["五更相次曉，一曲有餘清。", "忽醒山林夢，遥聞鼓角聲。", "背風還迤邐，带月最分明。", "莫作邊城看，長淮久息兵。"]'),
('46112634-87ba-45ec-93ce-d52ee7fbd832','六月雨','仇遠','宋','宋诗','song-poetry','','[]','驟雨忽終日，高田知有秋。',48,'全唐诗/poet.song.245000.json','["驟雨忽終日，高田知有秋。", "斜風驅溽暑，平地作交流。", "屋漏忙移坐，泥深懶出游。", "美哉今夕睡，凉意已浮浮。"]'),
('b710c878-1efe-445d-8b56-ac5b44768fab','雁','仇遠','宋','宋诗','song-poetry','','[]','四郊皆積水，鳴雁一何多。',48,'全唐诗/poet.song.246000.json','["四郊皆積水，鳴雁一何多。", "隨處沙頭宿，常時月下過。", "弟兄求口食，羈旅困風波。", "寄語支更者，蘆深有網羅。"]'),
('a6610ece-29c9-4e17-8c58-845fa61701ec','新秋','仇遠','宋','宋诗','song-poetry','','[]','雙星方卜夜，載宿已交秋。',48,'全唐诗/poet.song.246000.json','["雙星方卜夜，載宿已交秋。", "未覺炎凉改，先爲草木憂。", "雁來催燕去，火老讓金柔。", "阮籍知何事，江東尚滯留。"]'),
('afee71fd-d53b-4d90-828a-835cc8f0e376','秋感  其一','仇遠','宋','宋诗','song-poetry','','[]','明朝交白露，此夜起金風。',48,'全唐诗/poet.song.246000.json','["明朝交白露，此夜起金風。", "燈下倚孤枕，籬根語百蟲。", "梧桐何處落，杼軸幾家空。", "客意驚秋半，炎凉信轉蓬。"]'),
('e3b35b0f-20f4-4bf5-a836-6e94e1688570','秋感  其二','仇遠','宋','宋诗','song-poetry','','[]','蛩依莎底露，螢墮樹頭風。',48,'全唐诗/poet.song.246000.json','["蛩依莎底露，螢墮樹頭風。", "秋已來多日，人誰念二蟲。", "火流豳月應，雲散楚天空。", "摇落年年事，吾生鬢亦蓬。"]'),
('cdb8036f-6fda-4992-91aa-ec0c91ff9251','八月二十三日三溪書房賞桂二花','仇遠','宋','宋诗','song-poetry','','[]','二花香更烈，不與一花同。',48,'全唐诗/poet.song.246000.json','["二花香更烈，不與一花同。", "曾記和雲折，惟愁著雨空。", "舊遊明月窟，古意小山叢。", "十日中秋過，渾疑秋未中。"]'),
('e70737fa-513a-4340-9415-43616da78c1d','冷坐','仇遠','宋','宋诗','song-poetry','','[]','冷官宜靜坐，借屋近荒村。',48,'全唐诗/poet.song.246000.json','["冷官宜靜坐，借屋近荒村。", "無酒可延客，未昏先閉門。", "水明知月上，木落見梅尊。", "滿目凄凉者，相逢不必言。"]'),
('a86d2410-7c9c-47f0-8135-2bcd2dd42e86','抱膝','仇遠','宋','宋诗','song-poetry','','[]','抱膝坐終日，澹然忘是非。',48,'全唐诗/poet.song.246000.json','["抱膝坐終日，澹然忘是非。", "縱令官未滿，已與世相違。", "古道平蕪合，誰家新燕歸。", "年荒烟火歇，空老一山薇。"]'),
('d6324951-ad73-4c0f-b270-9d8581743976','七月梨花','仇遠','宋','宋诗','song-poetry','','[]','紫薇紅槿外，忽見此花嬌。',48,'全唐诗/poet.song.246000.json','["紫薇紅槿外，忽見此花嬌。", "縱被秋陽暴，何愁香雪消。", "夢回雲冉冉，春遠夜寥寥。", "魂隔梧桐雨，時吹玉笛招。"]'),
('b0a4027f-a37c-493f-8fc4-8886284b47da','和卞仲祥','仇遠','宋','宋诗','song-poetry','','[]','我愛中秋月，行歌荒野中。',48,'全唐诗/poet.song.246000.json','["我愛中秋月，行歌荒野中。", "亂雲催薄暮，喬木易高風。", "鏡裏花難折，樽中酒不空。", "南飛有烏鵲，未見北來鴻。"]'),
('0f451d67-2838-48b7-99b9-64c2ff4ce5bb','和黄晉卿金陵見寄','仇遠','宋','宋诗','song-poetry','','[]','臺城爲客久，書札竟寥寥。',48,'全唐诗/poet.song.246000.json','["臺城爲客久，書札竟寥寥。", "山水舟車近，風霜歲月遥。", "窮猿猶擇木，威鳳合沖霄。", "曾有論文約，應須折簡招。"]'),
('f718c7ec-d616-45cd-90c1-0cedcf09c291','再和卞仲祥','仇遠','宋','宋诗','song-poetry','','[]','待月東扉外，一枝明燭殘。',48,'全唐诗/poet.song.246000.json','["待月東扉外，一枝明燭殘。", "誰將丹桂子，種在碧雲端。", "病葉依窗濕，饑鴻集渚寒。", "嬋娟爲雨妒，怊悵又更闌。"]'),
('e96ccda6-9b0b-4f4a-ba67-4ca292d40148','次西和韻','仇遠','宋','宋诗','song-poetry','','[]','貧是儒家事，生平畏四知。',48,'全唐诗/poet.song.246000.json','["貧是儒家事，生平畏四知。", "燈花空送喜，瓶粟不供炊。", "湖海心終在，田園計未遲。", "願同華山叟，馿背倒能騎。"]'),
('54e60e55-a967-479c-afd9-e6df61a0450b','八月十四夜月下聞秋聲','仇遠','宋','宋诗','song-poetry','','[]','中秋纔一宿，此夜已圓明。',48,'全唐诗/poet.song.246000.json','["中秋纔一宿，此夜已圓明。", "星斗何曾見，雲煙不敢生。", "黄花千萬粟，白髪兩三莖。", "愁聽東南角，奔騰風雨聲。"]'),
('bb7bffe2-64f9-4686-a215-000a02816099','樹葉','仇遠','宋','宋诗','song-poetry','','[]','不知何樹葉，紅潤極鮮明。',48,'全唐诗/poet.song.246000.json','["不知何樹葉，紅潤極鮮明。", "一片風吹落，幾番霜染成。", "止啼誠誑語，題字亦閒情。", "把玩真堪惜，携歸予繡枰。"]');
